use super::*;

fn read_policy_history_jsonl(path: &Path) -> Vec<serde_json::Value> {
    std::fs::read_to_string(path)
        .expect("policy history jsonl")
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(|line| serde_json::from_str(line).expect("policy history record json"))
        .collect()
}

fn read_moment_history_jsonl(path: &Path) -> Vec<serde_json::Value> {
    std::fs::read_to_string(path)
        .expect("moment history jsonl")
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(|line| serde_json::from_str(line).expect("moment history record json"))
        .collect()
}

fn test_human_input(controller_slot: usize, player_id: Option<usize>, seq: u64) -> HumanInputFrame {
    HumanInputFrame {
        pace: 0,
        controller_slot,
        player_id,
        seq,
        axis: Vec2::zero(),
        sprint: false,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }
}

fn test_controller_assignment(controller_slot: usize, player_id: usize) -> ControllerAssignment {
    ControllerAssignment {
        controller_slot,
        player_id,
        player_name: format!("P{player_id}"),
        team: Team::Home,
    }
}

fn test_decision_trace(
    snapshot: &WorldSnapshot,
    player_id: usize,
    action: &str,
) -> AgentDecisionTrace {
    let observation = snapshot.observation_for(player_id);
    AgentDecisionTrace {
        mdp_state: snapshot.mdp_state_for_player(player_id),
        belief: belief_from_observation(&observation),
        observation,
        operation_order: vec![action.to_string()],
        scheduled_index: None,
        action_options: single_action_option(action),
        action_target: None,
        mdp_mpc_comparison: None,
        learned_mpc_replan: None,
        behavior_policy_probability: None,
        action: action.to_string(),
    }
}

fn test_pending_pass(
    team: Team,
    from: usize,
    target: usize,
    origin: Vec2,
    intended_target: Vec2,
) -> PendingPass {
    PendingPass {
        team,
        from,
        target: Some(target),
        flight: PassFlight::Floor,
        is_cross: false,
        launch_tick: 0,
        origin,
        intended_target,
        distance_yards: origin.distance(intended_target),
        receiver_openness: 1.0,
        passer_skill: 1.0,
        launch_speed_yps: 18.0,
        receiver_position_at_launch: Some(intended_target),
        receiver_velocity_at_launch: Some(Vec2::zero()),
        offside: None,
        offside_candidates: Vec::new(),
        learn_features: Vec::new(),
    }
}

#[test]
fn policy_head_trains_skill_specialists_independently() {
    let sample = |role: PlayerRole, action: &str| -> SoccerPolicySample {
        let state_features: [f64; SOCCER_POLICY_FEATURE_DIM] =
            soccer_policy_features_for_role(&[0.0; SOCCER_NEURAL_FEATURE_DIM], role, None)
                .try_into()
                .expect("policy feature dim");
        SoccerPolicySample {
            state_features,
            action_index: soccer_policy_action_index(action).expect("known policy action"),
            advantage: 1.0,
            old_action_probability: None,
        }
    };
    let specialist_steps = |head: &SoccerPolicyHead, kind: SoccerPolicySpecialistKind| {
        head.role_heads
            .iter()
            .flat_map(|role_head| role_head.specialist_heads.iter())
            .filter(|specialist| specialist.kind == kind)
            .map(|specialist| specialist.training_steps)
            .sum::<usize>()
    };
    let role_specialist_steps =
        |head: &SoccerPolicyHead, role: PlayerRole, kind: SoccerPolicySpecialistKind| {
            head.role_head_for_role(role)
                .expect("role policy head")
                .specialist_heads
                .iter()
                .find(|specialist| specialist.kind == kind)
                .expect("specialist head")
                .training_steps
        };

    let mut head = SoccerPolicyHead::new(42);
    head.train(&[sample(PlayerRole::Midfielder, "pass")], None);
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Passing),
        1
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Dribbling),
        0
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Shooting),
        0
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Goalkeeping),
        0
    );
    assert_eq!(
        role_specialist_steps(
            &head,
            PlayerRole::Forward,
            SoccerPolicySpecialistKind::Passing
        ),
        0,
        "midfield pass training must not update the forward passing specialist"
    );

    head.train(
        &[
            sample(PlayerRole::Midfielder, "carry-forward"),
            sample(PlayerRole::Forward, "shoot"),
            sample(PlayerRole::Goalkeeper, "keeper-survey-hands"),
        ],
        None,
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Passing),
        1
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Dribbling),
        1
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Shooting),
        1
    );
    assert_eq!(
        specialist_steps(&head, SoccerPolicySpecialistKind::Goalkeeping),
        1
    );
    assert_eq!(
        role_specialist_steps(
            &head,
            PlayerRole::Forward,
            SoccerPolicySpecialistKind::Shooting
        ),
        1
    );
    assert_eq!(
        role_specialist_steps(
            &head,
            PlayerRole::Goalkeeper,
            SoccerPolicySpecialistKind::Goalkeeping
        ),
        1
    );
}

#[test]
fn policy_head_snapshot_round_trips_role_heads_and_specialists() {
    let sample = |role: PlayerRole, action: &str| -> SoccerPolicySample {
        let state_features: [f64; SOCCER_POLICY_FEATURE_DIM] =
            soccer_policy_features_for_role(&[0.0; SOCCER_NEURAL_FEATURE_DIM], role, None)
                .try_into()
                .expect("policy feature dim");
        SoccerPolicySample {
            state_features,
            action_index: soccer_policy_action_index(action).expect("known policy action"),
            advantage: 1.0,
            old_action_probability: None,
        }
    };

    let mut head = SoccerPolicyHead::new(77);
    head.train(
        &[
            sample(PlayerRole::Forward, "shoot"),
            sample(PlayerRole::Goalkeeper, "keeper-survey-hands"),
        ],
        None,
    );

    let snapshot = soccer_policy_head_snapshot(&head);
    assert_eq!(
        snapshot.role_heads.len(),
        SOCCER_POLICY_ROLE_EMBEDDING_DIM,
        "new actor snapshots must carry one head per role group"
    );
    let restored = soccer_policy_head_from_snapshot(&snapshot, 99)
        .expect("role-head actor snapshot should restore");

    let forward_head = restored
        .role_head_for_role(PlayerRole::Forward)
        .expect("forward role head");
    assert_eq!(forward_head.training_steps, 1);
    assert_eq!(
        forward_head
            .specialist_heads
            .iter()
            .find(|specialist| specialist.kind == SoccerPolicySpecialistKind::Shooting)
            .expect("shooting specialist")
            .training_steps,
        1
    );
    let defender_head = restored
        .role_head_for_role(PlayerRole::Defender)
        .expect("defender role head");
    assert_eq!(
        defender_head.training_steps, 0,
        "restoring a trained forward head must not smear steps onto defenders"
    );
    let goalkeeper_head = restored
        .role_head_for_role(PlayerRole::Goalkeeper)
        .expect("goalkeeper role head");
    assert_eq!(goalkeeper_head.training_steps, 1);
    assert_eq!(
        goalkeeper_head
            .specialist_heads
            .iter()
            .find(|specialist| specialist.kind == SoccerPolicySpecialistKind::Goalkeeping)
            .expect("goalkeeping specialist")
            .training_steps,
        1
    );
}

#[test]
fn keeper_policy_actions_are_distinct_from_outfield_actions() {
    assert!(soccer_policy_action_index("keeper-mpc-floor-pass").is_some());
    assert!(soccer_policy_action_index("keeper-mpc-aerial-pass").is_some());
    assert!(soccer_policy_action_index("keeper-mpc-clearance").is_some());
    assert!(soccer_policy_action_index("keeper-survey-hands").is_some());
    assert_ne!(
        soccer_policy_action_index("keeper-mpc-clearance"),
        soccer_policy_action_index("clearance")
    );
}

#[test]
fn save_outcome_credits_goalkeeper_recent_decision() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        learning_enabled: true,
        ..MatchConfig::default()
    });
    let keeper = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Goalkeeper)
        .expect("away keeper")
        .id;
    let shooter = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Forward)
        .expect("home forward")
        .id;
    sim.tick = 55;
    sim.players[keeper].position = Vec2::new(40.0, 118.0);
    sim.players[shooter].position = Vec2::new(40.0, 104.0);
    let before = WorldSnapshot::from_match(&sim);
    let keeper_decision = test_decision_trace(&before, keeper, "keeper-position");
    sim.recent_learning_history
        .push_back(SoccerLearningTransition {
            tick: 50,
            player_id: keeper,
            team: Team::Away,
            role: PlayerRole::Goalkeeper,
            state: before.mdp_state_for_player(keeper),
            observation: before.observation_for(keeper),
            belief: keeper_decision.belief.clone(),
            action: keeper_decision.action.clone(),
            action_target: keeper_decision.action_target.clone(),
            decision_context: SoccerDecisionContext::default(),
            tactical_trace: SoccerTacticalLearningTrace::default(),
            reward: 0.0,
            next_state: before.mdp_state_for_player(keeper),
            next_observation: before.observation_for(keeper),
            done: false,
        });
    let event_start = sim.reward_events.len();

    sim.apply_ball_outcome(BallStepOutcome::Save {
        shot: PendingShot {
            team: Team::Home,
            shooter,
            origin: sim.players[shooter].position,
        },
        defending_team: Team::Away,
        keeper_id: keeper,
        save_position: sim.players[keeper].position,
    });

    assert!(sim.reward_events[event_start..].iter().any(|event| {
        event.player_id == keeper
            && event.kind == SoccerRewardEventKind::GoalkeeperSave
            && event.amount > GOALKEEPER_SAVE_BASE_REWARD_POINTS
    }));
    let credited = sim
        .deferred_reward_transitions
        .iter()
        .rev()
        .find(|transition| transition.player_id == keeper)
        .expect("deferred keeper transition");
    assert_eq!(credited.role, PlayerRole::Goalkeeper);
    assert_eq!(credited.action, "keeper-position");
    assert!(credited.reward > GOALKEEPER_SAVE_BASE_REWARD_POINTS);
}

#[test]
fn default_match_config_preserves_initial_runtime_contract() {
    let config = MatchConfig::default().sanitized_for_runtime();
    assert_eq!(config.dt_seconds, DEFAULT_DT_SECONDS);
    assert_eq!(config.dt_seconds, 1.0 / 15.0);
    assert_eq!(config.duration_seconds, DEFAULT_DURATION_SECONDS);
    assert_eq!(config.duration_seconds, 10.0 * 60.0);
    assert_eq!(config.effective_duration_seconds(), 600.0);
    assert_eq!(config.total_ticks(), 9_000);
    assert_eq!(config.human_slots(), 4);
    assert!(config.learning_enabled);
    assert!(config.learning_logging_enabled);
    assert_eq!(
        config.learning_interval_ticks,
        default_learning_interval_ticks()
    );
    assert_eq!(
        config.policy_train_max_transitions_per_tick,
        default_policy_train_max_transitions_per_tick()
    );
    assert!(config.full_game_learning_enabled);

    let sim = SoccerMatch::default_11v11(config);
    assert_eq!(sim.players.len(), 22);
    assert_eq!(sim.officials.len(), 3);
    assert_eq!(sim.ball.id, BALL_AGENT_ID);
    assert_eq!(sim.config.total_ticks(), 9_000);
    assert_eq!(sim.config.human_slots(), 4);
    assert_eq!(sim.config.field_length_yards, DEFAULT_FIELD_LENGTH_YARDS);
    assert_eq!(sim.config.field_width_yards, DEFAULT_FIELD_WIDTH_YARDS);
    assert_eq!(sim.config.goal_width_yards, DEFAULT_GOAL_WIDTH_YARDS);
}

#[test]
fn default_players_spawn_inside_custom_pitch_dimensions() {
    let sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.0,
        half_duration_seconds: 0.0,
        field_width_yards: 36.0,
        field_length_yards: 54.0,
        max_human_players: 0,
        ..MatchConfig::default()
    });

    assert_eq!(sim.players.len(), 22);
    for player in &sim.players {
        assert!(
            (0.0..=sim.config.field_width_yards).contains(&player.position.x),
            "player {} x={} outside width {}",
            player.id,
            player.position.x,
            sim.config.field_width_yards
        );
        assert!(
            (0.0..=sim.config.field_length_yards).contains(&player.position.y),
            "player {} y={} outside length {}",
            player.id,
            player.position.y,
            sim.config.field_length_yards
        );
    }
}

#[test]
fn pomdp_observation_carries_previous_tick_decision_state() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        seed: 91_001,
        ..MatchConfig::default()
    });
    let player_id = sim
        .players
        .iter()
        .find(|player| player.role != PlayerRole::Goalkeeper)
        .expect("field player")
        .id;

    let before = WorldSnapshot::from_match(&sim);
    assert!(
        before
            .observation_for(player_id)
            .previous_tick_carryover
            .is_none(),
        "a fresh match must not invent previous-tick state"
    );

    sim.run_time_step();

    let after = WorldSnapshot::from_match(&sim);
    let serialized_snapshot = serde_json::to_string(&after).expect("snapshot json");
    assert!(
        !serialized_snapshot.contains("\"playerTickCarryover\""),
        "the full carryover cache is internal; snapshots expose only per-observation carryover"
    );
    let observation = after.observation_for(player_id);
    let carryover = observation
        .previous_tick_carryover
        .as_ref()
        .expect("previous run_time_step decision should be visible");
    let decision = sim.players[player_id]
        .last_decision
        .as_ref()
        .expect("player decision");
    assert_eq!(carryover.player_id, player_id);
    assert_eq!(carryover.observed_at_tick, after.tick);
    assert_eq!(
        carryover.age_ticks,
        after.tick.saturating_sub(carryover.decision_tick)
    );
    assert_eq!(carryover.action, decision.action);
    assert_eq!(carryover.mdp_phase, decision.mdp_state.phase);
    assert_eq!(carryover.mdp_ball_grid, decision.mdp_state.ball_grid);
    assert_eq!(carryover.mdp_player_grid, decision.mdp_state.player_grid);
    assert_eq!(
        carryover.pomdp_visible_ball,
        decision.observation.visible_ball
    );
    assert_eq!(
        carryover.pomdp_visible_teammates,
        decision.observation.visible_teammates
    );
    assert!(!carryover.mpc_guidance_present);
    assert_eq!(
        carryover.chosen_action_mpc_feasibility, 1.0,
        "no MPC comparison should be neutral, not an infeasibility signal"
    );
    assert_eq!(
        carryover.commitment_ticks.last().copied(),
        Some(carryover.decision_tick)
    );
    assert_eq!(carryover.recent_commitment_count_7_ticks, 1);
    assert_eq!(carryover.ticks_since_commitment, carryover.age_ticks);
    assert!(
        carryover.decision_cadence_switch_locked,
        "the next observation should know a fresh commitment is still inside the 3-tick reaction lock"
    );

    let transition = SoccerLearningTransition {
        tick: after.tick,
        player_id,
        team: sim.players[player_id].team,
        role: sim.players[player_id].role,
        state: decision.mdp_state.clone(),
        observation: observation.clone(),
        belief: decision.belief.clone(),
        action: decision.action.clone(),
        action_target: decision.action_target.clone(),
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: after.mdp_state_for_player(player_id),
        next_observation: observation.clone(),
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert_eq!(
        features[SOCCER_NEURAL_FEATURE_DECISION_COMMITMENT_WINDOW_PRESSURE], 0.5,
        "one recent commitment should occupy half of the two-in-seven-ticks cadence budget"
    );
    assert_eq!(
        features[SOCCER_NEURAL_FEATURE_DECISION_COMMITMENT_SWITCH_LOCKED], 1.0,
        "neural learners should see that a strategy switch is currently cadence-locked"
    );
}

#[test]
fn player_tick_carryover_marks_stale_decisions_and_clears_on_restart_reset() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 2.0,
        seed: 91_002,
        ..MatchConfig::default()
    });
    sim.run_time_step();
    let player_id = sim
        .players
        .iter()
        .find(|player| player.last_decision.is_some())
        .expect("player with decision")
        .id;
    let first = WorldSnapshot::from_match(&sim)
        .observation_for(player_id)
        .previous_tick_carryover
        .expect("initial carryover");
    sim.players[player_id].slide_recovery_seconds = sim.config.dt_seconds * 2.0;

    sim.run_time_step();

    let stale = WorldSnapshot::from_match(&sim)
        .observation_for(player_id)
        .previous_tick_carryover
        .expect("stale carryover");
    assert_eq!(
        stale.decision_tick, first.decision_tick,
        "skipped players should retain the previous decision tick"
    );
    assert!(
        stale.age_ticks > first.age_ticks,
        "age_ticks should reveal that the carried decision is stale"
    );
    assert!(
        stale.ticks_since_commitment > first.ticks_since_commitment,
        "skipped players should still age their active decision commitment"
    );

    sim.start_new_period(2, Team::Away);
    assert!(
        sim.player_tick_carryover.is_empty(),
        "restart reset should not carry old open-play decisions"
    );
    assert!(
        sim.players
            .iter()
            .all(|player| player.last_decision.is_none()),
        "restart reset should clear stale player decisions before they can repopulate carryover"
    );
    let kickoff_holder = sim.ball.holder.expect("kickoff holder");
    assert!(
        WorldSnapshot::from_match(&sim)
            .observation_for(kickoff_holder)
            .previous_tick_carryover
            .is_none(),
        "post-reset observations should start with no previous open-play carryover"
    );
}

#[test]
fn tier2_mpc_is_inert_when_disabled_and_active_when_enabled() {
    // Disabled (default): the analytic movement path runs and no per-player
    // MPC controller is ever instantiated, no matter how long the match runs.
    let mut off = SoccerMatch::default_11v11(MatchConfig {
        seed: 7_777,
        ..Default::default()
    });
    assert!(!off.config.mpc.tier2_player_enabled);
    for _ in 0..300 {
        off.run_time_step();
    }
    assert!(
        off.mpc_player_controllers.is_empty(),
        "MPC must not allocate controllers when tier2 is off"
    );

    // Enabled: controllers are created lazily for the active subset, the match
    // still advances normally, and no controller drives a player past the
    // heuristic speed envelope.
    let mut on = SoccerMatch::default_11v11(MatchConfig {
        seed: 7_777,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    for _ in 0..300 {
        on.run_time_step();
    }
    assert!(
        !on.mpc_player_controllers.is_empty(),
        "tier2 enabled should populate controllers for the active subset"
    );
    assert_eq!(on.tick, 300, "match must advance the same with MPC on");
    for player in &on.players {
        let speed = player.velocity.len();
        let cap = player_top_speed_yps(player.role, &player.skills) * 1.5 + 1.0;
        assert!(
            speed <= cap,
            "player {} exceeded plausible speed under MPC: {speed} > {cap}",
            player.id
        );
    }
}

#[test]
fn field_aware_mpc_runs_a_full_match_without_breaking_physics() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 5_150,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            field_aware_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    for _ in 0..300 {
        sim.run_time_step();
    }
    assert_eq!(sim.tick, 300);
    assert!(!sim.mpc_player_controllers.is_empty());
    for player in &sim.players {
        let speed = player.velocity.len();
        assert!(
            speed.is_finite(),
            "player {} got non-finite velocity",
            player.id
        );
        let cap = player_top_speed_yps(player.role, &player.skills) * 1.5 + 1.0;
        assert!(
            speed <= cap,
            "player {} too fast under field-aware MPC: {speed}",
            player.id
        );
    }
}

#[test]
fn mpc_latent_objective_learns_from_pass_chains_shots_and_goals() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 5_152,
        mpc: SoccerMpcConfig {
            latent_objective_enabled: true,
            latent_learning_rate: 0.5,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let home_ids: Vec<usize> = sim
        .players
        .iter()
        .filter(|player| player.team == Team::Home && player.role != PlayerRole::Goalkeeper)
        .take(4)
        .map(|player| player.id)
        .collect();
    assert!(home_ids.len() >= 4);

    let pass1 = test_pending_pass(
        Team::Home,
        home_ids[0],
        home_ids[1],
        Vec2::new(24.0, 24.0),
        Vec2::new(28.0, 31.0),
    );
    sim.ball.position = pass1.intended_target;
    sim.record_completed_pass_reward(&pass1, home_ids[1]);
    let after_one = sim.mpc_latent_objective(Team::Home);
    assert!(after_one.pass_chain_continuity > 0.0);

    let pass2 = test_pending_pass(
        Team::Home,
        home_ids[1],
        home_ids[2],
        pass1.intended_target,
        Vec2::new(32.0, 39.0),
    );
    sim.ball.position = pass2.intended_target;
    sim.record_completed_pass_reward(&pass2, home_ids[2]);
    let after_two = sim.mpc_latent_objective(Team::Home);
    assert!(after_two.pass_chain_continuity > after_one.pass_chain_continuity);

    let pass3 = test_pending_pass(
        Team::Home,
        home_ids[2],
        home_ids[3],
        pass2.intended_target,
        Vec2::new(34.0, 49.0),
    );
    sim.ball.position = pass3.intended_target;
    sim.record_completed_pass_reward(&pass3, home_ids[3]);
    let after_three = sim.mpc_latent_objective(Team::Home);
    assert!(after_three.pass_chain_continuity > after_two.pass_chain_continuity);

    // Shot-on-target credit is now distance-gated to within 20yd of goal, so the shooter must be
    // in genuine shooting range for the latent objective to register shot pressure.
    sim.players[home_ids[3]].position = Vec2::new(40.0, 108.0);
    sim.record_shot_on_target_rewards(Team::Home, home_ids[3]);
    let after_shot = sim.mpc_latent_objective(Team::Home);
    assert!(after_shot.shot_pressure > 0.0);

    sim.record_goal_rewards(Team::Home, Some(home_ids[3]));
    let after_goal = sim.mpc_latent_objective(Team::Home);
    assert!(after_goal.goal_pressure > 0.0);
    assert_eq!(
        sim.mpc_latent_objective(Team::Away),
        SoccerMpcLatentObjective::default()
    );
}

#[test]
fn mpc_latent_objective_shapes_controller_weights_but_keeps_short_horizon() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 5_153,
        local_mpc_enabled: true,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            latent_objective_enabled: true,
            latent_weight_boost: 0.5,
            latent_reference_bias_yards: 2.0,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let holder = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role != PlayerRole::Goalkeeper)
        .map(|player| player.id)
        .expect("home outfield holder");
    sim.home_mpc_latent_objective = SoccerMpcLatentObjective {
        pass_chain_continuity: 1.0,
        shot_pressure: 0.5,
        goal_pressure: 0.25,
        ..Default::default()
    };
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    for _ in 0..5 {
        sim.run_time_step();
        if sim
            .mpc_player_controllers
            .iter()
            .any(|(player_id, _)| sim.players[*player_id].team == Team::Home)
        {
            break;
        }
    }

    let base = crate::des::general::mpc_point_mass::PlanarMpcConfig::default();
    let cfg = sim
        .mpc_player_controllers
        .iter()
        .find(|(player_id, _)| sim.players[**player_id].team == Team::Home)
        .map(|(_, controller)| *controller.config())
        .expect("home latent MPC controller");
    assert_eq!(cfg.horizon, sim.config.mpc.player_horizon);
    assert_eq!(cfg.iters, 90);
    assert!(cfg.q_pos > base.q_pos);
    assert!(cfg.q_vel > base.q_vel);
    assert!(cfg.qf_pos > base.qf_pos);
    assert!(cfg.qf_vel > base.qf_vel);
}

#[test]
fn mpc_pitch_value_terminal_gain_prefers_higher_threat_targets() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 5_154,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let player_id = 6;
    park_players_except(&mut sim, &[player_id]);
    sim.ball.holder = Some(player_id);
    sim.ball.position = Vec2::new(40.0, 54.0);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[player_id].position = sim.ball.position;
    sim.players[player_id].home_position = sim.ball.position;

    let low_value_target = Vec2::new(40.0, 56.0);
    let high_value_target = Vec2::new(40.0, 74.0);
    let low_gain = sim.mpc_pitch_value_terminal_gain_for(player_id, low_value_target);
    let high_gain = sim.mpc_pitch_value_terminal_gain_for(player_id, high_value_target);
    assert!(
        high_gain > low_gain + 0.02,
        "MPC terminal xT gain should prefer advancing into value: low={low_gain:.4} high={high_gain:.4}"
    );

    let shaped = sim.mpc_pitch_value_shaped_target(player_id, high_value_target);
    let base_value = expected_threat(
        Team::Home,
        high_value_target,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );
    let shaped_value = expected_threat(
        Team::Home,
        shaped,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );
    assert!(
        shaped_value >= base_value + MPC_PITCH_VALUE_REFERENCE_MIN_GAIN,
        "xT terminal reference should nudge toward a higher-value local point: raw={high_value_target:?} shaped={shaped:?} base={base_value:.4} shaped={shaped_value:.4}"
    );
    assert!(
        shaped.distance(high_value_target) <= MPC_PITCH_VALUE_REFERENCE_MAX_NUDGE_YARDS + 1e-6,
        "xT reference nudge must stay bounded and single-player: {shaped:?}"
    );
}

#[test]
fn tier2_mpc_field_obstacles_use_player_and_ball_kinematics() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 5_151,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            field_aware_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let player_id = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role != PlayerRole::Goalkeeper)
        .map(|player| player.id)
        .expect("controlled player");
    let opponent_id = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role != PlayerRole::Goalkeeper)
        .map(|player| player.id)
        .expect("opponent obstacle");
    let obstacle_position = Vec2::new(31.0, 44.0);
    let obstacle_velocity = Vec2::new(3.5, -4.0);
    let obstacle_acceleration = Vec2::new(6.0, 2.5);
    if let Some(opponent) = sim
        .players
        .iter_mut()
        .find(|player| player.id == opponent_id)
    {
        opponent.position = obstacle_position;
        opponent.velocity = obstacle_velocity;
        opponent.acceleration = obstacle_acceleration;
    }
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(62.0, 33.0);
    sim.ball.velocity = Vec2::new(-8.0, 5.0);
    sim.ball.acceleration = Vec2::new(-5.0, 3.0);

    let dt = sane_dt_seconds(sim.config.dt_seconds, DEFAULT_DT_SECONDS).max(1e-6);
    let half_dt2 = 0.5 * dt * dt;
    let (width, length) =
        sane_pitch_dimensions(sim.config.field_width_yards, sim.config.field_length_yards);
    let my_team = sim
        .players
        .iter()
        .find(|player| player.id == player_id)
        .map(|player| player.team)
        .expect("controlled player team");
    let obstacles = sim.mpc_field_obstacles(player_id, my_team, dt);
    assert_eq!(
        obstacles.len(),
        sim.players.len(),
        "Tier-2 MPC should model every other player plus the ball"
    );

    let expected_opponent_center = finite_pitch_point(
        obstacle_position + obstacle_velocity * dt + obstacle_acceleration * half_dt2,
        width,
        length,
        obstacle_position,
    );
    let expected_opponent_velocity =
        limit_vec2_len(obstacle_velocity + obstacle_acceleration * dt, 28.0);
    let opponent_obstacle = obstacles
        .iter()
        .find(|obstacle| {
            Vec2::new(obstacle.center[0], obstacle.center[1]).distance(expected_opponent_center)
                < 1e-9
        })
        .expect("opponent obstacle should use projected position");
    assert!(
        Vec2::new(opponent_obstacle.velocity[0], opponent_obstacle.velocity[1])
            .distance(expected_opponent_velocity)
            < 1e-9,
        "opponent obstacle velocity should include acceleration over the tick"
    );
    assert!(
        opponent_obstacle.weight > sim.config.mpc.keepout_weight,
        "moving/accelerating opponent should carry extra obstacle pressure"
    );

    let expected_ball_center = finite_pitch_point(
        sim.ball.position + sim.ball.velocity * dt + sim.ball.acceleration * half_dt2,
        width,
        length,
        sim.ball.position,
    );
    let expected_ball_velocity =
        limit_vec2_len(sim.ball.velocity + sim.ball.acceleration * dt, 36.0);
    let ball_obstacle = obstacles
        .iter()
        .find(|obstacle| {
            (obstacle.radius - 0.75).abs() < 1e-9
                && Vec2::new(obstacle.center[0], obstacle.center[1]).distance(expected_ball_center)
                    < 1e-9
        })
        .expect("ball obstacle should use projected ball kinematics");
    assert!(
        Vec2::new(ball_obstacle.velocity[0], ball_obstacle.velocity[1])
            .distance(expected_ball_velocity)
            < 1e-9,
        "ball obstacle velocity should include acceleration over the tick"
    );
}

#[test]
fn mdp_mpc_reconciliation_records_divergence_and_blends_when_sensible() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 9_191,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            reconcile_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    assert_eq!(sim.mpc_reconcile_stats().samples, 0);
    for _ in 0..300 {
        sim.run_time_step();
    }
    let stats = sim.mpc_reconcile_stats();
    assert!(
        stats.samples > 0,
        "expected MDP/MPC comparisons to be recorded"
    );
    assert_eq!(
        stats.blended_samples + stats.deferred_to_policy_samples,
        stats.samples,
        "every compared sample must be resolved exactly one way"
    );
    assert!(stats.deviating_samples <= stats.samples);
    assert!(stats.max_deviation_yps >= stats.mean_deviation_yps() - 1e-9);
    assert!(stats.mean_deviation_yps() >= 0.0);
    assert_eq!(sim.tick, 300);
}

fn push_stationary_mpc_guidance(snapshot: &mut WorldSnapshot, player_id: usize, target: Vec2) {
    snapshot
        .formation_lp_guidance
        .retain(|guidance| guidance.player_id != player_id);
    snapshot
        .formation_lp_guidance
        .push(SoccerFormationLpPlayerGuidance {
            team: snapshot
                .players
                .iter()
                .find(|player| player.id == player_id)
                .map(|player| player.team)
                .unwrap_or(Team::Home),
            player_id,
            slot: player_id,
            current: target,
            target,
            formation_anchor: target,
            pressure_target: None,
            recommended_move: Vec2::zero(),
            target_velocity: Vec2::zero(),
            target_acceleration: Vec2::zero(),
            local_mpc_guidance: true,
            recommended_move_yards: 0.0,
            recommended_speed_yps: 0.0,
            recommended_acceleration_yps2: 0.0,
            formation_error_yards: 0.0,
            movement_error_yards: 0.0,
            pair_error_yards: 0.0,
            role_line_error_yards: 0.0,
            pressure_error_yards: 0.0,
            fore_aft_speed_error_yps: 0.0,
            pressure_weight: 1.0,
            speed_match_weight: 0.0,
            alignment_weight: 1.0,
            reduced_cost_target_x: 0.0,
            reduced_cost_target_y: 0.0,
            solver_status: "optimal".to_string(),
            solver_objective: 0.0,
            solver_iterations: Some(1),
            solver_elapsed_ms: 0.0,
            variable_count: 1,
            constraint_count: 1,
        });
}

#[test]
fn learned_mdp_action_reselects_when_mpc_cannot_execute_it() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 9_192,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            reconcile_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let holder = 7;
    park_players_except(&mut sim, &[holder]);
    sim.players[holder].role = PlayerRole::Midfielder;
    sim.players[holder].position = Vec2::new(40.0, 58.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].velocity = Vec2::zero();
    sim.players[holder].skills.acceleration = 4.0;
    sim.players[holder].skills.top_speed = 4.2;
    sim.players[holder].skills.dribbling = 4.4;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let mut snapshot = WorldSnapshot::from_match(&sim);
    snapshot
        .formation_lp_guidance
        .retain(|guidance| guidance.player_id != holder);
    snapshot
        .formation_lp_guidance
        .push(SoccerFormationLpPlayerGuidance {
            team: Team::Home,
            player_id: holder,
            slot: holder,
            current: sim.players[holder].position,
            target: sim.players[holder].position,
            formation_anchor: sim.players[holder].home_position,
            pressure_target: None,
            recommended_move: Vec2::zero(),
            target_velocity: Vec2::zero(),
            target_acceleration: Vec2::zero(),
            local_mpc_guidance: true,
            recommended_move_yards: 0.0,
            recommended_speed_yps: 0.0,
            recommended_acceleration_yps2: 0.0,
            formation_error_yards: 0.0,
            movement_error_yards: 0.0,
            pair_error_yards: 0.0,
            role_line_error_yards: 0.0,
            pressure_error_yards: 0.0,
            fore_aft_speed_error_yps: 0.0,
            pressure_weight: 1.0,
            speed_match_weight: 0.0,
            alignment_weight: 1.0,
            reduced_cost_target_x: 0.0,
            reduced_cost_target_y: 0.0,
            solver_status: "optimal".to_string(),
            solver_objective: 0.0,
            solver_iterations: Some(1),
            solver_elapsed_ms: 0.0,
            variable_count: 1,
            constraint_count: 1,
        });

    let learned_plan = SoccerLearnedPlan {
        action: "vertical-attack".to_string(),
        target_player: None,
        target_point: Some(Vec2::new(72.0, 112.0)),
        mpc_replan: None,
    };
    let mut player = sim.players[holder].clone();
    let _intent = player.run_time_step(
        &snapshot,
        None,
        Some(&learned_plan),
        &mut SeededRandom::new(9_193),
    );
    let decision = player
        .last_decision
        .as_ref()
        .expect("player should make a fallback decision");
    assert!(
        decision
            .operation_order
            .iter()
            .any(|op| op == "learned-mpc-reselect:vertical-attack"),
        "learned action should be sent back through MDP when MPC cannot execute it: {decision:?}"
    );
    assert_ne!(
        decision.action, "vertical-attack",
        "final action should not keep the MPC-rejected learned action"
    );
}

#[test]
fn mpc_pass_execution_prices_lane_and_ball_recipe() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 9_194,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            reconcile_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let passer = 7;
    let receiver = 9;
    let blocker = 13;
    park_players_except(&mut sim, &[passer, receiver, blocker]);
    sim.players[passer].position = Vec2::new(40.0, 58.0);
    sim.players[passer].home_position = sim.players[passer].position;
    sim.players[passer].skills.passing_completion_rate = 6.0;
    sim.players[passer].skills.passing = 6.0;
    sim.players[receiver].team = Team::Home;
    sim.players[receiver].position = Vec2::new(40.0, 76.0);
    sim.players[blocker].team = Team::Away;
    sim.players[blocker].position = Vec2::new(40.0, 66.0);
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let mut snapshot = WorldSnapshot::from_match(&sim);
    push_stationary_mpc_guidance(&mut snapshot, passer, sim.players[passer].position);
    let player = sim.players[passer].clone();
    let action = SoccerAction::Pass {
        target_player: Some(receiver),
        power: 0.58,
        flight: PassFlight::Floor,
    };
    let target = player.action_target_trace(&action, &snapshot);
    let trace = player_mdp_mpc_comparison_trace(&snapshot, &player, &target, "pass1")
        .expect("MPC should trace a guided pass command");
    assert_eq!(trace.decision, "reselect-mdp-after-mpc-low-confidence");
    assert_eq!(trace.mpc_reselect_reason, "mpc-pass-lane-blocked-now");
    assert!(
        trace.mpc_pass_completion_probability < 0.34,
        "blocked lane should be low-completion: {trace:?}"
    );
    assert!(trace.mpc_recommended_speed_yps > 0.0);
    assert!(trace.mpc_recommended_angle_degrees.is_finite());
    assert!(trace.mpc_recommended_spin_rps >= 0.0);
}

#[test]
fn learnable_pass_velocity_drives_a_contested_lane_harder_than_an_open_one() {
    // A ground pass up x=40 from y=58 to a receiver at y=76. With the lane OPEN the value
    // trade-off keeps a weighted ball (the slowest bucket wins on the overhit penalty); with
    // a defender closing on the corridor it chooses a DRIVEN ball to thread the gap before
    // the defender steps in. This proves the learnable-velocity layer is live and
    // discriminates ("price the speed needed, don't veto the lane"), not that it always maxes
    // out. The geometry is asserted to be a real risk gradient so the test is deterministic.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 4_242,
        ..Default::default()
    });
    let passer = 7usize;
    let receiver = 9usize;
    let blocker = 13usize;
    park_players_except(&mut sim, &[passer, receiver, blocker]);
    sim.players[passer].position = Vec2::new(40.0, 58.0);
    sim.players[passer].home_position = sim.players[passer].position;
    sim.players[passer].skills.passing_completion_rate = 6.0;
    sim.players[passer].skills.passing = 6.0;
    sim.players[receiver].team = Team::Home;
    sim.players[receiver].position = Vec2::new(40.0, 76.0);
    sim.players[receiver].velocity = Vec2::zero();
    sim.players[blocker].team = Team::Away;
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let aim = Vec2::new(40.0, 76.0);
    let slow_speed = pass_speed_yps_from_power(
        PASS_VELOCITY_POWER_BUCKETS[0],
        PassFlight::Floor,
        false,
        &sim.players[passer].skills,
    );
    let fast_speed = pass_speed_yps_from_power(
        *PASS_VELOCITY_POWER_BUCKETS.last().unwrap(),
        PassFlight::Floor,
        false,
        &sim.players[passer].skills,
    );

    let plan_for = |sim: &SoccerMatch| {
        let snapshot = WorldSnapshot::from_match(sim);
        let passer_snap = snapshot
            .players
            .iter()
            .find(|p| p.id == passer)
            .cloned()
            .unwrap();
        let receiver_pos = snapshot
            .players
            .iter()
            .find(|p| p.id == receiver)
            .map(|p| p.position)
            .unwrap();
        let receiver_snap = snapshot
            .players
            .iter()
            .find(|p| p.id == receiver)
            .cloned()
            .unwrap();
        let plan = pass_velocity_plan_for_snapshot(
            &snapshot,
            &passer_snap,
            passer_snap.position,
            aim,
            PassFlight::Floor,
            false,
            Some((&receiver_snap, receiver_pos)),
        );
        let risk_slow = snapshot
            .pass_lane_interception_risk(
                passer_snap.position,
                aim,
                Team::Away,
                2.5,
                slow_speed,
                PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
            )
            .risk;
        let risk_fast = snapshot
            .pass_lane_interception_risk(
                passer_snap.position,
                aim,
                Team::Away,
                2.5,
                fast_speed,
                PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
            )
            .risk;
        (plan, risk_slow, risk_fast)
    };

    // (a) Open lane: blocker far away.
    sim.players[blocker].position = Vec2::new(8.0, 20.0);
    sim.players[blocker].velocity = Vec2::zero();
    let (open_plan, _, _) = plan_for(&sim);

    // (b) Contested lane: blocker off the corridor, closing on it. The perpendicular gap is
    // tuned so a weighted ball lets the defender step in (high risk) while a driven ball
    // beats it to the corridor (lower risk) — a genuine speed gradient.
    sim.players[blocker].position = Vec2::new(45.5, 67.0);
    sim.players[blocker].velocity = Vec2::new(-4.0, 0.0);
    let (tight_plan, risk_slow, risk_fast) = plan_for(&sim);

    // The crafted geometry must be a genuine speed gradient (slow ball riskier than fast).
    assert!(
        risk_slow > risk_fast + 1e-3,
        "test geometry should make a weighted ball riskier than a driven one: \
         risk_slow={risk_slow} risk_fast={risk_fast}"
    );
    // Open lane: a weighted ball is kept (slowest bucket).
    assert!(
        (open_plan.speed_yps - slow_speed).abs() < 1e-6,
        "an open lane should keep the weighted ball: {open_plan:?}"
    );
    // Contested lane: the ball is driven harder than the open-lane choice.
    assert!(
        tight_plan.speed_yps > open_plan.speed_yps + 1e-6,
        "a contested lane should be driven harder than an open one: tight={} open={}",
        tight_plan.speed_yps,
        open_plan.speed_yps
    );
    // And it is scored at the safer (faster) speed, not the weighted one.
    assert!(
        tight_plan.lane_interception_risk <= risk_slow + 1e-9,
        "the chosen speed should not be riskier than the weighted bucket: chosen_risk={} risk_slow={}",
        tight_plan.lane_interception_risk,
        risk_slow
    );
    // The MPC feasibility floor is a real, finite threading pace.
    assert!(
        tight_plan.min_clearing_speed_yps >= slow_speed - 1e-6
            && tight_plan.min_clearing_speed_yps.is_finite(),
        "min clearing speed should be a finite threading pace: {tight_plan:?}"
    );
    // The execution layer fires only when the plan elects to DRIVE (power above the 0.68
    // nominal). An open lane keeps the weighted bucket (so execution leaves the ball
    // untouched); a contested lane elects a driven bucket (so execution firms it). These two
    // facts are exactly what the `plan.power > 0.68` execution gate keys on.
    assert!(
        open_plan.power <= 0.68,
        "an open lane must not elect a driven bucket (execution would wrongly firm it): {open_plan:?}"
    );
    assert!(
        tight_plan.power > 0.68,
        "a contested-but-threadable lane should elect a driven bucket so execution firms it: {tight_plan:?}"
    );
}

#[test]
fn goalkeeper_mpc_distribution_avoids_a_marked_teammate_for_a_deliverable_one() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 5_150,
        ..Default::default()
    });
    let keeper = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role == PlayerRole::Goalkeeper)
        .map(|p| p.id)
        .expect("home keeper");
    let open = 6usize;
    let marked = 7usize;
    let presser = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && p.role != PlayerRole::Goalkeeper)
        .map(|p| p.id)
        .expect("away presser");
    // Park every team-mate well up the far flank (poor, but not "marked") so the only sane
    // play-out is to the open man; the marked man has an opponent sitting on him.
    park_players_except(&mut sim, &[keeper, open, marked, presser]);
    let cx = sim.config.field_width_yards * 0.5;
    sim.players[keeper].position = Vec2::new(cx, 2.0);
    sim.players[open].position = Vec2::new(cx - 26.0, 30.0); // wide, no opponent near
    sim.players[marked].position = Vec2::new(cx, 30.0); // central ...
    sim.players[presser].position = Vec2::new(cx, 30.6); // ... with an opponent on him
    sim.ball.holder = Some(keeper);
    sim.ball.position = sim.players[keeper].position;

    let snap = WorldSnapshot::from_match(&sim);
    let (target, _flight) = snap
        .goalkeeper_mpc_distribution_for(keeper)
        .expect("MPC should find a deliverable play-out");
    assert_ne!(
        target, marked,
        "MPC must not play the ball out to a team-mate an opponent is sitting on"
    );
    // Whatever it chose must itself be genuinely deliverable: no opponent tight to the receiver.
    let chosen = sim
        .players
        .iter()
        .find(|p| p.id == target)
        .unwrap()
        .position;
    let nearest_opp = sim
        .players
        .iter()
        .filter(|p| p.team == Team::Away)
        .map(|p| p.position.distance(chosen))
        .fold(f64::INFINITY, f64::min);
    assert!(
        nearest_opp > 3.0,
        "MPC chose a marked receiver (nearest opponent {nearest_opp:.1}yd)"
    );
}

#[test]
fn goalkeeper_mpc_distribution_rolls_when_clear_and_lofts_over_a_block() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 9_001,
        ..Default::default()
    });
    let keeper = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role == PlayerRole::Goalkeeper)
        .map(|p| p.id)
        .expect("home keeper");
    let mate = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role != PlayerRole::Goalkeeper)
        .map(|p| p.id)
        .expect("home outfielder");
    let blocker = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && p.role != PlayerRole::Goalkeeper)
        .map(|p| p.id)
        .expect("away outfielder");
    let width = sim.config.field_width_yards;
    let length = sim.config.field_length_yards;
    let cx = width * 0.5;
    // Make `mate` the ONLY sensible play-out: bury every other team-mate at the far end
    // (undeliverable) and every opponent far away, so only `blocker` matters to the lane.
    for p in sim.players.iter_mut() {
        p.velocity = Vec2::zero();
        if p.id == keeper {
            p.position = Vec2::new(cx, 2.0);
        } else if p.id == mate {
            p.position = Vec2::new(cx, 30.0);
        } else if p.team == Team::Home {
            p.position = Vec2::new(cx, length - 8.0);
        } else {
            p.position = Vec2::new(width - 4.0, length - 4.0);
        }
    }
    sim.ball.holder = Some(keeper);
    sim.ball.position = Vec2::new(cx, 2.0);

    // A clear ground lane → roll it out (the controllable technique).
    let (target, flight) = WorldSnapshot::from_match(&sim)
        .goalkeeper_mpc_distribution_for(keeper)
        .expect("a deliverable play-out");
    assert_eq!(target, mate);
    assert_eq!(
        flight,
        PassFlight::Floor,
        "MPC should roll a clear ground lane rather than loft it"
    );

    // A defender squarely in the ground lane → loft OVER it (the ground roll is undeliverable).
    sim.players[blocker].position = Vec2::new(cx, 16.0);
    let (target2, flight2) = WorldSnapshot::from_match(&sim)
        .goalkeeper_mpc_distribution_for(keeper)
        .expect("a deliverable play-out");
    assert_eq!(target2, mate);
    assert_eq!(
        flight2,
        PassFlight::Aerial,
        "MPC should loft over a defender blocking the ground lane"
    );
}

#[test]
fn goalkeeper_cannot_handle_the_ball_outside_its_box() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper = sim.goalkeeper_for(Team::Home).expect("home keeper");
    park_players_except(&mut sim, &[keeper]);
    let cx = sim.config.field_width_yards * 0.5;
    sim.ball.holder = Some(keeper);

    // Inside his own box: a held ball is in his HANDS — unstealable handling holder.
    sim.players[keeper].position = Vec2::new(cx, 6.0);
    sim.ball.position = sim.players[keeper].position;
    assert_eq!(
        sim.keeper_handling_holder(),
        Some(keeper),
        "a keeper holding inside his box handles with his hands"
    );

    // Outside the 18-yard box: he CANNOT handle — the ball is a normal foot-played, stealable
    // ball, so the MDP/POMDP must decide how he plays it with his feet (no hand-claim path).
    sim.players[keeper].position = Vec2::new(cx, 24.0);
    sim.ball.position = sim.players[keeper].position;
    assert_eq!(
        sim.keeper_handling_holder(),
        None,
        "a keeper outside his penalty area cannot handle the ball — feet only"
    );
}

#[test]
fn mpc_reselects_normal_shot_when_execution_is_poor() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 9_197,
        mpc: SoccerMpcConfig {
            tier2_player_enabled: true,
            reconcile_enabled: true,
            ..SoccerMpcConfig::default()
        },
        ..Default::default()
    });
    let shooter = 9usize;
    let blocker = 15usize;
    let keeper = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Goalkeeper)
        .map(|player| player.id)
        .expect("away keeper");
    park_players_except(&mut sim, &[shooter, blocker, keeper]);
    sim.players[shooter].team = Team::Home;
    sim.players[shooter].role = PlayerRole::Forward;
    sim.players[shooter].position = Vec2::new(40.0, 92.0);
    sim.players[shooter].home_position = sim.players[shooter].position;
    sim.players[shooter].velocity = Vec2::new(0.0, -2.0);
    sim.players[shooter].skills.shooting = 1.0;
    sim.players[shooter].skills.first_touch = 1.0;
    sim.players[shooter].skills.acceleration = 1.0;
    sim.players[shooter].skills.right_foot_shot_power = 1.0;
    sim.players[shooter].skills.left_foot_shot_power = 1.0;
    sim.players[shooter].fatigue = 0.92;
    sim.players[blocker].team = Team::Away;
    sim.players[blocker].position = Vec2::new(40.0, 96.0);
    sim.players[keeper].position = Vec2::new(40.0, 119.0);
    sim.ball.holder = Some(shooter);
    sim.ball.position = sim.players[shooter].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let mut snapshot = WorldSnapshot::from_match(&sim);
    push_stationary_mpc_guidance(&mut snapshot, shooter, sim.players[shooter].position);
    let player = sim.players[shooter].clone();
    let action = SoccerAction::Shoot {
        power: shot_power_for_skill(ability01(player.skills.shooting)),
    };
    let target = player.action_target_trace(&action, &snapshot);
    let trace = player_mdp_mpc_comparison_trace(&snapshot, &player, &target, "shoot")
        .expect("MPC should trace a normal shot command");

    assert_eq!(trace.decision, "reselect-mdp-after-mpc-low-confidence");
    assert!(
        trace.mpc_reselect_reason.starts_with("mpc-shot")
            || trace.mpc_reselect_reason == "mpc-target-beyond-reachable-horizon",
        "normal shot should be sent back through MDP/POMDP when MPC cannot execute it: {trace:?}"
    );
    assert!(
        trace.mpc_execution_probability < 0.34,
        "poor shot execution should be below the reselect floor: {trace:?}"
    );
}

