#[test]
fn pass_marking_guard_evaluates_one_two_four_and_four_plus_ticks() {
    for horizon_ticks in [1.0_f64, 2.0, 4.0, 8.0] {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: 0.1,
            seed: 41_211,
            ..Default::default()
        });
        let passer = 5usize;
        let receiver = 8usize;
        let marker = 15usize;
        park_players_except(&mut sim, &[passer, receiver, marker]);
        sim.players[passer].position = Vec2::new(40.0, 58.0);
        sim.players[receiver].position = Vec2::new(40.0, 76.0);
        sim.players[receiver].velocity = Vec2::zero();
        sim.players[marker].position = Vec2::new(43.6, 76.0);
        let dt = sim.config.dt_seconds.max(1e-6);
        let required_step = 3.6 - (TIGHT_MAN_MARK_RECEIVER_HARD_RADIUS_YARDS - 0.10);
        sim.players[marker].velocity = Vec2::new(-required_step / (dt * horizon_ticks), 0.0);
        sim.ball.holder = Some(passer);
        sim.ball.position = sim.players[passer].position;
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);

        let snapshot = WorldSnapshot::from_match(&sim);
        let receiver_position = snapshot
            .player_position(receiver)
            .expect("receiver position");
        assert!(
            snapshot.nearest_opponent_distance_at(Team::Home, receiver_position)
                > TIGHT_MAN_MARK_RECEIVER_RADIUS_YARDS,
            "fixture should be open on the current tick for horizon {horizon_ticks}"
        );
        assert!(
            snapshot.pass_target_marked_under_pressure(
                Team::Home,
                receiver_position,
                receiver_position,
                0.05,
                18.0,
            ),
            "future marker arrival at {horizon_ticks} ticks must make the receiver unsafe"
        );
    }
}

#[test]
fn forward_pass_progress_is_valued_three_times_backward_recycle() {
    let weight = 0.37;
    let forward = directional_pass_progress_score(10.0, weight);
    let backward = directional_pass_progress_score(-10.0, weight);

    assert!((forward - 10.0 * weight * FORWARD_PASS_VALUE_MULTIPLIER).abs() < 1e-12);
    assert!((backward + 10.0 * weight * BACKWARD_PASS_VALUE_MULTIPLIER).abs() < 1e-12);
    assert!(
        (forward / backward.abs() - 3.0).abs() < 1e-12,
        "a forward pass of equal yardage must be worth exactly 3x the backward recycle"
    );
}

#[test]
fn backward_recycle_prefers_three_to_five_yard_reset_over_long_retreat() {
    let weight = 0.37;
    let short_reset =
        directional_pass_progress_score(-4.0, weight) + backward_pass_depth_adjustment(-4.0);
    let long_retreat =
        directional_pass_progress_score(-9.0, weight) + backward_pass_depth_adjustment(-9.0);

    assert!(
        backward_pass_depth_adjustment(-4.0) > 0.0,
        "3-5yd backward releases should get a reset bonus"
    );
    assert!(
        backward_pass_depth_adjustment(-6.0) < 0.0,
        ">5yd backward releases should be demoted"
    );
    assert!(
        short_reset > long_retreat + 2.0,
        "short reset should clearly outrank long retreat: short={short_reset} long={long_retreat}"
    );
}

#[test]
fn long_backward_pass_penalty_grows_linearly_past_short_reset() {
    let ten_back = long_backward_pass_penalty(-10.0);
    let twenty_back = long_backward_pass_penalty(-20.0);

    assert_eq!(long_backward_pass_penalty(-5.0), 0.0);
    assert!(
        ten_back > 7.0,
        "10yd backward must be a real penalty: {ten_back}"
    );
    assert!(
        (twenty_back - ten_back * 3.0).abs() < 1e-12,
        "penalty should be linear in yards beyond 5: 10yd={ten_back} 20yd={twenty_back}"
    );
}

#[test]
fn aerial_pass_in_bounds_launch_speed_caps_overcooked_loft_toward_touchline() {
    let field_width = 80.0;
    let field_length = 115.0;
    let origin = Vec2::new(40.0, 60.0);
    // Aim a long loft toward the right touchline; the receiver is just inside the line.
    let aim = Vec2::new(76.0, 60.0);
    let reference_distance = origin.distance(aim);
    let overcooked_speed = 60.0;
    let capped = aerial_pass_in_bounds_launch_speed(
        origin,
        aim,
        overcooked_speed,
        reference_distance,
        PassFlight::Aerial,
        field_width,
        field_length,
    );
    assert!(
        capped < overcooked_speed,
        "an over-hit loft toward the touchline must be trimmed: {capped} !< {overcooked_speed}"
    );
    // The capped pace must actually land inside the pitch margin along the aim direction.
    let apex = lofted_pass_apex_yards(reference_distance);
    let hang_time = 2.0 * (2.0 * apex / GRAVITY_YPS2).sqrt();
    let carry = capped * hang_time / AERIAL_LAND_AT_TARGET_DRAG_COMP;
    let landing = origin + (aim - origin).normalized() * carry;
    assert!(
        landing.x <= field_width - AERIAL_PASS_OOB_LANDING_SAFETY_MARGIN_YARDS + 1e-6,
        "capped loft must land inside the touchline margin: landing.x={}",
        landing.x
    );
}

#[test]
fn aerial_pass_in_bounds_launch_speed_leaves_safe_central_loft_untouched() {
    let field_width = 80.0;
    let field_length = 115.0;
    let origin = Vec2::new(40.0, 50.0);
    let aim = Vec2::new(40.0, 78.0); // central, well short of the far byline
    let reference_distance = origin.distance(aim);
    let speed = 16.0; // a weighted loft that comfortably lands at the target
    let result = aerial_pass_in_bounds_launch_speed(
        origin,
        aim,
        speed,
        reference_distance,
        PassFlight::Aerial,
        field_width,
        field_length,
    );
    assert!(
        (result - speed).abs() < 1e-9,
        "a loft that already lands in-field must be unchanged: {result} vs {speed}"
    );
}

#[test]
fn aerial_pass_landing_safety_drops_near_the_touchline() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 7_777,
        ..Default::default()
    });
    let passer = 6usize;
    let central_receiver = 7usize;
    let wide_receiver = 8usize;
    park_players_except(&mut sim, &[passer, central_receiver, wide_receiver]);

    let passer_pos = Vec2::new(40.0, 70.0);
    sim.players[passer].position = passer_pos;
    sim.players[passer].velocity = Vec2::zero();
    // One outlet deep in midfield, one hugging the right touchline.
    let central_pos = Vec2::new(40.0, 45.0);
    let wide_pos = Vec2::new(sim.config.field_width_yards - 2.0, 45.0);
    sim.players[central_receiver].position = central_pos;
    sim.players[central_receiver].velocity = Vec2::zero();
    sim.players[wide_receiver].position = wide_pos;
    sim.players[wide_receiver].velocity = Vec2::zero();
    sim.ball.holder = Some(passer);
    sim.ball.position = passer_pos;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let central_safety =
        aerial_pass_landing_safety_for_snapshot(&snapshot, passer_pos, central_receiver);
    let wide_safety = aerial_pass_landing_safety_for_snapshot(&snapshot, passer_pos, wide_receiver);
    assert!(
        wide_safety < central_safety,
        "a loft to a touchline-hugger must read less safe than one to a central outlet: \
         wide={wide_safety} central={central_safety}"
    );
    assert!(
        central_safety > 0.9,
        "a central outlet should read essentially safe: {central_safety}"
    );
}

#[test]
fn backward_pass_path_traffic_prices_floor_and_aerial_retreats() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 41_212,
        ..Default::default()
    });
    let passer = 6usize;
    let receiver = 7usize;
    let opponents = [12usize, 13usize, 14usize];
    park_players_except(
        &mut sim,
        &[passer, receiver, opponents[0], opponents[1], opponents[2]],
    );

    let passer_pos = Vec2::new(40.0, 75.0);
    let receiver_pos = Vec2::new(40.0, 45.0);
    sim.players[passer].role = PlayerRole::Midfielder;
    sim.players[passer].position = passer_pos;
    sim.players[passer].home_position = passer_pos;
    sim.players[passer].velocity = Vec2::zero();
    sim.players[passer].skills.passing_completion_rate = 8.8;
    sim.players[passer].skills.passing = 8.8;
    sim.players[passer].skills.vision = 9.0;
    sim.players[receiver].role = PlayerRole::Midfielder;
    sim.players[receiver].position = receiver_pos;
    sim.players[receiver].home_position = receiver_pos;
    sim.players[receiver].velocity = Vec2::zero();
    for opponent in opponents {
        sim.players[opponent].velocity = Vec2::zero();
        sim.players[opponent].acceleration = Vec2::zero();
    }
    sim.ball.holder = Some(passer);
    sim.ball.position = passer_pos;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let clean_snapshot = WorldSnapshot::from_match(&sim);
    let clean_passer = clean_snapshot
        .players
        .iter()
        .find(|player| player.id == passer)
        .expect("passer");
    let clean_receiver = clean_snapshot
        .players
        .iter()
        .find(|player| player.id == receiver)
        .expect("receiver");
    let clean_floor = pass_target_quality_for_snapshot(
        &clean_snapshot,
        clean_passer,
        passer_pos,
        clean_receiver,
        receiver_pos,
        PassFlight::Floor,
    );
    let clean_aerial = pass_target_quality_for_snapshot(
        &clean_snapshot,
        clean_passer,
        passer_pos,
        clean_receiver,
        receiver_pos,
        PassFlight::Aerial,
    );
    assert_eq!(clean_floor.backward_path_opponent_count, 0);
    assert_eq!(clean_aerial.backward_path_opponent_count, 0);

    sim.players[12].position = Vec2::new(39.0, 68.0);
    sim.players[13].position = Vec2::new(41.0, 61.0);
    sim.players[14].position = Vec2::new(40.0, 54.0);
    let crowded_snapshot = WorldSnapshot::from_match(&sim);
    let crowded_passer = crowded_snapshot
        .players
        .iter()
        .find(|player| player.id == passer)
        .expect("passer");
    let crowded_receiver = crowded_snapshot
        .players
        .iter()
        .find(|player| player.id == receiver)
        .expect("receiver");
    let traffic = backward_pass_path_traffic_for_snapshot(
        &crowded_snapshot,
        crowded_passer,
        passer_pos,
        receiver_pos,
    );
    let expected_scaled = opponents.len() as f64
        * ((passer_pos.y - receiver_pos.y) - BACKWARD_PASS_PATH_TRAFFIC_FREE_YARDS);
    assert_eq!(traffic.opponent_count, 3);
    assert!(
        (traffic.risk
            - expected_scaled * BACKWARD_PASS_PATH_TRAFFIC_RISK_PER_OPPONENT_PER_BACKWARD_YARD)
            .abs()
            < 1e-12,
        "traffic risk should be count * backward depth"
    );
    assert!(
        (traffic.score_penalty
            - expected_scaled
                * BACKWARD_PASS_PATH_TRAFFIC_SCORE_PENALTY_PER_OPPONENT_PER_BACKWARD_YARD)
            .abs()
            < 1e-12,
        "traffic score penalty should be count * backward depth"
    );

    let crowded_floor = pass_target_quality_for_snapshot(
        &crowded_snapshot,
        crowded_passer,
        passer_pos,
        crowded_receiver,
        receiver_pos,
        PassFlight::Floor,
    );
    let crowded_aerial = pass_target_quality_for_snapshot(
        &crowded_snapshot,
        crowded_passer,
        passer_pos,
        crowded_receiver,
        receiver_pos,
        PassFlight::Aerial,
    );

    assert_eq!(crowded_floor.backward_path_opponent_count, 3);
    assert_eq!(crowded_aerial.backward_path_opponent_count, 3);
    assert!(
        crowded_floor.backward_path_traffic_penalty > clean_floor.backward_path_traffic_penalty,
        "floor backward traffic should add score penalty"
    );
    assert!(
        crowded_aerial.backward_path_traffic_penalty > clean_aerial.backward_path_traffic_penalty,
        "aerial backward traffic should add score penalty"
    );
    assert!(
        crowded_floor.lane_interception_risk > clean_floor.lane_interception_risk + 0.70,
        "floor backward lane risk should rise with three opponents on the path"
    );
    assert!(
        crowded_aerial.lane_interception_risk > clean_aerial.lane_interception_risk + 0.70,
        "aerial backward lane risk should rise with three opponents on the path"
    );
    assert!(
        crowded_floor.expected_completion < clean_floor.expected_completion * 0.60,
        "floor completion should be gated by backward path traffic"
    );
    assert!(
        crowded_aerial.expected_completion < clean_aerial.expected_completion * 0.60,
        "aerial completion should be gated by backward path traffic"
    );
}

#[test]
fn half_open_forward_target_stays_visible_and_beats_backward_recycle() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 41_211,
        ..Default::default()
    });
    let passer = 6usize;
    let backward_recycle = 7usize;
    let forward_runner = 9usize;
    let presser = 12usize;
    let marker = 14usize;
    park_players_except(
        &mut sim,
        &[passer, backward_recycle, forward_runner, presser, marker],
    );

    sim.players[passer].role = PlayerRole::Midfielder;
    sim.players[passer].position = Vec2::new(40.0, 35.0);
    sim.players[passer].velocity = Vec2::zero();
    sim.players[passer].action_facing = FacingBucket::East;
    sim.players[passer].receive_facing = FacingBucket::East;
    sim.players[passer].skills.passing_completion_rate = 8.8;
    sim.players[passer].skills.passing = 8.8;
    sim.players[passer].skills.vision = 9.0;

    sim.players[backward_recycle].role = PlayerRole::Midfielder;
    sim.players[backward_recycle].position = Vec2::new(52.0, 23.0);
    sim.players[backward_recycle].velocity = Vec2::zero();

    sim.players[forward_runner].role = PlayerRole::Forward;
    sim.players[forward_runner].position = Vec2::new(52.0, 58.0);
    sim.players[forward_runner].velocity = Vec2::new(0.0, 2.0);
    sim.players[forward_runner].skills.first_touch = 8.4;
    sim.players[forward_runner].skills.top_speed = 8.6;

    sim.players[marker].position = Vec2::new(57.0, 58.0);
    sim.players[marker].velocity = Vec2::zero();
    sim.players[presser].position = Vec2::new(31.0, 35.0);
    sim.players[presser].velocity = Vec2::zero();

    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(snapshot.player_can_see_player(passer, forward_runner));
    assert!(snapshot.player_can_see_player(passer, backward_recycle));
    assert!(
        snapshot.clear_line(
            sim.players[passer].position,
            sim.players[forward_runner].position,
            Team::Away,
            2.5
        ),
        "half-open forward runner should have a passable lane"
    );

    let visible_targets = snapshot.ranked_visible_pass_targets(passer, 5);
    assert!(
        visible_targets.contains(&forward_runner),
        "half-open forward runner must remain a visible pass option: {visible_targets:?}"
    );
    assert!(
        visible_targets.contains(&backward_recycle),
        "test setup should expose the backward recycle too: {visible_targets:?}"
    );
    assert_eq!(
        visible_targets.first().copied(),
        Some(forward_runner),
        "forward half-open teammate should outrank the safer backward recycle: {visible_targets:?}"
    );

    let observation = snapshot.observation_for(passer);
    assert!(observation.visible_forward_pass_options >= 1);
    assert!(
        observation.best_forward_pass_receiver_openness >= HALF_OPEN_FORWARD_PASS_MIN_OPENNESS,
        "forward receiver should qualify as half-open: {:.3}",
        observation.best_forward_pass_receiver_openness
    );
}

#[test]
fn field_numbers_vector_is_wired_into_every_observation_and_lifts_carrier_urgency() {
    // The 11v11 field-numbers vector must be computed onto every player's observation and,
    // when an attacking overload sits ahead of the carrier, lift the carrier's offensive
    // urgency. Home attacks toward +y; stack all teammates ahead and all opponents behind.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 7_321,
        ..Default::default()
    });
    let carrier = 6usize;
    for player in &mut sim.players {
        if player.id == carrier {
            continue;
        }
        let spread = 8.0 + (player.id % 8) as f64 * 8.0; // 8..=64 across the width
        player.position = match player.team {
            // Home teammates ahead of the carrier (toward the attacking goal at y=120),
            // a couple driving forward so the centroid velocity is up-field.
            Team::Home => Vec2::new(spread, 82.0 + (player.id % 5) as f64 * 3.0),
            // Away opponents goal-side of the carrier (toward our own goal at y=0).
            Team::Away => Vec2::new(spread, 30.0 + (player.id % 5) as f64 * 3.0),
        };
        player.velocity = match player.team {
            Team::Home => Vec2::new(0.0, 3.0),
            Team::Away => Vec2::zero(),
        };
        player.acceleration = Vec2::zero();
    }
    sim.players[carrier].role = PlayerRole::Midfielder;
    sim.players[carrier].position = Vec2::new(40.0, 55.0);
    sim.players[carrier].velocity = Vec2::new(0.0, 2.0);
    sim.ball.holder = Some(carrier);
    sim.ball.position = sim.players[carrier].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(carrier);
    let fnv = &observation.field_numbers;

    // The full field vector (all 22 bodies), not vision-filtered: 10 teammates ahead, all
    // 11 opponents behind.
    assert_eq!(fnv.teammates_ahead, 10, "all 10 teammates stacked ahead");
    assert_eq!(fnv.opponents_ahead, 0);
    assert_eq!(fnv.opponents_behind, 11, "all 11 opponents goal-side of the carrier");
    assert_eq!(fnv.ahead_overload, 10);
    assert_eq!(
        fnv.players_ahead,
        fnv.teammates_ahead + fnv.opponents_ahead,
        "players_ahead is the both-teams total"
    );
    assert!(fnv.ahead_ratio > 1.0, "numbers up going forward");

    // Counts + ratio drive a real offensive urgency, and it is folded into the carrier's
    // offensive urgency (which therefore exceeds the bare shot-geometry baseline).
    assert!(
        fnv.offensive_numbers_urgency > 0.5,
        "a big attacking overload ahead should spark offensive urgency: {fnv:?}"
    );
    assert!(
        observation.offensive_urgency >= fnv.offensive_numbers_urgency * 0.40 - 1e-6,
        "offensive numbers urgency must be folded into the carrier's offensive urgency: \
         offensive_urgency {} vs numbers {}",
        observation.offensive_urgency,
        fnv.offensive_numbers_urgency
    );

    // Team centroids read off the field vector: our centre of mass sits up-field, theirs
    // goal-side, and our collective velocity is shoving forward.
    assert!(
        fnv.own_center_of_mass_forward_yards > 0.0,
        "own team centre of mass is ahead of the carrier"
    );
    assert!(
        fnv.opp_center_of_mass_forward_yards < 0.0,
        "opposing team centre of mass is goal-side of the carrier"
    );
    assert!(
        fnv.own_center_of_velocity_forward_yps > 0.0 && fnv.team_push_forward_yps > 0.0,
        "our side is winning the collective shove up-field: {fnv:?}"
    );
}

#[test]
fn pass_launch_sanitizes_explicit_opponent_target_to_teammate() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 41_209,
        ..Default::default()
    });
    let passer = 6usize;
    let teammate = 7usize;
    let opponent = 14usize;
    park_players_except(&mut sim, &[passer, teammate, opponent]);
    sim.players[passer].position = Vec2::new(40.0, 60.0);
    sim.players[passer].velocity = Vec2::new(4.0, 0.0);
    sim.players[passer].action_facing = FacingBucket::East;
    sim.players[passer].receive_facing = FacingBucket::East;
    sim.players[passer].skills.passing_completion_rate = 8.8;
    sim.players[passer].skills.passing = 8.8;
    sim.players[teammate].position = Vec2::new(56.0, 60.0);
    sim.players[teammate].velocity = Vec2::zero();
    sim.players[opponent].position = Vec2::new(68.0, 60.0);
    sim.players[opponent].velocity = Vec2::zero();
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    assert_eq!(
        snapshot.ranked_visible_pass_targets(passer, 1),
        vec![teammate],
        "setup should expose the teammate as the safe pass target"
    );

    sim.apply_player_intent(PlayerIntent {
        player_id: passer,
        action: SoccerAction::Pass {
            target_player: Some(opponent),
            power: 0.68,
            flight: PassFlight::Floor,
        },
        sprint: false,
    });

    let pass = sim.pending_pass.as_ref().expect("pass launched");
    assert_eq!(
        pass.target,
        Some(teammate),
        "launch path must never preserve an explicit opponent pass target"
    );
    assert!(
        pass.intended_target
            .distance(sim.players[teammate].position)
            < pass
                .intended_target
                .distance(sim.players[opponent].position),
        "sanitized pass should aim nearer the teammate than the opponent: target={:?}",
        pass.intended_target
    );
}

/// Regression for "the defender played the shortest pass to nobody and ran away": a one-two
/// "give" must be laid off to the wall partner's FEET, not led forward toward goal like a
/// through-ball. The generic reception lead biases the aim ahead of even a stationary partner
/// (role forward-bias), so the give sailed into space the partner never ran into while the
/// passer had already burst into the return run — the ball was left to nobody. With the carrier
/// committing a live one-two naming this target as the wall, the give is aimed straight at the
/// partner (and the partner is bound to collect it); the identical pass WITHOUT the commitment
/// leads clearly ahead.
#[test]
fn one_two_give_is_aimed_at_the_wall_partners_feet_and_binds_the_partner() {
    let passer = 6usize;
    let partner = 7usize;
    let partner_pos = Vec2::new(40.0, 78.0);
    let launch_give = |with_one_two: bool| -> SoccerMatch {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: 0.1,
            seed: 73_117,
            ..Default::default()
        });
        park_players_except(&mut sim, &[passer, partner]);
        // Carrier in the opponent half, facing the attacking goal (+y, North).
        sim.players[passer].position = Vec2::new(40.0, 70.0);
        sim.players[passer].velocity = Vec2::new(0.0, 2.0);
        sim.players[passer].facing_yaw = std::f64::consts::FRAC_PI_2;
        sim.players[passer].action_facing = FacingBucket::North;
        sim.players[passer].receive_facing = FacingBucket::North;
        sim.players[passer].skills.passing = 9.6;
        sim.players[passer].skills.passing_completion_rate = 9.6;
        sim.players[passer].skills.vision = 9.6;
        // The wall: a forward partner just ahead, making a forward run (so the generic lead
        // would otherwise throw the give ahead of his feet).
        sim.players[partner].role = PlayerRole::Forward;
        sim.players[partner].position = partner_pos;
        sim.players[partner].velocity = Vec2::new(0.0, 7.0);
        if with_one_two {
            sim.players[passer].one_two = Some(OneTwoRun {
                wall_partner: partner,
                launch_clock_seconds: 0.0,
                return_target: Vec2::new(40.0, 92.0),
            });
        }
        sim.ball.holder = Some(passer);
        sim.ball.position = sim.players[passer].position;
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);
        sim.apply_player_intent(PlayerIntent {
            player_id: passer,
            action: SoccerAction::Pass {
                target_player: Some(partner),
                power: 0.58,
                flight: PassFlight::Floor,
            },
            sprint: false,
        });
        sim
    };

    // Fix A: the give is laid off to the partner's feet, not led ahead toward goal.
    let give = launch_give(true);
    let give_pass = give.pending_pass.as_ref().expect("give launched");
    assert_eq!(give_pass.target, Some(partner));
    let give_to_feet = give_pass.intended_target.distance(partner_pos);

    let normal = launch_give(false);
    let normal_pass = normal.pending_pass.as_ref().expect("pass launched");
    let led_ahead = normal_pass.intended_target.distance(partner_pos);

    assert!(
        give_to_feet < 1.5,
        "one-two give should be aimed at the partner's feet, was {give_to_feet:.2}yd away"
    );
    assert!(
        led_ahead > give_to_feet + 1.0,
        "an ordinary pass to the same moving partner should lead clearly ahead of his feet \
         (led={led_ahead:.2}yd vs give={give_to_feet:.2}yd)"
    );

    // Fix B: the named wall partner is bound to collect the give — it serves the reception and
    // attacks (sprints) the ball rather than backing off, so the give is not abandoned to nobody.
    let snapshot = WorldSnapshot::from_match(&give);
    assert!(
        snapshot.is_bound_one_two_give_receiver(partner),
        "the named wall partner of a live one-two give should be bound to collect it"
    );
    let (_, sprint) = snapshot
        .pending_pass_reception_target_for(partner)
        .expect("bound wall partner should move to meet the give");
    assert!(
        sprint,
        "bound wall partner should attack the give at a sprint"
    );
}

#[test]
fn targeted_floor_pass_noise_does_not_pull_aim_into_opponent() {
    for seed in 41_300..41_360 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: 0.1,
            seed,
            ..Default::default()
        });
        let passer = 6usize;
        let teammate = 7usize;
        let opponent = 14usize;
        let pressure = 12usize;
        park_players_except(&mut sim, &[passer, teammate, opponent, pressure]);
        sim.players[passer].position = Vec2::new(40.0, 60.0);
        sim.players[passer].velocity = Vec2::new(4.0, 0.0);
        sim.players[passer].action_facing = FacingBucket::East;
        sim.players[passer].receive_facing = FacingBucket::East;
        sim.players[passer].skills.passing_completion_rate = 1.0;
        sim.players[passer].skills.passing = 1.0;
        sim.players[teammate].position = Vec2::new(66.0, 60.0);
        sim.players[teammate].velocity = Vec2::zero();
        sim.players[opponent].position =
            Vec2::new(66.0, 60.0 + TIGHT_MAN_MARK_RECEIVER_RADIUS_YARDS + 0.45);
        sim.players[opponent].velocity = Vec2::zero();
        sim.players[pressure].position = Vec2::new(40.0, 62.0);
        sim.players[pressure].velocity = Vec2::zero();
        sim.ball.holder = Some(passer);
        sim.ball.position = sim.players[passer].position;
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);

        sim.apply_player_intent(PlayerIntent {
            player_id: passer,
            action: SoccerAction::Pass {
                target_player: Some(teammate),
                power: 0.68,
                flight: PassFlight::Floor,
            },
            sprint: false,
        });

        let pass = sim.pending_pass.as_ref().expect("pass launched");
        assert_eq!(pass.target, Some(teammate));
        let teammate_distance = pass
            .intended_target
            .distance(sim.players[teammate].position);
        let opponent_distance = pass
            .intended_target
            .distance(sim.players[opponent].position);
        assert!(
            teammate_distance <= opponent_distance,
            "seed {seed}: targeted pass aim drifted closer to opponent than teammate: target={:?} teammate_distance={teammate_distance} opponent_distance={opponent_distance}",
            pass.intended_target
        );
    }
}

#[test]
fn final_third_pressure_exposes_killer_pass_option() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 22_903,
        ..Default::default()
    });
    let passer = 8;
    let receiver = 9;
    park_players_except(&mut sim, &[passer, receiver]);
    sim.players[passer].role = PlayerRole::Midfielder;
    sim.players[passer].position = Vec2::new(40.0, 76.0);
    sim.players[passer].velocity = Vec2::new(0.0, 2.0);
    sim.players[passer].action_facing = FacingBucket::South;
    sim.players[passer].skills.passing_completion_rate = 9.0;
    sim.players[passer].skills.passing = 8.8;
    sim.players[passer].skills.vision = 9.2;
    sim.players[receiver].role = PlayerRole::Forward;
    sim.players[receiver].position = Vec2::new(42.0, 87.0);
    sim.players[receiver].velocity = Vec2::new(0.0, 5.0);
    sim.players[receiver].skills.shooting = 8.6;
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let visible_targets = snapshot.ranked_visible_pass_targets(passer, 3);
    assert!(
        visible_targets.contains(&receiver),
        "receiver should be visible as a forward passing option: {visible_targets:?}"
    );
    assert_eq!(
        snapshot.killer_pass_target_for(passer, &visible_targets),
        Some(receiver)
    );

    let observation = snapshot.observation_for(passer);
    let options = sim.players[passer].possession_action_options(
        &observation,
        &snapshot.tactical_directive(Team::Home),
        visible_targets.len(),
        snapshot.ranked_visible_aerial_pass_targets(passer, 3).len(),
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let killer = options
        .iter()
        .find(|option| option.label == "killer-pass")
        .expect("killer-pass option");
    assert!(
        killer.legal && killer.score > 0.0 && killer.tick_probability > 0.0,
        "killer pass should be legal and learnable in a final-third threaded lane: {killer:?}"
    );
    assert!(learned_action_label_is_legal(
        "through-pass",
        &snapshot,
        passer
    ));
}

#[test]
fn goal_proximity_raises_shot_and_killer_pass_pressure() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 22_905,
        ..Default::default()
    });
    let attacker = 9;
    let keeper = 11;
    park_players_except(&mut sim, &[attacker, keeper]);
    sim.players[attacker].role = PlayerRole::Forward;
    sim.players[attacker].position = Vec2::new(40.0, 91.0);
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.ball.holder = Some(attacker);
    sim.ball.position = sim.players[attacker].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut observation = snapshot.observation_for(attacker);
    observation.shot_lane_open = true;
    observation.shot_block_probability = 0.18;
    observation.shot_on_frame_probability = 0.48;
    observation.shot_beat_goalkeeper_probability = 0.34;
    observation.opponent_goal_angle_degrees = 24.0;
    observation.forward_dribble_space_yards = 7.0;
    observation.offensive_urgency = 0.36;
    observation.decision_urgency = 0.30;
    observation.goal_attack_window_score = 0.28;
    observation.yards_to_goal = 29.0;
    // Keeper out of position so the long/mid-range shots clear the distance gate
    // and the floor's monotonic rise with proximity can be exercised.
    observation.opposing_goalkeeper_out_of_position = 0.9;

    // Ranges within the 30yd shot cap (no shot is taken beyond it now), ramping in toward goal.
    observation.yards_to_goal = 28.0;
    observation.goal_attack_window_score = 0.08;
    let long_range_shot_floor =
        goal_proximity_shot_pressure_floor(&observation, PlayerRole::Forward, ability01(8.2));
    observation.yards_to_goal = 18.0;
    observation.goal_attack_window_score = 0.22;
    let mid_range_shot_floor =
        goal_proximity_shot_pressure_floor(&observation, PlayerRole::Forward, ability01(8.2));
    observation.yards_to_goal = 10.0;
    observation.goal_attack_window_score = 0.44;
    let close_range_shot_floor =
        goal_proximity_shot_pressure_floor(&observation, PlayerRole::Forward, ability01(8.2));
    assert!(
            long_range_shot_floor < mid_range_shot_floor
                && mid_range_shot_floor < close_range_shot_floor,
            "shot pressure should rise monotonically as range closes: long={long_range_shot_floor} mid={mid_range_shot_floor} close={close_range_shot_floor}"
        );

    observation.yards_to_goal = 29.0;
    observation.goal_attack_window_score = 0.28;
    let farther_shot =
        near_goal_shot_pressure_floor(&observation, PlayerRole::Forward, ability01(8.2));
    observation.yards_to_goal = 24.0;
    observation.goal_attack_window_score = 0.62;
    let closer_shot =
        near_goal_shot_pressure_floor(&observation, PlayerRole::Forward, ability01(8.2));
    assert!(
            closer_shot > farther_shot + 0.14,
            "shot floor should rise as the ball enters the goalmouth window: far={farther_shot} close={closer_shot}"
        );

    observation.shot_lane_open = false;
    observation.yards_to_goal = 47.0;
    observation.goal_attack_window_score = 0.03;
    observation.threaded_goal_pass_available = true;
    observation.visible_forward_pass_options = observation.visible_forward_pass_options.max(1);
    observation.best_forward_pass_receiver_openness = 0.70;
    observation.best_pass_stride_fit = 0.74;
    observation.floor_pass_lane_score = 0.68;
    let farther_killer = killer_pass_goal_pressure_score(&observation);
    observation.yards_to_goal = 31.0;
    observation.goal_attack_window_score = 0.36;
    let closer_killer = killer_pass_goal_pressure_score(&observation);
    assert!(
            closer_killer > farther_killer + 0.24,
            "killer-pass pressure should rise near goal when a threaded lane exists: far={farther_killer} close={closer_killer}"
        );
    assert!(
        killer_pass_goal_pressure_floor(&observation) >= 0.28,
        "close threaded lanes should receive a meaningful killer-pass floor"
    );
}

