#[test]
fn q_policy_keys_separate_same_action_by_goal_attack_window() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 1424,
        ..Default::default()
    });
    let attacker = 9;
    sim.ball.holder = Some(attacker);
    sim.ball.position = sim.players[attacker].position;
    sim.ball.last_touch_team = Some(Team::Home);
    let snapshot = WorldSnapshot::from_match(&sim);
    let mdp_state = snapshot.mdp_state_for_player(attacker);
    let base_observation = snapshot.observation_for(attacker);

    let mut attack_observation = base_observation.clone();
    attack_observation.goal_attack_window_score = 0.86;
    let attack_state = SoccerQStateKey::from_parts(
        &mdp_state,
        &attack_observation,
        Team::Home,
        sim.players[attacker].role,
    );

    let mut neutral_observation = attack_observation.clone();
    neutral_observation.goal_attack_window_score = 0.04;
    let neutral_state = SoccerQStateKey::from_parts(
        &mdp_state,
        &neutral_observation,
        Team::Home,
        sim.players[attacker].role,
    );

    assert_ne!(
        attack_state.goal_attack_window_bin,
        neutral_state.goal_attack_window_bin
    );
    assert_ne!(attack_state, neutral_state);

    let mut policy = SoccerQPolicy::default();
    policy.set_action_value(attack_state.clone(), "shoot", 6.0);
    assert_eq!(
        policy.best_action_hierarchical(&attack_state).as_deref(),
        Some("shoot")
    );
    assert!(
        policy.best_action_hierarchical(&neutral_state).is_none(),
        "goal-window bins should prevent reusing learned shot choices outside the window"
    );
}

#[test]
fn team_brain_defensive_cover_target_is_state_derived() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let away_holder = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && p.role == PlayerRole::Forward)
        .map(|p| p.id)
        .unwrap();
    sim.players[away_holder].position = Vec2::new(40.0, 10.0);
    sim.ball.holder = Some(away_holder);
    sim.ball.position = sim.players[away_holder].position;
    sim.ball.last_touch_team = Some(Team::Away);
    let deep_home_danger = WorldSnapshot::from_match(&sim);
    assert_eq!(
        agentic_defensive_cover_target(&deep_home_danger, Team::Home),
        4,
        "opponent possession near Home goal should demand maximum cover"
    );

    let home_holder = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role == PlayerRole::Forward)
        .map(|p| p.id)
        .unwrap();
    sim.players[home_holder].position = Vec2::new(40.0, 100.0);
    sim.ball.holder = Some(home_holder);
    sim.ball.position = sim.players[home_holder].position;
    sim.ball.last_touch_team = Some(Team::Home);
    let home_in_possession = WorldSnapshot::from_match(&sim);
    assert_eq!(
        agentic_defensive_cover_target(&home_in_possession, Team::Home),
        1,
        "Home possession high upfield should relax the cover target without a random draw"
    );

    sim.players[home_holder].position = Vec2::new(40.0, 110.0);
    sim.ball.holder = Some(home_holder);
    sim.ball.position = sim.players[home_holder].position;
    sim.ball.last_touch_team = Some(Team::Home);
    let deep_away_danger = WorldSnapshot::from_match(&sim);
    assert_eq!(
        agentic_defensive_cover_target(&deep_away_danger, Team::Away),
        4,
        "opponent possession near Away goal should also demand maximum cover"
    );
}

#[test]
fn team_brain_cover_rule_sets_goal_side_defensive_line() {
    let conservative = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(40.0, 37.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile {
            target: 3,
            actual: 0,
            foremost_attacker_y: Some(33.0),
        },
        AttackingOverloadProfile::default(),
        false,
        &SoccerTacticalLearningWeights::default(),
    );
    let aggressive = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(40.0, 37.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile {
            target: 0,
            actual: 4,
            foremost_attacker_y: Some(33.0),
        },
        AttackingOverloadProfile::default(),
        false,
        &SoccerTacticalLearningWeights::default(),
    );

    assert_eq!(conservative.defensive_cover_target, 3);
    assert_eq!(conservative.defensive_cover_actual, 0);
    assert_eq!(conservative.foremost_attacker_y, Some(33.0));
    assert!(conservative.defensive_line_y < 33.0);
    assert!(conservative.defensive_line_y < aggressive.defensive_line_y);
}

#[test]
fn defensive_team_strategy_channels_carrier_between_forty_and_fifteen_yards() {
    let covered = DefensiveCoverProfile {
        target: 3,
        actual: 3,
        foremost_attacker_y: Some(35.0),
    };
    let left_half = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(34.0, 35.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        covered,
        AttackingOverloadProfile::default(),
        false,
        &SoccerTacticalLearningWeights::default(),
    );
    let right_half = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(46.0, 35.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        covered,
        AttackingOverloadProfile::default(),
        false,
        &SoccerTacticalLearningWeights::default(),
    );
    let already_wide = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(10.0, 25.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile {
            target: 3,
            actual: 2,
            foremost_attacker_y: Some(25.0),
        },
        AttackingOverloadProfile::default(),
        false,
        &SoccerTacticalLearningWeights::default(),
    );

    assert_eq!(
        left_half.defense_strategy,
        TeamDefenseStrategy::ForceWideLeftTrap,
        "left-half carrier should be shown to the left touchline"
    );
    assert_eq!(
        right_half.defense_strategy,
        TeamDefenseStrategy::ForceWideRightTrap,
        "right-half carrier should be shown to the right touchline"
    );
    assert_eq!(
        already_wide.defense_strategy,
        TeamDefenseStrategy::DoubleTeamBallCarrier,
        "a covered wide carrier near the box should trigger the trap/double-team"
    );
}

#[test]
fn tactical_learning_weights_bias_directive_decisions_and_press() {
    let mut conservative_learning = SoccerTacticalLearningWeights::default();
    conservative_learning.shot_choice_learning_weight = 0.55;
    conservative_learning.goal_entry_pass_learning_weight = 0.55;
    conservative_learning.pressure_release_learning_weight = 0.55;
    conservative_learning.pass_target_ranking_learning_weight = 0.55;
    conservative_learning.defensive_line_press_learning_weight = 0.55;

    let mut assertive_learning = SoccerTacticalLearningWeights::default();
    assertive_learning.shot_choice_learning_weight = 1.55;
    assertive_learning.goal_entry_pass_learning_weight = 1.55;
    assertive_learning.pressure_release_learning_weight = 1.55;
    assertive_learning.pass_target_ranking_learning_weight = 1.55;
    assertive_learning.defensive_line_press_learning_weight = 1.55;

    let overload = AttackingOverloadProfile {
        attackers: 5,
        defenders: 3,
        advantage: 2,
        score: 0.75,
    };
    let conservative_attack = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::HomeAttack,
        Some(Team::Home),
        Vec2::new(18.0, 96.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        overload,
        false,
        &conservative_learning,
    );
    let assertive_attack = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::HomeAttack,
        Some(Team::Home),
        Vec2::new(18.0, 96.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        overload,
        false,
        &assertive_learning,
    );

    assert!(assertive_attack.pass_priority > conservative_attack.pass_priority);
    assert!(assertive_attack.risk_tolerance > conservative_attack.risk_tolerance);
    assert_eq!(assertive_attack.pressure_release_learning_weight, 1.55);
    assert_eq!(conservative_attack.pressure_release_learning_weight, 0.55);

    let conservative_defense = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(40.0, 52.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        AttackingOverloadProfile::default(),
        false,
        &conservative_learning,
    );
    let assertive_defense = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::AwayAttack,
        Some(Team::Away),
        Vec2::new(40.0, 52.0),
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        AttackingOverloadProfile::default(),
        false,
        &assertive_learning,
    );

    assert!(assertive_defense.press_intensity > conservative_defense.press_intensity);
    assert!(assertive_defense.defensive_line_y > conservative_defense.defensive_line_y);
}

#[test]
fn one_touch_feasibility_discriminates_easy_from_coin_flip() {
    // Routine ground ball at a comfortable pace, no turn, decent first touch, dry, calm:
    // a one-touch is clearly ON (gate ≈ identity).
    let easy = one_touch_contact_feasibility(12.0, 0.0, None, 0.7, 0.0, 0.0, false);
    assert!(
        easy > 0.85,
        "routine ground one-touch should be ~1.0, got {easy}"
    );

    // Fast, chest-high ball to a low-skill player under pressure: a coin-flip — must
    // fall below the veto so a settling touch wins.
    let hard = one_touch_contact_feasibility(30.0, 1.5, None, 0.3, 0.6, 0.0, false);
    assert!(
        hard < ONE_TOUCH_VETO_FEASIBILITY,
        "fast chest-high one-touch under pressure should be vetoed, got {hard}"
    );
    assert!(hard < easy);

    // A volley/header tolerates the same height far better than a controlled ground pass.
    let strike_high = one_touch_contact_feasibility(18.0, 1.5, None, 0.6, 0.0, 0.0, true);
    let pass_high = one_touch_contact_feasibility(18.0, 1.5, None, 0.6, 0.0, 0.0, false);
    assert!(strike_high > pass_high);

    // Turning a ball ~180° to hit the goal is much harder one-touch than striking it
    // straight on.
    let straight = one_touch_contact_feasibility(14.0, 0.2, Some(0.0), 0.6, 0.0, 0.0, true);
    let reverse =
        one_touch_contact_feasibility(14.0, 0.2, Some(std::f64::consts::PI), 0.6, 0.0, 0.0, true);
    assert!(
        reverse < straight * 0.8,
        "reverse strike should be much harder"
    );
}

#[test]
fn defensive_cover_ignores_isolated_ball_less_goal_hanger() {
    // Home defends y=0; Away attacks toward y=0. Away's outfield block sits as a
    // coherent line ~y60, with the ball there (held by no one in particular), EXCEPT
    // one forward parked on Home's goal line — a lone goal-hanger, NOT on the ball.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 58.0);
    sim.ball.last_touch_team = Some(Team::Away);
    let mut x = 12.0;
    let mut hung = false;
    for player in sim
        .players
        .iter_mut()
        .filter(|p| p.team == Team::Away && p.role != PlayerRole::Goalkeeper)
    {
        if player.role == PlayerRole::Forward && !hung {
            player.position = Vec2::new(40.0, 2.0); // stranded goal-hanger
            hung = true;
        } else {
            player.position = Vec2::new(x, 60.0);
            x += 5.0;
        }
    }
    assert!(
        hung,
        "expected at least one forward to park as the goal-hanger"
    );
    let snapshot = WorldSnapshot::from_match(&sim);
    let profile = defensive_cover_profile(&snapshot, Team::Home, 2);
    let foremost = profile.foremost_attacker_y.expect("an attacker exists");
    // The supported block (~y60), not the stranded hanger at y2, sets the line.
    assert!(
        foremost > 40.0,
        "isolated ball-less goal-hanger dragged the cover line to y={foremost}"
    );

    // But the SAME deep player, when it is the ball carrier, IS the live threat and
    // must anchor the line (the defence has to step onto it).
    let carrier_id = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && (p.position.y - 2.0).abs() < 1e-6)
        .map(|p| p.id)
        .expect("goal-hanger id");
    sim.ball.holder = Some(carrier_id);
    sim.ball.position = Vec2::new(40.0, 2.0);
    let snapshot = WorldSnapshot::from_match(&sim);
    let profile = defensive_cover_profile(&snapshot, Team::Home, 2);
    assert!(
        profile.foremost_attacker_y.expect("carrier") < 10.0,
        "the lone ball CARRIER must anchor the line, not be ignored"
    );
}

#[test]
fn match_frame_exposes_central_brain_global_awareness() {
    let kickoff = SoccerMatch::default_11v11(MatchConfig::default()).to_frame();
    assert_eq!(kickoff.central_brain.possession_team, Some(Team::Home));
    assert_eq!(kickoff.central_brain.ball_holder, Some(5));

    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        max_human_players: 4,
        ..Default::default()
    });
    sim.assign_controller_slot(0, Some(9))
        .expect("assign home striker controller");
    sim.assign_controller_slot(1, Some(14))
        .expect("assign away defender controller");
    sim.players[9].position = Vec2::new(41.0, 94.0);
    sim.players[9].velocity = Vec2::new(0.5, 1.0);
    sim.players[9].acceleration = Vec2::new(0.2, 0.4);
    sim.players[9].jerk = Vec2::new(0.05, 0.09);
    sim.ball.holder = Some(9);
    sim.ball.position = sim.players[9].position;
    sim.ball.velocity = Vec2::new(0.5, 1.0);
    sim.ball.acceleration = Vec2::new(0.2, 0.4);
    sim.ball.jerk = Vec2::new(0.05, 0.09);
    sim.ball.altitude_yards = 0.35;
    sim.ball.last_touch_team = Some(Team::Home);
    let before = WorldSnapshot::from_match(&sim);
    let mut rng = mulberry32(1002);
    sim.central_brain.run_time_step(&before, &mut rng);

    let frame = sim.to_frame();

    assert_eq!(frame.central_brain.tracked_players.len(), 22);
    assert_eq!(frame.central_brain.tracked_officials, 3);
    assert_eq!(frame.central_brain.tracked_official_awareness.len(), 3);
    assert_eq!(frame.central_brain.controlled_human_players, 2);
    assert_eq!(frame.central_brain.controller_assignments.len(), 2);
    assert_eq!(
        frame.central_brain.controller_assignments[0].controller_slot,
        0
    );
    assert_eq!(frame.central_brain.controller_assignments[0].player_id, 9);
    assert_eq!(
        frame.central_brain.controller_assignments[1].controller_slot,
        1
    );
    assert_eq!(frame.central_brain.controller_assignments[1].player_id, 14);
    let central_decision = frame
        .central_brain
        .last_decision
        .as_ref()
        .expect("central brain decision trace");
    assert_eq!(central_decision.controlled_human_players, 2);
    assert_eq!(central_decision.controller_assignments.len(), 2);
    assert_eq!(frame.central_brain.possession_team, Some(Team::Home));
    assert_eq!(frame.central_brain.ball_holder, Some(9));
    assert_eq!(frame.central_brain.ball_position, sim.ball.position);
    assert_eq!(frame.central_brain.ball_velocity, sim.ball.velocity);
    assert_eq!(frame.central_brain.ball_acceleration, sim.ball.acceleration);
    assert_eq!(frame.central_brain.ball_jerk, sim.ball.jerk);
    assert_eq!(
        frame.central_brain.ball_altitude_yards,
        sim.ball.altitude_yards
    );
    assert_eq!(frame.home_brain.team, Team::Home);
    assert_eq!(frame.home_brain.mode, TeamBrainMode::Attack);
    assert!(frame.home_brain.in_possession);
    assert_eq!(frame.home_brain.tracked_team_players, 11);
    assert_eq!(frame.home_brain.controlled_human_players, 1);
    assert_eq!(frame.home_brain.ball_holder, Some(9));
    assert_eq!(frame.home_brain.ball_jerk, sim.ball.jerk);
    assert_eq!(frame.away_brain.ball_jerk, sim.ball.jerk);
    let expected_home_centroid = frame
        .central_brain
        .tracked_players
        .iter()
        .filter(|player| player.team == Team::Home)
        .map(|player| player.position)
        .fold(Vec2::zero(), |acc, position| acc + position)
        / 11.0;
    let expected_home_average_velocity = frame
        .central_brain
        .tracked_players
        .iter()
        .filter(|player| player.team == Team::Home)
        .map(|player| player.velocity)
        .fold(Vec2::zero(), |acc, velocity| acc + velocity)
        / 11.0;
    let expected_home_spread = frame
        .central_brain
        .tracked_players
        .iter()
        .filter(|player| player.team == Team::Home)
        .map(|player| player.position.distance(expected_home_centroid))
        .sum::<f64>()
        / 11.0;
    let expected_home_near_ball = frame
        .central_brain
        .tracked_players
        .iter()
        .filter(|player| {
            player.team == Team::Home
                && player.position.distance(frame.central_brain.ball_position) <= 18.0
        })
        .count();
    assert!(
        frame
            .home_brain
            .team_centroid
            .distance(expected_home_centroid)
            < 1e-9
    );
    assert!(
        frame
            .home_brain
            .team_average_velocity
            .distance(expected_home_average_velocity)
            < 1e-9
    );
    assert!((frame.home_brain.team_spread_yards - expected_home_spread).abs() < 1e-9);
    assert_eq!(frame.home_brain.players_near_ball, expected_home_near_ball);
    assert_eq!(
        frame.home_brain.defensive_cover_target,
        frame.home_directive.defensive_cover_target
    );
    assert_eq!(frame.away_brain.team, Team::Away);
    assert_eq!(frame.away_brain.mode, TeamBrainMode::Defend);
    assert!(!frame.away_brain.in_possession);
    assert_eq!(frame.away_brain.tracked_team_players, 11);
    assert_eq!(frame.away_brain.controlled_human_players, 1);
    assert!(frame.away_brain.team_spread_yards.is_finite());
    assert!(frame.away_brain.players_near_ball <= 11);
    let striker = frame
        .central_brain
        .tracked_players
        .iter()
        .find(|p| p.id == 9)
        .expect("central brain tracks striker");
    let striker_frame = frame
        .players
        .iter()
        .find(|p| p.id == 9)
        .expect("frame striker");
    assert_eq!(striker.position, striker_frame.position);
    assert_eq!(striker.velocity, striker_frame.velocity);
    assert_eq!(striker.acceleration, striker_frame.acceleration);
    assert_eq!(striker.controller_slot, Some(0));
    assert_eq!(striker.scheduled_index, None);
    let center_ref = frame
        .central_brain
        .tracked_official_awareness
        .iter()
        .find(|official| official.kind == OfficialKind::CenterReferee)
        .expect("central brain tracks center ref");
    let sim_center_ref = sim
        .officials
        .iter()
        .find(|official| official.kind == OfficialKind::CenterReferee)
        .expect("sim center ref");
    assert_eq!(center_ref.id, sim_center_ref.id);
    assert_eq!(center_ref.position, sim_center_ref.position);
    assert_eq!(center_ref.velocity, sim_center_ref.velocity);
    assert_eq!(center_ref.acceleration, sim_center_ref.acceleration);
    assert_eq!(center_ref.scheduled_index, None);
    assert!(center_ref.offside_line.is_none());
}

