#[test]
fn close_ball_support_movement_keeps_existing_facing_to_avoid_spin() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        dt_seconds: 0.1,
        duration_seconds: 0.1,
        seed: 2113,
        ..Default::default()
    });
    let player = 2;
    // A team-mate holds the ball (a support, not a loose-ball recovery), and the scene sits deep
    // in our own third (inside the back-four shelf/goal-line area), so neither the
    // 20-40yd line band nor a back-line 50/50 forces a recovery sprint — isolating the facing/gait
    // logic under test. Only the player→ball bearing matters, which the uniform depth preserves.
    sim.ball.holder = Some(9);
    sim.ball.position = Vec2::new(40.0, 8.25);
    sim.players[player].position = Vec2::new(40.0, 8.0);
    sim.players[player].velocity = Vec2::zero();
    sim.players[player].action_facing = FacingBucket::East;

    sim.move_player_towards(player, Vec2::new(44.0, 8.0), false);

    assert_eq!(sim.players[player].movement_gait, MovementGait::SideStep);
    assert_eq!(
            sim.players[player].action_facing,
            FacingBucket::East,
            "when the ball is too close for a stable facing vector, keep the player's previous look direction instead of snapping to a team default"
        );
}

#[test]
fn support_movement_keeps_broad_ball_facing_to_avoid_bucket_spin() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        dt_seconds: 0.1,
        duration_seconds: 0.1,
        seed: 2114,
        ..Default::default()
    });
    let player = 2;
    // A team-mate holds the ball (support, not loose-ball recovery) deep in our own third (inside
    // the shelf/goal-line area) so neither the 20-40yd band nor a back-line 50/50 forces
    // a recovery sprint — isolating the facing logic. Uniform depth preserves the player→ball
    // bearings the facing buckets key on.
    sim.ball.holder = Some(9);
    sim.ball.position = Vec2::new(44.0, 18.0);
    sim.players[player].position = Vec2::new(40.0, 8.0);
    sim.players[player].velocity = Vec2::zero();
    sim.players[player].action_facing = FacingBucket::South;

    sim.move_player_towards(player, Vec2::new(46.0, 8.0), false);

    assert_eq!(sim.players[player].movement_gait, MovementGait::SideStep);
    assert_eq!(
            sim.players[player].action_facing,
            FacingBucket::South,
            "slight diagonal ball movement should not make a defender spin across adjacent facing buckets"
        );

    sim.ball.position = Vec2::new(62.0, 8.0);
    sim.players[player].position = Vec2::new(40.0, 8.0);
    sim.players[player].velocity = Vec2::zero();
    sim.players[player].action_facing = FacingBucket::South;

    sim.move_player_towards(player, Vec2::new(48.0, 8.0), false);

    assert_eq!(
            sim.players[player].action_facing,
            FacingBucket::SouthEast,
            "stale facing should rotate one bucket toward a square ball instead of snapping across the body"
        );
}

#[test]
fn broad_forward_view_keeps_defensive_facing_stable_until_ball_is_square() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        dt_seconds: 0.1,
        duration_seconds: 0.1,
        seed: 2115,
        ..Default::default()
    });
    let player = 2;
    sim.ball.holder = Some(9);
    // Deep in our own third (inside the shelf/goal-line area) so the 20-40yd line band
    // doesn't force a recovery sprint — isolating the facing logic. Uniform depth preserves the
    // player→ball bearings the facing buckets key on.
    sim.ball.position = Vec2::new(58.0, 13.0);
    sim.players[player].position = Vec2::new(40.0, 8.0);
    sim.players[player].velocity = Vec2::zero();
    sim.players[player].action_facing = FacingBucket::South;

    sim.move_player_towards(player, Vec2::new(46.0, 8.0), false);

    assert_eq!(sim.players[player].movement_gait, MovementGait::SideStep);
    assert_eq!(
            sim.players[player].action_facing,
            FacingBucket::South,
            "defenders should not spin from south to east while the ball is still in a broad forward view"
        );

    sim.ball.position = Vec2::new(62.0, 8.0);
    sim.players[player].position = Vec2::new(40.0, 8.0);
    sim.players[player].velocity = Vec2::zero();
    sim.players[player].action_facing = FacingBucket::South;

    sim.move_player_towards(player, Vec2::new(48.0, 8.0), false);

    assert_eq!(
            sim.players[player].action_facing,
            FacingBucket::SouthEast,
            "players should turn toward a square ball smoothly instead of snapping across facing buckets"
        );
}

#[test]
fn fast_away_facing_requires_target_and_velocity_away_from_ball() {
    let team = Team::Home;
    let position = Vec2::new(40.0, 60.0);
    let ball_position = Vec2::new(40.0, 40.0);
    let away_velocity = Vec2::new(0.0, 2.0);

    let recovering_facing = movement_action_facing_bucket(
        team,
        position,
        ball_position,
        Vec2::new(0.0, -12.0),
        away_velocity,
        MovementGait::Sprint,
        false,
        FacingBucket::South,
    );
    assert_eq!(
            recovering_facing,
            FacingBucket::North,
            "stale away momentum should not keep a defender facing away once the new target is back toward the ball"
        );

    let committed_away_facing = movement_action_facing_bucket(
        team,
        position,
        ball_position,
        Vec2::new(0.0, 18.0),
        away_velocity,
        MovementGait::Sprint,
        false,
        FacingBucket::South,
    );
    assert_eq!(
        committed_away_facing,
        FacingBucket::South,
        "a true sprint away from the ball can turn the body toward the run"
    );
}

