#[test]
fn human_input_queue_recovers_from_poisoned_controller_locks() {
    let q = SharedHumanInputs::new();
    let queue_poisoner = {
        let q = q.clone();
        std::thread::spawn(move || {
            let _guard = q.inner.write().expect("test poison queue lock");
            panic!("poison human input queue lock");
        })
    };
    assert!(queue_poisoner.join().is_err());

    let notifier_poisoner = {
        let notifier = q.notifier.clone();
        std::thread::spawn(move || {
            let (lock, _) = &*notifier;
            let _guard = lock.lock().expect("test poison notifier lock");
            panic!("poison human input notifier lock");
        })
    };
    assert!(notifier_poisoner.join().is_err());

    assert!(
        q.push(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(1),
            seq: 7,
            axis: Vec2::new(0.2, 0.9),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        }),
        "controller input should still be accepted after a thread poisons shared locks"
    );
    assert_eq!(q.queued_len(), 1);
    assert!(q.notification_version() > 0);

    let recovered = q
        .drain_latest_for_slot(0)
        .expect("recovered queue should drain latest input");
    assert_eq!(recovered.seq, 7);
    assert!(recovered.sprint);
}

#[test]
fn human_input_queue_coalesces_bursts_without_evicting_other_slots() {
    let q = SharedHumanInputs::new();
    assert!(q.push(HumanInputFrame {
        pace: 0,
        controller_slot: 1,
        player_id: Some(1),
        seq: 1,
        axis: Vec2::new(0.0, 1.0),
        sprint: false,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }));

    for seq in 1..=(HUMAN_INPUT_QUEUE_LIMIT as u64 + 10) {
        assert!(q.push(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq,
            axis: Vec2::new(seq as f64, 0.0),
            sprint: seq % 2 == 0,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        }));
    }

    assert_eq!(q.queued_len(), 2);
    assert_eq!(q.queued_len_for_slots(&[0]), 1);
    assert_eq!(q.queued_len_for_slots(&[1]), 1);

    let slot_one = q.drain_latest_for_slot(1).expect("slot 1 input");
    assert_eq!(slot_one.seq, 1);
    let slot_zero = q.drain_latest_for_slot(0).expect("slot 0 input");
    assert_eq!(slot_zero.seq, HUMAN_INPUT_QUEUE_LIMIT as u64 + 10);
}

