#[test]
fn shared_human_inputs_notify_waiting_main_loop() {
    let q = SharedHumanInputs::new();
    let version = q.notification_version();
    let waiter_queue = q.clone();
    let waiter = std::thread::spawn(move || {
        waiter_queue.wait_for_pending_input_result(Duration::from_millis(200))
    });
    std::thread::sleep(Duration::from_millis(2));
    assert!(q.push(HumanInputFrame {
        pace: 0,
        controller_slot: 0,
        player_id: Some(0),
        seq: 1,
        axis: Vec2::new(1.0, 0.0),
        sprint: true,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }));

    let wait_result = waiter.join().expect("waiter joins");
    assert_eq!(wait_result.version_before, version);
    assert!(wait_result.version_after > version);
    assert!(!wait_result.immediate_pending);
    assert!(wait_result.notified);
    assert_eq!(wait_result.queued_before, 0);
    assert_eq!(wait_result.queued_after, 1);
    let immediate = q.wait_for_pending_input_result(Duration::from_millis(0));
    assert!(immediate.immediate_pending);
    assert_eq!(immediate.queued_before, 1);
    assert!(q.wait_for_pending_input(Duration::from_millis(0)));
}

#[test]
fn shared_human_inputs_wait_prunes_expired_assigned_slot_frames() {
    let q = SharedHumanInputs::new();
    let stale_enqueued_at = soccer_unix_millis()
        .saturating_sub(HUMAN_INPUT_MAX_QUEUE_AGE_MS)
        .saturating_sub(50);
    assert!(q.push_with_enqueue_unix_ms(
        HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq: 1,
            axis: Vec2::new(1.0, 0.0),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        },
        stale_enqueued_at,
    ));

    let wait_result = q.wait_for_pending_input_for_slots_result(&[0], Duration::from_millis(0));

    assert!(
        !wait_result.pending(),
        "expired assigned-slot input should not wake/yield as immediately pending: {wait_result:?}"
    );
    assert_eq!(wait_result.queued_before, 0);
    assert_eq!(wait_result.queued_after, 0);
    assert_eq!(q.queued_len_for_slots(&[0]), 0);
    assert_eq!(q.expired_len_for_slot(0), 1);
    assert_eq!(q.expired_len(), 1);
}

