#[test]
fn four_native_controller_threads_drive_four_selected_players_in_one_tick() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        max_human_players: 4,
        seed: 22_801,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    let controlled_players = [1usize, 2, 3, 4];
    let start_positions = controlled_players
        .iter()
        .map(|player_id| sim.players[*player_id].position)
        .collect::<Vec<_>>();
    for (slot, player_id) in controlled_players.iter().copied().enumerate() {
        sim.assign_controller_slot(slot, Some(player_id))
            .expect("assign native controller slot");
    }

    let input_queue = sim.human_inputs.clone();
    let controllers =
        spawn_human_controller_threads(input_queue.clone(), 4, Duration::from_millis(1))
            .expect("spawn four native controller threads");
    for (slot, player_id) in controlled_players.iter().copied().enumerate() {
        controllers[slot]
            .send_input(HumanInputFrame {
                pace: 0,
                controller_slot: 99,
                player_id: Some(player_id),
                seq: 100 + slot as u64,
                axis: Vec2::new(1.0, 0.0),
                sprint: slot % 2 == 0,
                pass: false,
                pass_flight: PassFlight::Floor,
                shoot: false,
                action: None,
                target_player: None,
            })
            .expect("send controller-thread input");
    }

    let wait = input_queue
        .wait_for_pending_input_for_slots_result(&[0, 1, 2, 3], Duration::from_millis(300));
    assert!(
            wait.pending() && wait.queued_after == 4,
            "all four native controller slots should write to the shared queue before the main tick: {wait:?}"
        );

    sim.run_time_step();

    let yield_stats = sim.controller_yield_stats();
    assert_eq!(yield_stats.assigned_players, 4);
    assert_eq!(yield_stats.wait_attempts, 1);
    assert_eq!(yield_stats.immediate_pending_waits, 1);
    assert_eq!(yield_stats.timed_out_waits, 0);
    assert_eq!(input_queue.queued_len(), 0);
    for (slot, player_id) in controlled_players.iter().copied().enumerate() {
        let decision = sim.players[player_id]
            .last_decision
            .as_ref()
            .expect("controlled player decision");
        assert_eq!(
            decision.operation_order,
            vec!["human-input".to_string()],
            "player {player_id} should consume its own controller-thread input"
        );
        assert_eq!(decision.observation.controller_slot, Some(slot));
        assert!(decision.observation.human_controlled);
        assert!(decision.observation.human_input_present);
        assert_eq!(
            decision.observation.human_input_seq,
            Some(100 + slot as u64)
        );
        assert!(
            sim.players[player_id].position.x > start_positions[slot].x,
            "selected player {player_id} should move right from human controller input"
        );
    }
    for controller in controllers {
        controller.stop().expect("controller stops");
    }
}

#[test]
fn four_assigned_human_players_check_controller_slots_when_silent() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        max_human_players: 4,
        seed: 22_802,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    let controlled_players = [0usize, 1, 2, 3];
    for (slot, player_id) in controlled_players.iter().copied().enumerate() {
        sim.assign_controller_slot(slot, Some(player_id))
            .expect("assign silent controller slot");
    }

    sim.run_time_step();

    let yield_stats = sim.controller_yield_stats();
    assert_eq!(yield_stats.assigned_players, controlled_players.len());
    assert_eq!(
        yield_stats.last_queued_after, 0,
        "silent controller slots should not leave queued input after the scheduler yield"
    );
    assert_eq!(sim.human_inputs.queued_len(), 0);
    for (slot, player_id) in controlled_players.iter().copied().enumerate() {
        let player = &sim.players[player_id];
        assert_eq!(player.controller_slot, Some(slot));
        let decision = player
            .last_decision
            .as_ref()
            .expect("silent human-controlled player should still run its agent loop");
        assert_ne!(
            decision.operation_order.first().map(String::as_str),
            Some("human-input"),
            "quiet controller slot {slot} should not emit a fake human-input action"
        );
        assert_eq!(decision.observation.controller_slot, Some(slot));
        assert!(decision.observation.human_controlled);
        assert!(!decision.observation.human_input_present);
        assert_eq!(decision.observation.human_input_seq, None);
    }
}

#[test]
fn controller_input_router_debounces_assigned_slot_burst_without_queue_growth() {
    let q = SharedHumanInputs::new();
    let assignments = SharedControllerAssignments::new(4);
    assignments.assign_slot(0, Some(0));
    let controllers = spawn_human_controller_threads(q.clone(), 4, Duration::from_millis(40))
        .expect("spawn controller threads");
    let router = HumanControllerInputRouter::new(q.clone(), assignments, &controllers);

    for seq in 1..=12 {
        assert!(
            router.push_human_input(HumanInputFrame {
                pace: 0,
                controller_slot: 0,
                player_id: Some(0),
                seq,
                axis: Vec2::new(seq as f64 / 12.0, 0.0),
                sprint: seq == 12,
                pass: false,
                pass_flight: PassFlight::Floor,
                shoot: false,
                action: None,
                target_player: None,
            }),
            "assigned controller input {seq} should enter the native controller mailbox"
        );
    }

    assert_eq!(
        router.queued_len(),
        1,
        "router should expose one pending debounced mailbox frame for the slot"
    );
    let pending_stats = controllers[0].stats();
    assert_eq!(pending_stats.accepted_frames, 12);
    assert!(
            pending_stats.overwritten_frames >= 10,
            "same-slot burst should overwrite pending native input instead of growing the shared queue: {pending_stats:?}"
        );

    assert!(q.wait_for_pending_input(Duration::from_millis(300)));
    let input = q
        .drain_latest_for_slot(0)
        .expect("debounced slot input should reach the shared queue");
    assert_eq!(input.controller_slot, 0);
    assert_eq!(input.player_id, Some(0));
    assert_eq!(input.seq, 12);
    assert!(input.sprint);
    assert_eq!(
        q.queued_len(),
        0,
        "main loop should consume one coalesced frame, not a burst"
    );

    let pushed_stats = controllers[0].stats();
    assert_eq!(pushed_stats.pushed_frames, 1);
    assert_eq!(pushed_stats.debounced_frames, 1);
    for controller in controllers.iter().skip(1) {
        assert_eq!(controller.stats().accepted_frames, 0);
    }

    for controller in controllers {
        controller.stop().expect("controller stops");
    }
}

#[test]
fn controller_input_router_preserves_command_when_latest_same_slot_frame_is_motion() {
    let q = SharedHumanInputs::new();
    let assignments = SharedControllerAssignments::new(4);
    assignments.assign_slot(0, Some(0));
    let router = HumanControllerInputRouter::without_controller_threads(q.clone(), assignments);

    let accepted = router.push_human_inputs(vec![
        HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq: 41,
            axis: Vec2::new(0.0, 0.0),
            sprint: false,
            pass: true,
            pass_flight: PassFlight::Aerial,
            shoot: false,
            action: Some("aerial-pass".to_string()),
            target_player: Some(7),
        },
        HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq: 42,
            axis: Vec2::new(1.0, 0.0),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        },
    ]);

    assert_eq!(accepted, 1);
    assert_eq!(q.queued_len(), 1);
    let input = q
        .drain_latest_for_slot(0)
        .expect("coalesced same-slot input");
    assert_eq!(input.seq, 42);
    assert_eq!(input.axis, Vec2::new(1.0, 0.0));
    assert!(input.sprint);
    assert!(input.pass);
    assert_eq!(input.pass_flight, PassFlight::Aerial);
    assert_eq!(input.action.as_deref(), Some("aerial-pass"));
    assert_eq!(input.target_player, Some(7));
    assert!(!input.shoot);
}

#[test]
fn controller_mailbox_overwrites_pending_input_without_queue_growth() {
    let q = SharedHumanInputs::new();
    let controller = HumanControllerThread::spawn(q.clone(), 0, Duration::from_millis(50))
        .expect("spawn controller thread");

    for seq in 1..=20 {
        assert!(controller
            .send_input(HumanInputFrame {
                pace: 0,
                controller_slot: 99,
                player_id: Some(0),
                seq,
                axis: Vec2::new(seq as f64, 0.0),
                sprint: seq == 20,
                pass: false,
                pass_flight: PassFlight::Floor,
                shoot: false,
                action: None,
                target_player: None,
            })
            .expect("send input"));
    }
    assert!(!controller
        .send_input(HumanInputFrame {
            pace: 0,
            controller_slot: 99,
            player_id: Some(0),
            seq: 19,
            axis: Vec2::new(-1.0, 0.0),
            sprint: false,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        })
        .expect("stale input is rejected without stopping controller"));

    let pending_stats = controller.stats();
    assert_eq!(pending_stats.accepted_frames, 20);
    assert_eq!(pending_stats.rejected_stale_frames, 1);
    assert!(pending_stats.overwritten_frames > 0);
    assert!(pending_stats.pending);

    assert!(q.wait_for_pending_input(Duration::from_millis(300)));
    let input = q.drain_latest_for_slot(0).expect("slot 0 latest input");
    assert_eq!(input.controller_slot, 0);
    assert_eq!(input.seq, 20);
    assert!(input.sprint);
    assert_eq!(q.queued_len(), 0);

    let pushed_stats = controller.stats();
    assert_eq!(pushed_stats.pushed_frames, 1);
    assert!(!pushed_stats.pending);

    controller.stop().expect("controller stops");
}

#[test]
fn controller_mailbox_recovers_from_poisoned_lock() {
    let mailbox = HumanControllerMailbox::default();
    let poisoner = {
        let mailbox = mailbox.clone();
        std::thread::spawn(move || {
            let (lock, _) = &*mailbox.inner;
            let _guard = lock.lock().expect("test poison mailbox lock");
            panic!("poison human controller mailbox lock");
        })
    };
    assert!(poisoner.join().is_err());

    assert!(
        mailbox
            .send(HumanInputFrame {
                pace: 0,
                controller_slot: 0,
                player_id: Some(0),
                seq: 1,
                axis: Vec2::new(1.0, 0.0),
                sprint: true,
                pass: false,
                pass_flight: PassFlight::Floor,
                shoot: false,
                action: None,
                target_player: None,
            })
            .expect("poisoned mailbox should still accept input"),
        "mailbox should recover and accept a fresh controller frame"
    );
    assert_eq!(mailbox.pending_len(), 1);
    let stats = mailbox.stats(0);
    assert!(stats.pending);
    assert_eq!(stats.accepted_frames, 1);

    mailbox.clear_pending();
    assert_eq!(mailbox.pending_len(), 0);
    mailbox.close();
    assert!(mailbox
        .send(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq: 2,
            axis: Vec2::new(0.0, 1.0),
            sprint: false,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        })
        .is_err());
}

#[test]
fn controller_mailbox_debounce_extends_until_latest_frame_is_quiet() {
    let mailbox = HumanControllerMailbox::default();
    let waiter_mailbox = mailbox.clone();
    let debounce = Duration::from_millis(60);
    let waiter = std::thread::spawn(move || {
        let started = Instant::now();
        let input = waiter_mailbox
            .wait_for_debounced_input(debounce)
            .expect("debounced input");
        (input, started.elapsed())
    });

    std::thread::sleep(Duration::from_millis(5));
    assert!(mailbox
        .send(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq: 1,
            axis: Vec2::new(0.25, 0.0),
            sprint: false,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        })
        .expect("send first input"));
    std::thread::sleep(Duration::from_millis(35));
    assert!(mailbox
        .send(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(0),
            seq: 2,
            axis: Vec2::new(1.0, 0.0),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        })
        .expect("send latest input"));

    let (input, elapsed) = waiter.join().expect("waiter joins");
    assert_eq!(input.seq, 2);
    assert!(input.sprint);
    assert!(
        elapsed >= Duration::from_millis(85),
        "debounce should restart after the latest accepted frame, elapsed={elapsed:?}"
    );
    let stats = mailbox.stats(0);
    assert_eq!(stats.accepted_frames, 2);
    assert_eq!(stats.debounced_frames, 1);
    assert!(
        stats.last_debounce_ms >= 85.0,
        "debounce telemetry should include the extended quiet wait, stats={stats:?}"
    );
}

