#[test]
fn batched_live_step_consumes_controller_thread_input_between_ticks() {
    let mut session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig {
        duration_seconds: 0.4,
        max_human_players: 1,
        seed: 22_809,
        ..Default::default()
    });
    session
        .assign_controller_slot(SoccerControllerAssignmentRequest {
            controller_slot: 0,
            player_id: Some(0),
        })
        .expect("assign slot 0");
    let input_queue = session.input_queue();
    assert!(input_queue.push(HumanInputFrame {
        pace: 0,
        controller_slot: 0,
        player_id: Some(0),
        seq: 1,
        axis: Vec2::new(1.0, 0.0),
        sprint: true,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }));

    let writer_queue = input_queue.clone();
    let writer = std::thread::spawn(move || {
        let deadline = Instant::now() + Duration::from_millis(120);
        while Instant::now() < deadline {
            if writer_queue.queued_len_for_slots(&[0]) == 0 {
                return writer_queue.push(HumanInputFrame {
                    pace: 0,
                    controller_slot: 0,
                    player_id: Some(0),
                    seq: 2,
                    axis: Vec2::new(0.0, 1.0),
                    sprint: true,
                    pass: false,
                    pass_flight: PassFlight::Floor,
                    shoot: false,
                    action: None,
                    target_player: None,
                });
            }
            std::thread::yield_now();
        }
        false
    });

    let response = session.step(SoccerStepRequest {
        inputs: Vec::new(),
        ticks: 2,
        record_every_ticks: Some(1),
    });

    assert!(
        writer.join().expect("between-tick controller writer joins"),
        "controller thread should enqueue fresh input after the first batched tick drains"
    );
    assert_eq!(
            response.accepted_inputs, 0,
            "second controller frame should arrive from the shared thread queue, not the HTTP request body"
        );
    assert_eq!(response.frames.len(), 2);
    let first_decision = response.frames[0]
        .players
        .iter()
        .find(|player| player.id == 0)
        .and_then(|player| player.last_decision.as_ref())
        .expect("first batched frame human decision");
    let second_decision = response.frames[1]
        .players
        .iter()
        .find(|player| player.id == 0)
        .and_then(|player| player.last_decision.as_ref())
        .expect("second batched frame human decision");
    assert_eq!(
        first_decision.operation_order,
        vec!["human-input".to_string()]
    );
    assert_eq!(first_decision.observation.human_input_seq, Some(1));
    assert_eq!(
        second_decision.operation_order,
        vec!["human-input".to_string()]
    );
    assert_eq!(second_decision.observation.human_input_seq, Some(2));
    assert_eq!(input_queue.queued_len_for_slots(&[0]), 0);
    assert!(
        response.controller_yield.wait_attempts >= 2,
        "batched live stepping should yield once per simulated tick: {:?}",
        response.controller_yield
    );
    assert_eq!(response.controller_latency_budget.consumed_inputs, 1);
}

#[test]
fn late_controller_wait_time_is_reported_as_controller_yield_timing() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        max_human_players: 1,
        seed: 789,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    sim.assign_controller_slot(0, Some(0))
        .expect("assign slot 0");

    sim.run_time_step();

    let yield_stats = sim.controller_yield_stats();
    let timing = sim.step_timing_stats();
    assert_eq!(yield_stats.assigned_players, 1);
    assert!(
            yield_stats.late_wait_attempts >= 1,
            "no input should trigger a late assigned-slot wait after the initial yield: {yield_stats:?}"
        );
    assert!(
        yield_stats.total_wait_ms > 0.0,
        "controller wait stats should record the late timeout budget"
    );
    assert!(
            timing.controller_yield_ms + 0.05 >= yield_stats.total_wait_ms,
            "late waits should be charged to controllerYieldMs, not hidden inside player decision timing: timing={timing:?} yield={yield_stats:?}"
        );
}

#[test]
fn controller_yield_waits_for_assigned_slots_not_unassigned_backlog() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 2,
        seed: 782,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    sim.assign_controller_slot(0, Some(0))
        .expect("assign slot 0");
    let input_queue = sim.human_inputs.clone();
    assert!(input_queue.push(HumanInputFrame {
        pace: 0,
        controller_slot: 1,
        player_id: Some(1),
        seq: 1,
        axis: Vec2::new(0.0, 1.0),
        sprint: true,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }));

    sim.run_time_step();

    let stats = sim.controller_yield_stats();
    assert_eq!(stats.assigned_players, 1);
    assert_eq!(stats.wait_attempts, 2);
    assert_eq!(stats.immediate_pending_waits, 0);
    assert_eq!(stats.notified_waits, 0);
    assert_eq!(stats.timed_out_waits, 2);
    assert_eq!(stats.late_wait_attempts, 1);
    assert_eq!(stats.late_notified_waits, 0);
    assert_eq!(stats.late_timed_out_waits, 1);
    assert_eq!(stats.late_immediate_pending_waits, 0);
    assert!(stats.last_wait_late);
    assert!(!stats.last_immediate_pending);
    assert_eq!(stats.last_queued_before, 0);
    assert_eq!(stats.last_queued_after, 0);

    let observation = &sim.players[0]
        .last_decision
        .as_ref()
        .expect("assigned player decision")
        .observation;
    assert_eq!(observation.controller_slot, Some(0));
    assert!(observation.human_controlled);
    assert!(!observation.human_input_present);
    assert_eq!(observation.human_input_seq, None);

    let remaining = input_queue.drain_latest_by_slot();
    assert_eq!(remaining.get(&1).expect("unassigned slot remains").seq, 1);
    assert!(!remaining.contains_key(&0));
}

