#[test]
fn controller_assignment_flushes_stale_slot_level_input() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 1,
        seed: 784,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    sim.assign_controller_slot(0, Some(0))
        .expect("assign slot 0 to first player");
    let input_queue = sim.human_inputs.clone();
    assert!(input_queue.push(HumanInputFrame {
        pace: 0,
        controller_slot: 0,
        player_id: None,
        seq: 1,
        axis: Vec2::new(1.0, 0.0),
        sprint: true,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }));
    assert_eq!(input_queue.queued_len(), 1);

    sim.assign_controller_slot(0, Some(1))
        .expect("reassign slot 0 to second player");

    assert_eq!(input_queue.queued_len(), 0);
    assert_eq!(input_queue.last_seq_for_slot(0), None);
    sim.run_time_step();
    assert_ne!(
        sim.players[1]
            .last_decision
            .as_ref()
            .and_then(|decision| decision.operation_order.first())
            .map(String::as_str),
        Some("human-input"),
        "newly assigned player should not inherit stale slot-level input"
    );

    assert!(
        input_queue.push(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(1),
            seq: 1,
            axis: Vec2::new(0.0, 1.0),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        }),
        "reassigned slot should accept a fresh controller sequence"
    );
    sim.run_time_step();
    assert_eq!(
        sim.players[1]
            .last_decision
            .as_ref()
            .and_then(|decision| decision.operation_order.first())
            .map(String::as_str),
        Some("human-input"),
        "newly assigned player should consume fresh slot input"
    );
}

#[test]
fn clearing_controller_assignments_flushes_pending_slot_input() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 2,
        seed: 785,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    sim.assign_controller_slot(0, Some(0))
        .expect("assign slot 0");
    sim.assign_controller_slot(1, Some(1))
        .expect("assign slot 1");
    let input_queue = sim.human_inputs.clone();
    for slot in 0..2 {
        assert!(input_queue.push(HumanInputFrame {
            pace: 0,
            controller_slot: slot,
            player_id: None,
            seq: 7,
            axis: Vec2::new(1.0, 0.0),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        }));
    }
    assert_eq!(input_queue.queued_len(), 2);
    assert_eq!(input_queue.last_seq_for_slot(0), Some(7));
    assert_eq!(input_queue.last_seq_for_slot(1), Some(7));

    sim.clear_controller_assignments();

    assert!(sim.controller_assignments().is_empty());
    assert_eq!(
        input_queue.queued_len(),
        0,
        "bulk clearing controller assignments should discard stale queued inputs"
    );
    assert_eq!(input_queue.last_seq_for_slot(0), None);
    assert_eq!(input_queue.last_seq_for_slot(1), None);
    assert!(
        input_queue.push(HumanInputFrame {
            pace: 0,
            controller_slot: 0,
            player_id: Some(1),
            seq: 1,
            axis: Vec2::new(0.0, 1.0),
            sprint: true,
            pass: false,
            pass_flight: PassFlight::Floor,
            shoot: false,
            action: None,
            target_player: None,
        }),
        "cleared controller slot should accept a fresh low sequence"
    );
}

#[test]
fn controller_noop_assignment_preserves_pending_slot_input() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 1,
        seed: 790,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    assert!(
        sim.assign_controller_slot(0, Some(0))
            .expect("assign slot 0 to player 0"),
        "initial assignment should change controller state"
    );
    let input_queue = sim.human_inputs.clone();
    assert!(input_queue.push(HumanInputFrame {
        pace: 0,
        controller_slot: 0,
        player_id: Some(0),
        seq: 1,
        axis: Vec2::new(1.0, 0.0),
        sprint: true,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    }));
    assert_eq!(input_queue.queued_len(), 1);

    assert!(
        !sim.assign_controller_slot(0, Some(0))
            .expect("repeat assignment should be a no-op"),
        "repeat assignment should report no controller state change"
    );

    assert_eq!(
        input_queue.queued_len(),
        1,
        "no-op assignment must not clear already accepted input"
    );
    sim.run_time_step();
    assert_eq!(
        sim.players[0]
            .last_decision
            .as_ref()
            .and_then(|decision| decision.operation_order.first())
            .map(String::as_str),
        Some("human-input"),
        "controlled player should still consume pending input after a no-op assignment"
    );
}

