#[test]
fn realtime_session_accepts_four_human_controller_slots() {
    let mut session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig {
        duration_seconds: 1.0,
        seed: 83,
        ..Default::default()
    });

    let axes = [
        Vec2::new(1.0, 0.0),
        Vec2::new(-1.0, 0.0),
        Vec2::new(0.0, 1.0),
        Vec2::new(0.0, -1.0),
    ];
    {
        let sim = session.match_mut();
        sim.ball.holder = None;
        for player_id in 0..4 {
            sim.players[player_id].position = Vec2::new(30.0 + player_id as f64 * 8.0, 60.0);
            sim.players[player_id].home_position = sim.players[player_id].position;
            sim.players[player_id].velocity = Vec2::zero();
            sim.players[player_id].acceleration = Vec2::zero();
        }
    }
    let starts = (0..4)
        .map(|player_id| session.match_ref().players[player_id].position)
        .collect::<Vec<_>>();

    for slot in 0..4 {
        session
            .assign_controller_slot(SoccerControllerAssignmentRequest {
                controller_slot: slot,
                player_id: Some(slot),
            })
            .expect("assign four human slots");
    }

    assert_eq!(session.match_ref().config.human_slots(), 4);
    assert_eq!(session.match_ref().controller_assignments().len(), 4);

    let response = session.step(SoccerStepRequest {
        inputs: (0..4)
            .map(|slot| HumanInputFrame {
                pace: 0,
                controller_slot: slot,
                player_id: Some(slot),
                seq: 10 + slot as u64,
                axis: axes[slot],
                sprint: true,
                pass: false,
                pass_flight: PassFlight::Floor,
                shoot: false,
                action: None,
                target_player: None,
            })
            .collect(),
        ticks: 1,
        record_every_ticks: Some(1),
    });

    assert_eq!(response.accepted_inputs, 4);
    for player_id in 0..4 {
        let decision = session.match_ref().players[player_id]
            .last_decision
            .as_ref()
            .expect("human-controlled player decision");
        assert_eq!(decision.operation_order, vec!["human-input".to_string()]);
        assert_eq!(decision.action, "human-move");
        assert_eq!(
            decision.observation.controller_slot,
            Some(player_id),
            "player {player_id} should observe its own controller slot"
        );
        assert_eq!(
            decision.observation.human_input_seq,
            Some(10 + player_id as u64),
            "player {player_id} should consume only its slot's latest frame"
        );
        let target = decision
            .action_target
            .as_ref()
            .and_then(|target| target.point)
            .expect("human move target");
        let movement = target - starts[player_id];
        assert!(
                movement.normalized().dot(axes[player_id]) > 0.92,
                "player {player_id} should target its own distinct axis: movement={movement:?} axis={:?}",
                axes[player_id]
            );
    }
}

#[test]
fn realtime_session_native_controller_threads_drive_four_players_in_one_tick() {
    let mut session = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 4,
        seed: 84,
        ..Default::default()
    });
    assert_eq!(session.owned_controller_thread_count(), 4);
    {
        let sim = session.match_mut();
        sim.clear_controller_assignments();
        for player_id in 0..4 {
            sim.players[player_id].position = Vec2::new(20.0 + player_id as f64 * 8.0, 36.0);
            sim.players[player_id].home_position = sim.players[player_id].position;
            sim.players[player_id].velocity = Vec2::zero();
            sim.players[player_id].acceleration = Vec2::zero();
            sim.players[player_id].skills.acceleration = 10.0;
            sim.players[player_id].skills.top_speed = 10.0;
            sim.assign_controller_slot(player_id, Some(player_id))
                .expect("assign native controller slot");
        }
    }
    let axes = [
        Vec2::new(1.0, 0.0),
        Vec2::new(-1.0, 0.0),
        Vec2::new(0.0, 1.0),
        Vec2::new(0.0, -1.0),
    ];
    let starts = (0..4)
        .map(|player_id| session.match_ref().players[player_id].position)
        .collect::<Vec<_>>();

    let response = session.step(SoccerStepRequest {
        inputs: (0..4)
            .map(|slot| HumanInputFrame {
                pace: 0,
                controller_slot: slot,
                player_id: Some(slot),
                seq: 30 + slot as u64,
                axis: axes[slot],
                sprint: true,
                pass: false,
                pass_flight: PassFlight::Floor,
                shoot: false,
                action: None,
                target_player: None,
            })
            .collect(),
        ticks: 1,
        record_every_ticks: Some(1),
    });

    assert_eq!(response.accepted_inputs, 4);
    assert_eq!(response.queued_human_inputs, 0);
    assert_eq!(response.controller_threads.len(), 4);
    assert_eq!(response.controller_yield.assigned_players, 4);
    assert_eq!(response.controller_yield.wait_attempts, 1);
    assert_eq!(response.controller_yield.last_queued_after, 4);
    assert_eq!(session.match_ref().human_inputs.queued_len(), 0);
    let frame_liveness = soccer_frame_liveness_for_frames(&response.frames);
    assert_eq!(frame_liveness.human_input_present_decisions, 4);
    assert_eq!(frame_liveness.human_input_consumed_decisions, 4);
    assert_eq!(frame_liveness.human_input_unique_controller_slots, 4);
    assert_eq!(
        soccer_playback_tactical_liveness_json_with_frame_liveness(
            &response.summary,
            Some(frame_liveness.clone()),
        )["humanInputConsumedOk"],
        true
    );
    for slot in 0..4 {
        let stats = response
            .controller_threads
            .iter()
            .find(|stats| stats.controller_slot == slot)
            .expect("controller thread stats");
        assert_eq!(stats.accepted_frames, 1);
        assert_eq!(stats.pushed_frames, 1);

        let player = &session.match_ref().players[slot];
        let decision = player
            .last_decision
            .as_ref()
            .expect("native human-controlled player decision");
        assert_eq!(decision.operation_order, vec!["human-input".to_string()]);
        assert_eq!(decision.action, "human-move");
        assert_eq!(decision.observation.controller_slot, Some(slot));
        assert_eq!(decision.observation.human_input_seq, Some(30 + slot as u64));
        let target = decision
            .action_target
            .as_ref()
            .and_then(|target| target.point)
            .expect("native human move target");
        let intended = target - starts[slot];
        let actual = player.position - starts[slot];
        assert!(
                intended.normalized().dot(axes[slot]) > 0.92,
                "player {slot} should target its own native input axis: intended={intended:?} axis={:?}",
                axes[slot]
            );
        assert!(
                actual.normalized().dot(axes[slot]) > 0.60,
                "player {slot} should move along its own native input axis: actual={actual:?} axis={:?}",
                axes[slot]
            );
    }
}

#[test]
fn realtime_session_exports_live_tracking_dataset() {
    let mut session = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        seed: 86,
        ..Default::default()
    });

    assert_eq!(session.tracking_dataset().frames.len(), 1);
    let response = session.step(SoccerStepRequest {
        ticks: 2,
        record_every_ticks: Some(1),
        ..Default::default()
    });
    let tracking = session.tracking_dataset();

    assert_eq!(tracking.source, "live-session");
    assert_eq!(tracking.frames.len(), 3);
    assert_eq!(tracking.frames[0].tick, 0);
    assert_eq!(tracking.frames[2].tick, 2);
    assert_eq!(tracking.frames[2].players.len(), 22);
    assert_eq!(
        tracking.frames[2].officials.len(),
        SOCCER_MATCH_OFFICIAL_COUNT
    );
    assert_eq!(
        tracking.frames[2].officials[0].position,
        response.frame.officials[0].position
    );
    assert!(tracking.frames[2].officials.iter().all(|official| {
        official.velocity.unwrap_or_default().len().is_finite()
            && official
                .motion_acceleration
                .unwrap_or_default()
                .len()
                .is_finite()
            && official.motion_jerk.unwrap_or_default().len().is_finite()
    }));
    assert!(
        tracking.frames[2].ball_action.is_none()
            || tracking.frames[2]
                .ball_action
                .as_deref()
                .is_some_and(|action| {
                    normalize_tracking_ball_action(action)
                        .ok()
                        .flatten()
                        .is_some()
                })
    );
    assert_eq!(
        tracking.frames[2].ball_position,
        response.frame.ball.position
    );
    assert!(tracking.to_learning_dataset().is_ok());
}

