#[test]
fn realtime_session_captures_goal_moment_windows() {
    let mut session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig {
        duration_seconds: 1.0,
        seed: 87,
        ..Default::default()
    });
    let moment_path = std::env::temp_dir().join(format!(
        "soccer-moments-test-{}-{}.jsonl",
        std::process::id(),
        87
    ));
    let _ = std::fs::remove_file(&moment_path);
    session.set_moment_storage_path(&moment_path);
    session.tracking_frames.clear();
    for tick in 0..=8 {
        let mut frame = tracking_frame_from_match(&session.sim);
        frame.source_frame_id = Some(format!("goal-src-{tick:03}"));
        frame.tick = tick;
        frame.clock_seconds = tick as f64 * session.sim.config.dt_seconds;
        frame.ball_position = Vec2::new(38.0 + tick as f64 * 0.5, 72.0 + tick as f64 * 2.0);
        frame.ball_velocity = Some(Vec2::new(5.0, 20.0));
        frame.ball_acceleration = Some(Vec2::new(0.0, 1.5));
        frame.ball_holder = if tick < 8 { Some(9) } else { None };
        frame.last_touch_team = Some(Team::Home);
        if let Some(striker) = frame.players.iter_mut().find(|player| player.id == 9) {
            striker.position = frame.ball_position;
            striker.velocity = Some(Vec2::new(5.0, 20.0));
            striker.motion_acceleration = Some(Vec2::new(0.0, 1.5));
        }
        session.tracking_frames.push(frame);
    }

    let snapshot = WorldSnapshot::from_match(&session.sim);
    for (tick, player_id, action, target_player) in [
        (2, 6, "pass", Some(9)),
        (5, 9, "dribble", None),
        (8, 9, "shoot", None),
    ] {
        let mut decision = test_decision_trace(&snapshot, player_id, action);
        decision.action_target = Some(AgentActionTargetTrace {
            point: Some(Vec2::new(40.0, 92.0)),
            player_id: target_player,
            grid: Some(pitch_grid_address(
                Vec2::new(40.0, 92.0),
                snapshot.field_width,
                snapshot.field_length,
            )),
            facing: FacingBucket::North,
            dribble_touch: None,
        });
        let player = session
            .sim
            .players
            .iter()
            .find(|player| player.id == player_id)
            .expect("moment player");
        let decision_context = soccer_decision_context_for(
            player_id,
            player.team,
            &decision.action,
            decision.action_target.as_ref(),
            &snapshot,
            &snapshot,
        );
        session
            .sim
            .recent_learning_history
            .push_back(SoccerLearningTransition {
                tick,
                player_id,
                team: player.team,
                role: player.role,
                state: decision.mdp_state,
                observation: decision.observation,
                belief: decision.belief,
                action: decision.action,
                action_target: decision.action_target,
                decision_context,
                tactical_trace: SoccerTacticalLearningTrace::default(),
                reward: 0.5,
                next_state: snapshot.mdp_state_for_player(player_id),
                next_observation: snapshot.observation_for(player_id),
                done: false,
            });
    }

    session.capture_moments_for_events(&[MatchEvent {
        tick: 8,
        clock_seconds: 0.8,
        kind: "goal".to_string(),
        team: Some(Team::Home),
        player_id: Some(9),
        description: "Home goal".to_string(),
        ..MatchEvent::default()
    }]);

    let summaries = session.recent_moment_summaries();
    assert_eq!(summaries.len(), 3);
    assert!(summaries
        .iter()
        .any(|moment| moment.label == "great_shot_to_goal"));
    assert!(summaries
        .iter()
        .any(|moment| moment.label == "great_pass_to_goal"));
    assert!(summaries
        .iter()
        .any(|moment| moment.label == "great_dribble_to_goal"));
    assert!(summaries.iter().all(|moment| moment.frame_count == 9));
    assert!(summaries.iter().all(|moment| moment.action_count == 3));
    assert!(summaries.iter().all(|moment| moment.feature_vector_len > 0));

    let windows = session.moment_windows();
    assert_eq!(windows.moments.len(), 3);
    assert_eq!(windows.storage.backend, "jsonl-disk");
    assert_eq!(windows.storage.path, moment_path.display().to_string());
    assert_eq!(windows.storage.stored_records, 3);
    assert!(windows.storage.last_error.is_none());
    assert!(windows
        .moments
        .iter()
        .all(|moment| !moment.frames.is_empty() && !moment.feature_vector.is_empty()));
    assert!(windows
        .moments
        .iter()
        .all(|moment| moment.embedder_version == SOCCER_MOMENT_EMBEDDER_VERSION));
    assert!(windows.moments.iter().all(|moment| {
        moment.feature_vector.len()
            == SOCCER_MOMENT_FEATURE_FRAME_SAMPLES * SOCCER_MOMENT_FEATURES_PER_FRAME
    }));
    let query = SoccerMomentIndexSearchRequest {
        bucket: windows.moments[0].summary.bucket.clone(),
        feature_vector: windows.moments[0].feature_vector.clone(),
        limit: 2,
        max_candidates: 10,
        bucket_radius: 6,
        same_label_only: true,
    };
    let index = SoccerMomentVectorIndex::from_windows(&windows.moments);
    let status = index.status();
    assert_eq!(status.entries, 3);
    assert_eq!(status.dimension, windows.moments[0].feature_vector.len());
    assert_eq!(status.embedder_version, SOCCER_MOMENT_EMBEDDER_VERSION);
    let mut mixed_windows = windows.moments.clone();
    let mut stale_window = mixed_windows[0].clone();
    stale_window.embedder_version = "soccer-moment-local-v1".to_string();
    mixed_windows.push(stale_window);
    let mut wrong_dimension_window = mixed_windows[0].clone();
    let _ = wrong_dimension_window.feature_vector.pop();
    wrong_dimension_window.summary.feature_vector_len = wrong_dimension_window.feature_vector.len();
    mixed_windows.push(wrong_dimension_window);
    let hardened_status = SoccerMomentVectorIndex::from_windows(&mixed_windows).status();
    assert_eq!(hardened_status.entries, 3);
    assert_eq!(hardened_status.skipped_windows, 2);
    assert_eq!(
        hardened_status.dimension,
        soccer_moment_expected_feature_vector_len()
    );
    let search = index.search(&query);
    assert!(!search.results.is_empty());
    assert_eq!(search.results[0].summary.id, windows.moments[0].summary.id);
    assert!(search.results[0].score > 0.999);
    assert!(moment_path.exists());
    let records = read_moment_history_jsonl(&moment_path);
    assert_eq!(records.len(), 3);
    assert_eq!(records[0]["episodeIndex"], 0);
    assert_eq!(records[0]["recordedTick"], 0);
    assert_eq!(
        records[0]["window"]["summary"]["label"],
        "great_shot_to_goal"
    );
    assert_eq!(
        records[0]["window"]["summary"]["bucket"]["label"],
        "great_shot_to_goal"
    );
    assert_eq!(
        records[0]["window"]["embedderVersion"],
        SOCCER_MOMENT_EMBEDDER_VERSION
    );
    assert_eq!(
        records[0]["window"]["featureVector"]
            .as_array()
            .expect("feature vector")
            .len(),
        summaries[0].feature_vector_len
    );
    assert_eq!(
        records[0]["window"]["frames"][0]["sourceFrameId"],
        "goal-src-000"
    );
    let raw_records = std::fs::read_to_string(&moment_path).expect("moment jsonl raw");
    let typed_records =
        soccer_moment_records_from_jsonl(&raw_records).expect("typed moment records");
    assert_eq!(typed_records.len(), 3);
    assert_eq!(
        SoccerMomentVectorIndex::from_records(&typed_records)
            .status()
            .entries,
        3
    );
    let replay_dataset =
        soccer_moment_records_to_learning_dataset(&typed_records, session.sim.config.clone(), 1.0)
            .expect("moment replay dataset");
    assert_eq!(replay_dataset.transitions.len(), 3);
    let replay_actions = replay_dataset
        .transitions
        .iter()
        .map(|transition| transition.action.as_str())
        .collect::<Vec<_>>();
    assert!(replay_actions.contains(&"shoot"));
    assert!(replay_actions.contains(&"pass"));
    assert!(replay_actions.contains(&"dribble"));
    assert!(replay_dataset
        .transitions
        .iter()
        .all(|transition| transition.team == Team::Home && transition.reward > 10.0));
    assert!(replay_dataset
        .transitions
        .iter()
        .all(|transition| transition.action_target.is_some()));
    for transition in &replay_dataset.transitions {
        let expected_before_tick = transition.tick.saturating_sub(1);
        let expected_before = format!("goal-src-{expected_before_tick:03}");
        let expected_after = format!("goal-src-{:03}", transition.tick);
        assert_eq!(
            transition
                .decision_context
                .tracking_source_frame_id
                .as_deref(),
            Some(expected_before.as_str())
        );
        assert_eq!(
            transition
                .decision_context
                .next_tracking_source_frame_id
                .as_deref(),
            Some(expected_after.as_str())
        );
    }
    let dribble_replay = replay_dataset
        .transitions
        .iter()
        .find(|transition| transition.action == "dribble")
        .expect("dribble replay transition");
    let dribble_touch = dribble_replay
        .action_target
        .as_ref()
        .and_then(|target| target.dribble_touch)
        .expect("moment replay dribble touch");
    assert_eq!(
        dribble_replay.decision_context.dribble_touch_angle_bucket,
        Some(dribble_touch.angle_bucket)
    );
    assert_eq!(
        dribble_replay.decision_context.dribble_touch_forward_class,
        dribble_touch_forward_class(dribble_touch.angle_bucket)
    );
    assert!(
        dribble_replay.decision_context.dribble_touch_distance_yards > 0.0,
        "moment replay dribble should carry touch distance"
    );
    let pass_replay = replay_dataset
        .transitions
        .iter()
        .find(|transition| transition.action == "pass")
        .expect("pass replay transition");
    assert_eq!(
        pass_replay
            .action_target
            .as_ref()
            .and_then(|target| target.player_id),
        Some(9)
    );
    let (moment_policies, replay_dataset_again) = train_soccer_team_policies_from_moment_records(
        &typed_records,
        session.sim.config.clone(),
        SoccerQPolicyOptions::default(),
        1.0,
    )
    .expect("moment policy training");
    assert_eq!(replay_dataset_again.transitions.len(), 3);
    assert!(moment_policies.home.entries().len() >= 3);
    // (Per-grid-cell target learning removed for perf; action entries asserted above.)
    assert!(moment_policies.away.entries().is_empty());
    let history = session
        .moment_history(Some(&SoccerMomentHistoryReadRequest {
            path: Some(moment_path.display().to_string()),
            limit: 2,
        }))
        .expect("moment history read");
    assert_eq!(history.total_records, 3);
    assert_eq!(history.records.len(), 2);
    assert!(history.truncated);
    let session = Arc::new(Mutex::new(session));
    let input_queue = session.lock().unwrap().input_queue();
    let missing_search_path = std::env::temp_dir().join(format!(
        "soccer-moments-search-test-{}-{}.jsonl",
        std::process::id(),
        87
    ));
    let search_body = serde_json::to_string(&SoccerMomentVectorSearchRequest {
        path: Some(missing_search_path.display().to_string()),
        k: 1,
        labels: vec![windows.moments[0].summary.label.clone()],
        feature_vector: Some(windows.moments[0].feature_vector.clone()),
        bucket: Some(windows.moments[0].summary.bucket.clone()),
        max_bucket_distance: 0,
        ..SoccerMomentVectorSearchRequest::default()
    })
    .expect("moment search request json");
    let search_response = handle_live_soccer_request(
        &format!(
            "POST /api/moments/search HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            search_body.len(),
            search_body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(search_response.status, 200);
    let search_value: serde_json::Value =
        serde_json::from_str(&search_response.body).expect("moment search json");
    assert_eq!(search_value["searchedRecords"], 3);
    assert_eq!(search_value["candidateRecords"], 1);
    assert_eq!(
        search_value["hits"][0]["summary"]["id"],
        windows.moments[0].summary.id
    );
    let replay_body = serde_json::json!({
        "limit": 2,
        "passes": 2,
        "rewardScale": 1.0
    })
    .to_string();
    let replay_response = handle_live_soccer_request(
        &format!(
            "POST /api/moments/replay HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            replay_body.len(),
            replay_body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(replay_response.status, 200);
    let replay_value: serde_json::Value =
        serde_json::from_str(&replay_response.body).expect("moment replay import json");
    assert_eq!(replay_value["source"], moment_path.display().to_string());
    assert_eq!(replay_value["records"], 2);
    assert_eq!(replay_value["importedTransitions"], 2);
    assert_eq!(replay_value["replayPasses"], 2);
    assert!(replay_value["importedHomeEntries"].as_u64().unwrap() >= 2);
    // (Per-grid-cell target learning removed for perf; action entries asserted above.)
    let _ = std::fs::remove_file(moment_path);
}

#[test]
fn moment_feature_vector_role_aligns_players_by_team_and_role() {
    let sim = SoccerMatch::default_11v11(MatchConfig {
        max_human_players: 0,
        seed: 881,
        ..Default::default()
    });
    let frame = tracking_frame_from_match(&sim);
    let vector = soccer_moment_feature_vector(&[frame.clone()], Team::Home, &sim.config);
    let aligned = soccer_moment_role_aligned_players(&frame, Team::Home, &sim.config);

    assert_eq!(
        vector.len(),
        SOCCER_MOMENT_FEATURE_FRAME_SAMPLES * SOCCER_MOMENT_FEATURES_PER_FRAME
    );
    assert_eq!(aligned.len(), SOCCER_MOMENT_ROLE_ALIGNED_PLAYERS);
    assert_eq!(aligned[0].team, Team::Home);
    assert_eq!(aligned[0].role, PlayerRole::Goalkeeper);
    assert_eq!(aligned[11].team, Team::Away);
    assert_eq!(aligned[11].role, PlayerRole::Goalkeeper);
    assert!(aligned[..11].iter().all(|player| player.team == Team::Home));
    assert!(aligned[11..].iter().all(|player| player.team == Team::Away));
}

#[test]
fn moment_feature_vector_infers_motion_from_position_only_window() {
    let tracking = sample_position_only_kinematics_tracking_dataset();
    assert!(tracking.frames[2].players[0].velocity.is_none());
    assert!(tracking.frames[2].ball_velocity.is_none());

    let vector = soccer_moment_feature_vector(&tracking.frames, Team::Home, &tracking.config);
    assert_eq!(vector.len(), soccer_moment_expected_feature_vector_len());

    let sample_idx = 5;
    let frame_base = sample_idx * SOCCER_MOMENT_FEATURES_PER_FRAME;
    let player_base = frame_base + SOCCER_MOMENT_FEATURES_PER_ENTITY;
    let field_length = tracking.config.field_length_yards;
    assert!((vector[frame_base + 3] as f64 - 8.0 / field_length).abs() < 1e-6);
    assert!((vector[frame_base + 5] as f64 - 40.0 / field_length).abs() < 1e-6);
    assert!(
        (vector[frame_base + 7] as f64 - 1.0).abs() < 1e-6,
        "ball jerk should be inferred and clamped into the canonical motion vector"
    );
    assert!((vector[player_base + 3] as f64 - 3.0 / field_length).abs() < 1e-6);
    assert!((vector[player_base + 5] as f64 - 20.0 / field_length).abs() < 1e-6);
    assert!(
        (vector[player_base + 7] as f64 - 1.0).abs() < 1e-6,
        "player jerk should be inferred and clamped into the canonical motion vector"
    );
}

#[test]
fn moment_vector_search_uses_local_bucketed_role_aligned_vectors() {
    let mut session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig {
        max_human_players: 0,
        seed: 882,
        ..Default::default()
    });
    let frame = tracking_frame_from_match(&session.sim);
    let label = "great_pass_to_goal";
    let bucket = soccer_moment_bucket_key(label, Team::Home, &frame, &session.sim.config);
    let query_vector =
        soccer_moment_feature_vector(&[frame.clone()], Team::Home, &session.sim.config);
    let mut near_vector = query_vector.clone();
    if let Some(first) = near_vector.first_mut() {
        *first += 0.001;
    }
    let far_vector = query_vector.iter().map(|value| -*value).collect::<Vec<_>>();

    let make_window = |id: &str, feature_vector: Vec<f32>| {
        let summary = SoccerMomentSummary {
            id: id.to_string(),
            label: label.to_string(),
            team: Team::Home,
            player_id: Some(5),
            event_tick: 8,
            start_tick: 0,
            end_tick: 8,
            goal_delta_ticks: 8,
            frame_count: 1,
            action_count: 1,
            feature_vector_len: feature_vector.len(),
            bucket: bucket.clone(),
        };
        SoccerMomentWindow {
            summary,
            actions: vec![SoccerMomentActionMarker {
                tick: 2,
                player_id: 5,
                action: "pass".to_string(),
                target_player: Some(9),
                reward: 30.0,
            }],
            frames: vec![frame.clone()],
            embedder_version: SOCCER_MOMENT_EMBEDDER_VERSION.to_string(),
            feature_vector,
        }
    };
    let mut stale_window = make_window("stale", query_vector.clone());
    stale_window.embedder_version = "soccer-moment-local-v1".to_string();
    session.recent_moments.push_back(stale_window);
    session
        .recent_moments
        .push_back(make_window("far", far_vector));
    session
        .recent_moments
        .push_back(make_window("near", near_vector));
    let missing_path = std::env::temp_dir().join(format!(
        "soccer-moment-vector-search-missing-{}-{}.jsonl",
        std::process::id(),
        882
    ));
    let _ = std::fs::remove_file(&missing_path);

    let response = session
        .search_moment_vectors(SoccerMomentVectorSearchRequest {
            path: Some(missing_path.display().to_string()),
            k: 1,
            labels: vec![label.to_string()],
            feature_vector: Some(query_vector.clone()),
            bucket: Some(bucket.clone()),
            max_bucket_distance: 0,
            ..SoccerMomentVectorSearchRequest::default()
        })
        .expect("moment vector search");

    assert_eq!(response.query_feature_vector_len, query_vector.len());
    assert_eq!(response.searched_records, 3);
    assert_eq!(response.candidate_records, 2);
    assert_eq!(response.hits.len(), 1);
    assert_eq!(response.hits[0].summary.id, "near");
    assert_eq!(response.hits[0].bucket_distance, 0);
    assert!(response.hits[0].cosine_similarity > 0.99);
}

