#[test]
fn terminal_match_result_reward_records_team_win_and_loss_signal() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 1301,
        ..Default::default()
    });
    sim.score_home = 2;
    sim.score_away = 0;
    sim.record_match_result_rewards_at(77);

    let mut home_rewards = Vec::new();
    let mut away_rewards = Vec::new();
    for event in &sim.reward_events {
        let player = sim
            .players
            .iter()
            .find(|player| player.id == event.player_id)
            .expect("reward player");
        assert_eq!(event.tick, 77);
        match player.team {
            Team::Home => home_rewards.push(event.amount),
            Team::Away => away_rewards.push(event.amount),
        }
    }

    assert_eq!(home_rewards.len(), 11);
    assert_eq!(away_rewards.len(), 11);
    assert!(home_rewards.iter().all(|reward| *reward > 0.0));
    assert!(away_rewards.iter().all(|reward| *reward < 0.0));
    assert!(home_rewards[0] > MATCH_RESULT_WIN_PLAYER_REWARD);
    assert!(away_rewards[0] < -MATCH_RESULT_LOSS_PLAYER_PENALTY);
}

#[test]
fn final_tick_learning_batch_includes_terminal_match_result_reward() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        learning_interval_ticks: 100,
        seed: 1302,
        ..Default::default()
    });
    let total_ticks = sim.config.total_ticks() as usize;
    sim.score_home = 3;
    sim.score_away = 1;

    while !sim.is_done() {
        sim.run_time_step();
    }

    assert!(sim.is_done());
    assert_eq!(sim.learning_transitions.len(), 22 * total_ticks);
    let terminal_transitions = sim
        .learning_transitions
        .iter()
        .filter(|transition| transition.done)
        .collect::<Vec<_>>();
    assert_eq!(terminal_transitions.len(), 22);
    let home_rewards = terminal_transitions
        .iter()
        .filter(|transition| transition.team == Team::Home)
        .map(|transition| transition.reward)
        .collect::<Vec<_>>();
    let away_rewards = terminal_transitions
        .iter()
        .filter(|transition| transition.team == Team::Away)
        .map(|transition| transition.reward)
        .collect::<Vec<_>>();
    assert_eq!(home_rewards.len(), 11);
    assert_eq!(away_rewards.len(), 11);
    assert!(home_rewards.iter().all(|reward| *reward > 0.0));
    assert!(away_rewards.iter().all(|reward| *reward < 0.0));
}

#[test]
fn full_game_learning_replays_all_ticks_after_full_time() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.3,
        learning_logging_enabled: false,
        learning_interval_ticks: 100,
        max_human_players: 0,
        seed: 1303,
        ..Default::default()
    })
    .with_team_policies(SoccerTeamQPolicies::new(SoccerQPolicyOptions::default()));
    let total_ticks = sim.config.total_ticks();

    for _ in 0..total_ticks {
        sim.run_time_step();
    }

    assert!(sim.is_done());
    assert!(sim.learning_transitions.is_empty());
    let learning = sim.learning_snapshot();
    assert!(learning.full_game_learning_enabled);
    assert!(learning.full_game_learning_applied);
    assert!(learning.full_game_learning_episode_transitions >= total_ticks as usize * 22);
    assert_eq!(
        learning.full_game_learning_replay_transitions,
        learning.full_game_learning_episode_transitions
    );
    assert!(
        learning.home_policy_visits + learning.away_policy_visits >= (total_ticks as u64 + 1) * 22
    );
}

#[test]
fn full_game_learning_feeds_neural_value_model() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.3,
        learning_logging_enabled: false,
        learning_interval_ticks: 100,
        max_human_players: 0,
        neural_learning: SoccerNeuralLearningConfig {
            enabled: true,
            backend: SoccerNeuralLearningBackend::Inline,
            train_every_ticks: 100,
            batch_size: 128,
            max_batches_per_tick: 2,
            hidden_units: 8,
            ..SoccerNeuralLearningConfig::default()
        },
        seed: 1304,
        ..Default::default()
    })
    .with_team_policies(SoccerTeamQPolicies::new(SoccerQPolicyOptions::default()));
    let total_ticks = sim.config.total_ticks();

    for _ in 0..total_ticks {
        sim.run_time_step();
    }

    let learning = sim.learning_snapshot();
    assert!(learning.full_game_learning_applied);
    assert!(learning.full_game_learning_episode_transitions >= total_ticks as usize * 22);
    assert_eq!(
        learning.full_game_learning_replay_transitions,
        learning.full_game_learning_episode_transitions
    );
    assert!(learning.neural_learning_enabled);
    assert!(learning.neural_learning_training_steps >= 2);
    assert!(learning.neural_learning_samples >= learning.full_game_learning_replay_transitions);
    assert!(learning.neural_network.is_some());

    // Keystone: after training, the critic is queryable at runtime (no
    // longer write-only) and returns finite values for real transitions.
    let probe = sim
        .episode_learning_transitions
        .last()
        .expect("at least one transition");
    let value = sim
        .neural_value_for_transition(probe)
        .expect("trained critic returns a value");
    assert!(value.is_finite());
}

