#[test]
fn physics_smoke_report_flags_non_gk_exact_stationary_run_over_three_seconds() {
    let mut trace = run_simulation(
        MatchConfig {
            seed: 13_608,
            ..MatchConfig::playback_trace(4.0)
        },
        1,
    );
    let stuck_player_id = trace.frames[0]
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role != PlayerRole::Goalkeeper)
        .expect("away non-goalkeeper")
        .id;
    let away_keeper_id = trace.frames[0]
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Goalkeeper)
        .expect("away goalkeeper")
        .id;
    let stuck_spot = Vec2::new(31.25, 58.75);
    let keeper_spot = Vec2::new(40.0, 8.0);
    for frame in &mut trace.frames {
        for player in &mut frame.players {
            if player.id == stuck_player_id {
                player.position = stuck_spot;
                player.velocity = Vec2::zero();
                player.acceleration = Vec2::zero();
            } else if player.id == away_keeper_id {
                player.position = keeper_spot;
                player.velocity = Vec2::zero();
                player.acceleration = Vec2::zero();
            }
        }
    }

    let report = soccer_simulation_physics_smoke_report(&trace);

    assert!(!report.ok());
    assert!(
        report.violations.iter().any(|violation| {
            violation.subject == format!("player:{stuck_player_id}")
                && violation.metric == "exactStationarySeconds"
                && violation.value > 3.0
        }),
        "non-GK exact-position stall should be reported: {:?}",
        report.violations
    );
    assert!(
        !report.violations.iter().any(|violation| {
            violation.subject == format!("player:{away_keeper_id}")
                && violation.metric == "exactStationarySeconds"
        }),
        "goalkeeper exact-position holds are allowed: {:?}",
        report.violations
    );
}

#[test]
fn live_physics_report_flags_impossible_history_jump() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 13_061,
        ..Default::default()
    });
    sim.run_time_step();
    sim.run_time_step();
    let mut frame = sim.to_frame();
    let history = &mut frame.players[0].position_history;
    let last = history.len() - 1;
    history[last] = history[last - 1] + Vec2::new(200.0, 0.0);

    let report = soccer_live_frame_physics_report(&frame, &sim.config);

    assert!(!report.ok);
    assert!(
        report.max_player_frame_speed_yps > SOCCER_PHYSICS_PLAYER_MAX_SPEED_YPS,
        "history-derived speed should expose the impossible jump: {report:?}"
    );
    assert!(report.violations.iter().any(|violation| {
        violation.subject == "player:0" && violation.metric == "frameDisplacementSpeed"
    }));
}

#[test]
fn full_time_match_frames_pass_accounting_smoke_report() {
    let trace = run_simulation(
        MatchConfig {
            seed: 1307,
            // A liveness smoke needs a few seconds of play to observe goalward progress: a
            // 1s window from kickoff can legitimately net zero (kickoffs are played backward).
            ..MatchConfig::playback_trace(4.0)
        },
        1,
    );

    let report = soccer_simulation_accounting_smoke_report(&trace);

    assert!(report.full_time_reached);
    assert_eq!(report.frames_analyzed, trace.frames.len());
    assert_eq!(
        report.possession_frames + report.non_possession_frames,
        report.frames_analyzed
    );
    assert_eq!(
        report.home_possession_frames + report.away_possession_frames,
        report.possession_frames
    );
    assert!(report.fifty_fifty_duel_frames <= report.non_possession_frames);
    assert!(
        report.moving_player_count >= 6,
        "accounting smoke should observe active player movement, got {}",
        report.moving_player_count
    );
    assert!(
        report.player_movement_yards > 0.0,
        "accounting smoke should observe player displacement"
    );
    assert!(
        report.ball_active_frames > 0 || report.ball_movement_yards > 0.025,
        "accounting smoke should observe an active or moving ball"
    );
    assert!(
        report.ball_goalward_progress_yards > 0.10,
        "accounting smoke should observe some goalward ball progress, got {:.6}",
        report.ball_goalward_progress_yards
    );
    assert!(
        report.ok(),
        "accounting smoke violations: {:?}",
        report.violations
    );
}

