#[test]
fn agent_schedule_summary_exposes_full_runtime_loop_contract() {
    let trace = run_simulation(
        MatchConfig {
            seed: 13_083,
            ..MatchConfig::playback_trace(0.2)
        },
        1,
    );
    let initial = trace.frames.first().expect("initial frame");
    assert_eq!(initial.agent_schedule_summary.expected_player_count, 22);
    assert_eq!(initial.agent_schedule_summary.expected_official_count, 3);
    assert_eq!(initial.agent_schedule_summary.expected_ball_count, 1);
    assert_eq!(initial.agent_schedule_summary.expected_total_agents, 27);
    assert_eq!(
        initial.agent_schedule_summary.expected_field_shuffle_agents,
        26
    );
    assert_eq!(initial.agent_schedule_summary.total_agents, 0);
    assert_eq!(initial.agent_schedule_summary.field_shuffle_agents, 0);
    assert!(!initial.agent_schedule_summary.complete);

    let scheduled = trace
        .frames
        .iter()
        .find(|frame| frame.tick > 0)
        .expect("post-tick scheduled frame");
    let summary = &scheduled.agent_schedule_summary;
    assert_eq!(summary.expected_player_count, 22);
    assert_eq!(summary.expected_official_count, 3);
    assert_eq!(summary.expected_ball_count, 1);
    assert_eq!(summary.expected_total_agents, 27);
    assert_eq!(summary.expected_field_shuffle_agents, 26);
    assert_eq!(summary.total_agents, 27);
    assert_eq!(summary.field_shuffle_agents, 26);
    assert_eq!(summary.unique_agents, 27);
    assert_eq!(summary.duplicate_agents, 0);
    assert_eq!(summary.central_brain_count, 1);
    assert_eq!(summary.player_count, 22);
    assert_eq!(summary.official_count, 3);
    assert_eq!(summary.ball_count, 1);
    assert!(summary.central_brain_first);
    assert_eq!(summary.ball_scheduled_index, scheduled.ball.scheduled_index);
    assert!(summary.complete);

    let playback = SoccerPlaybackFrame::from(scheduled);
    assert!(playback.agent_schedule_summary.complete);
    assert_eq!(playback.agent_schedule_summary.total_agents, 27);
    assert_eq!(playback.agent_schedule_summary.field_shuffle_agents, 26);
}

#[test]
fn runtime_agent_schedule_orders_field_entities_agentically_each_tick() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.8,
        seed: 13_084,
        ..Default::default()
    });
    let expected_player_ids = (0..22).collect::<HashSet<_>>();
    let expected_official_ids = [22, 23, 24].into_iter().collect::<HashSet<_>>();
    let mut field_orders = HashSet::new();
    let mut ball_indexes = HashSet::new();

    for _ in 0..8 {
        sim.run_time_step();
        let summary = agent_schedule_summary_for(
            &sim.last_agent_schedule,
            sim.players.len(),
            sim.officials.len(),
        );
        assert!(
            summary.complete,
            "runtime schedule should stay complete: {summary:?}"
        );
        assert_eq!(summary.expected_total_agents, 27);
        assert_eq!(summary.player_count, 22);
        assert_eq!(summary.official_count, 3);
        assert_eq!(summary.ball_count, 1);
        assert!(summary.central_brain_first);
        ball_indexes.insert(summary.ball_scheduled_index.expect("ball scheduled"));
        let field_segment = sim.last_agent_schedule.iter().skip(1).collect::<Vec<_>>();
        assert_eq!(
            field_segment.len(),
            26,
            "agentic field schedule should include 22 players, 3 officials, and the ball"
        );
        assert!(
            field_segment
                .iter()
                .all(|entry| entry.kind != AgentScheduleKind::CentralBrain),
            "central brain should not be inside the field-agent segment"
        );
        assert_eq!(
            field_segment
                .iter()
                .filter(|entry| entry.kind == AgentScheduleKind::Player)
                .map(|entry| entry.id)
                .collect::<HashSet<_>>(),
            expected_player_ids,
            "every player should appear exactly once in the agentic field segment"
        );
        assert_eq!(
                field_segment
                    .iter()
                    .filter(|entry| entry.kind == AgentScheduleKind::Official)
                    .map(|entry| entry.id)
                    .collect::<HashSet<_>>(),
                expected_official_ids,
                "center ref and both assistants should appear exactly once in the agentic field segment"
            );
        assert_eq!(
            field_segment
                .iter()
                .filter(|entry| entry.kind == AgentScheduleKind::Ball)
                .map(|entry| entry.id)
                .collect::<Vec<_>>(),
            vec![BALL_AGENT_ID],
            "ball agent should appear exactly once in the agentic field segment"
        );
        field_orders.insert(
            sim.last_agent_schedule
                .iter()
                .skip(1)
                .map(|entry| (entry.kind.clone(), entry.id))
                .collect::<Vec<_>>(),
        );
    }

    assert!(
        !field_orders.is_empty(),
        "agentic field entity order should be observable each tick"
    );
    assert_eq!(
        ball_indexes,
        [26].into_iter().collect::<HashSet<_>>(),
        "ball agent should integrate after field agents, got {ball_indexes:?}"
    );
}

#[test]
fn ball_agent_run_time_step_trace_matches_agentic_schedule_each_tick() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.8,
        seed: 13_086,
        ..Default::default()
    });
    let mut ball_indexes = HashSet::new();
    let mut ball_operation_orders = HashSet::new();

    for _ in 0..8 {
        sim.run_time_step();
        let frame = sim.to_frame();
        let ball_schedule_index = sim
            .last_agent_schedule
            .iter()
            .position(|entry| entry.kind == AgentScheduleKind::Ball && entry.id == BALL_AGENT_ID)
            .expect("ball agent should be scheduled");
        let decision = sim
            .ball
            .last_decision
            .as_ref()
            .expect("ball agent should record a run_time_step decision");

        assert_eq!(decision.tick, sim.tick.saturating_sub(1));
        assert_eq!(decision.scheduled_index, Some(ball_schedule_index));
        assert_eq!(frame.ball.scheduled_index, Some(ball_schedule_index));
        assert_eq!(
            frame
                .ball
                .last_decision
                .as_ref()
                .and_then(|decision| decision.scheduled_index),
            Some(ball_schedule_index)
        );
        assert!(
            !decision.action.is_empty(),
            "ball agent action should describe its timestep outcome"
        );
        assert_eq!(
            decision.operation_order.len(),
            7,
            "ball agent should trace its internal weighted operation order"
        );
        for op in [
            "sync-holder",
            "apply-curl",
            "apply-resistance",
            "advance-position",
            "resolve-shot",
            "resolve-boundary",
            "resolve-control",
        ] {
            assert!(
                decision.operation_order.iter().any(|actual| actual == op),
                "ball agent operation order should include {op}: {:?}",
                decision.operation_order
            );
        }

        ball_indexes.insert(ball_schedule_index);
        ball_operation_orders.insert(decision.operation_order.join(">"));
    }

    assert!(
        ball_indexes == [26].into_iter().collect::<HashSet<_>>(),
        "ball agent should hold the final agentic field slot: {ball_indexes:?}"
    );
    assert_eq!(
        ball_operation_orders.len(),
        1,
        "ball agent internal operation order should be deterministic and replay-stable"
    );
}

