    assert!(observation.opposing_goalkeeper_distance > 0.0);
    assert!(observation.opposing_goalkeeper_angle_degrees > 0.0);
    assert!(observation.forward_dribble_space_yards < 10.0);
    assert!(observation.real_pressure > 0.0);
