#[test]
fn clean_twenty_yard_window_forces_shot_even_below_quality_gate() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 1418,
        ..Default::default()
    });
    let attacker = 8;
    let keeper = 11;
    park_players_except(&mut sim, &[attacker, keeper]);
    sim.players[attacker].role = PlayerRole::Midfielder;
    sim.players[attacker].position = Vec2::new(40.0, 101.0);
    sim.players[attacker].skills.shooting = 5.4;
    sim.players[attacker].skills.decision_noise = 0.0;
    sim.players[attacker].preferences.shoot_bias = 0.20;
    sim.players[attacker].preferences.pass_bias = 1.0;
    sim.players[attacker].preferences.dribble_bias = 1.0;
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.players[keeper].skills.goalkeeping = 8.8;
    sim.ball.holder = Some(attacker);
    sim.ball.position = sim.players[attacker].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut observation = snapshot.observation_for(attacker);
    observation.shot_lane_open = true;
    observation.yards_to_goal = CLEAN_SHOT_MUST_SHOOT_YARDS - 1.0;
    observation.shot_block_probability = 0.16;
    observation.shot_on_frame_probability = CLEAN_SHOT_MIN_ON_FRAME_PROBABILITY + 0.02;
    observation.shot_beat_goalkeeper_probability = CLEAN_SHOT_MIN_KEEPER_BEAT_PROBABILITY + 0.02;
    observation.forward_dribble_space_yards = 5.0;

    assert!(
        !shot_decision_is_qualified(&observation),
        "the base quality gate should stay conservative for this mediocre shot"
    );
    assert!(clean_twenty_yard_shot_is_qualified(
        &observation,
        sim.players[attacker].role
    ));
    assert!(must_shoot_near_goal(
        &observation,
        sim.players[attacker].role
    ));
    assert!(goal_attack_shot_is_required(
        &observation,
        sim.players[attacker].role
    ));

    let mut blocked = observation.clone();
    blocked.shot_lane_open = false;
    blocked.shot_block_probability = CLEAN_SHOT_MAX_BLOCK_PROBABILITY + 0.04;
    assert!(!clean_twenty_yard_shot_is_qualified(
        &blocked,
        sim.players[attacker].role
    ));
    assert!(!must_shoot_near_goal(&blocked, sim.players[attacker].role));

    let mut shoot_count = 0;
    for seed in 0..40 {
        let mut player = sim.players[attacker].clone();
        let intent = player.run_time_step_with_context(
            &snapshot,
            snapshot.mdp_state_for_player(attacker),
            observation.clone(),
            None,
            None,
            &mut mulberry32(26_000 + seed),
        );
        if matches!(intent.action, SoccerAction::Shoot { .. }) {
            shoot_count += 1;
        }
    }
    assert_eq!(
        shoot_count, 40,
        "clean 20-yard windows should be deterministic must-shoot events"
    );
}

#[test]
fn elite_shot_speed_reaches_seventy_near_the_cap() {
    // Shots now leave the boot at 50-72 mph (clearly faster than any pass). An elite full-power
    // strike reaches ~70 mph, just under the 72 mph hard cap.
    let skills = SkillProfile {
        shooting: 10.0,
        right_foot_shot_power: 10.0,
        left_foot_shot_power: 10.0,
        strength: 10.0,
        ..SkillProfile::default()
    };

    let speed = shot_speed_yps_from_power(shot_power_for_skill(1.0), &skills);

    assert!(speed <= mph_to_yps(72.0) + 1e-9);
    assert!(speed >= mph_to_yps(69.0));
}

#[test]
fn shot_launch_speed_stays_within_fifty_to_seventytwo_mph_band() {
    // A shot on goal must leave the boot in the shot band (clearly above the pass band so it reads
    // as a strike): even a zero-power placed effort clears the floor, and a full-power elite strike
    // tops out near 70, under the 72 mph cap. Sweep the whole power x technique space.
    let floor = mph_to_yps(SHOT_MIN_SPEED_MPH);
    let cap = mph_to_yps(SHOT_MAX_SPEED_MPH);
    let weak = SkillProfile {
        shooting: 0.0,
        right_foot_shot_power: 0.0,
        left_foot_shot_power: 0.0,
        strength: 0.0,
        ..SkillProfile::default()
    };
    let mid = SkillProfile {
        shooting: 5.0,
        right_foot_shot_power: 5.0,
        left_foot_shot_power: 5.0,
        strength: 5.0,
        ..SkillProfile::default()
    };
    let elite = SkillProfile {
        shooting: 10.0,
        right_foot_shot_power: 10.0,
        left_foot_shot_power: 10.0,
        strength: 10.0,
        ..SkillProfile::default()
    };

    for skills in [&weak, &mid, &elite] {
        for power in [0.0, 0.25, 0.5, 0.75, 1.0] {
            let speed = shot_speed_yps_from_power(power, skills);
            assert!(
                speed >= floor - 1e-9 && speed <= cap + 1e-9,
                "shot launch must stay in the shot mph band (power={power}, speed_yps={speed})"
            );
        }
    }

    // The floor is genuinely reached: a zero-power poke still leaves at exactly the floor.
    assert!((shot_speed_yps_from_power(0.0, &weak) - floor).abs() < 1e-9);
    // An elite full-power strike tops out near 70 mph (just under the 72 mph cap).
    let elite_full = shot_speed_yps_from_power(1.0, &elite);
    assert!(elite_full >= mph_to_yps(69.0) && elite_full <= cap + 1e-9);
}

#[test]
fn struck_shot_releases_the_ball_in_the_fifty_to_seventytwo_band() {
    // End-to-end guard on the launch path (`apply_player_intent` -> Shoot): a
    // planted shooter (no body momentum, so the kick-power factor is a full 1.0)
    // must send the ball away at the 50-72 mph shot pace, not a slow roll.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 7_788,
        ..Default::default()
    });
    let shooter = 9usize;
    park_players_except(&mut sim, &[shooter]);
    sim.players[shooter].team = Team::Home;
    sim.players[shooter].role = PlayerRole::Forward;
    sim.players[shooter].position = Vec2::new(40.0, 100.0);
    sim.players[shooter].home_position = sim.players[shooter].position;
    sim.players[shooter].velocity = Vec2::zero();
    sim.players[shooter].skills.shooting = 9.0;
    sim.players[shooter].skills.right_foot_shot_power = 9.0;
    sim.players[shooter].skills.left_foot_shot_power = 8.0;
    sim.ball.holder = Some(shooter);
    sim.ball.position = sim.players[shooter].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let power = shot_power_for_skill(ability01(sim.players[shooter].skills.shooting));
    sim.apply_player_intent(PlayerIntent {
        player_id: shooter,
        action: SoccerAction::Shoot { power },
        sprint: false,
    });

    assert!(
        sim.ball.holder.is_none(),
        "the strike must release the ball"
    );
    let launch = sim.ball.velocity.len();
    assert!(
        launch >= mph_to_yps(SHOT_MIN_SPEED_MPH) - 1e-6
            && launch <= mph_to_yps(SHOT_MAX_SPEED_MPH) + 1e-6,
        "a planted strike must leave the boot in the shot mph band (got {launch} yps)"
    );
}

