#[test]
fn neural_transition_features_include_strength_to_weight_burst_budget() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 15076,
        ..Default::default()
    });
    let player_id = 7;

    fn features_for_player(
        sim: &SoccerMatch,
        player_id: usize,
    ) -> [f64; SOCCER_NEURAL_FEATURE_DIM] {
        let snapshot = WorldSnapshot::from_match(sim);
        let decision = test_decision_trace(&snapshot, player_id, "carry-forward");
        let transition = SoccerLearningTransition {
            tick: snapshot.tick,
            player_id,
            team: sim.players[player_id].team,
            role: sim.players[player_id].role,
            state: decision.mdp_state.clone(),
            observation: decision.observation.clone(),
            belief: decision.belief.clone(),
            action: decision.action.clone(),
            action_target: decision.action_target.clone(),
            decision_context: SoccerDecisionContext::default(),
            tactical_trace: SoccerTacticalLearningTrace::default(),
            reward: 0.0,
            next_state: snapshot.mdp_state_for_player(player_id),
            next_observation: snapshot.observation_for(player_id),
            done: false,
        };
        soccer_neural_transition_features(&transition)
    }

    sim.players[player_id].skills.strength = 9.5;
    sim.players[player_id].skills.weight_pounds = 145.0;
    let high_burst = features_for_player(&sim, player_id);

    sim.players[player_id].skills.strength = 2.0;
    sim.players[player_id].skills.weight_pounds = 225.0;
    let low_burst = features_for_player(&sim, player_id);

    assert!(
        high_burst[SOCCER_NEURAL_FEATURE_STRENGTH_TO_WEIGHT] > 0.90,
        "stronger, lighter players should expose a high burst budget"
    );
    assert!(
        low_burst[SOCCER_NEURAL_FEATURE_STRENGTH_TO_WEIGHT] < 0.10,
        "weaker, heavier players should expose a low burst budget"
    );
    assert!(
        high_burst[SOCCER_NEURAL_FEATURE_STRENGTH_TO_WEIGHT]
            > low_burst[SOCCER_NEURAL_FEATURE_STRENGTH_TO_WEIGHT] + 0.75,
        "neural learner should see the same body-load signal used by movement physics"
    );
}

#[test]
fn decision_context_prefers_defenders_in_action_lane() {
    let sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 15075,
        ..Default::default()
    });
    let mut before = WorldSnapshot::from_match(&sim);
    let actor = 7;
    let off_lane_defender = 12;
    let lane_defender = 13;
    let actor_position = Vec2::new(40.0, 60.0);
    let target = Vec2::new(40.0, 100.0);
    before.players[actor].position = actor_position;
    before.players[off_lane_defender].position = Vec2::new(48.0, 62.0);
    before.players[lane_defender].position = Vec2::new(40.0, 74.0);
    before.shared_positions = SharedPlayerPositionSnapshot::from_player_snapshots(
        &before.players,
        before.tick,
        before.clock_seconds,
    );
    let after = before.clone();
    let action_target = AgentActionTargetTrace {
        point: Some(target),
        player_id: Some(9),
        grid: Some(pitch_grid_address(
            target,
            before.field_width,
            before.field_length,
        )),
        facing: facing_bucket_from_vector(target - actor_position),
        dribble_touch: None,
    };

    let context = soccer_decision_context_for(
        actor,
        Team::Home,
        "pass",
        Some(&action_target),
        &before,
        &after,
    );

    assert_eq!(
        context
            .nearest_defenders
            .first()
            .map(|defender| defender.player_id),
        Some(lane_defender)
    );
    assert!(
        context.nearest_defenders[0].lane_distance_yards < 0.2,
        "lane defender should be first: {:?}",
        context.nearest_defenders
    );
}

#[test]
fn decision_context_records_dribble_touch_bucket_and_distance() {
    let sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 15077,
        ..Default::default()
    });
    let snapshot = WorldSnapshot::from_match(&sim);
    let actor = 9;
    let origin = snapshot
        .player_position(actor)
        .expect("actor position for dribble context");
    let touch = DribbleTouchDecision::new(1, 4.4);
    let target = origin + touch.direction_for_team(Team::Home);
    let action_target = AgentActionTargetTrace {
        point: Some(target),
        player_id: None,
        grid: Some(pitch_grid_address(
            target,
            snapshot.field_width,
            snapshot.field_length,
        )),
        facing: facing_bucket_from_vector(target - origin),
        dribble_touch: Some(touch),
    };

    let context = soccer_decision_context_for(
        actor,
        Team::Home,
        "carry-forward",
        Some(&action_target),
        &snapshot,
        &snapshot,
    );

    assert_eq!(context.dribble_touch_angle_bucket, Some(1));
    assert_eq!(
        context.dribble_touch_distance_bin,
        dribble_touch_distance_bin(touch.distance_yards)
    );
    assert_eq!(context.dribble_touch_forward_class, 1);
    assert!((context.dribble_touch_distance_yards - touch.distance_yards).abs() < 1e-9);
}

