#[test]
fn neural_learning_pads_previous_full_snapshot_belief_tail_without_shifting_motion() {
    let config = MatchConfig {
        duration_seconds: 0.2,
        max_human_players: 0,
        neural_learning: SoccerNeuralLearningConfig {
            enabled: true,
            backend: SoccerNeuralLearningBackend::Inline,
            hidden_units: 8,
            ..SoccerNeuralLearningConfig::default()
        },
        seed: 15093,
        ..Default::default()
    };
    let mut previous_snapshot = SoccerMatch::default_11v11(config.clone())
        .learning_snapshot()
        .neural_network
        .expect("initial neural snapshot");
    // A legacy snapshot trained on base + the OLD six-channel whole-field motion block (no
    // jerk, no belief tail). Migration must interleave two zero jerk channels into each
    // entity's motion slot (6 → 8 channels) and zero-pad the appended belief tail.
    let previous_dim = SOCCER_NEURAL_FIELD_MOTION_TAIL_START_V1;
    assert_eq!(previous_dim, 330);
    assert!(SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&previous_dim));
    let removed_weights = previous_snapshot
        .layers
        .first()
        .map(|layer| layer.weights.len())
        .unwrap_or(0)
        .saturating_mul(SOCCER_NEURAL_FEATURE_DIM - previous_dim);
    previous_snapshot.input_dim = previous_dim;
    previous_snapshot.parameter_count = previous_snapshot
        .parameter_count
        .saturating_sub(removed_weights);
    for row in &mut previous_snapshot.layers[0].weights {
        row.truncate(previous_dim);
    }
    previous_snapshot.layers[0].weights[0][SOCCER_NEURAL_BASE_FEATURE_DIM] = 0.135_79;
    previous_snapshot.layers[0].weights[0][previous_dim - 1] = 0.975_31;

    let resumed = SoccerMatch::default_11v11(config)
        .with_neural_network_snapshot(previous_snapshot)
        .expect("resume previous full neural snapshot");
    let resumed_snapshot = resumed
        .learning_snapshot()
        .neural_network
        .expect("resumed neural snapshot");

    assert_eq!(resumed_snapshot.input_dim, SOCCER_NEURAL_FEATURE_DIM);
    // Entity 0, channel 0 sits at the very start of the motion block — its index is unchanged
    // by the 6→8 interleave.
    assert_eq!(
        resumed_snapshot.layers[0].weights[0][SOCCER_NEURAL_BASE_FEATURE_DIM], 0.135_79,
        "first motion-block weight should remain aligned after jerk interleave"
    );
    // The LAST old motion channel (the final entity's 6th channel) is remapped from its old
    // 6-channel slot to its new 8-channel slot: base + entity*8 + channel.
    let last_old_offset = previous_dim - 1 - SOCCER_NEURAL_BASE_FEATURE_DIM;
    let last_entity = last_old_offset / SOCCER_NEURAL_FIELD_MOTION_PER_PLAYER_V1;
    let last_channel = last_old_offset % SOCCER_NEURAL_FIELD_MOTION_PER_PLAYER_V1;
    let last_new_idx = SOCCER_NEURAL_BASE_FEATURE_DIM
        + last_entity * SOCCER_NEURAL_FIELD_MOTION_PER_PLAYER
        + last_channel;
    assert_eq!(
        resumed_snapshot.layers[0].weights[0][last_new_idx], 0.975_31,
        "last old motion-block weight should be remapped (not shifted/lost) by the jerk interleave"
    );
    // The two NEW jerk channels of entity 0 (channels 6 and 7 of its 8-channel slot) start neutral.
    assert_eq!(
        resumed_snapshot.layers[0].weights[0][SOCCER_NEURAL_BASE_FEATURE_DIM + 6],
        0.0,
        "new jerk.x channel should start neutral after migration"
    );
    assert_eq!(
        resumed_snapshot.layers[0].weights[0][SOCCER_NEURAL_BASE_FEATURE_DIM + 7],
        0.0,
        "new jerk.y channel should start neutral after migration"
    );
    // The appended belief tail (right after the jerk-augmented motion block) starts neutral.
    assert_eq!(
        resumed_snapshot.layers[0].weights[0]
            [SOCCER_NEURAL_FEATURE_BELIEF_BALL_POSITION_CONFIDENCE],
        0.0,
        "new belief-tail input should start neutral for a legacy six-channel-motion snapshot"
    );
}

#[test]
fn neural_learning_trains_on_threaded_backend() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.4,
        max_human_players: 0,
        neural_learning: SoccerNeuralLearningConfig {
            enabled: true,
            backend: SoccerNeuralLearningBackend::Threaded,
            train_every_ticks: 1,
            batch_size: 8,
            max_batches_per_tick: 2,
            hidden_units: 8,
            ..SoccerNeuralLearningConfig::default()
        },
        seed: 15072,
        ..Default::default()
    })
    .with_team_policies(SoccerTeamQPolicies::new(SoccerQPolicyOptions::default()));

    for _ in 0..4 {
        sim.run_time_step();
    }
    for _ in 0..40 {
        if let Some(learner) = &mut sim.neural_learner {
            learner.drain_results();
        }
        if sim.learning_snapshot().neural_learning_training_steps > 0 {
            break;
        }
        thread::sleep(Duration::from_millis(2));
    }

    let learning = sim.learning_snapshot();
    assert!(learning.neural_learning_enabled);
    assert_eq!(learning.neural_learning_backend, "threaded");
    assert!(learning.neural_learning_training_steps > 0);
    assert!(learning.neural_learning_samples > 0);
    assert!(learning.neural_learning_parameter_count > 0);
    assert!(learning.neural_learning_last_loss.is_some());
    assert!(sim.team_policy_artifact().learning.neural_network.is_some());

    sim.drain_neural_learning(Duration::from_millis(50));
    let artifact = sim.team_policy_artifact();
    let snapshot = artifact
        .learning
        .neural_network
        .as_ref()
        .expect("threaded neural snapshot");
    assert_eq!(
        snapshot.parameter_count,
        artifact.learning.neural_learning_parameter_count
    );
    assert_eq!(snapshot.input_dim, SOCCER_NEURAL_FEATURE_DIM);
    assert!(!snapshot.layers.is_empty());
    assert!(snapshot
        .layers
        .iter()
        .all(|layer| !layer.weights.is_empty()));
    let value = serde_json::to_value(&artifact).expect("team artifact json");
    assert!(
        value["learning"]["neuralNetwork"]["layers"]
            .as_array()
            .unwrap()
            .len()
            > 0
    );
}

#[test]
fn live_gameplay_defaults_keep_online_learning_off_and_neural_inference_ready() {
    let config = MatchConfig::live_gameplay();

    assert_eq!(config.dt_seconds, DEFAULT_DT_SECONDS);
    assert_eq!(config.duration_seconds, DEFAULT_DURATION_SECONDS);
    assert_eq!(config.total_ticks(), 9_000);
    assert_eq!(config.human_slots(), 4);
    assert!(!config.learning_enabled);
    assert!(!config.learning_logging_enabled);
    assert_eq!(
        config.learning_interval_ticks,
        LIVE_GAMEPLAY_POLICY_LEARNING_INTERVAL_TICKS
    );
    assert_eq!(
        config.policy_train_max_transitions_per_tick,
        LIVE_GAMEPLAY_POLICY_TRAIN_MAX_TRANSITIONS_PER_TICK
    );
    assert!(!config.full_game_learning_enabled);
    assert!(config.formation_lp_enabled);
    assert!(config.local_mpc_enabled);
    assert_eq!(
        config.local_mpc_max_players_per_team,
        DEFAULT_LOCAL_MPC_MAX_PLAYERS_PER_TEAM
    );
    assert!(config.local_mpc_max_players_per_team <= SOCCER_MATCH_TEAM_PLAYER_COUNT);
    assert!(config.mpc.tier2_player_enabled);
    assert!(config.mpc.reconcile_enabled);
    assert!(config.mpc.field_aware_enabled);
    assert_eq!(config.mpc.player_horizon, 45);
    assert!(config.mpc.player_horizon <= 60);
    assert!(config.mpc.active_radius_yards > 0.0);
    assert!(config.mpc.active_radius_yards <= 14.0);
    assert!(config.mpc.latent_objective_enabled);
    assert!(config.mpc.latent_learning_rate > 0.0);
    assert!(config.mpc.latent_learning_rate <= 1.0);
    assert!(config.mpc.latent_reference_bias_yards > 0.0);
    assert!(config.mpc.latent_weight_boost > 0.0);
    assert!(config.neural_learning.enabled);
    assert_eq!(
        config.neural_learning.backend,
        SoccerNeuralLearningBackend::Threaded
    );
    assert_eq!(
        config.neural_learning.train_every_ticks,
        LIVE_GAMEPLAY_NEURAL_TRAIN_EVERY_TICKS
    );
    assert_eq!(config.neural_learning.max_batches_per_tick, 1);
    assert_eq!(
        config.neural_learning.marl_algorithm,
        SoccerMarlAlgorithm::Mappo
    );
    assert_eq!(
        config.neural_learning.marl_team_reward_weight,
        DEFAULT_SOCCER_MARL_TEAM_REWARD_WEIGHT
    );
    assert_eq!(
        config.neural_learning.marl_intermediate_reward_weight,
        DEFAULT_SOCCER_MARL_INTERMEDIATE_REWARD_WEIGHT
    );
    assert_eq!(
        config.neural_learning.mappo_clip_epsilon,
        DEFAULT_SOCCER_MAPPO_CLIP_EPSILON
    );
    assert_eq!(
        config.neural_learning.mappo_team_reward_share,
        DEFAULT_SOCCER_MAPPO_TEAM_REWARD_SHARE
    );
    assert!(config.adversarial_embedding_exploitation_enabled);
    assert!(config.opponent_belief_enabled);
    // Synergy must be ACTIVE in real games, not just trained-and-ignored: the
    // neural value/actor blend into MDP/POMDP action selection, and the trained
    // critic couples back to the LP formation solver.
    assert_eq!(config.neural_blend.mode, SoccerNeuralBlendMode::Additive);
    assert!(config.neural_blend.actor_critic);
    assert!(config.neural_blend.mcts_enabled);
    assert_eq!(config.neural_blend.mcts_simulations, 8);
    assert_eq!(config.neural_blend.mcts_candidates, 4);
    assert_eq!(config.neural_blend.mcts_depth, 1);
    assert!(config.neural_learning.lp_coupling_enabled);
}

