#[test]
fn loose_ball_fifty_fifty_duel_is_labeled_and_rewarded() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 1509,
        ..Default::default()
    });
    let home = 5;
    let away = 11;
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.ball.velocity = Vec2::zero();
    for player in &mut sim.players {
        player.position = match player.team {
            Team::Home => Vec2::new(10.0, 20.0 + player.id as f64),
            Team::Away => Vec2::new(70.0, 80.0 + player.id as f64),
        };
        player.velocity = Vec2::zero();
    }
    sim.players[home].position = Vec2::new(38.0, 60.0);
    sim.players[home].velocity = Vec2::new(1.0, 0.0);
    sim.players[away].position = Vec2::new(42.0, 60.0);
    sim.players[away].velocity = Vec2::new(-1.0, 0.0);
    let before = WorldSnapshot::from_match(&sim);

    assert_eq!(loose_ball_fifty_fifty_duel(&before), Some((home, away)));

    let mut chaser = sim.players[home].clone();
    let mut rng = mulberry32(1509);
    let intent = chaser.run_time_step(&before, None, None, &mut rng);
    match intent.action {
        SoccerAction::MoveTo(target) => assert!(target.distance(sim.ball.position) < 0.01),
        other => panic!("expected 50:50 recovery move, got {other:?}"),
    }
    let decision = chaser.last_decision.as_ref().expect("50:50 decision");
    assert_eq!(decision.action, "recover");
    assert_eq!(decision.operation_order[0], "fifty-fifty-duel");
    assert_eq!(decision.action_options[0].label, "fifty-fifty-duel");

    sim.players[home].position = Vec2::new(39.5, 60.0);
    let after = WorldSnapshot::from_match(&sim);
    let reward = soccer_transition_reward(
        &sim.players[home],
        &test_decision_trace(&before, home, "recover"),
        &before,
        &after,
        0,
        0,
        0,
        0,
        false,
    );
    assert!(reward > 0.8, "50:50 contest reward: {reward}");
}

#[test]
fn untargeted_long_ball_duel_records_projected_drop_zone_recovery() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 1510,
        ..Default::default()
    });
    let home_runner = 8;
    let away_defender = 13;
    park_players_except(&mut sim, &[home_runner, away_defender]);
    sim.tick = 18;
    sim.clock_seconds = 1.8;
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 50.0);
    sim.ball.velocity = Vec2::new(0.0, 18.0);
    sim.ball.altitude_yards = 6.0;
    sim.ball.last_touch_team = Some(Team::Home);
    sim.ball
        .record_decision(sim.tick, "route-one", Some(BALL_AGENT_ID));

    let snapshot = WorldSnapshot::from_match(&sim);
    let drop_zone = snapshot
        .loose_long_ball_recovery_target()
        .expect("route-one long ball should expose a projected drop zone");
    sim.players[home_runner].position = Vec2::new(drop_zone.x - 4.0, drop_zone.y);
    sim.players[home_runner].velocity = Vec2::zero();
    sim.players[away_defender].position = Vec2::new(drop_zone.x + 4.0, drop_zone.y);
    sim.players[away_defender].velocity = Vec2::zero();
    let snapshot = WorldSnapshot::from_match(&sim);
    let drop_zone = snapshot
        .loose_long_ball_recovery_target()
        .expect("route-one long ball should remain projected after player placement");

    assert_eq!(
        loose_ball_fifty_fifty_duel(&snapshot),
        Some((home_runner, away_defender)),
        "untargeted long balls should be labeled as 50:50 contests at the projected landing zone"
    );

    let mut defender = sim.players[away_defender].clone();
    let intent = defender.run_time_step(&snapshot, None, None, &mut SeededRandom::new(1510));
    let SoccerAction::MoveTo(target) = intent.action else {
        panic!("long-ball defender should contest the drop zone, got {intent:?}");
    };
    assert!(
        target.x.is_finite() && target.y.is_finite(),
        "long-ball defender should produce a finite recovery target: {target:?}"
    );
    assert!(
        target.y >= drop_zone.y,
        "long-ball defender should recover goal-side or at the projected drop zone: target={target:?} drop={drop_zone:?}"
    );
    let decision = defender
        .last_decision
        .as_ref()
        .expect("long-ball recovery decision");
    assert!(!decision.action.is_empty());
    assert!(!decision.operation_order.is_empty());
    assert!(!decision.action_options.is_empty());
}

#[test]
fn loose_ball_race_reward_prefers_recovering_favored_free_ball() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 1511,
        ..Default::default()
    });
    let runner = 6;
    let opponent = 12;
    let ball_position = Vec2::new(40.0, 60.0);
    park_players_except(&mut sim, &[runner, opponent]);
    sim.ball.holder = None;
    sim.ball.position = ball_position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[runner].position = Vec2::new(40.0, 56.0);
    sim.players[runner].velocity = Vec2::new(0.0, 3.0);
    sim.players[opponent].position = Vec2::new(40.0, 71.0);
    sim.players[opponent].velocity = Vec2::zero();
    let before = WorldSnapshot::from_match(&sim);
    let before_obs = before.observation_for(runner);
    assert!(before_obs.loose_ball);
    assert!(before_obs.loose_ball_team_time_advantage_seconds > 0.35);

    let mut recovered = before.clone();
    recovered.set_player_position(runner, ball_position);
    recovered.ball.position = ball_position;
    recovered.ball.holder = Some(runner);
    recovered.ball.last_touch_team = Some(Team::Home);

    let mut lost = before.clone();
    lost.set_player_position(opponent, ball_position);
    lost.ball.position = ball_position;
    lost.ball.holder = Some(opponent);
    lost.ball.last_touch_team = Some(Team::Away);

    let recover_decision = test_decision_trace(&before, runner, "recover");
    let hold_decision = test_decision_trace(&before, runner, "hold");
    let recover_reward = soccer_transition_reward(
        &sim.players[runner],
        &recover_decision,
        &before,
        &recovered,
        0,
        0,
        0,
        0,
        false,
    );
    let hold_reward = soccer_transition_reward(
        &sim.players[runner],
        &hold_decision,
        &before,
        &recovered,
        0,
        0,
        0,
        0,
        false,
    );
    let lost_reward = soccer_transition_reward(
        &sim.players[runner],
        &recover_decision,
        &before,
        &lost,
        0,
        0,
        0,
        0,
        false,
    );

    assert!(
        recover_reward > hold_reward + 0.45,
        "recover reward {recover_reward} should beat hold reward {hold_reward}"
    );
    assert!(
        recover_reward > lost_reward + 2.0,
        "recover reward {recover_reward} should strongly beat lost-race reward {lost_reward}"
    );
    assert!(
        lost_reward < 0.0,
        "favored lost race should be penalized: {lost_reward}"
    );
}

