#[test]
fn self_play_training_request_uses_initial_learned_params() {
    let seed_artifact = train_soccer_team_policies_from_self_play(
        MatchConfig {
            duration_seconds: 0.2,
            seed: 1534,
            ..Default::default()
        },
        1,
        SoccerQPolicyOptions {
            alpha: 0.17,
            gamma: 0.91,
            ..Default::default()
        },
    );
    let mut seed_params = SoccerSelfPlayLearnedParams::from_training_artifact(&seed_artifact);
    seed_params.tactical_learning.attack_flank_lane_weight = 0.73;
    seed_params.tactical_learning.defense_contract_delta_weight = 0.84;
    let mut neural_seed_config = MatchConfig {
        duration_seconds: 0.2,
        seed: 1537,
        learning_enabled: true,
        learning_logging_enabled: false,
        max_human_players: 0,
        neural_learning: SoccerNeuralLearningConfig {
            enabled: true,
            backend: SoccerNeuralLearningBackend::Inline,
            learning_rate: 0.0,
            train_every_ticks: 10_000,
            batch_size: 4,
            max_batches_per_tick: 1,
            hidden_units: 8,
            ..SoccerNeuralLearningConfig::default()
        },
        ..Default::default()
    };
    let mut neural_snapshot = SoccerMatch::default_11v11(neural_seed_config.clone())
        .learning_snapshot()
        .neural_network
        .expect("initial neural snapshot");
    neural_snapshot.layers[0].weights[0][0] = 0.4321;
    neural_snapshot.layers[0].biases[0] = -0.1234;
    seed_params.neural_network = Some(neural_snapshot.clone());
    neural_seed_config.neural_learning.enabled = false;

    let mut session = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 0.2,
        seed: 1535,
        ..neural_seed_config
    });
    let response = session
        .train_self_play_team_policy(SoccerSelfPlayTrainingRequest {
            episodes: 1,
            minutes: Some(0.2 / 60.0),
            period_count: None,
            period_break_recovery_seconds: None,
            dt_seconds: None,
            learning_interval_ticks: None,
            formation_lp_enabled: None,
            local_mpc_enabled: None,
            local_mpc_max_players_per_team: None,
            seed: Some(1536),
            options: None,
            tactical_learning: None,
            spacing: None,
            initial_learned_params: Some(seed_params.clone()),
            artifact_path: None,
            learned_params_path: None,
            import_into_session: false,
        })
        .expect("self-play training response");

    assert_eq!(response.artifact.options.alpha, seed_params.options.alpha);
    assert_eq!(
        response.artifact.tactical_learning.attack_flank_lane_weight,
        0.73
    );
    assert_eq!(
        response
            .artifact
            .config
            .tactical_learning
            .defense_contract_delta_weight,
        0.84
    );
    assert!(response.artifact.home_entries.len() >= seed_params.home_entries.len());
    assert!(response.artifact.away_entries.len() >= seed_params.away_entries.len());
    assert!(response.artifact.config.neural_learning.enabled);
    let restored_neural_snapshot = response
        .learned_params
        .neural_network
        .expect("returned neural snapshot");
    assert_eq!(
        restored_neural_snapshot.layers[0].weights[0][0],
        neural_snapshot.layers[0].weights[0][0]
    );
    assert_eq!(
        restored_neural_snapshot.layers[0].biases[0],
        neural_snapshot.layers[0].biases[0]
    );
}

#[test]
fn goal_reward_divides_pool_across_recent_attacking_chain() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 154,
        ..Default::default()
    });
    sim.tick = 33;
    sim.possession_chain.clear();
    sim.possession_chain.push_back(5);
    sim.possession_chain.push_back(7);
    sim.possession_chain.push_back(12);

    sim.record_goal_rewards(Team::Home, Some(9));

    let reward_for = |player_id| {
        sim.reward_events
            .iter()
            .filter(|event| event.player_id == player_id)
            .map(|event| event.amount)
            .sum::<f64>()
    };
    let attacking_total = [5, 7, 9]
        .into_iter()
        .map(|player_id| reward_for(player_id))
        .sum::<f64>();
    assert_eq!(reward_for(9), 30.0);
    assert_eq!(reward_for(7), 30.0);
    assert_eq!(reward_for(5), 20.0);
    assert!((attacking_total - 80.0).abs() < 1e-9);
    assert!(attacking_total < GOAL_REWARD_POINTS);
    assert_eq!(reward_for(12), 0.0);
    assert!(reward_for(7) > reward_for(5));
    assert!(reward_for(5) > 0.0);
    assert!(sim
        .reward_events
        .iter()
        .any(|event| { event.tick == 33 && event.player_id == 9 && event.amount == 30.0 }));
}

#[test]
fn direct_turnover_goal_distributes_reduced_reward_pool() {
    // A goal where only a single scoring-team player touched the ball since
    // winning it from the opponent is a direct turnover: it distributes only the
    // reduced 30-point pool, while a built-up finish keeps the normal chain pool.
    let scoring_total = |scoring_touches: &[usize]| -> f64 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: 0.1,
            seed: 154,
            ..Default::default()
        });
        sim.tick = 40;
        sim.record_possession_touch(12);
        for &id in scoring_touches {
            sim.record_possession_touch(id);
        }
        assert_eq!(sim.possession_chain_previous_touch_team, Some(Team::Away));
        sim.reward_events.clear();
        sim.record_goal_rewards(Team::Home, Some(9));
        sim.reward_events
            .iter()
            .filter(|event| sim.players[event.player_id].team == Team::Home)
            .map(|event| event.amount)
            .sum::<f64>()
    };

    let turnover_total = scoring_total(&[9]);
    let buildup_total = scoring_total(&[5, 7, 9]);

    assert!((turnover_total - DIRECT_TURNOVER_GOAL_REWARD_POINTS).abs() < 1e-9);
    assert!((buildup_total - 80.0).abs() < 1e-9);
    assert!(
        turnover_total < buildup_total,
        "a direct-turnover goal must distribute less than a built-up goal"
    );
}

#[test]
fn direct_turnover_goal_distributes_only_thirty_points() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 155,
        ..Default::default()
    });
    let scorer = 9;
    let support = 7;
    let deeper_support = 5;
    let opponent = 12;
    assert_eq!(sim.players[scorer].team, Team::Home);
    assert_eq!(sim.players[support].team, Team::Home);
    assert_eq!(sim.players[deeper_support].team, Team::Home);
    assert_eq!(sim.players[opponent].team, Team::Away);

    sim.tick = 34;
    sim.record_possession_touch(opponent);
    sim.record_possession_touch(scorer);
    sim.record_possession_touch(scorer);
    assert_eq!(sim.possession_chain_previous_touch_team, Some(Team::Away));
    sim.reward_events.clear();

    sim.record_goal_rewards(Team::Home, Some(scorer));

    let reward_for = |player_id| {
        sim.reward_events
            .iter()
            .filter(|event| event.player_id == player_id)
            .map(|event| event.amount)
            .sum::<f64>()
    };
    let attacking_total = [deeper_support, support, scorer]
        .into_iter()
        .map(|player_id| reward_for(player_id))
        .sum::<f64>();
    assert_eq!(reward_for(scorer), DIRECT_TURNOVER_GOAL_REWARD_POINTS);
    assert_eq!(reward_for(support), 0.0);
    assert_eq!(reward_for(deeper_support), 0.0);
    assert_eq!(reward_for(opponent), 0.0);
    assert!((attacking_total - DIRECT_TURNOVER_GOAL_REWARD_POINTS).abs() < 1e-9);
    assert!(attacking_total < GOAL_REWARD_POINTS);
}

#[test]
fn direct_turnover_goal_requires_scorer_to_be_only_scoring_touch() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 159,
        ..Default::default()
    });
    let scorer = 9;
    let support = 7;
    let opponent = 12;

    sim.tick = 35;
    sim.record_possession_touch(opponent);
    sim.record_possession_touch(support);
    sim.record_possession_touch(scorer);
    assert_eq!(sim.possession_chain_previous_touch_team, Some(Team::Away));
    sim.reward_events.clear();

    sim.record_goal_rewards(Team::Home, Some(scorer));

    let reward_for = |player_id| {
        sim.reward_events
            .iter()
            .filter(|event| event.player_id == player_id)
            .map(|event| event.amount)
            .sum::<f64>()
    };
    assert_eq!(reward_for(scorer), GOAL_CHAIN_REWARD_PATTERN[0]);
    assert_eq!(reward_for(support), GOAL_CHAIN_REWARD_PATTERN[1]);
    assert!(reward_for(scorer) + reward_for(support) > DIRECT_TURNOVER_GOAL_REWARD_POINTS);
}

fn push_contextual_goal_credit_history(sim: &mut SoccerMatch, before: &WorldSnapshot) {
    for (tick, player_id, action, target, target_player) in [
        (112, 5, "dribble", Vec2::new(45.0, 76.0), None),
        (116, 7, "pass", Vec2::new(43.0, 91.0), Some(9)),
        (119, 9, "shoot", Vec2::new(40.0, 120.0), None),
    ] {
        let mut after = before.clone();
        after.ball.position = target;
        after.ball.velocity = Vec2::new(0.8, 18.0);
        after.ball.holder = target_player;
        let mut decision = test_decision_trace(before, player_id, action);
        decision.action_target = Some(AgentActionTargetTrace {
            point: Some(target),
            player_id: target_player,
            grid: Some(pitch_grid_address(
                target,
                before.field_width,
                before.field_length,
            )),
            facing: facing_bucket_from_vector(
                target
                    - before
                        .player_position(player_id)
                        .unwrap_or(before.ball.position),
            ),
            dribble_touch: None,
        });
        decision.observation.expected_pass_completion = 0.92;
        decision.observation.expected_aerial_pass_completion = 0.78;
        decision.observation.floor_pass_lane_score = 0.88;
        decision.observation.best_pass_receiver_openness = 0.84;
        decision.observation.forward_dribble_space_yards = 12.0;
        decision.observation.immediate_dispossession_risk = 0.12;
        decision.observation.shot_on_frame_probability = 0.82;
        decision.observation.shot_beat_goalkeeper_probability = 0.58;
        decision.observation.shot_block_probability = 0.10;
        decision.observation.perceived_pressure = 0.42;
        decision.observation.opponent_goal_angle_degrees = 31.0;
        let team = sim.players[player_id].team;
        let role = sim.players[player_id].role;
        let decision_context = soccer_decision_context_for(
            player_id,
            team,
            &decision.action,
            decision.action_target.as_ref(),
            before,
            &after,
        );
        sim.recent_learning_history
            .push_back(SoccerLearningTransition {
                tick,
                player_id,
                team,
                role,
                state: decision.mdp_state,
                observation: decision.observation,
                belief: decision.belief,
                action: decision.action,
                action_target: decision.action_target,
                decision_context,
                tactical_trace: SoccerTacticalLearningTrace::default(),
                reward: 0.4,
                next_state: after.mdp_state_for_player(player_id),
                next_observation: after.observation_for(player_id),
                done: false,
            });
    }
}

#[test]
fn goal_reward_contextualizes_recent_attacking_decisions() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 157,
        ..Default::default()
    });
    sim.tick = 120;
    let before = WorldSnapshot::from_match(&sim);
    push_contextual_goal_credit_history(&mut sim, &before);

    sim.record_goal_rewards(Team::Home, Some(9));

    let total = sim
        .deferred_reward_transitions
        .iter()
        .filter(|transition| transition.team == Team::Home)
        .map(|transition| transition.reward)
        .sum::<f64>();
    assert!((total - GOAL_REWARD_POINTS).abs() < 1e-9);
    assert_eq!(
        sim.deferred_reward_transitions
            .iter()
            .filter(|transition| transition.team == Team::Home)
            .count(),
        3
    );
    assert!(sim
        .deferred_reward_transitions
        .iter()
        .any(|transition| transition.action == "pass"
            && transition.decision_context.target_distance_yards > 0.0));
    assert!(sim
        .deferred_reward_transitions
        .iter()
        .any(|transition| transition.action == "shoot" && transition.reward > 0.0));
    assert!(!sim
        .reward_events
        .iter()
        .any(|event| event.tick == sim.tick && (event.amount - 30.0).abs() < 1e-9));
}

