#[test]
fn tracking_dataset_converts_pass_to_learning_transition_and_policy() {
    let tracking = sample_tracking_pass_dataset();
    let dataset = tracking.to_learning_dataset().expect("tracking conversion");
    assert_eq!(dataset.transitions.len(), 3);

    let passer = dataset
        .transitions
        .iter()
        .find(|t| t.player_id == 0)
        .expect("passer transition");
    assert_eq!(passer.action, "pass");
    assert!(passer.reward.is_finite());
    let passer_position = tracking.frames[0]
        .players
        .iter()
        .find(|player| player.id == 0)
        .expect("tracking passer")
        .position;
    let passer_grid = pitch_grid_address(
        passer_position,
        tracking.config.field_width_yards,
        tracking.config.field_length_yards,
    );
    assert_eq!(passer.state.player_grid, passer_grid);
    assert_eq!(passer.observation.player_grid, passer_grid);
    assert_eq!(
        passer_grid.fine.parent_id,
        Some(passer_grid.tactical.id),
        "imported tracking states should retain the fine -> tactical grid parent"
    );
    assert_eq!(
        passer_grid.tactical.parent_id,
        Some(passer_grid.macro_zone.id),
        "imported tracking states should retain the tactical -> macro grid parent"
    );
    assert_eq!(
        passer_grid.macro_zone.parent_id,
        Some(passer_grid.whole_pitch.id),
        "imported tracking states should retain the macro -> whole-pitch grid parent"
    );
    let action_target = passer
        .action_target
        .as_ref()
        .expect("tracking pass target trace");
    let target_position = tracking.frames[1]
        .players
        .iter()
        .find(|player| player.id == 1)
        .expect("tracking target player")
        .position;
    assert_eq!(action_target.player_id, Some(1));
    assert_eq!(action_target.point, Some(target_position));
    assert_eq!(
        action_target.grid.expect("tracking target grid").fine.id,
        pitch_grid_address(
            target_position,
            tracking.config.field_width_yards,
            tracking.config.field_length_yards
        )
        .fine
        .id
    );

    let policy = train_soccer_q_policy_from_tracking(&tracking, SoccerQPolicyOptions::default())
        .expect("tracking policy");
    let state = SoccerQStateKey::from_transition(passer);
    // Player pitch-grid cells are no longer part of the Q-key (they remain on
    // the MDP state / observation, asserted above, and feed the neural nets).
    assert!(policy.q_value(&state, "pass").is_some());
    // (Per-grid-cell target learning was removed for perf; the action-value policy and the
    // transition's target-grid TRACE are still asserted above.)

    let artifact =
        soccer_policy_artifact_from_learning_dataset(&dataset, SoccerQPolicyOptions::default());
    assert_eq!(artifact.transition_count, 3);
    assert!(!artifact.entries.is_empty());
}

#[test]
fn tracking_dataset_imports_all_visible_players_as_learning_samples() {
    let mut tracking = sample_tracking_pass_dataset();
    tracking.source = "unit-pass-all-visible-agents".to_string();
    tracking.frames[0].players[1].position = Vec2::new(48.0, 78.0);
    tracking.frames[0].players[1].velocity = Some(Vec2::new(-1.0, 4.0));
    tracking.frames[1].players[1].position = Vec2::new(44.0, 82.0);
    tracking.frames[1].players[1].velocity = Some(Vec2::new(-4.0, 4.0));
    tracking.frames[0].players[2].position = Vec2::new(58.0, 78.0);
    tracking.frames[0].players[2].velocity = Some(Vec2::new(-1.5, 0.5));
    tracking.frames[1].players[2].position = Vec2::new(56.5, 78.5);
    tracking.frames[1].players[2].velocity = Some(Vec2::new(-1.5, 0.5));

    let dataset = tracking
        .to_learning_dataset()
        .expect("tracking conversion should train every visible player");
    assert_eq!(
        dataset.transitions.len(),
        3,
        "every player visible in both tracking frames should produce a learning transition"
    );

    let passer = dataset
        .transitions
        .iter()
        .find(|transition| transition.player_id == 0)
        .expect("passer transition");
    let runner = dataset
        .transitions
        .iter()
        .find(|transition| transition.player_id == 1)
        .expect("off-ball runner transition");
    let defender = dataset
        .transitions
        .iter()
        .find(|transition| transition.player_id == 2)
        .expect("defender transition");

    assert_eq!(passer.action, "pass");
    assert_eq!(runner.action, "run-in-behind");
    assert_eq!(defender.action, "defend");
    assert!(!runner.observation.has_ball);
    assert!(runner.observation.visible_ball);
    assert!(runner.observation.visible_teammates > 0);
    assert!(defender.observation.visible_opponents > 0);
    assert!(
        defender.observation.nearest_opponent_distance.is_finite(),
        "defensive tracking samples should retain POMDP pressure geometry"
    );

    for transition in [&passer, &runner, &defender] {
        assert!(transition.reward.is_finite());
        assert!(transition.state.player_grid.fine.id > 0);
        assert_eq!(
            transition.state.player_grid.fine.id,
            transition.observation.player_grid.fine.id
        );
        assert_eq!(
            transition.next_state.player_grid.fine.id,
            transition.next_observation.player_grid.fine.id
        );
        assert!(
            (transition.belief.pressure
                - belief_from_observation(&transition.observation).pressure)
                .abs()
                < 1e-12
        );
        assert_eq!(
            transition.decision_context.tracking_confidence, 1.0,
            "default-confidence tracking rows should still annotate imported samples"
        );
    }

    let policy = train_soccer_q_policy(&dataset, SoccerQPolicyOptions::default());
    for transition in [&passer, &runner, &defender] {
        let state = SoccerQStateKey::from_transition(transition);
        assert!(
            policy.q_value(&state, &transition.action).is_some(),
            "policy should learn the imported {} action for player {}",
            transition.action,
            transition.player_id
        );
    }
}

