#[test]
fn tracking_dataset_uses_imported_player_skills_in_learning_state() {
    let mut tracking = sample_tracking_pass_dataset();
    let mut skills = SkillProfile::default();
    skills.top_speed = 9.4;
    skills.acceleration = 8.9;
    skills.shooting = 8.6;
    skills.passing = 8.8;
    skills.passing_completion_rate = 9.2;
    skills.first_touch = 7.7;
    skills.crossing_left = 4.1;
    skills.crossing_right = 8.7;
    skills.defending = 3.3;
    skills.defensive_tracking = 5.2;
    skills.vision = 9.1;
    for frame in &mut tracking.frames {
        frame
            .players
            .iter_mut()
            .find(|player| player.id == 0)
            .expect("tracking passer")
            .skills = Some(skills.clone());
    }

    let json = serde_json::to_string(&tracking).expect("tracking json");
    let parsed = soccer_tracking_dataset_from_json(&json).expect("parse tracking");
    let dataset = parsed.to_learning_dataset().expect("tracking conversion");
    let passer = dataset
        .transitions
        .iter()
        .find(|transition| transition.player_id == 0)
        .expect("passer transition");
    assert_eq!(passer.observation.skill_top_speed, 9.4);
    assert_eq!(passer.observation.skill_acceleration, 8.9);
    assert_eq!(passer.observation.skill_shooting, 8.6);
    assert_eq!(passer.observation.skill_passing, 8.8);
    assert_eq!(passer.observation.skill_passing_completion_rate, 9.2);
    assert_eq!(passer.observation.skill_first_touch, 7.7);
    assert_eq!(passer.observation.skill_crossing_left, 4.1);
    assert_eq!(passer.observation.skill_crossing_right, 8.7);
    assert_eq!(passer.observation.skill_defending, 3.3);
    assert_eq!(passer.observation.skill_defensive_tracking, 5.2);
    assert_eq!(passer.observation.skill_vision, 9.1);
    // Skills were removed from the discrete Q-key; they now reach the learner
    // only through the neural feature vector. Assert that the imported skills
    // populate the right feature slots and stay discriminative high-vs-low.
    let features = soccer_neural_transition_features(passer);
    assert_eq!(
        features[SOCCER_NEURAL_FEATURE_VISION_SKILL],
        soccer_neural_bin(skill_bucket(skills.vision), 5.0)
    );
    assert_eq!(
        features[SOCCER_NEURAL_FEATURE_SHOOTING_SKILL],
        soccer_neural_bin(skill_bucket(skills.shooting), 5.0)
    );
    assert_eq!(
        features[SOCCER_NEURAL_FEATURE_PASSING_SKILL],
        soccer_neural_bin(skill_bucket(skills.passing), 5.0)
    );
    assert_eq!(
        features[SOCCER_NEURAL_FEATURE_FIRST_TOUCH_SKILL],
        soccer_neural_bin(skill_bucket(skills.first_touch), 5.0)
    );

    let mut lower_vision = passer.clone();
    lower_vision.observation.skill_vision = 2.1;
    let lower_features = soccer_neural_transition_features(&lower_vision);
    assert!(
        features[SOCCER_NEURAL_FEATURE_VISION_SKILL]
            > lower_features[SOCCER_NEURAL_FEATURE_VISION_SKILL],
        "neural learner should receive a vision distinction across imported players"
    );

    let mut lower_shooting = passer.clone();
    lower_shooting.observation.skill_shooting = 2.4;
    let lower_shooting_features = soccer_neural_transition_features(&lower_shooting);
    assert!(
        features[SOCCER_NEURAL_FEATURE_SHOOTING_SKILL]
            > lower_shooting_features[SOCCER_NEURAL_FEATURE_SHOOTING_SKILL],
        "neural learner should receive a shooting distinction across imported players"
    );

    let mut lower_first_touch = passer.clone();
    lower_first_touch.observation.skill_first_touch = 1.9;
    let lower_first_touch_features = soccer_neural_transition_features(&lower_first_touch);
    assert!(
        features[SOCCER_NEURAL_FEATURE_FIRST_TOUCH_SKILL]
            > lower_first_touch_features[SOCCER_NEURAL_FEATURE_FIRST_TOUCH_SKILL],
        "neural learner should receive a first-touch distinction across imported players"
    );
}

