#[test]
fn player_collision_resolution_separates_body_overlap() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    // Isolate the two coincident bodies: park everyone else out to the corners so this
    // stays a clean 2-body separation (the kickoff formation otherwise leaves a third
    // player on the centre spot, and the single-pass resolver cannot fully settle a
    // 3-body pile in one sweep — that order-sensitive residual is a separate concern).
    park_players_except(&mut sim, &[0, 1]);
    sim.players[0].position = Vec2::new(40.0, 60.0);
    sim.players[1].position = Vec2::new(40.0, 60.0);
    sim.players[0].velocity = Vec2::new(1.0, 0.0);
    sim.players[1].velocity = Vec2::new(-1.0, 0.0);

    sim.resolve_player_collisions();

    let dist = sim.players[0].position.distance(sim.players[1].position);
    assert!(dist >= PLAYER_BODY_RADIUS_YARDS * 2.0 - 1e-6);
}

#[test]
fn agentic_tick_order_is_reproducible_and_disable_flag_is_obsolete() {
    // Live-causal operation order is now state-scored/semantic instead of randomized.
    // The legacy disable flag remains deserializable, but it must no longer change play.
    let run = |disable: bool| -> Vec<f64> {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            seed: 4242,
            disable_tick_order_shuffle: disable,
            learning_enabled: false,
            learning_logging_enabled: false,
            ..MatchConfig::default()
        });
        for _ in 0..240 {
            sim.run_time_step();
        }
        vec![
            sim.score_home as f64,
            sim.score_away as f64,
            sim.ball.position.x,
            sim.ball.position.y,
            sim.players[5].position.x,
            sim.players[5].position.y,
            sim.players[16].position.x,
            sim.players[16].position.y,
        ]
    };
    assert_eq!(
        run(false),
        run(false),
        "agentic order must be reproducible for a fixed seed"
    );
    assert_eq!(
        run(true),
        run(true),
        "legacy disable flag path must remain reproducible"
    );
    assert_eq!(
        run(false),
        run(true),
        "legacy disable flag must not alter live-causal agentic order"
    );
}

#[test]
fn agentic_collision_pileups_are_seed_invariant() {
    // A 3-body pile-up is order-sensitive, so the resolver uses state/contact pressure
    // plus stable ids instead of a random order. Same state should settle identically
    // across seeds, and the legacy disable flag is intentionally a no-op.
    let pile = |seed: u32, disable: bool| -> Vec<f64> {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            seed,
            disable_tick_order_shuffle: disable,
            ..MatchConfig::default()
        });
        park_players_except(&mut sim, &[0, 1, 2]);
        for id in [0usize, 1, 2] {
            sim.players[id].position = Vec2::new(40.0, 60.0);
            sim.players[id].velocity = Vec2::zero();
        }
        sim.resolve_player_collisions();
        [0usize, 1, 2]
            .iter()
            .flat_map(|&id| [sim.players[id].position.x, sim.players[id].position.y])
            .collect()
    };
    assert_eq!(
        pile(1, true),
        pile(7777, true),
        "legacy disabled order path must be seed-invariant"
    );
    assert_eq!(
        pile(1, false),
        pile(7777, false),
        "agentic collision order must not be seed-derived"
    );
    assert_eq!(
        pile(1, false),
        pile(1, true),
        "legacy disable flag must not alter collision resolution"
    );
}

#[test]
fn loose_ball_contest_is_agentic_and_skill_weighted() {
    let mut winners = std::collections::BTreeSet::new();
    for seed in 0..180 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            seed,
            ..Default::default()
        });
        sim.ball.holder = None;
        sim.ball.position = Vec2::new(40.0, 60.0);
        sim.ball.velocity = Vec2::zero();
        park_players_except(&mut sim, &[0, 11]);
        sim.players[0].position = Vec2::new(39.1, 60.0);
        sim.players[0].velocity = Vec2::zero();
        sim.players[0].skills.first_touch = 1.0;
        sim.players[0].skills.dribbling = 1.0;
        sim.players[0].skills.aggression = 1.0;
        sim.players[11].position = Vec2::new(41.15, 60.0);
        sim.players[11].velocity = Vec2::new(-4.0, 0.0);
        sim.players[11].skills.first_touch = 9.8;
        sim.players[11].skills.dribbling = 9.8;
        sim.players[11].skills.aggression = 9.5;

        winners.insert(sim.nearest_ball_controller().expect("loose-ball winner").0);
    }

    assert_eq!(
        winners,
        [11].into_iter().collect(),
        "loose-ball winner should be caused by reach, closing speed, and skill, not seed"
    );
}

#[test]
