#[test]
fn no_possession_nearest_players_chase_loose_ball() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Away);
    for player in &mut sim.players {
        player.position = match player.team {
            Team::Home => Vec2::new(8.0, 20.0 + player.id as f64),
            Team::Away => Vec2::new(72.0, 80.0 + player.id as f64),
        };
    }
    sim.players[5].position = Vec2::new(38.0, 60.0);
    sim.players[6].position = Vec2::new(42.0, 60.0);
    sim.players[7].position = Vec2::new(64.0, 60.0);

    let snapshot = WorldSnapshot::from_match(&sim);
    // Players 5 and 6 are equally close; player 6 has the better dynamic lane fit
    // to the ball's 12-lane band, so it is the designated retriever.
    let mut chaser = sim.players[6].clone();
    let mut rng = mulberry32(72);
    let intent = chaser.run_time_step(&snapshot, None, None, &mut rng);

    match intent.action {
        SoccerAction::MoveTo(target) => assert!(target.distance(sim.ball.position) < 0.01),
        other => panic!("expected loose-ball recovery move, got {other:?}"),
    }
    assert_eq!(
        chaser
            .last_decision
            .as_ref()
            .expect("decision trace")
            .action,
        "recover"
    );
}

#[test]
fn loose_ball_recovery_uses_agentic_operation_order() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Away);
    for player in &mut sim.players {
        player.position = match player.team {
            Team::Home => Vec2::new(8.0, 20.0 + player.id as f64),
            Team::Away => Vec2::new(72.0, 80.0 + player.id as f64),
        };
    }
    let chaser_id = 5;
    sim.players[chaser_id].position = Vec2::new(38.0, 60.0);
    sim.players[chaser_id].preferences.offensive_mindedness = 0.74;
    sim.players[chaser_id].preferences.defensive_mindedness = 0.42;

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut first_ops = std::collections::BTreeSet::new();
    for seed in 0..160 {
        let mut chaser = sim.players[chaser_id].clone();
        let intent = chaser.run_time_step(&snapshot, None, None, &mut mulberry32(31_500 + seed));
        match intent.action {
            SoccerAction::MoveTo(target) => assert!(target.distance(sim.ball.position) < 0.01),
            other => panic!("primary loose-ball chaser should recover, got {other:?}"),
        }
        let decision = chaser.last_decision.expect("loose-ball decision");
        assert_eq!(decision.action, "recover");
        assert!(decision
            .action_options
            .iter()
            .any(|option| option.label == "recover" && option.legal));
        assert!(decision
            .action_options
            .iter()
            .any(|option| option.label == "hold" && option.legal));
        let first = decision
            .operation_order
            .first()
            .cloned()
            .unwrap_or_default();
        first_ops.insert(first);
    }

    assert!(
        first_ops.contains("recover"),
        "recover should lead the loose-ball operation order from tactical urgency: {first_ops:?}"
    );
    assert_eq!(
        first_ops.len(),
        1,
        "same loose-ball state should not randomize first operation by RNG seed: {first_ops:?}"
    );
}

#[test]
fn carrier_turn_rate_drops_with_speed_and_below_off_ball_agility() {
    // Integrate several ticks of a 180-degree turn. With realistic rotational
    // inertia, the angular acceleration cap limits the first ticks identically
    // regardless of speed; the speed-scaled rate cap separates them as the turn
    // winds up over time.
    let turn = |speed: f64, holder: bool| -> f64 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let id = 5usize;
        sim.players[id].facing_yaw = 0.0; // facing East
        sim.players[id].yaw_rate = 0.0;
        sim.players[id].action_facing = FacingBucket::West; // demand a 180° turn
        sim.players[id].velocity = Vec2::new(0.0, speed); // magnitude is what matters
                                                          // Ball due West in both cases, so the desired heading is the same for
                                                          // the carrier and the off-ball face-the-ball path.
        sim.ball.position = sim.players[id].position - Vec2::new(10.0, 0.0);
        sim.ball.holder = if holder { Some(id) } else { None };
        let before = sim.players[id].facing_yaw;
        for _ in 0..5 {
            sim.update_player_facing_dizziness_energy();
        }
        (sim.players[id].facing_yaw - before).abs()
    };

    let slow_carrier = turn(0.0, true);
    let fast_carrier = turn(40.0, true); // well past top speed => fully capped
    let off_ball = turn(0.0, false);

    assert!(
            fast_carrier < slow_carrier - 1e-6,
            "a sprinting carrier turns less than a near-stationary one: fast={fast_carrier:.3} slow={slow_carrier:.3}"
        );
    assert!(
            slow_carrier < off_ball - 1e-6,
            "even a slow carrier turns less freely than an off-ball player: carrier={slow_carrier:.3} off_ball={off_ball:.3}"
    );
}

#[test]
fn rotational_inertia_makes_reversing_a_spin_take_real_time() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let id = 5usize;
    park_players_except(&mut sim, &[id]);
    sim.players[id].position = Vec2::new(40.0, 60.0);
    sim.players[id].facing_yaw = 0.0; // facing East
    sim.players[id].velocity = Vec2::zero();
    sim.ball.holder = None;
    sim.ball.position = sim.players[id].position + Vec2::new(0.0, -10.0);
    sim.players[id].yaw_rate = 4.5;

    let mut ticks_to_reverse = None;
    for t in 1..=45 {
        sim.update_player_facing_dizziness_energy();
        if sim.players[id].yaw_rate <= -3.2 {
            ticks_to_reverse = Some(t);
            break;
        }
    }

    let ticks = ticks_to_reverse.expect("the spin should eventually reverse");
    assert!(
        ticks >= 6,
        "reversing a saturated spin must take real time; took {ticks} ticks"
    );
}

#[test]
fn player_body_orientation_caps_single_tick_turn_and_tracks_ball_within_run_gait() {
    let dt = 1.0 / 15.0;
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        dt_seconds: dt,
        ..Default::default()
    });
    let id = 5usize;
    park_players_except(&mut sim, &[id]);
    sim.players[id].position = Vec2::new(40.0, 60.0);
    sim.players[id].facing_yaw = 0.0;
    sim.players[id].yaw_rate = 100.0;
    sim.players[id].velocity = Vec2::zero();
    sim.players[id].movement_gait = MovementGait::Stand;
    sim.ball.holder = None;
    let ball_west = sim.players[id].position - Vec2::new(20.0, 0.0);

    sim.players[id].update_body_orientation_dizziness_energy(dt, ball_west, None);

    let max_single_tick_turn = std::f64::consts::PI / 6.0;
    assert!(
        sim.players[id].facing_yaw.abs() <= max_single_tick_turn + 1e-9,
        "even a stale huge yaw_rate must not turn more than 30deg in one 15Hz tick: {:.3}rad",
        sim.players[id].facing_yaw
    );

    sim.players[id].position = Vec2::new(40.0, 60.0);
    sim.players[id].facing_yaw = 0.0;
    sim.players[id].yaw_rate = 0.0;
    sim.players[id].velocity = Vec2::new(6.0, 0.0);
    sim.players[id].movement_gait = MovementGait::Run;
    let ball_north = sim.players[id].position + Vec2::new(0.0, 20.0);
    for _ in 0..45 {
        sim.players[id].update_body_orientation_dizziness_energy(dt, ball_north, None);
    }

    assert!(
        sim.players[id].facing_yaw > 0.50,
        "running off-ball should still rotate toward the ball instead of staring down the run lane: {:.3}rad",
        sim.players[id].facing_yaw
    );
    assert!(
        sim.players[id].facing_yaw <= std::f64::consts::FRAC_PI_2,
        "run gait should keep ball-facing within the physical forward cone: {:.3}rad",
        sim.players[id].facing_yaw
    );
}

#[test]
fn held_ball_stays_in_front_of_carrier_facing_not_velocity() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.holder = Some(5);
    sim.players[5].position = Vec2::new(40.0, 60.0);
    // Facing the +x touchline, but actually moving +y: the ball must stay in front of
    // the BODY (+x), not flip to the direction of travel.
    sim.players[5].facing_yaw = 0.0;
    sim.players[5].velocity = Vec2::new(0.0, 6.0);

    sim.integrate_ball();

    assert!(
        sim.ball.position.x > sim.players[5].position.x + 0.75,
        "ball should lead in the facing direction (+x): {:?}",
        sim.ball.position
    );
    assert!(
        (sim.ball.position.y - sim.players[5].position.y).abs() < 0.05,
        "ball should not flip onto the velocity axis (+y): {:?}",
        sim.ball.position
    );
    assert_eq!(sim.ball.last_touch_team, Some(Team::Home));
}

