#[test]
fn aerial_pass_likelihood_boosts_when_defender_or_midfielder_spots_runner() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 2;
    let midfielder = 6;
    let striker = 9;
    sim.tick = 20;
    sim.clock_seconds = 2.0;
    sim.players[defender].position = Vec2::new(40.0, 44.0);
    sim.players[midfielder].position = Vec2::new(40.0, 56.0);
    sim.players[striker].position = Vec2::new(40.0, 72.0);
    sim.players[striker].velocity = Vec2::new(0.0, 3.2);
    sim.players[striker].position_history =
        VecDeque::from_iter((0..=20).map(|_| sim.players[striker].position));
    {
        let mut store = sim
            .shared_positions
            .inner
            .write()
            .expect("shared position lock");
        store.histories.insert(
            striker,
            VecDeque::from_iter((0..=20).map(|step| PlayerPositionSample {
                player_id: striker,
                tick: step,
                clock_seconds: step as f64 * 0.1,
                position: Vec2::new(40.0, 66.0 + step as f64 * 0.3),
                velocity: Vec2::new(0.0, 3.0),
                acceleration: Vec2::zero(),
                jerk: Vec2::zero(),
            })),
        );
    }
    for away in 11..22 {
        sim.players[away].position = Vec2::new(72.0, 96.0);
    }
    sim.players[11].position = Vec2::new(40.0, 118.0);
    sim.players[12].position = Vec2::new(42.0, 90.0);
    sim.ball.last_touch_team = Some(Team::Home);

    sim.ball.holder = Some(defender);
    sim.ball.position = sim.players[defender].position;
    let defender_snapshot = WorldSnapshot::from_match(&sim);
    let defender_observation = defender_snapshot.observation_for(defender);
    assert!((defender_observation.aerial_forward_runner_pass_multiplier - 1.15).abs() < 1e-9);

    sim.ball.holder = Some(midfielder);
    sim.ball.position = sim.players[midfielder].position;
    let midfielder_snapshot = WorldSnapshot::from_match(&sim);
    let midfielder_observation = midfielder_snapshot.observation_for(midfielder);
    assert!((midfielder_observation.aerial_forward_runner_pass_multiplier - 1.50).abs() < 1e-9);

    let directive = midfielder_snapshot.tactical_directive(Team::Home);
    sim.players[midfielder].preferences.pass_bias = 0.35;
    let mut base_observation = midfielder_observation.clone();
    base_observation.aerial_forward_runner_pass_multiplier = 1.0;
    let base_options = sim.players[midfielder].possession_action_options(
        &base_observation,
        &directive,
        1,
        1,
        false,
        midfielder_snapshot.dt_seconds,
        midfielder_snapshot.field_width,
    );
    let boosted_options = sim.players[midfielder].possession_action_options(
        &midfielder_observation,
        &directive,
        1,
        1,
        false,
        midfielder_snapshot.dt_seconds,
        midfielder_snapshot.field_width,
    );
    assert!(
        action_option_score(&boosted_options, "aerial-pass1")
            > action_option_score(&base_options, "aerial-pass1") * 1.45
    );
}

#[test]
fn ball_carrier_has_high_confidence_front_vision() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 9;
    let rear_teammate = 8;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.players[holder].position = sim.ball.position;
    sim.players[holder].velocity = Vec2::zero();
    sim.players[rear_teammate].position = Vec2::new(40.0, 40.0);
    sim.players[rear_teammate].velocity = Vec2::zero();

    let snapshot = WorldSnapshot::from_match(&sim);
    let perception = &tunables().pomdp_perception;
    let core = Vec2::new(40.0, 80.0);
    let shoulder = Vec2::new(58.0, 66.5);
    let behind = Vec2::new(40.0, 40.0);

    assert!(snapshot.player_can_see_point(holder, core));
    assert!(
        snapshot
            .player_position_confidence_for_point(holder, core)
            .unwrap()
            >= perception.ball_holder_core_confidence
    );
    assert!(snapshot.player_can_see_point(holder, shoulder));
    let shoulder_confidence = snapshot
        .player_position_confidence_for_point(holder, shoulder)
        .unwrap();
    assert!(shoulder_confidence >= perception.ball_holder_shoulder_confidence);
    assert!(shoulder_confidence < perception.ball_holder_core_confidence);
    assert!(snapshot.player_can_see_point(holder, behind));
    let behind_confidence = snapshot
        .player_position_confidence_for_point(holder, behind)
        .unwrap();
    assert!(
        behind_confidence >= perception.ball_holder_rear_scan_confidence,
        "rear scan confidence should remain usable: {behind_confidence}"
    );
    assert!(
        behind_confidence < shoulder_confidence,
        "rear scan confidence should stay below shoulder vision: rear={behind_confidence} shoulder={shoulder_confidence}"
    );
    let observation = snapshot.observation_for(holder);
    let rear_entry = observation
        .player_position_confidences
        .iter()
        .find(|entry| entry.player_id == rear_teammate)
        .expect("rear teammate confidence entry");
    assert!(
        rear_entry.latency_seconds >= perception.ball_holder_head_scan_min_seconds,
        "rear scan should cost realistic head-swivel time: {}",
        rear_entry.latency_seconds
    );
    assert!(
        rear_entry.latency_seconds <= perception.ball_holder_head_scan_max_seconds,
        "rear scan latency should stay inside configured head-swivel max: {}",
        rear_entry.latency_seconds
    );
    assert!(
        observation.look_behind_scan_active,
        "ball-holder rear scan should be surfaced on the POMDP observation"
    );
}

#[test]
fn attacking_support_seeks_forward_open_space_without_running_offside() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.holder = Some(5);
    sim.ball.position = Vec2::new(40.0, 56.0);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[5].position = sim.ball.position;
    sim.players[9].position = Vec2::new(31.0, 60.0);
    for away in 11..22 {
        sim.players[away].position = Vec2::new(68.0, 92.0);
    }
    sim.players[11].position = Vec2::new(40.0, 118.0);
    sim.players[12].position = Vec2::new(44.0, 108.0);

    let before = WorldSnapshot::from_match(&sim);
    let mut rng = mulberry32(206);
    sim.central_brain.run_time_step(&before, &mut rng);
    let snapshot = WorldSnapshot::from_match(&sim);
    let target = snapshot.positional_open_space_for(9, sim.players[9].home_position, false);

    assert!(
        (target.y - sim.ball.position.y) * Team::Home.attack_dir() > 4.0,
        "target should be ahead of the ball: {target:?}"
    );
    assert!(
        target.y > sim.players[9].position.y,
        "target should invite the forward into higher space: {target:?}"
    );
    let line_y = snapshot.second_last_defender_line_for(Team::Home).unwrap();
    assert!(
        target.y <= line_y + OPEN_SPACE_RUN_OFFSIDE_TOLERANCE_YARDS + 1e-9,
        "support target should respect the marginal open-space offside window: target={target:?} line_y={line_y}"
    );
    assert!(
        target.distance(sim.players[9].home_position) <= 20.0 + 1e-9,
        "non-roaming support should stay in positional radius"
    );
}

#[test]
fn striker_recovers_onside_unless_holding_ball_behind_enemy_line() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6;
    let striker = 9;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 84.0);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].position = sim.ball.position;
    sim.players[striker].position = Vec2::new(40.0, 99.0);

    sim.players[11].position = Vec2::new(40.0, 118.0);
    for (k, away) in (12..22).enumerate() {
        sim.players[away].position = Vec2::new(20.0 + k as f64 * 5.0, 95.0);
    }

    let snapshot = WorldSnapshot::from_match(&sim);
    let line_y = snapshot.second_last_defender_line_for(Team::Home).unwrap();
    let striker_snapshot = snapshot
        .players
        .iter()
        .find(|p| p.id == striker)
        .expect("striker snapshot");
    let offside_target =
        snapshot.clamp_forward_onside_support(striker_snapshot, Vec2::new(40.0, 104.0));
    assert!(
        offside_target.y <= line_y + OPEN_SPACE_RUN_OFFSIDE_TOLERANCE_YARDS + 1e-9,
        "non-holder striker should be sent back within the marginal open-space window: target={offside_target:?} line_y={line_y}"
    );

    sim.ball.holder = Some(striker);
    sim.ball.position = Vec2::new(40.0, 101.0);
    sim.players[striker].position = sim.ball.position;
    let holder_snapshot = WorldSnapshot::from_match(&sim);
    let striker_holder_snapshot = holder_snapshot
        .players
        .iter()
        .find(|p| p.id == striker)
        .expect("striker holder snapshot");
    let breakaway_target = Vec2::new(42.0, 106.0);
    assert_eq!(
        holder_snapshot.clamp_forward_onside_support(striker_holder_snapshot, breakaway_target),
        breakaway_target,
        "a striker already behind the defensive line with possession must not be pulled back onside"
    );
}

#[test]
fn exploit_space_strategy_sends_runner_to_receivable_pocket() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6;
    let runner = 9;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 58.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(58.0, 64.0);
    sim.players[runner].home_position = Vec2::new(58.0, 64.0);
    for away in 11..22 {
        sim.players[away].position = Vec2::new(20.0 + (away - 11) as f64 * 1.2, 78.0);
    }
    sim.players[11].position = Vec2::new(40.0, 120.0);
    sim.players[12].position = Vec2::new(28.0, 86.0);
    sim.players[13].position = Vec2::new(38.0, 86.0);
    sim.players[14].position = Vec2::new(48.0, 86.0);
    sim.players[15].position = Vec2::new(58.0, 86.0);
    sim.players[20].position = Vec2::new(68.0, 116.0);
    sim.players[21].position = Vec2::new(72.0, 112.0);
    sim.central_brain.home_directive.attack_strategy = TeamAttackStrategy::ExploitSpace;

    let snapshot = WorldSnapshot::from_match(&sim);
    let movement =
        snapshot.attacking_support_movement_for(runner, sim.players[runner].home_position, false);
    let options = sim.players[runner].support_action_options(&snapshot);
    let exploit_option = options
        .iter()
        .find(|option| option.label == "exploit-space-run" && option.legal)
        .expect("exploit-space strategy should expose a scored support run");
    let line_y = snapshot.second_last_defender_line_for(Team::Home).unwrap();

    assert_eq!(movement.action_label, "exploit-space-run");
    assert!(
        exploit_option.probability >= 0.24 - 1e-9,
        "exploit-space run should have a usable support-action floor: {options:?}"
    );
    let mut runner_agent = sim.players[runner].clone();
    runner_agent.fatigue = SPRINT_CONSERVE_FATIGUE + 0.08;
    let intent = runner_agent.run_time_step(&snapshot, None, None, &mut mulberry32(22_902));
    assert!(
        runner_agent
            .last_decision
            .as_ref()
            .is_some_and(|decision| decision.action == "exploit-space-run"),
        "exploit-space strategy should choose the line-gap run, not passive support: {:?}",
        runner_agent.last_decision
    );
    assert!(
        intent.sprint,
        "exploit-space run should remain a peak sprinting moment even under fatigue conservation"
    );
    assert!(
        snapshot.attacking_support_sprint_active(Team::Home),
        "exploit-space strategy should lift off-ball support runs to a sprint"
    );
    assert!(
        (movement.point.y - sim.players[runner].position.y) * Team::Home.attack_dir() > 5.0,
        "runner should sprint goalward into the pocket: target={:?}",
        movement.point
    );
    assert!(
        movement.point.y <= line_y + OPEN_SPACE_RUN_OFFSIDE_TOLERANCE_YARDS + 1e-9,
        "behind-line pocket may stretch only marginally offside: target={:?} line_y={line_y}",
        movement.point
    );
    assert!(
        movement.point.x >= 50.0,
        "runner should prefer the open right-side pocket rather than the congested center/left: {:?}",
        movement.point
    );
    assert!(
        snapshot.clear_line(sim.ball.position, movement.point, Team::Away, 1.8),
        "the exploit-space target should remain receivable from the carrier"
    );
}

