#[test]
fn attacking_midfielder_roams_and_overlaps_when_striker_has_ball() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let striker = 9;
    let winger = 8;
    sim.ball.holder = Some(striker);
    sim.ball.position = Vec2::new(40.0, 72.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[striker].position = sim.ball.position;
    sim.players[winger].position = Vec2::new(63.0, 58.0);
    for away in 11..22 {
        sim.players[away].position = Vec2::new(70.0, 100.0);
    }
    sim.players[11].position = Vec2::new(40.0, 118.0);

    let snapshot = WorldSnapshot::from_match(&sim);
    let options = sim.players[winger].support_action_options(&snapshot);
    let roam_probability = options
        .iter()
        .find(|option| option.label == "support-roam")
        .map(|option| option.probability)
        .unwrap_or(0.0);
    let overlap_probability = options
        .iter()
        .find(|option| option.label == "overlap-run")
        .map(|option| option.probability)
        .unwrap_or(0.0);
    let target =
        snapshot.positional_open_space_for(winger, sim.players[winger].home_position, false);

    assert!(roam_probability > 0.05);
    assert!(
        overlap_probability + 1e-9 >= FLANK_OVERLAP_MIN_OPTION_SHARE,
        "flank overlap-run should be at least one third when available: {overlap_probability}"
    );
    assert!(snapshot.attacking_support_sprint_active(Team::Home));
    assert!(
        target.y > sim.players[striker].position.y,
        "wide attacking mid should overlap beyond striker: {target:?}"
    );

    sim.ball.holder = Some(6);
    sim.players[6].position = Vec2::new(40.0, 62.0);
    sim.ball.position = sim.players[6].position;
    sim.players[5].movement_gait = MovementGait::Run;
    let surge_snapshot = WorldSnapshot::from_match(&sim);
    assert!(surge_snapshot.attacking_support_sprint_active(Team::Home));
    assert!(surge_snapshot.defensive_tracking_sprint_active(Team::Away));
}

#[test]
fn uncontested_carrier_pulls_off_ball_attackers_forward_not_back() {
    // A midfielder dribbles the ball forward UNPRESSURED (nearest opponent far away) and
    // at a calm pace — none of the pace-based momentum cues fire. An off-ball striker
    // sitting just behind/level, whose formation home is deep, must still be supported
    // FORWARD (push up, no backward drift), not dragged back toward his home line.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 6;
    let striker = 9;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 80.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[carrier].position = sim.ball.position;
    // Carry calmly: no sprint, so forward_attacking_momentum / carrier-driving stay off.
    sim.players[carrier].movement_gait = MovementGait::Jog;
    sim.players[striker].position = Vec2::new(42.0, 78.0);
    sim.players[striker].home_position = Vec2::new(42.0, 60.0);
    // Park every opponent deep in their own half so the carrier is unpressured and the
    // onside line sits well ahead of the striker.
    for away in 11..22 {
        sim.players[away].position = Vec2::new(30.0 + (away - 11) as f64 * 2.0, 118.0);
    }

    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        snapshot.uncontested_carrier_advancing(Team::Home).is_some(),
        "an unpressured calm carrier should be flagged as an advancing-support cue"
    );
    assert!(
        snapshot.attacking_support_sprint_active(Team::Home),
        "off-ball runners should lift to a sprint to support a free carrier"
    );

    let support =
        snapshot.attacking_support_movement_for(striker, sim.players[striker].home_position, false);
    let attack = Team::Home.attack_dir();
    let current = sim.players[striker].position;
    let support_forward_yards = (support.point.y - current.y) * attack;
    assert!(
        support_forward_yards >= UNCONTESTED_SUPPORT_PUSH_YARDS + 1.0,
        "off-ball striker should be pushed FORWARD to support the free carrier, \
         not held or dropped back: target {:?} vs current {:?}",
        support.point,
        current
    );
    assert!(
        support.point.distance(current) > 3.5,
        "forward support target should be far enough to sustain a sprint: target {:?} vs current {:?}",
        support.point,
        current
    );
    assert!(
        !snapshot.position_would_be_offside(Team::Home, support.point),
        "forward support push must stay onside: {:?}",
        support.point
    );
}

#[test]
fn front_line_carrier_pulls_support_runners_even_when_marked() {
    // The holder is the second-furthest-forward outfielder: only one teammate is
    // ahead. Even with a marker close enough to disable the "uncontested carrier"
    // cue, off-ball attackers should sprint and run forward to give the carrier
    // options instead of leaving him isolated at the front of the attack.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 6;
    let runner = 9;
    let ahead_teammate = 10;
    let marker = 12;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 80.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    for home in 1..11 {
        if home != carrier && home != runner && home != ahead_teammate {
            sim.players[home].position = Vec2::new(20.0 + home as f64, 54.0);
        }
    }
    sim.players[carrier].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(43.0, 70.0);
    sim.players[runner].home_position = Vec2::new(43.0, 58.0);
    sim.players[ahead_teammate].position = Vec2::new(48.0, 84.0);
    for away in 11..22 {
        sim.players[away].position = Vec2::new(30.0 + (away - 11) as f64 * 2.0, 118.0);
    }
    sim.players[marker].position = Vec2::new(41.0, 81.0);

    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        snapshot.uncontested_carrier_advancing(Team::Home).is_none(),
        "close marker should disable the old unpressured-carrier cue"
    );
    assert!(
        snapshot
            .front_line_carrier_support_cue(Team::Home)
            .is_some(),
        "carrier with only one teammate ahead should be a front-line support cue"
    );
    assert!(
        snapshot.attacking_support_sprint_active(Team::Home),
        "front-line carrier should trigger off-ball sprint support"
    );

    let support =
        snapshot.attacking_support_movement_for(runner, sim.players[runner].home_position, false);
    let forward_yards =
        (support.point.y - sim.players[runner].position.y) * Team::Home.attack_dir();
    assert!(
        forward_yards >= UNCONTESTED_SUPPORT_PUSH_YARDS + 1.0,
        "runner should push forward for a front-line carrier: target={:?} current={:?}",
        support.point,
        sim.players[runner].position
    );
}

#[test]
fn flank_cross_policy_exposes_overlap_run_at_directive_floor() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6;
    let winger = 8;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(4.0, 84.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].position = sim.ball.position;
    sim.players[winger].position = Vec2::new(68.0, 74.0);
    sim.players[winger].home_position = Vec2::new(68.0, 64.0);
    // Defend the box deep so the box runners are onside (not all clamped to a
    // high line together) — keeps the high-vs-low arrival lanes geometric and
    // robust to shot-window weighting.
    for away in 11..22 {
        sim.players[away].position = Vec2::new(30.0, 116.0 + (away - 11) as f64 * 0.3);
    }
    let mut directive = TeamTacticalDirective::neutral(
        Team::Home,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );
    directive.flank_attack_policy = FlankAttackPolicy::PlayDownFlankHighCross;
    directive.flank_overlap_run_probability = 0.42;
    sim.central_brain.home_directive = directive.clone();

    let snapshot = WorldSnapshot::from_match(&sim);
    let options = sim.players[winger].support_action_options(&snapshot);
    let overlap = options
        .iter()
        .find(|option| option.label == "overlap-run")
        .expect("flank policy should expose overlap-run");

    assert!(overlap.legal);
    assert!(
        overlap.probability + 1e-9 >= directive.flank_overlap_run_probability,
        "policy overlap probability should honor directive floor: {overlap:?}"
    );
    assert!(
        action_option_score(&options, "wide-outlet") > 0.0,
        "flank policy should still leave wide outlet support available: {options:?}"
    );
}

