#[test]
fn learned_support_target_points_are_shape_guarded() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 7;
    let runner = 6;
    let occupying_teammate = 5;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 56.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(33.0, 55.0);
    sim.players[occupying_teammate].position = Vec2::new(34.0, 60.0);
    for away in 11..22 {
        sim.players[away].position = Vec2::new(70.0, 96.0 + (away - 11) as f64 * 0.5);
    }

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(runner);
    let bad_target = sim.players[occupying_teammate].position;
    let safe_fallback = snapshot
        .attacking_support_movement_for(runner, sim.players[runner].home_position, false)
        .point;
    let runner_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == runner)
        .expect("runner snapshot");
    let clamped_bad = snapshot.clamp_to_role_position(
        runner,
        bad_target,
        sim.players[runner].home_position,
        false,
    );
    let guarded = snapshot.shape_guarded_learned_support_target(
        runner,
        bad_target,
        safe_fallback,
        sim.players[runner].home_position,
    );

    assert!(
            snapshot.movement_target_shape_score(runner_snapshot, guarded)
                > snapshot.movement_target_shape_score(runner_snapshot, clamped_bad) + 0.10,
            "shape guard should prefer the safe support point over teammate-occupied learned target: guarded={guarded:?} bad={clamped_bad:?}"
        );
    assert!(
            guarded.distance(bad_target) > TEAMMATE_OCCUPIED_SPACE_HARD_RADIUS_YARDS,
            "guarded learned support target should move away from occupied teammate space: guarded={guarded:?} bad={bad_target:?}"
        );

    let plan = SoccerLearnedPlan {
        action: "support-shape".to_string(),
        target_player: None,
        target_point: Some(bad_target),
        mpc_replan: None,
    };
    let (action, label) = sim.players[runner]
        .action_from_learned_plan(&plan, &snapshot, &observation)
        .expect("support-shape learned action");
    assert_eq!(label, "support-shape");
    match action {
        SoccerAction::MoveTo(target) => {
            assert!(
                    target.distance(guarded) < 1e-9,
                    "learned support action should use shape-guarded target: target={target:?} guarded={guarded:?}"
                );
            assert!(
                    target.distance(bad_target) > TEAMMATE_OCCUPIED_SPACE_HARD_RADIUS_YARDS,
                    "learned support action should not obey an occupied raw target: target={target:?} bad={bad_target:?}"
                );
        }
        other => panic!("expected support movement, got {other:?}"),
    }
}

#[test]
fn defenders_and_midfielders_preserve_vertical_lanes_by_phase() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 9;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(74.0, 62.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].position = sim.ball.position;

    let possession_snapshot = WorldSnapshot::from_match(&sim);
    for player_id in [1usize, 2, 3, 4, 5, 6, 7, 8] {
        let player = &sim.players[player_id];
        let target =
            possession_snapshot.positional_open_space_for(player_id, player.home_position, false);
        let target_lane = vertical_lane_index(target.x, possession_snapshot.field_width);
        let (min_lane, max_lane) = role_vertical_lane_range(
            player.role,
            player.home_position.x,
            possession_snapshot.field_width,
            true,
        );
        let possession_max_lane = (max_lane + 1).min(11);
        assert!(
            (min_lane..=possession_max_lane).contains(&target_lane),
            "{} should keep its 12-grid vertical lane band or adjacent support lane in possession: home={:?} target={:?} lane={target_lane} allowed={min_lane}..={possession_max_lane}",
            player.name,
            player.home_position,
            target
        );
    }

    let away_holder = 17;
    sim.ball.holder = Some(away_holder);
    sim.ball.position = Vec2::new(72.0, 72.0);
    sim.ball.last_touch_team = Some(Team::Away);
    sim.players[away_holder].position = sim.ball.position;
    let defense_snapshot = WorldSnapshot::from_match(&sim);
    for player_id in [1usize, 2, 3, 4, 5, 6, 7, 8] {
        let player = &sim.players[player_id];
        let target =
            defense_snapshot.defensive_assignment_for(player_id, player.home_position, false);
        let target_lane = vertical_lane_index(target.x, defense_snapshot.field_width);
        let (min_lane, max_lane) = role_vertical_lane_range(
            player.role,
            player.home_position.x,
            defense_snapshot.field_width,
            false,
        );
        assert!(
            (min_lane..=max_lane).contains(&target_lane),
            "{} should keep its 12-grid vertical lane band while defending unless actively tracking: home={:?} target={:?} lane={target_lane} allowed={min_lane}..={max_lane}",
            player.name,
            player.home_position,
            target
        );
    }
}

#[test]
fn possession_support_expands_width_while_respecting_all_outfield_lanes() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 58.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    for id in 1..11 {
        sim.players[id].position = Vec2::new(37.0 + (id % 4) as f64 * 2.0, 50.0 + id as f64);
        sim.players[id].velocity = Vec2::zero();
    }
    sim.players[holder].position = sim.ball.position;
    for away in 11..22 {
        sim.players[away].position = Vec2::new(70.0, 96.0 + (away - 11) as f64 * 0.5);
    }

    let snapshot = WorldSnapshot::from_match(&sim);
    let compact_width = sim.players[1..11]
        .iter()
        .filter(|player| player.id != holder)
        .map(|player| player.position.x)
        .fold((f64::INFINITY, f64::NEG_INFINITY), |(min_x, max_x), x| {
            (min_x.min(x), max_x.max(x))
        });
    let compact_width = compact_width.1 - compact_width.0;
    let mut min_target_x = f64::INFINITY;
    let mut max_target_x = f64::NEG_INFINITY;
    let center = snapshot.field_width * 0.5;

    for player_id in 1usize..11 {
        if player_id == holder {
            continue;
        }
        let player = &sim.players[player_id];
        let target = snapshot
            .attacking_support_movement_for(player_id, player.home_position, false)
            .point;
        let target_lane = vertical_lane_index(target.x, snapshot.field_width);
        let (min_lane, max_lane) = role_vertical_lane_range(
            player.role,
            player.home_position.x,
            snapshot.field_width,
            true,
        );
        let possession_max_lane = (max_lane + 1).min(VERTICAL_LANE_COUNT - 1);
        assert!(
            (min_lane..=possession_max_lane).contains(&target_lane),
            "{} should keep its home 12-grid lane band or immediate support lane in possession: home={:?} target={:?} lane={target_lane} allowed={min_lane}..={possession_max_lane}",
            player.name,
            player.home_position,
            target
        );
        if (player.home_position.x - center).abs() > snapshot.field_width * 0.18 {
            assert!(
                (target.x - center).abs() > (player.position.x - center).abs() + 5.0,
                "{} should widen from the compact start toward its lane: start={:?} home={:?} target={:?}",
                player.name,
                player.position,
                player.home_position,
                target
            );
        }
        min_target_x = min_target_x.min(target.x);
        max_target_x = max_target_x.max(target.x);
    }

    let target_width = max_target_x - min_target_x;
    assert!(
        target_width > compact_width + snapshot.field_width * 0.62,
        "support targets should expand a compact possession shape across the field: compact={compact_width:.2} target={target_width:.2}"
    );
    assert!(
        target_width > snapshot.field_width * 0.76,
        "support targets should use most of the field width in possession: field={:.2} target={target_width:.2}",
        snapshot.field_width
    );
}

#[test]
fn possession_shape_score_prefers_width_restoring_home_lane_target() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 58.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    for id in 1..11 {
        sim.players[id].position = Vec2::new(39.0 + (id % 3) as f64, 53.0 + id as f64 * 0.2);
        sim.players[id].velocity = Vec2::zero();
    }
    sim.players[holder].position = sim.ball.position;
    for away in 11..22 {
        sim.players[away].position = Vec2::new(68.0, 94.0 + (away - 11) as f64 * 0.5);
    }

    let snapshot = WorldSnapshot::from_match(&sim);
    let center = snapshot.field_width * 0.5;
    let runner = sim.players[1..11]
        .iter()
        .find(|player| {
            player.id != holder
                && player.role != PlayerRole::Goalkeeper
                && player.home_position.x < center - snapshot.field_width * 0.18
        })
        .expect("left-side support runner")
        .id;
    let runner_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == runner)
        .expect("runner snapshot");
    let forward_y = (sim.ball.position.y + runner_snapshot.team.attack_dir() * 10.0)
        .clamp(0.0, snapshot.field_length);
    let wide_home_lane = Vec2::new(runner_snapshot.home_position.x, forward_y);
    let central_collapse = Vec2::new(center + 1.0, forward_y);

    let wide_score = snapshot.movement_target_shape_score(runner_snapshot, wide_home_lane);
    let central_score = snapshot.movement_target_shape_score(runner_snapshot, central_collapse);

    assert!(
        wide_score > central_score + 0.35,
        "width-restoring home-lane support should beat central collapse: wide={wide_score:.3} central={central_score:.3} runner={runner}"
    );
}

#[test]
fn ball_side_wide_support_keeps_x_width_floor_after_shape_guards() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6usize;
    let winger = 9usize;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(16.0, 58.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    for id in 1..11 {
        sim.players[id].position = Vec2::new(38.0 + (id % 3) as f64 * 2.0, 52.0 + id as f64);
        sim.players[id].velocity = Vec2::zero();
    }
    sim.players[holder].position = sim.ball.position;
    sim.players[winger].role = PlayerRole::Forward;
    sim.players[winger].home_position = Vec2::new(8.0, 76.0);
    sim.players[winger].position = Vec2::new(28.0, 66.0);
    for away in 11..22 {
        sim.players[away].position = Vec2::new(70.0, 96.0 + (away - 11) as f64 * 0.4);
    }

    let snapshot = WorldSnapshot::from_match(&sim);
    let center = snapshot.field_width * 0.5;
    let collapsing_target = Vec2::new(center, 76.0);
    let guarded = snapshot.shape_guarded_support_point(
        winger,
        collapsing_target,
        &[collapsing_target],
        sim.players[winger].home_position,
        false,
    );
    let intent = snapshot.possession_wide_lane_floor_adjusted_intent(PlayerIntent {
        player_id: winger,
        action: SoccerAction::MoveTo(collapsing_target),
        sprint: false,
    });
    let SoccerAction::MoveTo(intent_target) = intent.action else {
        panic!("expected MoveTo intent");
    };

    assert!(
        guarded.x < center - snapshot.field_width * 0.24,
        "shape guard should preserve ball-side x-axis width for a wide support runner: guarded={guarded:?} center={center}"
    );
    assert!(
        intent_target.x < center - snapshot.field_width * 0.18,
        "final intent guard should also restore x-axis width after learned/late movement targets: target={intent_target:?}"
    );
    assert!(
        guarded.x < collapsing_target.x - 16.0 && intent_target.x < collapsing_target.x - 12.0,
        "central collapse should be corrected outward: guarded={guarded:?} intent={intent_target:?} collapse={collapsing_target:?}"
    );
}

#[test]
fn defender_and_midfielder_markov_lane_affinities_sum_to_one() {
    for (name, table) in [
        ("defender", &DEFENDER_MARKOV_LANE_PMF_BY_SLOT),
        ("midfielder", &MIDFIELDER_MARKOV_LANE_PMF_BY_SLOT),
    ] {
        for (slot, row) in table.iter().enumerate() {
            let sum: f64 = row.iter().sum();
            assert!(
                (sum - 1.0).abs() < 1e-9,
                "{name} slot {slot} must sum to 1.0, got {sum:.12}"
            );
            assert!(
                row.iter().all(|value| (0.0..=1.0).contains(value)),
                "{name} slot {slot} must stay inside probability bounds: {row:?}"
            );
        }
    }
}

#[test]
fn defender_and_midfielder_markov_lane_pmfs_are_mirrored_and_smooth() {
    for (name, table) in [
        ("defender", &DEFENDER_MARKOV_LANE_PMF_BY_SLOT),
        ("midfielder", &MIDFIELDER_MARKOV_LANE_PMF_BY_SLOT),
    ] {
        for slot in 0..table.len() {
            let mirror_slot = table.len() - 1 - slot;
            for lane in 0..VERTICAL_LANE_COUNT {
                let mirror_lane = VERTICAL_LANE_COUNT - 1 - lane;
                assert!(
                    (table[slot][lane] - table[mirror_slot][mirror_lane]).abs() < 1e-9,
                    "{name} slot {slot} lane {lane} must mirror slot {mirror_slot} lane {mirror_lane}"
                );
            }
            let max_step = table[slot]
                .windows(2)
                .map(|pair| (pair[1] - pair[0]).abs())
                .fold(0.0_f64, f64::max);
            assert!(
                max_step <= 0.16,
                "{name} slot {slot} PMF should transition smoothly between adjacent lanes, max_step={max_step}"
            );
        }
    }
}

#[test]
fn markov_lane_pmf_probability_is_separate_from_peak_affinity() {
    let sim = SoccerMatch::default_11v11(MatchConfig::default());
    let snapshot = WorldSnapshot::from_match(&sim);
    let lane_center = |lane: usize| {
        let (left, right) = vertical_lane_bounds(lane, snapshot.field_width);
        (left + right) * 0.5
    };

    let left_back = snapshot
        .players
        .iter()
        .filter(|p| p.team == Team::Home && p.role == PlayerRole::Defender)
        .min_by(|a, b| a.home_position.x.total_cmp(&b.home_position.x))
        .unwrap();
    let peak = Vec2::new(lane_center(3), left_back.home_position.y);
    let shoulder = Vec2::new(lane_center(0), left_back.home_position.y);
    assert!(
        (snapshot.markov_lane_probability_for_player_target(left_back, peak) - 0.30).abs() < 1e-9
    );
    assert!(
        (snapshot.markov_lane_probability_for_player_target(left_back, shoulder) - 0.05).abs()
            < 1e-9
    );
    assert!((snapshot.markov_lane_affinity_for_player_target(left_back, peak) - 1.0).abs() < 1e-9);
    assert!(
        snapshot.markov_lane_affinity_for_player_target(left_back, shoulder)
            < snapshot.markov_lane_affinity_for_player_target(left_back, peak) * 0.20
    );

    let left_midfielder = snapshot
        .players
        .iter()
        .filter(|p| p.team == Team::Home && p.role == PlayerRole::Midfielder)
        .min_by(|a, b| a.home_position.x.total_cmp(&b.home_position.x))
        .unwrap();
    let mid_peak = Vec2::new(lane_center(3), left_midfielder.home_position.y);
    assert!(
        (snapshot.markov_lane_probability_for_player_target(left_midfielder, mid_peak) - 0.24)
            .abs()
            < 1e-9
    );
    assert!(
        (snapshot.markov_lane_affinity_for_player_target(left_midfielder, mid_peak) - 1.0).abs()
            < 1e-9
    );
}

#[test]
fn markov_lane_pmf_interpolates_for_non_four_player_role_lines() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let mut defenders: Vec<usize> = sim
        .players
        .iter()
        .filter(|p| p.team == Team::Home && p.role == PlayerRole::Defender)
        .map(|p| p.id)
        .collect();
    defenders.sort_by(|a, b| {
        sim.players[*a]
            .home_position
            .x
            .total_cmp(&sim.players[*b].home_position.x)
    });
    assert_eq!(defenders.len(), 4, "test setup expects a back four");
    let right_back = defenders[3];
    let middle_defender = defenders[1];
    sim.players[right_back].role = PlayerRole::Forward;

    let snapshot = WorldSnapshot::from_match(&sim);
    let lane_center = |lane: usize| {
        let (left, right) = vertical_lane_bounds(lane, snapshot.field_width);
        (left + right) * 0.5
    };
    let player = snapshot
        .players
        .iter()
        .find(|p| p.id == middle_defender)
        .unwrap();
    let left_center_peak = Vec2::new(lane_center(5), player.home_position.y);
    let right_center_peak = Vec2::new(lane_center(6), player.home_position.y);

    assert!(
        (snapshot.markov_lane_probability_for_player_target(player, left_center_peak) - 0.23).abs()
            < 1e-9,
        "three-player defender line should interpolate the middle slot between LCB and RCB"
    );
    assert!(
        (snapshot.markov_lane_probability_for_player_target(player, right_center_peak) - 0.23)
            .abs()
            < 1e-9,
        "interpolated middle slot should be symmetric across the centre lanes"
    );
    assert!(
        (snapshot.markov_lane_affinity_for_player_target(player, left_center_peak) - 1.0).abs()
            < 1e-9
    );
    assert!(
        (snapshot.markov_lane_affinity_for_player_target(player, right_center_peak) - 1.0).abs()
            < 1e-9
    );
}

#[test]
fn forwards_have_light_dynamic_lane_affinity_prior() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let forward = 9;
    sim.ball.holder = None;
    sim.ball.last_touch_team = None;
    sim.players[forward].role = PlayerRole::Forward;
    sim.players[forward].team = Team::Home;
    sim.players[forward].position = Vec2::new(20.0, 74.0);
    sim.players[forward].home_position = Vec2::new(20.0, 74.0);

    let snapshot = WorldSnapshot::from_match(&sim);
    let player = snapshot.players.iter().find(|p| p.id == forward).unwrap();
    let home_lane_target = Vec2::new(22.0, 90.0);
    let cross_pitch_target = Vec2::new(64.0, 90.0);
    let home_lane_affinity =
        snapshot.dynamic_lane_affinity_for_player_target(player, home_lane_target);
    let cross_pitch_affinity =
        snapshot.dynamic_lane_affinity_for_player_target(player, cross_pitch_target);

    assert!(
        home_lane_affinity > cross_pitch_affinity + 0.10,
        "forwards should keep a lighter lane prior so learned/MPC support does not send them cross-pitch: home={home_lane_affinity:.3} cross={cross_pitch_affinity:.3}"
    );
    assert!(
        cross_pitch_affinity > 0.0,
        "forward lane affinity should stay soft rather than a hard zero: cross={cross_pitch_affinity:.3}"
    );
}

#[test]
fn dynamic_lane_affinity_establishes_home_width_for_all_eleven_players() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.holder = None;
    sim.ball.last_touch_team = None;
    sim.ball.position = Vec2::new(
        DEFAULT_FIELD_WIDTH_YARDS * 0.5,
        DEFAULT_FIELD_LENGTH_YARDS * 0.5,
    );
    sim.ball.velocity = Vec2::zero();
    sim.ball.acceleration = Vec2::zero();
    sim.ball.jerk = Vec2::zero();

    let snapshot = WorldSnapshot::from_match(&sim);
    let lane_center = |lane: usize| {
        let (left, right) = vertical_lane_bounds(lane, snapshot.field_width);
        (left + right) * 0.5
    };
    let mut checked = 0usize;
    for player in snapshot.players.iter().filter(|p| p.team == Team::Home) {
        let home_grid = pitch_grid_address(
            player.home_position,
            snapshot.field_width,
            snapshot.field_length,
        )
        .fine;
        let cross_lane = if home_grid.x < PITCH_FINE_GRID_COLUMNS / 2 {
            PITCH_FINE_GRID_COLUMNS - 1
        } else {
            0
        };
        let home_target = Vec2::new(lane_center(home_grid.x), player.home_position.y);
        let cross_target = Vec2::new(lane_center(cross_lane), player.home_position.y);
        let home_affinity = snapshot.dynamic_lane_affinity_for_player_target(player, home_target);
        let cross_affinity = snapshot.dynamic_lane_affinity_for_player_target(player, cross_target);

        assert!(
            home_affinity > cross_affinity + 0.04,
            "player {} {:?} should prefer its own 12-lane width identity: home={home_affinity:.3} cross={cross_affinity:.3}",
            player.id,
            player.role
        );
        checked += 1;
    }
    assert_eq!(checked, 11);
}

#[test]
fn dynamic_lane_affinity_dampens_for_team_in_possession_until_turnover() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 1;
    let home_holder = 9;
    let away_holder = 17;
    park_players_except(&mut sim, &[defender, home_holder, away_holder]);
    for (id, home_x) in [(1usize, 22.0), (2, 36.0), (3, 52.0), (4, 68.0)] {
        sim.players[id].team = Team::Home;
        sim.players[id].role = PlayerRole::Defender;
        sim.players[id].home_position = Vec2::new(home_x, 34.0);
        sim.players[id].position = Vec2::new(home_x, 34.0);
    }
    sim.players[home_holder].team = Team::Home;
    sim.players[away_holder].team = Team::Away;
    sim.ball.position = Vec2::new(44.0, 58.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.acceleration = Vec2::zero();
    sim.ball.jerk = Vec2::zero();
    let target = Vec2::new(22.0, 36.0);

    sim.ball.holder = None;
    sim.ball.last_touch_team = None;
    let free_snapshot = WorldSnapshot::from_match(&sim);
    let free_player = free_snapshot
        .players
        .iter()
        .find(|p| p.id == defender)
        .unwrap();
    let free_affinity = free_snapshot.dynamic_lane_affinity_for_player_target(free_player, target);

    sim.ball.holder = Some(home_holder);
    sim.ball.last_touch_team = Some(Team::Home);
    let possession_snapshot = WorldSnapshot::from_match(&sim);
    let possession_player = possession_snapshot
        .players
        .iter()
        .find(|p| p.id == defender)
        .unwrap();
    let possession_affinity =
        possession_snapshot.dynamic_lane_affinity_for_player_target(possession_player, target);

    sim.ball.holder = Some(away_holder);
    sim.ball.last_touch_team = Some(Team::Away);
    let turnover_snapshot = WorldSnapshot::from_match(&sim);
    let turnover_player = turnover_snapshot
        .players
        .iter()
        .find(|p| p.id == defender)
        .unwrap();
    let turnover_affinity =
        turnover_snapshot.dynamic_lane_affinity_for_player_target(turnover_player, target);

    assert!(
        possession_affinity < free_affinity * 0.86,
        "own possession should still damp lane affinity: free={free_affinity:.3} possession={possession_affinity:.3}"
    );
    assert!(
        possession_affinity > free_affinity * 0.62,
        "own possession should preserve a live lane signal for width: free={free_affinity:.3} possession={possession_affinity:.3}"
    );
    assert!(
        turnover_affinity > possession_affinity * 1.16,
        "after giving it away, defensive lane affinity should return: turnover={turnover_affinity:.3} possession={possession_affinity:.3}"
    );
}

