#[test]
fn untargeted_long_ball_flight_records_ball_agent_schedule_index() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 2;
    park_players_except(&mut sim, &[defender]);
    sim.players[defender].position = Vec2::new(31.0, 24.0);
    sim.ball.holder = Some(defender);
    sim.ball.position = sim.players[defender].position;
    sim.ball.last_touch_team = Some(Team::Home);
    let target = clearance_target_for_player(
        Team::Home,
        sim.players[defender].position,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );

    sim.launch_untargeted_long_ball(defender, target, 0.94, "clearance");
    assert_eq!(
        sim.ball
            .last_decision
            .as_ref()
            .and_then(|decision| decision.scheduled_index),
        None,
        "player launch records the clearance before the ball agent's scheduled loop runs"
    );
    sim.players[defender].position = Vec2::new(5.0, 5.0);

    sim.tick = sim.tick.saturating_add(1);
    sim.clock_seconds += sim.config.dt_seconds;
    sim.last_agent_schedule = vec![
        AgentScheduleEntry {
            kind: AgentScheduleKind::CentralBrain,
            id: CENTRAL_BRAIN_AGENT_ID,
            label: "central brain".to_string(),
        },
        AgentScheduleEntry {
            kind: AgentScheduleKind::Ball,
            id: BALL_AGENT_ID,
            label: "ball".to_string(),
        },
    ];

    sim.run_ball_time_step();

    let decision = sim
        .ball
        .last_decision
        .as_ref()
        .expect("ball-agent flight decision");
    assert_eq!(decision.action, "long-ball-flight");
    assert_eq!(decision.scheduled_index, Some(1));
    assert!(
        !decision.operation_order.is_empty(),
        "ball-agent flight should expose its internal operation order"
    );
}

#[test]
fn pressure_clearance_target_bends_toward_visible_aerial_outlet() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 2;
    let runner = 9;
    park_players_except(&mut sim, &[defender, runner]);
    sim.players[defender].position = Vec2::new(30.0, 24.0);
    sim.players[defender].home_position = sim.players[defender].position;
    sim.players[defender].action_facing = FacingBucket::South;
    sim.players[defender].receive_facing = FacingBucket::South;
    sim.players[defender].skills.passing_completion_rate = 7.2;
    sim.players[runner].role = PlayerRole::Forward;
    sim.players[runner].position = Vec2::new(52.0, 62.0);
    sim.players[runner].home_position = sim.players[runner].position;
    sim.players[runner].velocity = Vec2::new(0.0, 3.0);
    sim.ball.holder = Some(defender);
    sim.ball.position = sim.players[defender].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let base = clearance_target_for_player(
        Team::Home,
        sim.players[defender].position,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );
    let target = snapshot
        .pressure_clearance_target_for(defender)
        .expect("visible forward outlet should shape clearance");

    assert!(
        target.y > sim.players[defender].position.y + 40.0,
        "pressure clearance should still be a long territorial ball: target={target:?}"
    );
    assert!(
            target.x > base.x + 10.0,
            "target should bend toward the visible runner lane instead of static channel: base={base:?} target={target:?}"
        );
    assert!(
        target.distance(sim.players[runner].position) < base.distance(sim.players[runner].position),
        "teammate-shaped clearance should land closer to the aerial outlet"
    );
}

