#[test]
fn floor_pass_leads_open_receiver_into_upfield_stride_space() {
    let passer = Vec2::new(40.0, 50.0);
    let receiver = Vec2::new(43.0, 65.0);
    let receiver_velocity = Vec2::new(0.6, 2.8);
    let open_target = led_pass_target_for_receiver(
        passer,
        receiver,
        receiver_velocity,
        18.0,
        0.86,
        0.90,
        Team::Home,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
    );
    let marked_target = led_pass_target_for_receiver(
        passer,
        receiver,
        Vec2::zero(),
        18.0,
        0.86,
        0.12,
        Team::Home,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
    );
    let backward_target = led_pass_target_for_receiver(
        passer,
        Vec2::new(43.0, 45.0),
        Vec2::zero(),
        18.0,
        0.86,
        0.90,
        Team::Home,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
    );

    assert!(
        open_target.y > receiver.y + 6.0,
        "open runner should receive into forward stride space: {open_target:?}"
    );
    assert!(
            open_target.y > marked_target.y + 1.5,
            "openness should increase the safe forward lead: open={open_target:?} marked={marked_target:?}"
        );
    assert!(
        backward_target.y <= 45.1,
        "backward passes should not receive an artificial upfield lead: {backward_target:?}"
    );

    let open_stride_fit = pass_into_stride_fit(
        passer,
        receiver,
        receiver_velocity,
        open_target,
        18.0,
        Team::Home,
    );
    let static_feet_fit = pass_into_stride_fit(
        passer,
        receiver,
        receiver_velocity,
        receiver,
        18.0,
        Team::Home,
    );
    assert!(
            open_stride_fit > static_feet_fit + 0.16,
            "pass into stride should score above pass to static feet: open={open_stride_fit}, static={static_feet_fit}"
        );
}

#[test]
fn pass_target_quality_rewards_receiver_stride_anticipation() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let passer = 6;
    let runner = 9;
    let static_outlet = 7;
    sim.ball.holder = Some(passer);
    sim.ball.position = Vec2::new(40.0, 48.0);
    sim.ball.last_touch_team = Some(Team::Home);
    park_players_except(&mut sim, &[passer, runner, static_outlet]);
    sim.players[passer].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(45.0, 66.0);
    sim.players[runner].velocity = Vec2::new(0.8, 3.2);
    sim.players[static_outlet].position = Vec2::new(35.0, 66.0);
    sim.players[static_outlet].velocity = Vec2::zero();
    sim.players[runner].skills.passing_completion_rate = 7.5;
    sim.players[static_outlet].skills.passing_completion_rate = 7.5;

    let snapshot = WorldSnapshot::from_match(&sim);
    let passer_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == passer)
        .expect("passer");
    let runner_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == runner)
        .expect("runner");
    let static_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == static_outlet)
        .expect("static outlet");
    let passer_position = snapshot.player_position(passer).unwrap();
    let runner_quality = pass_target_quality_for_snapshot(
        &snapshot,
        passer_snapshot,
        passer_position,
        runner_snapshot,
        snapshot.player_position(runner).unwrap(),
        PassFlight::Floor,
    );
    let static_quality = pass_target_quality_for_snapshot(
        &snapshot,
        passer_snapshot,
        passer_position,
        static_snapshot,
        snapshot.player_position(static_outlet).unwrap(),
        PassFlight::Floor,
    );
    assert!(
            runner_quality.stride_fit > static_quality.stride_fit + 0.12,
            "runner stride fit should beat static outlet: runner={runner_quality:?}, static={static_quality:?}"
        );
    assert_eq!(
        snapshot.ranked_visible_pass_targets(passer, 1),
        vec![runner]
    );
    let observation = snapshot.observation_for(passer);
    assert!(
            observation.best_pass_stride_fit > static_quality.stride_fit + 0.12,
            "POMDP observation should expose the passer's best anticipation fit: observation={:.3}, static={:.3}",
            observation.best_pass_stride_fit,
            static_quality.stride_fit
        );

    let state = snapshot.mdp_state_for_player(passer);
    let stride_key =
        SoccerQStateKey::from_parts(&state, &observation, Team::Home, PlayerRole::Midfielder);
    let mut static_observation = observation.clone();
    static_observation.best_pass_stride_fit = static_quality.stride_fit;
    let static_key = SoccerQStateKey::from_parts(
        &state,
        &static_observation,
        Team::Home,
        PlayerRole::Midfielder,
    );
    assert!(
        stride_key.best_pass_stride_fit_bin > static_key.best_pass_stride_fit_bin,
        "Q-state should bin pass anticipation separately from completion: stride={}, static={}",
        stride_key.best_pass_stride_fit_bin,
        static_key.best_pass_stride_fit_bin
    );
}

