#[test]
fn goal_credit_scores_pass_into_stride_above_static_feet() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let passer = 6;
    let runner = 9;
    sim.ball.holder = Some(passer);
    sim.ball.position = Vec2::new(40.0, 48.0);
    sim.ball.last_touch_team = Some(Team::Home);
    park_players_except(&mut sim, &[passer, runner]);
    sim.players[passer].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(45.0, 66.0);
    sim.players[runner].velocity = Vec2::new(0.8, 3.2);

    let before = WorldSnapshot::from_match(&sim);
    let receiver_feet = before.player_position(runner).expect("runner position");
    let stride_target = before
        .anticipated_pass_reception_point(passer, runner, PassFlight::Floor, 18.0)
        .expect("anticipated stride target");
    let mut after = before.clone();
    after.ball.holder = None;
    after.ball.velocity = (stride_target - sim.players[passer].position).normalized() * 18.0;

    let transition_for_target = |target: Vec2, action: &str| {
        let mut observation = before.observation_for(passer);
        observation.expected_pass_completion = 0.86;
        observation.best_pass_receiver_openness = 0.90;
        observation.floor_pass_lane_score = 0.92;
        let mut next_observation = observation.clone();
        next_observation.yards_to_goal = (observation.yards_to_goal - 8.0).max(0.0);
        let action_target = AgentActionTargetTrace {
            point: Some(target),
            player_id: Some(runner),
            grid: Some(pitch_grid_address(
                target,
                before.field_width,
                before.field_length,
            )),
            facing: facing_bucket_from_vector(target - sim.players[passer].position),
            dribble_touch: None,
        };
        SoccerLearningTransition {
            tick: before.tick,
            player_id: passer,
            team: Team::Home,
            role: sim.players[passer].role,
            state: before.mdp_state_for_player(passer),
            observation,
            belief: BeliefState {
                possession_confidence: 1.0,
                pressure: 0.0,
                pass_lane_open: 1.0,
                shot_quality: 0.0,
            },
            action: action.to_string(),
            action_target: Some(action_target.clone()),
            decision_context: soccer_decision_context_for(
                passer,
                Team::Home,
                action,
                Some(&action_target),
                &before,
                &after,
            ),
            tactical_trace: SoccerTacticalLearningTrace::default(),
            reward: 0.0,
            next_state: after.mdp_state_for_player(passer),
            next_observation,
            done: false,
        }
    };

    let stride_score =
        soccer_goal_credit_transition_score(&transition_for_target(stride_target, "pass"), 0);
    let feet_score =
        soccer_goal_credit_transition_score(&transition_for_target(receiver_feet, "pass"), 0);
    let killer_score = soccer_goal_credit_transition_score(
        &transition_for_target(stride_target, "killer-pass"),
        0,
    );

    assert!(
        stride_score > feet_score + 0.18,
        "pass goal-credit should reward anticipation: stride={stride_score}, feet={feet_score}"
    );
    assert!(
            killer_score >= stride_score - 1e-9,
            "killer pass should receive goal-credit as a threaded pass into stride: killer={killer_score}, pass={stride_score}"
        );
}

#[test]
fn completed_pass_reward_reinforces_passer_anticipating_receiver_stride() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let passer = 6;
    let receiver = 9;
    park_players_except(&mut sim, &[passer, receiver]);
    sim.players[passer].position = Vec2::new(40.0, 48.0);
    sim.players[receiver].position = Vec2::new(45.0, 66.0);
    sim.players[receiver].velocity = Vec2::new(0.8, 3.2);

    let origin = sim.players[passer].position;
    let receiver_position = sim.players[receiver].position;
    let receiver_velocity = sim.players[receiver].velocity;
    let stride_target = led_pass_target_for_receiver(
        origin,
        receiver_position,
        receiver_velocity,
        18.0,
        0.86,
        0.90,
        Team::Home,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );
    let pending_for_target = |intended_target: Vec2| PendingPass {
        team: Team::Home,
        from: passer,
        target: Some(receiver),
        flight: PassFlight::Floor,
        is_cross: false,
        launch_tick: sim.tick,
        origin,
        intended_target,
        distance_yards: origin.distance(intended_target),
        receiver_openness: 0.90,
        passer_skill: 0.86,
        launch_speed_yps: 18.0,
        receiver_position_at_launch: Some(receiver_position),
        receiver_velocity_at_launch: Some(receiver_velocity),
        offside: None,
        offside_candidates: Vec::new(),
        learn_features: Vec::new(),
    };
    let feet_pass = pending_for_target(receiver_position);
    let stride_pass = pending_for_target(stride_target);

    assert!(
        completed_pass_stride_anticipation_fit(&stride_pass)
            > completed_pass_stride_anticipation_fit(&feet_pass) + 0.20,
        "passer should score the led ball higher than static feet"
    );
    assert!(
        completed_pass_anticipation_reward(&stride_pass)
            > completed_pass_anticipation_reward(&feet_pass) + 0.85,
        "completed pass reward should reinforce anticipating the receiver's run"
    );

    let event_start = sim.reward_events.len();
    sim.record_completed_pass_reward(&stride_pass, receiver);
    let passer_reward = sim.reward_events[event_start..]
        .iter()
        .find(|event| event.player_id == passer)
        .expect("passer reward event")
        .amount;
    let base_reward = completed_pass_reward(
        Team::Home,
        origin,
        stride_target,
        sim.config.field_length_yards,
    );
    assert!(
            passer_reward > base_reward + 0.85,
            "passer event should include stride anticipation bonus: reward={passer_reward}, base={base_reward}"
        );
}

#[test]
fn transition_reward_reinforces_completed_pass_into_future_stride() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let passer = 6;
    let runner = 9;
    sim.ball.holder = Some(passer);
    sim.ball.position = Vec2::new(40.0, 48.0);
    sim.ball.last_touch_team = Some(Team::Home);
    park_players_except(&mut sim, &[passer, runner]);
    sim.players[passer].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(45.0, 66.0);
    sim.players[runner].velocity = Vec2::new(0.8, 3.2);

    let before = WorldSnapshot::from_match(&sim);
    let origin = before.player_position(passer).expect("passer position");
    let receiver_position = before.player_position(runner).expect("runner position");
    let stride_target = before
        .anticipated_pass_reception_point(passer, runner, PassFlight::Floor, 18.0)
        .expect("anticipated runner target");
    let reward_for_target = |target: Vec2| {
        let mut after = before.clone();
        after.ball.holder = Some(runner);
        after.ball.position = target;
        after.ball.velocity = (target - origin).normalized() * 18.0;
        if let Some(player) = after.players.iter_mut().find(|player| player.id == runner) {
            player.position = target;
        }
        let action_target = AgentActionTargetTrace {
            point: Some(target),
            player_id: Some(runner),
            grid: Some(pitch_grid_address(
                target,
                before.field_width,
                before.field_length,
            )),
            facing: facing_bucket_from_vector(target - origin),
            dribble_touch: None,
        };
        let observation = before.observation_for(passer);
        let decision = AgentDecisionTrace {
            mdp_state: before.mdp_state_for_player(passer),
            belief: belief_from_observation(&observation),
            observation,
            operation_order: vec!["unit-pass".to_string()],
            scheduled_index: None,
            action_options: single_action_option("pass"),
            action_target: Some(action_target),
            mdp_mpc_comparison: None,
            learned_mpc_replan: None,
            behavior_policy_probability: None,
            action: "pass".to_string(),
        };
        soccer_transition_reward(
            &sim.players[passer],
            &decision,
            &before,
            &after,
            before.score_home,
            before.score_away,
            after.score_home,
            after.score_away,
            true,
        )
    };

    let stride_reward = reward_for_target(stride_target);
    let feet_reward = reward_for_target(receiver_position);
    assert!(
            stride_reward > feet_reward + 0.65,
            "transition reward should teach passer anticipation: stride={stride_reward}, feet={feet_reward}"
        );
}

#[test]
fn own_half_possession_pushes_support_upfield() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 6;
    let runner = 7;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 32.0);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].position = sim.ball.position;
    sim.players[runner].position = Vec2::new(47.0, 31.0);
    for id in 11..22 {
        sim.players[id].position = Vec2::new(70.0, 90.0);
    }

    let before = WorldSnapshot::from_match(&sim);
    let mut rng = mulberry32(706);
    sim.central_brain.run_time_step(&before, &mut rng);
    let snapshot = WorldSnapshot::from_match(&sim);
    let target =
        snapshot.positional_open_space_for(runner, sim.players[runner].home_position, false);

    assert!(
        target.y > sim.players[runner].position.y + 3.0,
        "own-half support should urgently move upfield: {target:?}"
    );
    assert!(
        snapshot.home_directive.carry_priority > 1.0,
        "own-half possession should increase carry urgency"
    );
}

