#[test]
fn defensive_line_average_uses_hard_band_not_genome_permutation() {
    // The hard shelf/20-40yd defender average band is tactical structure, not evolved genome shape.
    // Genome permutations may tune other behaviors, but must not weaken this guard.
    let target_average_y_for_band = |permutation_index: usize| {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let mut genome = crate::des::general::soccer_genome::SoccerTeamGenome::default();
        genome.apply_defensive_line_band_permutation(permutation_index);
        sim.set_team_tactical_genome(Team::Home, genome);
        let defenders: Vec<usize> = sim
            .players
            .iter()
            .filter(|p| p.team == Team::Home && p.role == PlayerRole::Defender)
            .map(|p| p.id)
            .collect();
        park_players_except(&mut sim, &defenders);
        for &defender in &defenders {
            sim.players[defender].home_position =
                Vec2::new(sim.players[defender].home_position.x, 20.0);
            sim.players[defender].position = sim.players[defender].home_position;
        }
        sim.ball.holder = None;
        sim.ball.position = Vec2::new(40.0, 68.0);
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Away);

        let snapshot = WorldSnapshot::from_match(&sim);
        defenders
            .iter()
            .map(|&defender| {
                snapshot
                    .defensive_line_cushion_adjusted_target(
                        defender,
                        sim.players[defender].position,
                    )
                    .y
            })
            .sum::<f64>()
            / defenders.len() as f64
    };

    let high_line_y = target_average_y_for_band(0);
    let deeper_line_y = target_average_y_for_band(14);
    let starting_line_y = 20.0;
    let hard_deepest_y = 68.0 - DEFENSIVE_LINE_MAX_BEHIND_BALL_YARDS;
    assert!(
        high_line_y > starting_line_y + (hard_deepest_y - starting_line_y) * 0.60,
        "hard 40yd average band should pull the high-line permutation materially toward \
         the legal band under the grace period: high_avg={high_line_y}"
    );
    assert!(
        deeper_line_y > starting_line_y + (hard_deepest_y - starting_line_y) * 0.60,
        "hard 40yd average band should pull the deep-line permutation materially toward \
         the legal band under the grace period: deep_avg={deeper_line_y}"
    );
    assert!(
        (high_line_y - deeper_line_y).abs() < 1e-9,
        "genome permutations must not change the hard average band: high={high_line_y} deep={deeper_line_y}"
    );
}

#[test]
fn back_line_cushion_lets_one_wingback_overlap_while_holding_the_other_three() {
    // Reconciled rule: in possession the back-line cushion grants exactly ONE exemption —
    // an OVERLAPPING WINGBACK (an outside back clearly ahead of the line). That player is
    // left alone to bomb forward while the other three are still pulled up toward a high
    // ball. Defending and 50:50 phases grant no ordinary line exemption.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defenders: Vec<usize> = sim
        .players
        .iter()
        .filter(|p| p.team == Team::Home && p.role == PlayerRole::Defender)
        .map(|p| p.id)
        .collect();
    assert!(defenders.len() >= 4, "need a back four");
    // The widest-home-x defender is an outside back; the most central is a holder.
    let right_back = *defenders
        .iter()
        .max_by(|&&a, &&b| {
            sim.players[a]
                .home_position
                .x
                .total_cmp(&sim.players[b].home_position.x)
        })
        .unwrap();
    let center_back = *defenders
        .iter()
        .min_by(|&&a, &&b| {
            (sim.players[a].home_position.x - 40.0)
                .abs()
                .total_cmp(&(sim.players[b].home_position.x - 40.0).abs())
        })
        .unwrap();
    // Deep, flat line except the right back, who has overlapped high up the flank.
    for &d in &defenders {
        sim.players[d].position = Vec2::new(sim.players[d].home_position.x, 20.0);
    }
    sim.players[right_back].position = Vec2::new(sim.players[right_back].home_position.x, 78.0);
    // Home in possession with the ball high up the pitch.
    let holder = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role == PlayerRole::Forward)
        .map(|p| p.id)
        .unwrap();
    sim.players[holder].position = Vec2::new(50.0, 90.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(50.0, 90.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snap = WorldSnapshot::from_match(&sim);
    // The overlapping wingback is the one exemption: its decided move is untouched.
    let wb_target = Vec2::new(sim.players[right_back].home_position.x, 80.0);
    let wb_adjusted = snap.defensive_line_cushion_adjusted_target(right_back, wb_target);
    assert!(
        (wb_adjusted.y - wb_target.y).abs() < 1e-6,
        "the overlapping wingback is exempt and not pulled back: {wb_adjusted:?}"
    );
    // A holding central defender is still pulled UP toward the high ball.
    let cb_target = Vec2::new(sim.players[center_back].home_position.x, 22.0);
    let cb_adjusted = snap.defensive_line_cushion_adjusted_target(center_back, cb_target);
    assert!(
        cb_adjusted.y > cb_target.y + 1.0,
        "a holding defender steps up toward the high ball: {cb_adjusted:?}"
    );
}

#[test]
fn flank_overlap_directive_can_release_wingback_before_it_is_already_ahead() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defenders: Vec<usize> = sim
        .players
        .iter()
        .filter(|p| p.team == Team::Home && p.role == PlayerRole::Defender)
        .map(|p| p.id)
        .collect();
    let right_back = *defenders
        .iter()
        .max_by(|&&a, &&b| {
            sim.players[a]
                .home_position
                .x
                .total_cmp(&sim.players[b].home_position.x)
        })
        .unwrap();
    let holder = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role == PlayerRole::Forward)
        .map(|p| p.id)
        .unwrap();
    assert_eq!(defenders.len(), 4, "need a back four");
    for &d in &defenders {
        sim.players[d].position = Vec2::new(sim.players[d].home_position.x, 30.0);
    }
    sim.players[holder].position = Vec2::new(sim.players[right_back].home_position.x, 64.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    let mut directive = TeamTacticalDirective::neutral(
        Team::Home,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
    );
    directive.flank_attack_policy = FlankAttackPolicy::PlayDownFlankHighCross;
    directive.flank_overlap_run_probability = 0.48;
    directive.risk_tolerance = 0.72;
    sim.central_brain.home_directive = directive;

    let target = Vec2::new(sim.players[right_back].home_position.x, 46.0);
    let snap = WorldSnapshot::from_match(&sim);
    let adjusted = snap.defensive_line_cushion_adjusted_target(right_back, target);

    assert!(
        (adjusted.y - target.y).abs() < 1e-9,
        "an active flank-overlap strategy should release the wingback target before it is already ahead: target={target:?} adjusted={adjusted:?}"
    );
}

