#[test]
fn goalkeeper_runtime_recovery_movement_improves_ball_goal_line_alignment() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper = sim.goalkeeper_for(Team::Home).expect("home keeper");
    let threat = 17;
    park_players_except(&mut sim, &[keeper, threat]);
    sim.players[threat].position = Vec2::new(58.0, 35.0);
    sim.ball.holder = Some(threat);
    sim.ball.position = sim.players[threat].position;
    sim.ball.last_touch_team = Some(Team::Away);

    let setup_snapshot = WorldSnapshot::from_match(&sim);
    let line_target = setup_snapshot.goalkeeper_ball_goal_tracking_target(Team::Home);
    let goal = Vec2::new(
        setup_snapshot.field_width * 0.5,
        setup_snapshot.own_goal_y_for(Team::Home),
    );
    let tangent = (setup_snapshot.ball.position - goal).normalized();
    let lateral = Vec2::new(-tangent.y, tangent.x);
    sim.players[keeper].position = (line_target + lateral * 2.0)
        .clamp_to_pitch(sim.config.field_width_yards, sim.config.field_length_yards);

    let before = WorldSnapshot::from_match(&sim);
    let before_score = goalkeeper_ball_goal_line_alignment_score(
        Team::Home,
        sim.players[keeper].position,
        &before,
    );
    let mut keeper_player = sim.players[keeper].clone();
    let intent = keeper_player.run_time_step(&before, None, None, &mut SeededRandom::new(19_218));
    let SoccerAction::MoveTo(runtime_target) = intent.action else {
        panic!(
            "off-line keeper should move back to the direct line, got {:?}",
            intent.action
        );
    };
    assert!(
        runtime_target.distance(before.goalkeeper_ball_goal_tracking_target(Team::Home)) < 1e-9,
        "keeper intent should target the exact ball-goal line: target={runtime_target:?}"
    );
    assert!(
        intent.sprint,
        "off-line keeper intent should request sprint recovery"
    );

    sim.apply_player_intent(PlayerIntent {
        player_id: keeper,
        action: SoccerAction::MoveTo(runtime_target),
        sprint: intent.sprint,
    });
    let after = WorldSnapshot::from_match(&sim);
    let after_score =
        goalkeeper_ball_goal_line_alignment_score(Team::Home, sim.players[keeper].position, &after);

    assert!(
        sim.players[keeper].movement_gait != MovementGait::Stand,
        "keeper should actively move when visibly off the ball-goal line"
    );
    assert!(
            after_score > before_score,
            "applied keeper movement should improve direct line alignment: before={before_score} after={after_score}"
        );
}

#[test]
fn goalkeeper_defensive_shape_tracks_direct_ball_goal_line() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper = sim.goalkeeper_for(Team::Home).expect("home keeper");
    let threat = 17;
    sim.players[keeper].position = Vec2::new(25.0, 8.0);
    sim.players[threat].position = Vec2::new(58.0, 35.0);
    sim.ball.holder = Some(threat);
    sim.ball.position = sim.players[threat].position;
    sim.ball.last_touch_team = Some(Team::Away);

    let snapshot = WorldSnapshot::from_match(&sim);
    let line_target = snapshot.goalkeeper_ball_goal_tracking_target(Team::Home);
    let target = snapshot.defensive_shape_for(keeper, sim.players[keeper].home_position);
    let assignment =
        snapshot.defensive_assignment_for(keeper, sim.players[keeper].home_position, false);
    let goal = Vec2::new(
        snapshot.field_width * 0.5,
        snapshot.own_goal_y_for(Team::Home),
    );
    let line_distance = segment_distance_to_point(goal, snapshot.ball.position, target);
    let line_projection = segment_projection_factor(goal, snapshot.ball.position, target);
    let options = sim.players[keeper].defensive_action_options(
        &snapshot,
        snapshot.tactical_directive(Team::Home),
        snapshot.dt_seconds,
    );
    let shape = options
        .iter()
        .find(|option| option.label == "defend-shape")
        .expect("keeper shape option");
    let roam = options
        .iter()
        .find(|option| option.label == "defend-roam")
        .expect("keeper roam option");

    assert!(
            line_distance < 1e-9 && (0.0..=1.0).contains(&line_projection),
            "keeper target should sit directly on the ball-goal line: target={target:?} line_distance={line_distance} projection={line_projection}"
        );
    assert!(
            assignment.distance(line_target) < 1e-9,
            "keeper defensive assignment should bypass generic mark/spacing sampling: assignment={assignment:?} line_target={line_target:?}"
        );
    assert!(
            shape.probability >= 0.97,
            "keeper should almost always prefer ball-goal-line shape tracking: shape={shape:?} roam={roam:?}"
        );
    assert!(
            roam.probability <= 0.03,
            "keeper roam should be rare unless making a close intervention: shape={shape:?} roam={roam:?}"
        );

    sim.players[keeper].position = Vec2::new(40.0, 7.0);
    sim.players[threat].position = Vec2::new(40.5, 7.5);
    sim.ball.holder = Some(threat);
    sim.ball.position = sim.players[threat].position;
    let close_setup_snapshot = WorldSnapshot::from_match(&sim);
    let close_line_target = close_setup_snapshot.goalkeeper_ball_goal_tracking_target(Team::Home);
    sim.players[keeper].position = close_line_target;
    let close_snapshot = WorldSnapshot::from_match(&sim);
    let close_goal = Vec2::new(
        close_snapshot.field_width * 0.5,
        close_snapshot.own_goal_y_for(Team::Home),
    );
    let close_line_distance =
        segment_distance_to_point(close_goal, close_snapshot.ball.position, close_line_target);
    let close_projection =
        segment_projection_factor(close_goal, close_snapshot.ball.position, close_line_target);
    assert!(
            close_line_distance < 1e-9 && (0.0..1.0).contains(&close_projection),
            "close keeper target must stay between the ball and goal instead of overshooting: target={close_line_target:?} projection={close_projection}"
        );
    assert!(
            close_line_target.distance(close_snapshot.ball.position) >= 0.70,
            "keeper should not target the ball endpoint when holding the direct line: target={close_line_target:?} ball={:?}",
            close_snapshot.ball.position
        );
    let close_options = sim.players[keeper].defensive_action_options(
        &close_snapshot,
        close_snapshot.tactical_directive(Team::Home),
        close_snapshot.dt_seconds,
    );
    let close_shape = close_options
        .iter()
        .find(|option| option.label == "defend-shape")
        .expect("close keeper shape option");
    let close_tackle = close_options
        .iter()
        .find(|option| option.label == "tackle")
        .expect("close keeper tackle option");
    assert!(
        close_tackle.legal,
        "test setup should make keeper intervention legal: {close_tackle:?}"
    );
    assert!(
            close_shape.probability >= 0.95,
            "keeper should keep at least 95% ball-goal-line tracking even when a close intervention is legal: shape={close_shape:?} tackle={close_tackle:?}"
        );

    let mut lp_snapshot = snapshot.clone();
    lp_snapshot
        .formation_lp_guidance
        .push(SoccerFormationLpPlayerGuidance {
            team: Team::Home,
            player_id: keeper,
            slot: 0,
            current: sim.players[keeper].position,
            target: Vec2::new(16.0, line_target.y + 6.0),
            formation_anchor: sim.players[keeper].home_position,
            pressure_target: None,
            recommended_move: Vec2::new(-10.0, 6.0),
            target_velocity: Vec2::zero(),
            target_acceleration: Vec2::zero(),
            local_mpc_guidance: false,
            recommended_move_yards: 11.7,
            recommended_speed_yps: 0.0,
            recommended_acceleration_yps2: 0.0,
            formation_error_yards: 0.0,
            movement_error_yards: 11.7,
            pair_error_yards: 0.0,
            role_line_error_yards: 0.0,
            pressure_error_yards: 0.0,
            fore_aft_speed_error_yps: 0.0,
            pressure_weight: 1.0,
            speed_match_weight: 0.0,
            alignment_weight: 1.0,
            reduced_cost_target_x: 0.0,
            reduced_cost_target_y: 0.0,
            solver_status: "optimal".to_string(),
            solver_objective: 0.0,
            solver_iterations: Some(1),
            solver_elapsed_ms: 0.0,
            variable_count: 1,
            constraint_count: 1,
        });
    let mut keeper_player = sim.players[keeper].clone();
    let intent =
        keeper_player.run_time_step(&lp_snapshot, None, None, &mut SeededRandom::new(26_118));
    let SoccerAction::MoveTo(runtime_target) = intent.action else {
        panic!(
            "keeper should choose defensive movement, got {:?}",
            intent.action
        );
    };
    assert!(
            runtime_target.distance(line_target) < 1e-9,
            "runtime keeper defense should ignore off-line LP guidance: runtime={runtime_target:?} line_target={line_target:?}"
        );
}

#[test]
fn goalkeeper_runtime_tracks_ball_goal_line_at_least_ninety_five_percent() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper = sim.goalkeeper_for(Team::Home).expect("home keeper");
    let threat = 17;
    park_players_except(&mut sim, &[keeper, threat]);
    sim.players[threat].position = Vec2::new(40.5, 7.5);
    sim.ball.holder = Some(threat);
    sim.ball.position = sim.players[threat].position;
    sim.ball.last_touch_team = Some(Team::Away);
    let setup_snapshot = WorldSnapshot::from_match(&sim);
    let line_target = setup_snapshot.goalkeeper_ball_goal_tracking_target(Team::Home);
    sim.players[keeper].position = line_target;

    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        snapshot.goalkeeper_direct_intervention_is_safe(keeper),
        "test setup should permit a rare legal keeper intervention"
    );
    let options = sim.players[keeper].defensive_action_options(
        &snapshot,
        snapshot.tactical_directive(Team::Home),
        snapshot.dt_seconds,
    );
    let tackle = options
        .iter()
        .find(|option| option.label == "tackle")
        .expect("keeper tackle option");
    assert!(
            tackle.legal && tackle.score > 0.0,
            "legal keeper intervention should remain in the option table for close-ball emergencies: {tackle:?}"
        );

    let mut line_tracking = 0usize;
    let mut legal_interventions = 0usize;
    let samples = 512usize;
    for seed in 0..samples {
        let mut keeper_player = sim.players[keeper].clone();
        let intent =
            keeper_player.run_time_step(&snapshot, None, None, &mut SeededRandom::new(seed as u32));
        match intent.action {
            SoccerAction::MoveTo(target) if target.distance(line_target) < 1e-9 => {
                line_tracking += 1;
            }
            SoccerAction::Tackle { .. } => {
                legal_interventions += 1;
            }
            other => {
                panic!(
                        "keeper should either track the direct line or make a legal intervention, got {other:?}"
                    );
            }
        }
    }

    let line_share = line_tracking as f64 / samples as f64;
    assert!(
            line_share >= 0.95,
            "keeper should track the ball-goal line at least 95% of runtime decisions; line={line_tracking} interventions={legal_interventions} samples={samples}"
        );
}

