#[test]
fn autonomous_goal_kick_taker_releases_restart_instead_of_dribbling() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::GoalKick,
        awarded_team: Team::Home,
        position: Vec2::new(40.0, 10.0),
    });
    let taker = sim.ball.holder.expect("goal kick taker");
    let snapshot = WorldSnapshot::from_match(&sim);
    let mut taker_agent = sim.players[taker].clone();
    let mut rng = mulberry32(7_501);

    assert_eq!(
        snapshot
            .ball
            .last_decision
            .as_ref()
            .map(|d| d.action.as_str()),
        Some("goal-kick")
    );
    assert!(held_restart_action_for_snapshot(&snapshot, taker).is_some());
    assert!(!learned_action_label_is_legal("dribble", &snapshot, taker));
    assert!(learned_action_label_is_legal(
        "aerial-pass",
        &snapshot,
        taker
    ));

    let intent = taker_agent.run_time_step(&snapshot, None, None, &mut rng);
    assert!(
        matches!(intent.action, SoccerAction::Pass { .. }),
        "goal kick should release with a pass-like restart action: {:?}",
        intent.action
    );
    assert_eq!(
        taker_agent
            .last_decision
            .as_ref()
            .map(|decision| decision.action.as_str()),
        Some("goal-kick")
    );

    sim.apply_player_intent(intent);
    assert_eq!(sim.ball.holder, None);
    assert!(sim.pending_pass.is_some());
    assert_eq!(
        sim.ball.last_decision.as_ref().map(|d| d.action.as_str()),
        Some("goal-kick")
    );
}

#[test]
fn human_throw_in_motion_holds_until_pass_release() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::ThrowIn,
        awarded_team: Team::Home,
        position: Vec2::new(0.0, 64.0),
    });
    let taker = sim.ball.holder.expect("throw-in taker");
    let target = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.id != taker)
        .map(|player| player.id)
        .expect("home throw-in target");
    let snapshot = WorldSnapshot::from_match(&sim);
    let mut taker_agent = sim.players[taker].clone();
    let mut rng = mulberry32(7_502);
    let move_input = HumanInputFrame {
        pace: 0,
        controller_slot: 0,
        player_id: Some(taker),
        seq: 1,
        axis: Vec2::new(1.0, 0.0),
        sprint: true,
        pass: false,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: None,
    };

    let hold_intent = taker_agent.run_time_step(&snapshot, Some(&move_input), None, &mut rng);
    match hold_intent.action {
        SoccerAction::MoveTo(target) => {
            assert!(target.distance(sim.players[taker].position) < 0.01)
        }
        other => panic!("human motion should hold restart, got {other:?}"),
    }
    assert_eq!(
        taker_agent
            .last_decision
            .as_ref()
            .map(|decision| decision.action.as_str()),
        Some("hold-restart")
    );

    sim.apply_player_intent(hold_intent);
    sim.integrate_ball();
    assert_eq!(sim.ball.holder, Some(taker));
    assert!(sim.pending_pass.is_none());
    assert_eq!(
        sim.ball.last_decision.as_ref().map(|d| d.action.as_str()),
        Some("throw-in")
    );

    let snapshot = WorldSnapshot::from_match(&sim);
    let pass_input = HumanInputFrame {
        pace: 0,
        controller_slot: 0,
        player_id: Some(taker),
        seq: 2,
        axis: Vec2::zero(),
        sprint: false,
        pass: true,
        pass_flight: PassFlight::Floor,
        shoot: false,
        action: None,
        target_player: Some(target),
    };
    let release_intent = taker_agent.run_time_step(&snapshot, Some(&pass_input), None, &mut rng);
    match release_intent.action {
        SoccerAction::Pass {
            target_player,
            flight,
            ..
        } => {
            assert_eq!(target_player, Some(target));
            assert_eq!(flight, PassFlight::Aerial);
        }
        other => panic!("throw-in pass should release restart, got {other:?}"),
    }
    assert_eq!(
        taker_agent
            .last_decision
            .as_ref()
            .map(|decision| decision.action.as_str()),
        Some("throw-in")
    );

    sim.apply_player_intent(release_intent);
    assert_eq!(sim.ball.holder, None);
    assert_eq!(
        sim.pending_pass
            .as_ref()
            .map(|pass| (pass.target, pass.flight)),
        Some((Some(target), PassFlight::Aerial))
    );
}

#[test]
fn defender_between_ball_and_goal_can_physically_block_shot() {
    let mut saw_block = false;
    for seed in 0..240 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            dt_seconds: 0.2,
            seed,
            ..Default::default()
        });
        let attacker = 9;
        let blocker = 13;
        sim.players[attacker].position = Vec2::new(40.0, 103.0);
        for away in 11..22 {
            sim.players[away].position = Vec2::new(74.0, 18.0 + away as f64 * 2.0);
        }
        sim.players[blocker].position = Vec2::new(40.0, 106.0);
        sim.players[blocker].skills.defending = 10.0;
        sim.players[blocker].skills.defensive_tracking = 10.0;
        sim.players[blocker].skills.aggression = 10.0;
        sim.players[blocker].skills.strength = 10.0;

        sim.ball.holder = None;
        sim.ball.position = sim.players[attacker].position;
        sim.ball.velocity = Vec2::new(0.0, mph_to_yps(58.0));
        sim.ball.last_touch_team = Some(Team::Home);
        sim.pending_shot = Some(PendingShot {
            team: Team::Home,
            shooter: attacker,
            origin: sim.players[attacker].position,
        });

        sim.integrate_ball();

        if sim.events.iter().any(|event| event.kind == "shot-blocked") {
            saw_block = true;
            assert_eq!(sim.stats.shot_blocks_away, 1);
            break;
        }
    }
    assert!(saw_block);
}

#[test]
fn goal_restart_sets_center_kickoff_for_conceding_team() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());

    sim.score_goal(Team::Home);
    // Goals now hold a brief celebration before the kickoff; advance through it.
    while sim.goal_celebration_remaining_ticks > 0 {
        sim.run_time_step();
    }

    let center = Vec2::new(
        sim.config.field_width_yards * 0.5,
        sim.config.field_length_yards * 0.5,
    );
    let holder_id = sim.ball.holder.expect("kickoff holder");
    let holder = sim
        .players
        .iter()
        .find(|player| player.id == holder_id)
        .expect("holder player");
    assert_eq!(sim.score_home, 1);
    assert_eq!(sim.score_away, 0);
    assert_eq!(holder.team, Team::Away);
    assert_eq!(sim.ball.position, center);
    assert_eq!(holder.position, center);
    assert_kickoff_shape(&sim, Team::Away);
    assert_eq!(sim.ball.velocity, Vec2::zero());
    assert_eq!(sim.ball.last_touch_team, Some(Team::Away));
    assert_eq!(
        sim.ball
            .last_decision
            .as_ref()
            .expect("ball decision")
            .action,
        "kickoff"
    );
    assert!(sim
        .events
        .iter()
        .any(|event| event.kind == "goal" && event.team == Some(Team::Home)));
    assert!(sim
        .events
        .iter()
        .any(|event| event.kind == "kickoff" && event.team == Some(Team::Away)));
}

#[test]
fn opening_kickoff_arms_no_double_touch_guard_on_first_match_step() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 5.0,
        seed: 91,
        ..Default::default()
    });
    // A pristine constructed match: the ball and the home kickoff taker are on the
    // centre spot and nothing has been played yet, so no guard is armed.
    let taker = sim.ball.holder.expect("opening kickoff holder");
    assert_eq!(sim.restart_double_touch_guard, None);

    // The first real match step lazily brings the opening kickoff under the
    // no-double-touch rule (the taker may not be the next to control the ball).
    sim.run_time_step();
    assert_eq!(sim.restart_double_touch_guard, Some(taker));
}

#[test]
fn sandbox_match_off_centre_ball_does_not_arm_opening_kickoff_guard() {
    // Mirrors how decision/serialization fixtures stage their own scenarios: the ball
    // is hijacked to a non-centre spot, so the pristine opening-kickoff pattern does
    // not match and the lazy stage leaves the guard alone.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 5.0,
        seed: 91,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    let holder = 5;
    sim.ball.holder = Some(holder);
    sim.ball.position = Vec2::new(40.0, 40.0);
    sim.players[holder].position = sim.ball.position;

    sim.run_time_step();

    assert_eq!(sim.restart_double_touch_guard, None);
}

#[test]
fn kickoff_arms_no_double_touch_guard_and_clears_on_another_touch() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.score_goal(Team::Home);
    // Goals now hold a brief celebration before the kickoff; advance through it.
    while sim.goal_celebration_remaining_ticks > 0 {
        sim.run_time_step();
    }
    let taker = sim.ball.holder.expect("kickoff holder");

    // The kickoff taker may not touch the ball twice in a row.
    assert_eq!(sim.restart_double_touch_guard, Some(taker));

    // ...and is forced to play it to a teammate (held restart), not dribble it away.
    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(held_restart_action_for_snapshot(&snapshot, taker).is_some());

    // The taker touching again does NOT clear their own guard.
    sim.record_possession_touch(taker);
    assert_eq!(sim.restart_double_touch_guard, Some(taker));

    // Any other player's touch clears it — the no-double-touch rule is satisfied.
    let other = sim
        .players
        .iter()
        .find(|p| p.id != taker)
        .map(|p| p.id)
        .expect("another player");
    sim.record_possession_touch(other);
    assert_eq!(sim.restart_double_touch_guard, None);
}

#[test]
fn restart_double_touch_guard_lets_a_teammate_collect_not_stall() {
    // The taker can't re-control after a restart — but the ball must NOT stall at its feet when
    // the taker is the closest player. The guard is passed INTO the controller search, so the
    // taker is excluded from candidacy and the nearest OTHER player (a team-mate receiving the
    // restart) collects the loose ball. (Pre-fix, filtering the single nearest to None left the
    // ball dead at the taker's feet — the opening-kickoff stall.)
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let taker = 6;
    let teammate = 7;
    park_players_except(&mut sim, &[taker, teammate]);
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.pending_pass = None;
    sim.restart_double_touch_guard = Some(taker);
    // Taker closest to the loose ball; the team-mate is just behind, still within control range.
    sim.players[taker].position = Vec2::new(40.3, 60.0);
    sim.players[teammate].position = Vec2::new(40.9, 60.0);

    sim.run_ball_time_step();

    assert_eq!(
        sim.ball.holder,
        Some(teammate),
        "a team-mate must collect the restart (guarded taker excluded), not stall the ball"
    );
}

#[test]
fn restart_taker_double_touch_guard_armed_for_throw_in_and_goal_kick() {
    // The no-double-touch guard must arm on EVERY restart kind taken through the central
    // restart path — throw-ins and goal kicks included, not just kickoffs.
    for kind in [BallRestartKind::ThrowIn, BallRestartKind::GoalKick] {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let spot = match kind {
            BallRestartKind::GoalKick => Vec2::new(40.0, 6.0),
            _ => Vec2::new(0.0, 60.0),
        };
        sim.apply_restart(BallRestart {
            kind,
            awarded_team: Team::Home,
            position: spot,
        });
        let taker = sim.ball.holder.expect("restart taker");
        assert_eq!(
            sim.restart_double_touch_guard,
            Some(taker),
            "guard should arm for {kind:?}"
        );
        // The taker re-touching does not clear it; another player's touch does.
        sim.record_possession_touch(taker);
        assert_eq!(sim.restart_double_touch_guard, Some(taker));
        let other = sim
            .players
            .iter()
            .find(|p| p.id != taker)
            .map(|p| p.id)
            .expect("another player");
        sim.record_possession_touch(other);
        assert_eq!(sim.restart_double_touch_guard, None);
    }
}

#[test]
fn goal_kick_controlled_inside_the_box_is_retaken() {
    // Law 16: the ball must leave the penalty area on the first touch. A goal kick brought
    // under control by a teammate while STILL inside the box did not clear the area, so it
    // is retaken (the outcome backstop, independent of how the keeper was steered).
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let spot = Vec2::new(40.0, 6.0);
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::GoalKick,
        awarded_team: Team::Home,
        position: spot,
    });
    let keeper = sim.goalkeeper_for(Team::Home).expect("home keeper");
    assert_eq!(sim.goal_kick_must_clear_box, Some((Team::Home, spot)));
    assert_eq!(sim.stats.goal_kicks_home, 1);

    // The kick is released and a teammate brings it under control INSIDE the box.
    let in_box = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.id != keeper)
        .map(|p| p.id)
        .expect("home teammate");
    sim.players[in_box].position = Vec2::new(sim.config.field_width_yards * 0.5, 9.0);
    sim.ball.holder = None;
    sim.apply_ball_outcome(BallStepOutcome::Controlled {
        holder: in_box,
        holder_team: Team::Home,
        possession_result: BallPossessionResult::PassCompleted(Team::Home),
        untargeted_long_ball: None,
    });

    // Retaken: the keeper holds again and the must-clear guard is re-armed.
    assert_eq!(sim.ball.holder, Some(keeper));
    assert_eq!(sim.goal_kick_must_clear_box, Some((Team::Home, spot)));
    assert_eq!(sim.stats.goal_kicks_home, 2);
}

#[test]
fn goal_kick_controlled_outside_the_box_is_legal_and_clears_the_guard() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let spot = Vec2::new(40.0, 6.0);
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::GoalKick,
        awarded_team: Team::Home,
        position: spot,
    });
    let keeper = sim.goalkeeper_for(Team::Home).expect("home keeper");
    let outlet = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.id != keeper)
        .map(|p| p.id)
        .expect("home teammate");
    // Received OUTSIDE the box (y=30 is beyond the 18-yard line).
    sim.players[outlet].position = Vec2::new(sim.config.field_width_yards * 0.5, 30.0);
    sim.ball.holder = None;
    sim.apply_ball_outcome(BallStepOutcome::Controlled {
        holder: outlet,
        holder_team: Team::Home,
        possession_result: BallPossessionResult::PassCompleted(Team::Home),
        untargeted_long_ball: None,
    });

    // Legal: no retake, the guard is retired, the outlet keeps the ball.
    assert_eq!(sim.ball.holder, Some(outlet));
    assert_eq!(sim.goal_kick_must_clear_box, None);
    assert_eq!(sim.stats.goal_kicks_home, 1);
}

#[test]
fn goal_kick_guard_clears_the_instant_the_ball_leaves_the_box() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let spot = Vec2::new(40.0, 6.0);
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::GoalKick,
        awarded_team: Team::Home,
        position: spot,
    });
    assert_eq!(sim.goal_kick_must_clear_box, Some((Team::Home, spot)));

    // Ball still inside the box: guard stays armed.
    sim.ball.position = Vec2::new(40.0, 12.0);
    sim.update_goal_kick_clearance();
    assert_eq!(sim.goal_kick_must_clear_box, Some((Team::Home, spot)));

    // Ball clears the 18-yard line: the kick is legally in play, guard retires.
    sim.ball.position = Vec2::new(40.0, 24.0);
    sim.update_goal_kick_clearance();
    assert_eq!(sim.goal_kick_must_clear_box, None);
}

#[test]
fn held_restart_pushes_encroaching_opponents_back_ten_yards() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let spot = Vec2::new(40.0, 60.0);
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::FreeKick,
        awarded_team: Team::Home,
        position: spot,
    });
    assert_eq!(sim.ball.position, spot);

    // An Away (defending) outfielder creeps to within ~3yd of the ball.
    let keeper = sim.goalkeeper_for(Team::Away);
    let opponent = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && Some(p.id) != keeper)
        .map(|p| p.id)
        .expect("away outfielder");
    sim.players[opponent].position = spot + Vec2::new(3.0, 1.0);

    sim.enforce_restart_keepout_for(opponent);

    let dist = sim.players[opponent].position.distance(spot);
    assert!(
        dist >= RESTART_OPPONENT_KEEPOUT_YARDS - 1e-6,
        "encroaching opponent should be held 10yd off the ball, got {dist}"
    );

    // The taker's own teammate near the spot is never pushed away.
    let teammate = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && sim.ball.holder != Some(p.id))
        .map(|p| p.id)
        .expect("home teammate");
    let near = spot + Vec2::new(2.0, 0.0);
    sim.players[teammate].position = near;
    sim.enforce_restart_keepout_for(teammate);
    assert_eq!(sim.players[teammate].position, near);
}

#[test]
fn throw_in_holds_opponents_two_yards_off_the_ball() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let spot = Vec2::new(0.0, 60.0);
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::ThrowIn,
        awarded_team: Team::Home,
        position: spot,
    });

    let keeper = sim.goalkeeper_for(Team::Away);
    let opponent = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && Some(p.id) != keeper)
        .map(|p| p.id)
        .expect("away outfielder");

    // An opponent crowding to within ~1yd of the throw is pushed out to 2yd (Law 15),
    // NOT the full 10yd a kickoff/free-kick/corner/goal-kick demands.
    sim.players[opponent].position = spot + Vec2::new(1.0, 0.2);
    sim.enforce_restart_keepout_for(opponent);
    let dist = sim.players[opponent].position.distance(spot);
    assert!(
        (dist - THROW_IN_OPPONENT_KEEPOUT_YARDS).abs() < 1e-6,
        "throw-in opponent should be held exactly 2yd off the ball, got {dist}"
    );

    // An opponent already beyond 2yd (but inside 10yd) is left alone — the long
    // keep-out does not apply to throw-ins.
    let near = spot + Vec2::new(4.0, 0.0);
    sim.players[opponent].position = near;
    sim.enforce_restart_keepout_for(opponent);
    assert_eq!(
        sim.players[opponent].position, near,
        "throw-in keep-out is only 2yd — a defender 4yd away is not pushed back"
    );
}

#[test]
fn throw_in_defenders_drop_behind_ball_because_offside_is_off() {
    for (throwing_team, defending_team, spot) in [
        (Team::Home, Team::Away, Vec2::new(0.0, 60.0)),
        (Team::Away, Team::Home, Vec2::new(80.0, 60.0)),
    ] {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            learning_enabled: false,
            learning_logging_enabled: false,
            formation_lp_enabled: true,
            max_human_players: 0,
            ..Default::default()
        });
        sim.apply_restart(BallRestart {
            kind: BallRestartKind::ThrowIn,
            awarded_team: throwing_team,
            position: spot,
        });
        let line_y = throw_in_no_offside_defender_line_y(
            defending_team,
            spot.y,
            sim.config.field_length_yards,
        );
        let defenders = sim
            .players
            .iter()
            .filter(|player| player.team == defending_team && player.role == PlayerRole::Defender)
            .collect::<Vec<_>>();
        assert!(!defenders.is_empty());
        for defender in defenders {
            let depth = (spot.y - defender.position.y) * defending_team.attack_dir();
            assert!(
                depth >= THROW_IN_NO_OFFSIDE_DEFENDER_DEPTH_YARDS - 1e-6,
                "{defending_team:?} defender {} should stage at least 25yd goal-side of throw-in ball, got {depth}",
                defender.id
            );
            assert!((defender.position.y - line_y).abs() < 1e-6);
        }

        let before = WorldSnapshot::from_match(&sim);
        let mut rng = mulberry32(25_015);
        sim.central_brain.run_time_step(&before, &mut rng);
        let solved = WorldSnapshot::from_match(&sim);
        let lp_targets = solved
            .formation_lp_guidance
            .iter()
            .filter(|guidance| guidance.team == defending_team)
            .filter(|guidance| {
                sim.players
                    .iter()
                    .find(|player| player.id == guidance.player_id)
                    .is_some_and(|player| player.role == PlayerRole::Defender)
            })
            .collect::<Vec<_>>();
        assert!(!lp_targets.is_empty());
        for guidance in lp_targets {
            let depth = (spot.y - guidance.target.y) * defending_team.attack_dir();
            assert!(
                depth >= THROW_IN_NO_OFFSIDE_DEFENDER_DEPTH_YARDS - 1e-6,
                "{defending_team:?} defender {} LP target should stay at least 25yd goal-side of throw-in ball, got {depth}",
                guidance.player_id
            );
        }
    }
}

#[test]
fn throw_in_defenders_track_no_offside_runners_up_to_thirty_yards() {
    for (throwing_team, defending_team, spot, runner_x) in [
        (Team::Home, Team::Away, Vec2::new(0.0, 60.0), 20.0),
        (Team::Away, Team::Home, Vec2::new(80.0, 60.0), 60.0),
    ] {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            learning_enabled: false,
            learning_logging_enabled: false,
            formation_lp_enabled: true,
            max_human_players: 0,
            ..Default::default()
        });
        sim.apply_restart(BallRestart {
            kind: BallRestartKind::ThrowIn,
            awarded_team: throwing_team,
            position: spot,
        });
        let runner_target = Vec2::new(
            runner_x,
            spot.y + throwing_team.attack_dir() * THROW_IN_RUNNER_TRACK_DEPTH_YARDS,
        );
        let call = sim.active_set_play.as_mut().expect("throw-in set play");
        let runner = call
            .assignments
            .iter_mut()
            .find(|assignment| assignment.role == SoccerSetPlayAssignmentRole::PrimaryRunner)
            .expect("primary throw-in runner");
        runner.target = runner_target;

        let before = WorldSnapshot::from_match(&sim);
        let mut rng = mulberry32(30_030);
        sim.central_brain.run_time_step(&before, &mut rng);
        let solved = WorldSnapshot::from_match(&sim);
        let defender_targets = solved
            .formation_lp_guidance
            .iter()
            .filter(|guidance| guidance.team == defending_team)
            .filter(|guidance| {
                solved
                    .players
                    .iter()
                    .find(|player| player.id == guidance.player_id)
                    .is_some_and(|player| player.role == PlayerRole::Defender)
            })
            .collect::<Vec<_>>();
        assert!(!defender_targets.is_empty());

        let deepest = defender_targets
            .iter()
            .max_by(|a, b| {
                let a_depth = (spot.y - a.target.y) * defending_team.attack_dir();
                let b_depth = (spot.y - b.target.y) * defending_team.attack_dir();
                a_depth
                    .partial_cmp(&b_depth)
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .expect("deepest defender target");
        let depth = (spot.y - deepest.target.y) * defending_team.attack_dir();
        assert!(
            (depth - THROW_IN_RUNNER_TRACK_DEPTH_YARDS).abs() < 1e-6,
            "{defending_team:?} defender {} should track the throw-in runner up to 30yd from the throw-in spot, got {depth}",
            deepest.player_id
        );
        assert!(
            (deepest.target.x - runner_target.x).abs() <= 18.0,
            "{defending_team:?} defender {} should lane-track the deep throw-in runner, target x {} runner x {}",
            deepest.player_id,
            deepest.target.x,
            runner_target.x
        );
    }
}

#[test]
fn corner_kick_holds_opponents_ten_yards_off_the_ball() {
    // Focused check that a corner (a held restart for the attacking team) engages the
    // full 10yd keep-out, not just free kicks.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let spot = Vec2::new(0.0, 0.0);
    sim.apply_restart(BallRestart {
        kind: BallRestartKind::CornerKick,
        awarded_team: Team::Home,
        position: spot,
    });

    // The taker (attacker) holds the ball; the keep-out applies to the DEFENDERS.
    let taker = sim.ball.holder.expect("corner taker holds the ball");
    assert_eq!(sim.players[taker].team, Team::Home);

    let keeper = sim.goalkeeper_for(Team::Away);
    let defender = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && Some(p.id) != keeper)
        .map(|p| p.id)
        .expect("away outfielder");
    // A defender crowds to ~4yd from the corner flag.
    sim.players[defender].position = spot + Vec2::new(3.0, 2.5);
    sim.enforce_restart_keepout_for(defender);
    let dist = sim.players[defender].position.distance(spot);
    assert!(
        dist >= RESTART_OPPONENT_KEEPOUT_YARDS - 1e-6,
        "a defender must be held 10yd off a corner, got {dist}"
    );

    // The corner taker's own teammate is never pushed away.
    let teammate = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && sim.ball.holder != Some(p.id))
        .map(|p| p.id)
        .expect("home teammate");
    let near = spot + Vec2::new(5.0, 1.0);
    sim.players[teammate].position = near;
    sim.enforce_restart_keepout_for(teammate);
    assert_eq!(
        sim.players[teammate].position, near,
        "the attacking team is not subject to its own corner keep-out"
    );
}

#[test]
