    sim.ball.holder = None;
    sim.ball.position = Vec2::new(outside_post_x, 100.0);
    sim.ball.velocity = (Vec2::new(outside_post_x, sim.config.field_length_yards + 8.0)
        - sim.ball.position)
        .normalized()
        * 44.0;
