#[test]
fn pomdp_and_q_state_track_receiver_openness_for_pass_completion() {
    let open = pass_quality_observation_for_marked_receiver(false);
    let marked = pass_quality_observation_for_marked_receiver(true);
    // The forward receiver is a visible option in BOTH cases: a 22yd-forward teammate with
    // a marker ~3yd off is "half-open", which a skilled passer keeps as a priced option
    // (the half-open forward exception) rather than hiding. The observation must still rate
    // the genuinely-open receiver clearly higher on openness AND completion.
    assert_eq!(open.visible_pass_options, 1);
    assert_eq!(marked.visible_pass_options, 1);
    assert!(
        open.best_pass_receiver_openness > marked.best_pass_receiver_openness + 0.30,
        "open receiver {:.3} should exceed marked {:.3}",
        open.best_pass_receiver_openness,
        marked.best_pass_receiver_openness
    );
    assert!(
        open.expected_pass_completion > marked.expected_pass_completion + 0.12,
        "open completion {:.3} should exceed marked {:.3}",
        open.expected_pass_completion,
        marked.expected_pass_completion
    );

    let state = SoccerMdpState {
        tick: 0,
        ball_zone_x: 4,
        ball_zone_y: 4,
        ball_grid: PitchGridAddress::default(),
        player_grid: PitchGridAddress::default(),
        receive_facing: FacingBucket::Unknown,
        action_facing: FacingBucket::North,
        possession_team: Some(Team::Home),
        phase: TacticalPhase::HomeBuildUp,
        score_diff_for_home: 0,
    };
    let open_key = SoccerQStateKey::from_parts(&state, &open, Team::Home, PlayerRole::Midfielder);
    let marked_key =
        SoccerQStateKey::from_parts(&state, &marked, Team::Home, PlayerRole::Midfielder);
    assert!(open_key.best_pass_receiver_openness_bin > marked_key.best_pass_receiver_openness_bin);
    assert!(open_key.expected_pass_completion_bin > marked_key.expected_pass_completion_bin);
}

#[test]
fn low_pressure_marked_receiver_favors_carry_over_forced_pass() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2261,
        ..Default::default()
    });
    let passer = 6;
    let receiver = 9;
    let marker = 12;
    let lane_marker = 13;
    park_players_except(&mut sim, &[passer, receiver, marker, lane_marker]);
    sim.players[passer].position = Vec2::new(40.0, 64.0);
    sim.players[passer].home_position = sim.players[passer].position;
    sim.players[passer].velocity = Vec2::new(0.0, 1.6);
    sim.players[passer].skills.dribbling = 7.4;
    sim.players[passer].skills.passing_completion_rate = 7.0;
    sim.players[passer].skills.decision_noise = 0.0;
    sim.players[passer].preferences.dribble_bias = 0.76;
    sim.players[passer].preferences.pass_bias = 1.0;
    sim.players[receiver].position = Vec2::new(54.0, 82.0);
    sim.players[receiver].velocity = Vec2::new(0.0, 1.0);
    sim.players[marker].position = Vec2::new(52.5, 80.5);
    sim.players[marker].velocity = Vec2::zero();
    sim.players[lane_marker].position = Vec2::new(49.5, 76.0);
    sim.players[lane_marker].velocity = Vec2::zero();
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.shared_positions.sync_from_players_and_ball(
        &sim.players,
        &sim.officials,
        &sim.ball,
        sim.tick,
        sim.clock_seconds,
    );

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(passer);
    assert!(
        observation.perceived_pressure < 0.22,
        "holder should have time: pressure={}",
        observation.perceived_pressure
    );
    assert!(
        observation.visible_pass_options >= 1,
        "test should expose a visible pass target"
    );
    assert!(
            low_pressure_patient_carry_preferred(&observation),
            "marked receiver should make patience carry preferred: completion={} openness={} lane={} space={}",
            observation.expected_pass_completion,
            observation.best_pass_receiver_openness,
            observation.floor_pass_lane_score,
            observation.forward_dribble_space_yards
        );

    let pass_targets = snapshot.ranked_visible_pass_targets(passer, 3);
    let options = sim.players[passer].possession_action_options(
        &observation,
        &snapshot.tactical_directive(Team::Home),
        pass_targets.len(),
        0,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let dribble_score = action_option_score(&options, "dribble");
    let carry_forward_score = action_option_score(&options, "carry-forward");
    let carry_out_left_score = action_option_score(&options, "carry-out-left");
    let carry_out_right_score = action_option_score(&options, "carry-out-right");
    let best_carry_out_score = carry_out_left_score.max(carry_out_right_score);
    let pass_score = action_option_score(&options, "pass1");
    assert!(
            carry_forward_score > pass_score * 1.15,
            "patient carry-forward should outrank forced pass: carry_forward={carry_forward_score} pass={pass_score}"
        );
    assert!(
            best_carry_out_score > pass_score * 0.82,
            "carrying out should remain viable while waiting for support: best_carry_out={best_carry_out_score} pass={pass_score}"
        );
    assert!(
            carry_out_left_score > 0.0 && carry_out_right_score > 0.0,
            "directional carry-out options should be available: left={carry_out_left_score} right={carry_out_right_score}"
        );
    assert!(
            // Dribble must clearly outrank the forced pass; robust 1.5x margin (the
            // exact ratio sits near 1.6x and is sensitive to scoring tweaks).
            dribble_score > pass_score * 1.5,
            "generic dribble/carry should outrank forced pass: dribble={dribble_score} pass={pass_score}"
        );

    let carry_probability = options
        .iter()
        .filter(|option| {
            matches!(
                option.label.as_str(),
                "dribble" | "carry-forward" | "carry-out-left" | "carry-out-right"
            )
        })
        .map(|option| option.probability)
        .sum::<f64>();
    let pass_probability = options
        .iter()
        .filter(|option| option.label.starts_with("pass"))
        .map(|option| option.probability)
        .sum::<f64>();
    assert!(
        carry_probability > pass_probability * 1.35,
        "deterministic agentic ordering should still price patient carries above forced passes: carry_p={carry_probability} pass_p={pass_probability} options={options:?}"
    );
}

#[test]
fn low_pressure_poor_pass_receives_learning_penalty_vs_carry() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2262,
        ..Default::default()
    });
    let passer = 6;
    let receiver = 9;
    let marker = 12;
    let lane_marker = 13;
    park_players_except(&mut sim, &[passer, receiver, marker, lane_marker]);
    sim.players[passer].position = Vec2::new(40.0, 64.0);
    sim.players[passer].home_position = sim.players[passer].position;
    sim.players[passer].velocity = Vec2::new(0.0, 1.6);
    sim.players[passer].skills.dribbling = 7.4;
    sim.players[receiver].position = Vec2::new(54.0, 82.0);
    sim.players[receiver].velocity = Vec2::new(0.0, 1.0);
    sim.players[marker].position = Vec2::new(52.5, 80.5);
    sim.players[marker].velocity = Vec2::zero();
    sim.players[lane_marker].position = Vec2::new(49.5, 76.0);
    sim.players[lane_marker].velocity = Vec2::zero();
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.shared_positions.sync_from_players_and_ball(
        &sim.players,
        &sim.officials,
        &sim.ball,
        sim.tick,
        sim.clock_seconds,
    );

    let before = WorldSnapshot::from_match(&sim);
    let observation = before.observation_for(passer);
    assert!(low_pressure_patient_carry_preferred(&observation));

    let poor_lateral_target = Vec2::new(55.0, 64.2);
    let mut poor_pass_after = before.clone();
    poor_pass_after.ball.holder = None;
    poor_pass_after.ball.position = poor_lateral_target;
    let mut poor_pass_decision = test_decision_trace(&before, passer, "pass");
    poor_pass_decision.action_target = Some(AgentActionTargetTrace {
        point: Some(poor_lateral_target),
        player_id: None,
        grid: Some(pitch_grid_address(
            poor_lateral_target,
            before.field_width,
            before.field_length,
        )),
        facing: facing_bucket_from_vector(poor_lateral_target - sim.players[passer].position),
        dribble_touch: None,
    });
    let pass_context = soccer_decision_context_for(
        passer,
        Team::Home,
        "pass",
        poor_pass_decision.action_target.as_ref(),
        &before,
        &poor_pass_after,
    );
    let penalty = low_pressure_forced_pass_penalty_points(
        &observation,
        &pass_context,
        PassFlight::Floor,
        false,
    );
    assert!(
        penalty > 0.20,
        "forced low-quality pass should carry a learning penalty: {penalty}"
    );
    let poor_pass_reward = soccer_transition_reward(
        &sim.players[passer],
        &poor_pass_decision,
        &before,
        &poor_pass_after,
        0,
        0,
        0,
        0,
        false,
    );

    let carry_target = Vec2::new(40.0, 67.2);
    let mut carry_after = before.clone();
    carry_after.ball.holder = Some(passer);
    carry_after.ball.position = carry_target;
    if let Some(player) = carry_after
        .players
        .iter_mut()
        .find(|player| player.id == passer)
    {
        player.position = carry_target;
    }
    let mut carry_decision = test_decision_trace(&before, passer, "carry-forward");
    carry_decision.action_target = Some(AgentActionTargetTrace {
        point: Some(carry_target),
        player_id: None,
        grid: Some(pitch_grid_address(
            carry_target,
            before.field_width,
            before.field_length,
        )),
        facing: facing_bucket_from_vector(carry_target - sim.players[passer].position),
        dribble_touch: None,
    });
    let carry_reward = soccer_transition_reward(
        &sim.players[passer],
        &carry_decision,
        &before,
        &carry_after,
        0,
        0,
        0,
        0,
        false,
    );

    assert!(
        carry_reward > poor_pass_reward + 0.35,
        "carry should beat forced poor pass: carry={carry_reward} pass={poor_pass_reward}"
    );
}

