#[test]
fn fifty_fifty_loose_ball_sends_two_nearest_teammates_to_compete() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_110,
        ..Default::default()
    });
    let first = 6;
    let second = 8;
    let opponent = 17;
    park_players_except(&mut sim, &[first, second, opponent]);
    sim.active_set_play = None;
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = None;
    sim.players[first].position = Vec2::new(38.3, 60.0);
    sim.players[second].position = Vec2::new(39.2, 62.0);
    sim.players[opponent].position = Vec2::new(41.6, 60.0);

    let snapshot = WorldSnapshot::from_match(&sim);
    let first_target = snapshot.loose_ball_recovery_target_for(first);
    let second_target = snapshot.loose_ball_recovery_target_for(second);
    assert_eq!(first_target, sim.ball.position);
    assert_eq!(second_target, sim.ball.position);

    let mut first_player = sim.players[first].clone();
    let first_intent =
        first_player.run_time_step(&snapshot, None, None, &mut SeededRandom::new(26_111));
    let mut second_player = sim.players[second].clone();
    let second_intent =
        second_player.run_time_step(&snapshot, None, None, &mut SeededRandom::new(26_112));
    for (name, intent, decision) in [
        (
            "first",
            first_intent,
            first_player.last_decision.as_ref().expect("first decision"),
        ),
        (
            "second",
            second_intent,
            second_player
                .last_decision
                .as_ref()
                .expect("second decision"),
        ),
    ] {
        let SoccerAction::MoveTo(target) = intent.action else {
            panic!("{name} teammate should attack the loose ball, got {intent:?}");
        };
        assert!(
            target.distance(sim.ball.position) < 1e-9,
            "{name} teammate should target the 50:50 ball: target={target:?}"
        );
        assert_eq!(decision.action, "recover");
    }
    assert!(
        first_player
            .last_decision
            .as_ref()
            .expect("first decision")
            .operation_order
            .iter()
            .any(|op| op == "fifty-fifty-duel"),
        "nearest player should enter the explicit 50:50 duel option"
    );
}

#[test]
fn non_elite_overheld_carry_gets_dense_learning_penalty() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_108,
        ..Default::default()
    });
    let holder = 6;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[holder].skills.dribbling = 7.0;
    sim.players[holder].skills.passing_completion_rate = 7.5;
    let target = sim.players[holder].position + Vec2::new(0.0, Team::Home.attack_dir() * 0.7);

    let before = WorldSnapshot::from_match(&sim);
    let mut after = before.clone();
    after.ball.holder = Some(holder);
    after.ball.position = target;
    if let Some(player) = after.players.iter_mut().find(|player| player.id == holder) {
        player.position = target;
    }

    let mut fresh_decision = test_decision_trace(&before, holder, "carry-forward");
    fresh_decision.observation.has_ball = true;
    fresh_decision.observation.perceived_pressure = 0.72;
    fresh_decision.observation.pressure_urgency = 0.78;
    fresh_decision.observation.immediate_dispossession_risk = 0.66;
    fresh_decision.observation.forward_dribble_space_yards = 8.0;
    fresh_decision.observation.actual_time_on_ball_seconds = 0.8;
    let mut overheld_decision = fresh_decision.clone();
    overheld_decision.observation.actual_time_on_ball_seconds = 7.1;

    let hold_penalty = excessive_hold_penalty_points(
        &overheld_decision.observation,
        ability01(sim.players[holder].skills.dribbling),
    );
    let fresh_reward = soccer_transition_reward(
        &sim.players[holder],
        &fresh_decision,
        &before,
        &after,
        0,
        0,
        0,
        0,
        false,
    );
    let overheld_reward = soccer_transition_reward(
        &sim.players[holder],
        &overheld_decision,
        &before,
        &after,
        0,
        0,
        0,
        0,
        false,
    );

    assert!(
        hold_penalty > 0.70,
        "pressured non-elite overhold should produce a material learning penalty: {hold_penalty}"
    );
    assert!(
            overheld_reward < fresh_reward - 0.65,
            "dense learner should punish overheld carry: fresh={fresh_reward} overheld={overheld_reward}"
        );
}

