#[test]
fn pressured_holder_can_protect_ball_with_body_shield() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_101,
        ..Default::default()
    });
    let holder = 8;
    let defender = 12;
    park_players_except(&mut sim, &[holder, defender]);
    sim.players[holder].position = Vec2::new(40.0, 70.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.4;
    sim.players[holder].skills.strength = 8.1;
    sim.players[defender].position = Vec2::new(41.1, 70.4);
    sim.players[defender].skills.defending = 7.8;
    sim.players[defender].skills.aggression = 7.2;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(holder);
    assert!(
        observation.nearest_opponent_distance <= 5.2,
        "defender should be close enough to force shielding"
    );
    let options = sim.players[holder].possession_action_options(
        &observation,
        &snapshot.tactical_directive(Team::Home),
        0,
        0,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let protect = options
        .iter()
        .find(|option| option.label == "protect-ball")
        .expect("protect-ball option");
    assert!(protect.legal);
    assert!(
        protect.score > 0.18,
        "protect-ball should be meaningful under pressure: {}",
        protect.score
    );
    assert!(learned_action_label_is_legal(
        "protect_ball",
        &snapshot,
        holder
    ));

    let plan = SoccerLearnedPlan {
        action: "protect_ball".to_string(),
        target_player: None,
        target_point: None,
        mpc_replan: None,
    };
    let (action, label) = sim.players[holder]
        .action_from_learned_plan(&plan, &snapshot, &observation)
        .expect("learned protect-ball plan");
    assert_eq!(label, "protect-ball");
    match action {
        SoccerAction::DribbleMove { kind, touch, .. } => {
            assert_eq!(kind, DribbleMoveKind::ProtectBall);
            assert!(touch.distance_yards <= 1.45);
        }
        other => panic!("expected protect-ball dribble, got {other:?}"),
    }
}

#[test]
fn granular_pressure_differentiates_closing_and_accelerating_opponents() {
    let sim = SoccerMatch::default_11v11(MatchConfig::default());
    let mut obs = WorldSnapshot::from_match(&sim).observation_for(8);
    obs.nearest_opponent_distance = 8.0;
    obs.neural_extended.nearest_opponent_closing_rate_yps = 0.0;
    obs.neural_extended.nearest_opponent_closing_accel_yps2 = 0.0;
    let still = granular_pressure_signal(&obs);

    obs.neural_extended.nearest_opponent_closing_rate_yps = 6.0;
    let closing = granular_pressure_signal(&obs);

    obs.neural_extended.nearest_opponent_closing_accel_yps2 = 12.0;
    let accelerating = granular_pressure_signal(&obs);

    obs.neural_extended.nearest_opponent_closing_accel_yps2 = -12.0;
    let braking = granular_pressure_signal(&obs);

    assert!(
        closing > still + 0.05,
        "a closing opponent reads as more pressure than a static one at the same \
             distance: closing={closing} still={still}"
    );
    assert!(
        accelerating > closing,
        "still accelerating in reads higher than constant-speed closing: \
             accel={accelerating} closing={closing}"
    );
    assert!(
        braking < closing,
        "a braking / pulling-out opponent eases pressure vs constant closing: \
             braking={braking} closing={closing}"
    );
}

#[test]
fn pressure_rising_signal_tracks_closing_defender() {
    let sim = SoccerMatch::default_11v11(MatchConfig::default());
    let mut observation = WorldSnapshot::from_match(&sim).observation_for(8);
    observation.nearest_opponent_distance = 4.0;

    // A defender sprinting straight in raises the signal.
    observation
        .neural_extended
        .nearest_opponent_closing_rate_yps = 6.0;
    let closing = pressure_rising_signal(&observation);
    assert!(
        closing > 0.45,
        "a fast-closing in-range defender should read as rising pressure: {closing}"
    );

    // Standing off / retreating defender: no rising pressure.
    observation
        .neural_extended
        .nearest_opponent_closing_rate_yps = -2.0;
    assert_eq!(pressure_rising_signal(&observation), 0.0);

    // Same closing speed but far away must not spike it.
    observation
        .neural_extended
        .nearest_opponent_closing_rate_yps = 6.0;
    observation.nearest_opponent_distance = 30.0;
    assert_eq!(pressure_rising_signal(&observation), 0.0);
}

