#[test]
fn protect_ball_leads_ball_to_far_side_of_body() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_134,
        ..Default::default()
    });
    let holder = 8;
    let defender = 12;
    park_players_except(&mut sim, &[holder, defender]);
    let holder_pos = Vec2::new(40.0, 70.0);
    let defender_pos = Vec2::new(43.0, 71.5);
    sim.players[holder].position = holder_pos;
    sim.players[holder].home_position = holder_pos;
    sim.players[defender].position = defender_pos;
    sim.ball.holder = Some(holder);
    sim.ball.position = holder_pos;

    let snapshot = WorldSnapshot::from_match(&sim);
    let target = snapshot.dribble_move_target_for_touch(
        holder,
        holder_pos,
        DribbleMoveKind::ProtectBall,
        DribbleTouchDecision::new(0, 1.0),
    );
    let to_target = target - holder_pos;
    let to_defender = defender_pos - holder_pos;
    // The shield lead must point AWAY from the defender (ball on the far side of
    // the body), so the body sits between the defender and the ball.
    assert!(
        dot(to_target, to_defender) < 0.0,
        "protect-ball should lead the ball to the far side of the body from the \
             defender: to_target={to_target:?} to_defender={to_defender:?}"
    );
}

#[test]
fn protect_ball_orbit_command_aims_the_ball_away_from_the_defender() {
    // The continuous carried-ball orbit (what sets ball.position every tick) must, on
    // protect-ball, point the ball to the FAR side of the body from the nearest defender.
    let facing = std::f64::consts::FRAC_PI_2; // carrier faces +y
    let to_defender = Vec2::new(1.0, 0.0); // defender is off to the carrier's +x
    let (dir, _radius, _through, _long_orbit, _winding_cap, _rate) = carried_ball_orbit_command(
        facing,
        Some(DribbleMoveKind::ProtectBall),
        1.6,
        Some(to_defender),
    );
    assert!(
        dot(dir, to_defender) < -0.5,
        "protect-ball orbit must aim the ball opposite the defender: dir={dir:?}"
    );
    // With no defender to shield from, it falls back to keeping the ball ahead of the body.
    let (ahead, _r, _t, _long, _cap, _rt) = carried_ball_orbit_command(
        facing,
        Some(DribbleMoveKind::ProtectBall),
        f64::INFINITY,
        None,
    );
    assert!(
        ahead.y > 0.9,
        "no defender → ball stays ahead of the body: {ahead:?}"
    );
}

#[test]
fn xavi_turn_orbit_keeps_far_side_and_winds_the_long_way() {
    let facing = std::f64::consts::FRAC_PI_2; // carrier faces +y
    let to_defender = Vec2::new(1.0, 0.0); // defender is off to the carrier's +x
    let (desired_dir, desired_radius, allow_through, prefer_long_orbit, winding_cap, orbit_rate) =
        carried_ball_orbit_command(
            facing,
            Some(DribbleMoveKind::XaviTurn),
            1.6,
            Some(to_defender),
        );
    assert!(
        dot(desired_dir, to_defender) < -0.80,
        "xavi-turn must keep the ball on the defender's far side: dir={desired_dir:?}"
    );
    assert!(
        !allow_through,
        "xavi-turn should go around the body/defender, not through the body line"
    );
    assert!(prefer_long_orbit, "xavi-turn must request the long orbit");
    assert!(
        winding_cap >= XAVI_TURN_MAX_ORBIT_RAD - 1e-9,
        "xavi-turn should allow the 300-degree cap, got {winding_cap}"
    );
    assert!(
        desired_radius >= CARRY_TIGHT_RADIUS_YARDS,
        "xavi-turn should remain close-control, got {desired_radius}"
    );

    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier_pos = Vec2::new(40.0, 60.0);
    sim.ball.position = carrier_pos + Vec2::new(0.0, 1.0);
    sim.ball.reset_carry_orbit();
    let mut rng = SeededRandom::new(29);
    for step in 0..40u64 {
        sim.ball.position = sim.ball.advance_carried_ball_orbit(
            step + 1,
            carrier_pos,
            desired_dir,
            desired_radius,
            allow_through,
            prefer_long_orbit,
            winding_cap,
            orbit_rate,
            1.0 / 30.0,
            sim.config.field_width_yards,
            sim.config.field_length_yards,
            &mut rng,
        );
    }
    let swept = sim.ball.carry_orbit_swept_rad.abs();
    assert!(
        swept >= XAVI_TURN_MIN_ORBIT_RAD - 0.03 && swept <= XAVI_TURN_MAX_ORBIT_RAD + 1e-9,
        "xavi-turn should sweep 280-300 degrees, swept {swept}"
    );
    assert!(
        dot(sim.ball.position - carrier_pos, to_defender) < -0.10,
        "xavi-turn should finish with the ball on the defender's far side: ball={:?}",
        sim.ball.position
    );
    assert!((XAVI_TURN_DISPOSSESSION_PROBABILITY - 0.10).abs() < 1e-12);
    assert_eq!(
        xavi_turn_tackle_success_cap(DribbleMoveKind::XaviTurn),
        Some(XAVI_TURN_TACKLE_SUCCESS_CAP)
    );
    assert!(
        dribble_dispossession_kind_multiplier(DribbleMoveKind::XaviTurn)
            < dribble_dispossession_kind_multiplier(DribbleMoveKind::ProtectBall)
    );
}

#[test]
fn xavi_turn_orbit_command_keeps_far_side_for_common_defender_bearings() {
    let facings = [
        0.0,
        std::f64::consts::FRAC_PI_2,
        std::f64::consts::PI,
        -std::f64::consts::FRAC_PI_2,
    ];
    for facing in facings {
        for defender_degrees in [0.0_f64, 45.0, 90.0, 135.0, 180.0, 225.0, 270.0, 315.0] {
            let defender_angle = defender_degrees.to_radians();
            let to_defender = Vec2::new(defender_angle.cos(), defender_angle.sin());
            let (desired_dir, _radius, allow_through, prefer_long_orbit, winding_cap, _rate) =
                carried_ball_orbit_command(
                    facing,
                    Some(DribbleMoveKind::XaviTurn),
                    1.6,
                    Some(to_defender),
                );
            assert!(
                dot(desired_dir, to_defender) <= -0.35,
                "xavi-turn must keep the ball on the far side for facing={facing}, \
                 defender_degrees={defender_degrees}: dir={desired_dir:?}"
            );
            assert!(!allow_through, "xavi-turn cannot cut through the body line");
            assert!(prefer_long_orbit, "xavi-turn must request a long orbit");
            assert!(
                winding_cap >= XAVI_TURN_MAX_ORBIT_RAD - 1e-9,
                "xavi-turn must preserve the 300-degree winding cap"
            );
        }
    }
}

#[test]
fn xavi_turn_orbit_command_sanitizes_non_finite_facing() {
    let (desired_dir, desired_radius, allow_through, prefer_long_orbit, winding_cap, orbit_rate) =
        carried_ball_orbit_command(
            f64::NAN,
            Some(DribbleMoveKind::XaviTurn),
            f64::INFINITY,
            Some(Vec2::new(f64::NAN, 1.0)),
        );
    assert!(
        desired_dir.x.is_finite() && desired_dir.y.is_finite(),
        "xavi-turn orbit direction must stay finite: {desired_dir:?}"
    );
    assert!(desired_radius.is_finite(), "radius must stay finite");
    assert!(orbit_rate.is_finite(), "orbit rate must stay finite");
    assert!(!allow_through, "xavi-turn cannot cut through the body line");
    assert!(
        prefer_long_orbit,
        "xavi-turn must still request a long orbit"
    );
    assert!(
        winding_cap >= XAVI_TURN_MAX_ORBIT_RAD - 1e-9,
        "xavi-turn must preserve the 300-degree winding cap"
    );
}

#[test]
fn pressured_carry_and_feint_orbits_keep_ball_away_from_defender() {
    // A pressured dribbler should not expose the ball on the defender's side while
    // carrying or feinting. The body should sit between defender and ball even when
    // the chosen action is not the explicit protect-ball label.
    let facing = std::f64::consts::FRAC_PI_2; // carrier faces +y
    let to_defender = Vec2::new(1.0, 0.0); // defender is tight on the carrier's +x side
    let (carry_dir, _carry_radius, _carry_through, _carry_long, _carry_cap, _carry_rate) =
        carried_ball_orbit_command(
            facing,
            Some(DribbleMoveKind::CarryForward),
            1.6,
            Some(to_defender),
        );
    assert!(
        dot(carry_dir, to_defender) < -0.35,
        "pressured carry should keep the ball on the far side of the body: dir={carry_dir:?}"
    );

    let (feint_dir, _feint_radius, _feint_through, _feint_long, _feint_cap, _feint_rate) =
        carried_ball_orbit_command(
            facing,
            Some(DribbleMoveKind::FakeLeftCutRight),
            1.6,
            Some(to_defender),
        );
    assert!(
        dot(feint_dir, to_defender) < -0.20,
        "pressured feint should still shield the ball from the defender: dir={feint_dir:?}"
    );
}

#[test]
fn protect_ball_orbit_settles_into_a_body_shield() {
    // Driving the orbit over several ticks, the protected ball swings to the far side of the
    // body and the geometric shield gate (which gates dispossession to ~0) starts to hold.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 8usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    let carrier_pos = Vec2::new(40.0, 60.0);
    sim.players[carrier].position = carrier_pos;
    sim.players[carrier].facing_yaw = std::f64::consts::FRAC_PI_2;
    sim.players[defender].position = Vec2::new(42.0, 60.0); // 2yd to the carrier's +x
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 61.0); // ball starts AHEAD of the body
    sim.ball.reset_carry_orbit();
    assert!(
        !sim.carrier_shields_ball_from_defender(carrier, defender),
        "ball ahead of the body is not yet shielding the side-on defender"
    );

    let to_defender = sim.players[defender].position - carrier_pos;
    let (desired_dir, desired_radius, allow_through, prefer_long_orbit, winding_cap, orbit_rate) =
        carried_ball_orbit_command(
            sim.players[carrier].facing_yaw,
            Some(DribbleMoveKind::ProtectBall),
            to_defender.len(),
            Some(to_defender.normalized()),
        );
    let mut rng = SeededRandom::new(11);
    for step in 0..30u64 {
        let pos = sim.ball.advance_carried_ball_orbit(
            step + 1,
            carrier_pos,
            desired_dir,
            desired_radius,
            allow_through,
            prefer_long_orbit,
            winding_cap,
            orbit_rate,
            sim.config.dt_seconds,
            sim.config.field_width_yards,
            sim.config.field_length_yards,
            &mut rng,
        );
        sim.ball.position = pos;
    }
    assert!(
        sim.carrier_shields_ball_from_defender(carrier, defender),
        "after settling the orbit the body must shield the ball from the defender; \
         ball={:?} carrier={carrier_pos:?} defender={:?}",
        sim.ball.position,
        sim.players[defender].position
    );
}

#[test]
fn xavi_turn_label_round_trips_and_folds_aliases() {
    // The new dribble label is a first-class member of the action vocabulary.
    assert_eq!(
        SoccerActionLabel::from_label("xavi-turn"),
        SoccerActionLabel::XaviTurn
    );
    assert_eq!(SoccerActionLabel::XaviTurn.as_str(), "xavi-turn");
    for alias in [
        "xaviturn",
        "xavi_turn",
        "la-pelopina",
        "shielded-turn",
        "turn-and-shield",
    ] {
        assert_eq!(
            SoccerActionLabel::from_label(alias).as_str(),
            "xavi-turn",
            "alias {alias} should fold onto xavi-turn"
        );
    }
    // The decision/execution layers resolve the label back to the move kind.
    assert_eq!(
        dribble_move_kind_for_action_label("xavi-turn"),
        Some(DribbleMoveKind::XaviTurn)
    );
    assert_eq!(DribbleMoveKind::XaviTurn.label(), "xavi-turn");
}

