#[test]
fn xavi_turn_flag_defaults_on_and_respects_config() {
    // The xavi-turn is live by default (unless a process-wide env flag pins it off for a
    // parity run), and the per-match config flag can always force it off.
    if std::env::var("DD_SOCCER_DISABLE_XAVI_TURN").is_err() {
        assert!(xavi_turn_enabled(&MatchConfig::default()));
        let sim = SoccerMatch::default_11v11(MatchConfig::default());
        assert!(WorldSnapshot::from_match(&sim).xavi_turn_enabled);
    }
    assert!(!xavi_turn_enabled(&MatchConfig {
        disable_xavi_turn: true,
        ..Default::default()
    }));
    let off = SoccerMatch::default_11v11(MatchConfig {
        disable_xavi_turn: true,
        ..Default::default()
    });
    assert!(!WorldSnapshot::from_match(&off).xavi_turn_enabled);
}

#[test]
fn xavi_turn_clean_steal_is_capped_at_ten_percent() {
    // The headline mechanic: while turning the man, a clean dispossession tops out at 10%
    // — tighter than a static body-shield (20%), and nothing for every other move.
    assert_eq!(
        xavi_turn_tackle_success_cap(DribbleMoveKind::XaviTurn),
        Some(XAVI_TURN_TACKLE_SUCCESS_CAP)
    );
    assert!((XAVI_TURN_TACKLE_SUCCESS_CAP - 0.10).abs() < 1e-9);
    assert_eq!(
        xavi_turn_tackle_success_cap(DribbleMoveKind::ProtectBall),
        Some(SHIELDED_HOLDER_TACKLE_SUCCESS_CAP)
    );
    assert!(XAVI_TURN_TACKLE_SUCCESS_CAP < SHIELDED_HOLDER_TACKLE_SUCCESS_CAP);
    for kind in [
        DribbleMoveKind::CarryForward,
        DribbleMoveKind::LeftCut,
        DribbleMoveKind::Nutmeg,
    ] {
        assert_eq!(xavi_turn_tackle_success_cap(kind), None);
    }
    // The move is also priced as the most secure dribble in the kind multiplier.
    assert!(
        dribble_dispossession_kind_multiplier(DribbleMoveKind::XaviTurn)
            < dribble_dispossession_kind_multiplier(DribbleMoveKind::ProtectBall)
    );
}

#[test]
fn xavi_turn_orbit_keeps_ball_on_far_side_and_arcs_around() {
    // The carried-ball orbit on a xavi-turn holds the ball on the FAR side of the defender
    // (like a shield) and arcs it AROUND the body (never through), swept a touch faster.
    let facing = std::f64::consts::FRAC_PI_2; // carrier faces +y
    let to_defender = Vec2::new(1.0, 0.0); // defender off to the carrier's +x
    let (dir, _radius, allow_through, prefer_long_orbit, winding_cap, rate) =
        carried_ball_orbit_command(
            facing,
            Some(DribbleMoveKind::XaviTurn),
            1.6,
            Some(to_defender),
        );
    assert!(
        dot(dir, to_defender) < -0.5,
        "xavi-turn orbit must keep the ball opposite the defender: dir={dir:?}"
    );
    assert!(
        !allow_through,
        "the ball arcs around the body, never through it"
    );
    assert!(prefer_long_orbit, "xavi-turn must request the long orbit");
    assert!(
        winding_cap >= XAVI_TURN_MAX_ORBIT_RAD - 1e-9,
        "xavi-turn should preserve the 300-degree winding cap: {winding_cap}"
    );
    assert!(
        (rate - CARRY_ORBIT_XAVI_RATE_RAD_S).abs() < 1e-9,
        "xavi-turn uses its own sweep rate: rate={rate}"
    );
}

#[test]
fn xavi_turn_move_target_wheels_around_the_defender() {
    // The carrier's movement target traces the long way AROUND the defender: mostly
    // tangential (perpendicular to the defender axis), never stepping toward the defender.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 8usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    let carrier_pos = Vec2::new(40.0, 60.0);
    sim.players[carrier].position = carrier_pos;
    sim.players[carrier].home_position = carrier_pos;
    let defender_pos = Vec2::new(41.5, 60.0); // defender tight on the +x side
    sim.players[defender].position = defender_pos;
    sim.ball.holder = Some(carrier);
    sim.ball.position = carrier_pos;

    let snapshot = WorldSnapshot::from_match(&sim);
    let target = snapshot.dribble_move_target_for_touch(
        carrier,
        carrier_pos,
        DribbleMoveKind::XaviTurn,
        DribbleTouchDecision::new(0, 1.2),
    );
    let to_target = target - carrier_pos;
    let to_defender = defender_pos - carrier_pos;
    assert!(
        dot(to_target, to_defender) < 0.0,
        "xavi-turn must wheel AWAY from the defender, never into them: to_target={to_target:?}"
    );
    assert!(
        (target.y - carrier_pos.y).abs() > (target.x - carrier_pos.x).abs(),
        "the turn should be dominated by the tangential (around-the-man) component: \
         to_target={to_target:?}"
    );
}

#[test]
fn xavi_turn_hold_up_contest_retains_possession() {
    // Same exposed-ball hold-up geometry that lets a strong defender rob a weak dribbler
    // mid-cut — but on a xavi-turn the 10% steal cap keeps the probability below the
    // dispossession threshold, so the carrier keeps the ball while turning the man.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 0;
    let attacker = 11;
    sim.players[defender].position = Vec2::new(40.0, 60.0);
    sim.players[defender].skills.defending = 9.4;
    sim.players[defender].skills.aggression = 8.0;
    sim.players[attacker].position = Vec2::new(41.0, 60.0);
    sim.players[attacker].skills.dribbling = 2.0;
    sim.players[attacker].skills.first_touch = 2.0;
    sim.ball.holder = Some(attacker);
    sim.ball.position = Vec2::new(40.55, 60.0);
    let before = WorldSnapshot::from_match(&sim);
    sim.players[attacker].last_decision = Some(test_decision_trace(&before, attacker, "xavi-turn"));
    sim.players[defender].last_decision = Some(test_decision_trace(&before, defender, "defend"));
    assert!(
        !sim.carrier_shields_ball_from_defender(attacker, defender),
        "setup keeps the ball exposed, so the 10% cap (not the geometric shield) is what holds it"
    );

    sim.resolve_dribble_hold_up_contests();

    assert_eq!(
        sim.ball.holder,
        Some(attacker),
        "a xavi-turn carrier is not dispossessed by a hold-up contest (steal capped at 10%)"
    );
    assert!(!sim
        .events
        .iter()
        .any(|event| event.kind == "hold-up-dispossession"));
}

#[test]
fn xavi_turn_wheel_keeps_one_rotational_sense() {
    // Hardening: once the carrier is wheeling, the committed tangent must NOT reverse as the
    // defender's bearing sweeps the full circle through the turn — otherwise the pirouette
    // would unwind mid-move (and momentarily swing the ball back toward the defender). The
    // sense is taken from the carrier's angular momentum, so it is self-consistent all the way
    // around. (A naive per-tick goalward test flips twice per orbit — the bug this fixes.)
    let center_x = 40.0;
    let attack_dir = 1.0;
    for deg in (0..360).step_by(15) {
        let a = (deg as f64).to_radians();
        let away = Vec2::new(a.cos(), a.sin());
        // Counter-clockwise momentum (velocity along the +90° tangent) keeps the CCW tangent.
        let ccw_vel = Vec2::new(-away.y, away.x) * 3.0;
        let t = xavi_turn_wheel_tangent(away, ccw_vel, 38.0, center_x, attack_dir);
        assert!(
            away.x * t.y - away.y * t.x > 0.0,
            "deg={deg}: a CCW wheel must stay CCW (no mid-turn reversal)"
        );
        // Clockwise momentum keeps the CW tangent.
        let cw_vel = Vec2::new(away.y, -away.x) * 3.0;
        let t = xavi_turn_wheel_tangent(away, cw_vel, 38.0, center_x, attack_dir);
        assert!(
            away.x * t.y - away.y * t.x < 0.0,
            "deg={deg}: a CW wheel must stay CW (no mid-turn reversal)"
        );
    }
}

#[test]
fn xavi_turn_wheel_initiates_toward_open_middle() {
    // From a near-standstill (no committed momentum yet) the wheel seeds toward the middle of
    // the pitch, so a boxed-in carrier near a touchline turns infield rather than into the line.
    let center_x = 40.0;
    let away = Vec2::new(0.0, -1.0); // defender square, goal-side
    let near_left = xavi_turn_wheel_tangent(away, Vec2::zero(), 8.0, center_x, 1.0);
    assert!(
        near_left.x > 0.0,
        "near the left touchline the wheel curls toward centre: {near_left:?}"
    );
    let near_right = xavi_turn_wheel_tangent(away, Vec2::zero(), 72.0, center_x, 1.0);
    assert!(
        near_right.x < 0.0,
        "near the right touchline the wheel curls toward centre: {near_right:?}"
    );
}

#[test]
fn xavi_turn_is_chosen_by_a_skilled_boxed_in_carrier() {
    // Reachability hardening: a technical carrier, boxed in by a tight goal-side defender with
    // the forward path shut, actually SELECTS the xavi-turn through the real on-ball decision —
    // it is not dead-coded behind options (protect-ball / side-step) that always outrank it.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 8usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    let cpos = Vec2::new(40.0, 60.0);
    sim.players[carrier].position = cpos;
    sim.players[carrier].home_position = cpos;
    sim.players[carrier].skills.dribbling = 9.4;
    sim.players[carrier].skills.flair_passing = 8.4;
    sim.players[carrier].skills.first_touch = 8.4;
    sim.players[defender].position = Vec2::new(40.2, 61.6); // ~1.6yd, goal-side: forward shut
    sim.players[defender].skills.defending = 7.0;
    sim.ball.holder = Some(carrier);
    sim.ball.position = cpos;
    let snapshot = WorldSnapshot::from_match(&sim);
    let mut player = sim.players[carrier].clone();
    let mut rng = mulberry32(99);
    let _ = player.run_time_step(&snapshot, None, None, &mut rng);
    let decision = player.last_decision.as_ref().unwrap();
    assert_eq!(
        decision.action, "xavi-turn",
        "a skilled, boxed-in carrier should wheel out of it; order={:?}",
        decision.operation_order
    );
}

#[test]
fn xavi_turn_journeyman_shields_instead_of_turning() {
    // Skill-gate hardening: in the SAME boxed-in geometry, a low-skill carrier keeps it simple.
    // The superlinear skill gate keeps the turn's appetite below the shield, so a journeyman
    // does not attempt a xavi-turn he cannot reliably pull off.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 8usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    let cpos = Vec2::new(40.0, 60.0);
    sim.players[carrier].position = cpos;
    sim.players[carrier].home_position = cpos;
    sim.players[carrier].skills.dribbling = 3.5;
    sim.players[carrier].skills.flair_passing = 3.0;
    sim.players[carrier].skills.first_touch = 3.0;
    sim.players[defender].position = Vec2::new(40.2, 61.6);
    sim.players[defender].skills.defending = 7.0;
    sim.ball.holder = Some(carrier);
    sim.ball.position = cpos;
    let snapshot = WorldSnapshot::from_match(&sim);
    let mut player = sim.players[carrier].clone();
    let mut rng = mulberry32(99);
    let _ = player.run_time_step(&snapshot, None, None, &mut rng);
    let decision = player.last_decision.as_ref().unwrap();
    assert_ne!(
        decision.action, "xavi-turn",
        "a journeyman should shield, not turn; order={:?}",
        decision.operation_order
    );
}

#[test]
fn xavi_turn_not_offered_deep_in_own_defensive_third() {
    // Safety hardening: even a technical carrier does not turn his back deep in his own third —
    // the option is never even offered there, so a trick-induced turnover near his own goal
    // is impossible.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 8usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    let cpos = Vec2::new(40.0, 16.0); // deep in Home's own third (own goal at low y)
    sim.players[carrier].position = cpos;
    sim.players[carrier].home_position = cpos;
    sim.players[carrier].skills.dribbling = 9.4;
    sim.players[carrier].skills.flair_passing = 8.4;
    sim.players[carrier].skills.first_touch = 8.4;
    sim.players[defender].position = Vec2::new(40.2, 17.6); // tight, goal-side
    sim.players[defender].skills.defending = 7.0;
    sim.ball.holder = Some(carrier);
    sim.ball.position = cpos;
    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(carrier);
    assert!(
        observation.yards_to_own_goal < XAVI_TURN_MIN_OWN_GOAL_YARDS,
        "scenario must sit inside the guard: yards_to_own_goal={}",
        observation.yards_to_own_goal
    );
    let mut player = sim.players[carrier].clone();
    let mut rng = mulberry32(99);
    let _ = player.run_time_step(&snapshot, None, None, &mut rng);
    let decision = player.last_decision.as_ref().unwrap();
    assert!(
        !decision
            .operation_order
            .iter()
            .any(|label| label == "xavi-turn"),
        "xavi-turn must not be offered deep in own third; order={:?}",
        decision.operation_order
    );
}

#[test]
fn agentic_dribble_move_kind_is_stable_for_same_state() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 8usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[holder, defender]);
    sim.players[holder].position = Vec2::new(40.0, 64.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[defender].position = Vec2::new(42.6, 64.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;

    let first = {
        let snapshot = WorldSnapshot::from_match(&sim);
        let observation = snapshot.observation_for(holder);
        sim.players[holder].agentic_fallback_dribble_kind(&snapshot, &observation, true, false)
    };
    for tick in [
        1_u64,
        DRIBBLE_COMMIT_WINDOW_TICKS + 1,
        DRIBBLE_COMMIT_WINDOW_TICKS * 3,
    ] {
        sim.tick = tick;
        let snapshot = WorldSnapshot::from_match(&sim);
        let observation = snapshot.observation_for(holder);
        assert_eq!(
            sim.players[holder].agentic_fallback_dribble_kind(&snapshot, &observation, true, false),
            first,
            "fallback dribble kind should depend on the same football state, not tick sampling"
        );
    }
}

#[test]
fn unpressured_holder_with_clean_pass_throws_fewer_feints() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_135,
        ..Default::default()
    });
    let holder = 8;
    let defender = 12;
    park_players_except(&mut sim, &[holder, defender]);
    sim.players[holder].position = Vec2::new(40.0, 64.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.0;
    // Defender close enough that a feint is legal, but the holder is not yet in
    // genuine duress (moderate static pressure, no closing).
    sim.players[defender].position = Vec2::new(44.4, 64.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;

    let snapshot = WorldSnapshot::from_match(&sim);
    let directive = snapshot.tactical_directive(Team::Home);
    let base_obs = snapshot.observation_for(holder);

    let feint_score = |clean_pass: bool| -> f64 {
        let mut observation = base_obs.clone();
        observation.pressure_urgency = 0.36;
        observation.perceived_pressure = 0.36;
        observation
            .neural_extended
            .nearest_opponent_closing_rate_yps = 0.0;
        let (completion, openness, lane) = if clean_pass {
            (0.92, 0.9, 0.9)
        } else {
            (0.12, 0.1, 0.1)
        };
        observation.expected_pass_completion = completion;
        observation.best_pass_receiver_openness = openness;
        observation.floor_pass_lane_score = lane;
        let options = sim.players[holder].possession_action_options(
            &observation,
            &directive,
            2,
            1,
            false,
            snapshot.dt_seconds,
            snapshot.field_width,
        );
        action_option_score(&options, "fake-left-cut-right")
            .max(action_option_score(&options, "fake-right-cut-left"))
    };

    let with_pass = feint_score(true);
    let without_pass = feint_score(false);
    assert!(
        with_pass < without_pass,
        "an unpressured holder with a clean pass on should feint LESS (settle and \
             pass): with_pass={with_pass} without_pass={without_pass}"
    );
}

#[test]
fn pressured_holder_without_good_outlet_prefers_escape_over_panic_pass() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_136,
        ..Default::default()
    });
    let holder = 8;
    let receiver = 9;
    let defender = 12;
    park_players_except(&mut sim, &[holder, receiver, defender]);
    sim.players[holder].position = Vec2::new(40.0, 64.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.5;
    sim.players[holder].skills.acceleration = 8.0;
    sim.players[holder].preferences.dribble_bias = 0.92;
    sim.players[holder].preferences.pass_bias = 0.78;
    sim.players[receiver].position = Vec2::new(47.0, 70.0);
    sim.players[defender].position = Vec2::new(42.2, 65.2);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let directive = snapshot.tactical_directive(Team::Home);
    let mut observation = snapshot.observation_for(holder);
    observation.perceived_pressure = 0.76;
    observation.pressure_urgency = 0.78;
    observation.immediate_dispossession_risk = 0.72;
    observation
        .neural_extended
        .nearest_opponent_closing_rate_yps = 6.0;
    observation.expected_pass_completion = 0.26;
    observation.best_pass_receiver_openness = 0.18;
    observation.floor_pass_lane_score = 0.22;
    observation.expected_aerial_pass_completion = 0.18;
    observation.best_aerial_pass_receiver_openness = 0.14;
    observation.open_support_outlets = 0;

    let options = sim.players[holder].possession_action_options(
        &observation,
        &directive,
        1,
        0,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let escape_score = action_option_score(&options, "protect-ball")
        .max(action_option_score(&options, "side-step"))
        .max(action_option_score(&options, "left-cut"))
        .max(action_option_score(&options, "right-cut"))
        .max(action_option_score(&options, "nutmeg"))
        .max(action_option_score(&options, "fake-left-cut-right"))
        .max(action_option_score(&options, "fake-right-cut-left"));
    let pass_score = action_option_score(&options, "pass1");

    assert!(
        escape_score > pass_score * 1.15,
        "with no good outlet under steal pressure, retain by shielding/feinting rather than panic pass: escape={escape_score} pass={pass_score}"
    );
}

#[test]
fn opponent_press_risk_modulation_is_neutral_at_prior_and_monotonic() {
    // The prior-mean tendency leaves the analytic geometric risk unchanged (no Bayesian shift
    // until the belief actually moves off the prior).
    assert!((opponent_press_risk_modulation(OPPONENT_PRESS_NEUTRAL_TENDENCY) - 1.0).abs() < 1e-9);
    // A passive defender discounts the priced lane risk; a proven aggressor amplifies it.
    assert!(opponent_press_risk_modulation(0.2) < 1.0);
    assert!(opponent_press_risk_modulation(0.9) > 1.0);
    // Monotonic increasing in tendency.
    assert!(opponent_press_risk_modulation(0.3) < opponent_press_risk_modulation(0.7));
    // Bounded by the clamp either side.
    assert!(opponent_press_risk_modulation(0.0) >= OPPONENT_PRESS_RISK_MODULATION_FLOOR - 1e-9);
    assert!(opponent_press_risk_modulation(1.0) <= OPPONENT_PRESS_RISK_MODULATION_CEIL + 1e-9);
    // Non-finite tendency degrades to neutral (no shift) rather than poisoning the risk.
    assert!((opponent_press_risk_modulation(f64::NAN) - 1.0).abs() < 1e-9);
    assert!((opponent_press_risk_modulation(f64::INFINITY) - 1.0).abs() < 1e-9);
}

#[test]
fn opponent_press_belief_stays_bounded_and_finite_without_decay() {
    // forget == 1.0 is the dt == 0 degenerate case (no decay). The concentration cap must keep
    // alpha+beta finite and bounded over an arbitrarily long run, and the mean must stay sane.
    let mut belief = OpponentPressBelief::default();
    for _ in 0..100_000 {
        belief.step(1.0, Some(1.0));
    }
    let m = belief.mean();
    assert!(
        m.is_finite(),
        "mean must stay finite under unbounded evidence"
    );
    assert!(
        m > 0.9 && m <= 1.0,
        "sustained pressing with no decay should saturate high but bounded, got {m}"
    );

    // Non-finite evidence is dropped, not folded in.
    let before = belief.mean();
    belief.step(1.0, Some(f64::NAN));
    belief.step(1.0, Some(f64::INFINITY));
    assert!(
        (belief.mean() - before).abs() < 1e-9,
        "non-finite evidence must be a no-op"
    );
}

#[test]
fn opponent_press_belief_default_is_neutral_and_tracks_evidence() {
    // Conjugate Beta-Bernoulli filter: prior mean is neutral, evidence moves it, and absence
    // of observation forgets back toward the prior.
    let belief = OpponentPressBelief::default();
    assert!((belief.mean() - OPPONENT_PRESS_NEUTRAL_TENDENCY).abs() < 1e-9);

    let mut pressing = OpponentPressBelief::default();
    for _ in 0..30 {
        pressing.step(1.0, Some(1.0));
    }
    assert!(
        pressing.mean() > 0.8,
        "sustained pressing => high tendency, got {}",
        pressing.mean()
    );

    let mut holding = OpponentPressBelief::default();
    for _ in 0..30 {
        holding.step(1.0, Some(0.0));
    }
    assert!(
        holding.mean() < 0.2,
        "sustained holding => low tendency, got {}",
        holding.mean()
    );

    // No observation + forget < 1 relaxes a learned belief back toward the prior mean.
    let learned = pressing.mean();
    for _ in 0..400 {
        pressing.step(0.5, None);
    }
    assert!(
        pressing.mean() < learned
            && (pressing.mean() - OPPONENT_PRESS_NEUTRAL_TENDENCY).abs() < 1e-6,
        "forgetting should relax toward the prior mean, got {}",
        pressing.mean()
    );
}

#[test]
fn opponent_press_belief_disabled_by_default_keeps_belief_empty() {
    // Default config has the feature OFF: the per-tick update is a no-op and the belief map
    // stays empty, so pass-lane risk falls back to the analytic-only path (byte-identical).
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let snapshot = WorldSnapshot::from_match(&sim);
    sim.update_opponent_press_beliefs(&snapshot);
    assert!(
        sim.opponent_press_belief.is_empty(),
        "disabled belief must never populate"
    );
    assert!(WorldSnapshot::from_match(&sim)
        .opponent_press_tendency
        .is_empty());
}

#[test]
fn opponent_press_belief_learns_press_vs_hold_from_geometry() {
    // With the feature enabled, the per-tick update should learn a HIGH tendency for a defender
    // who keeps driving onto the ball and a LOW one for a defender who sits off it.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        opponent_belief_enabled: true,
        ..Default::default()
    });
    let presser = 14; // away
    let holder = 16; // away
    park_players_except(&mut sim, &[presser, holder]);
    sim.ball.position = Vec2::new(40.0, 50.0);
    sim.ball.holder = None;
    sim.players[presser].position = Vec2::new(46.0, 50.0);
    sim.players[presser].velocity = Vec2::new(-6.0, 0.0); // closing on the ball
    sim.players[holder].position = Vec2::new(34.0, 50.0);
    sim.players[holder].velocity = Vec2::zero(); // holding off

    for _ in 0..40 {
        let snapshot = WorldSnapshot::from_match(&sim);
        sim.update_opponent_press_beliefs(&snapshot);
    }

    let tendencies = sim.opponent_press_tendency_map();
    let p = tendencies[&presser];
    let h = tendencies[&holder];
    assert!(
        p > 0.5 && h < 0.5 && p > h,
        "presser should learn a high press tendency and holder a low one (presser={p}, holder={h})"
    );
}

#[test]
fn opponent_press_posterior_modulates_pass_lane_risk() {
    // The learned posterior shades the analytic lane risk: a defender proven to sit off lowers
    // the priced risk; a defender proven to step in raises it. An empty belief reproduces the
    // analytic baseline exactly.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        opponent_belief_enabled: true,
        ..Default::default()
    });
    let blocker = 14; // away
    park_players_except(&mut sim, &[blocker]);
    let from = Vec2::new(40.0, 40.0);
    let to = Vec2::new(40.0, 58.0);
    // 3yd off the lane but sprinting into it: a real geometric step-in risk (not in-corridor).
    sim.players[blocker].position = Vec2::new(43.0, 49.0);
    sim.players[blocker].velocity = Vec2::new(-8.0, 0.0);

    let lane_risk = |sim: &SoccerMatch| -> f64 {
        WorldSnapshot::from_match(sim)
            .pass_lane_interception_risk(
                from,
                to,
                Team::Away,
                2.5,
                17.0,
                PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
            )
            .risk
    };

    // Empty belief => analytic baseline (the modulation path is skipped).
    let analytic = lane_risk(&sim);
    assert!(analytic > 0.0, "the drifting defender must price some risk");

    let mut passive = OpponentPressBelief::default();
    for _ in 0..40 {
        passive.step(1.0, Some(0.0));
    }
    sim.opponent_press_belief.insert(blocker, passive);
    let posterior_passive = lane_risk(&sim);

    let mut aggressive = OpponentPressBelief::default();
    for _ in 0..40 {
        aggressive.step(1.0, Some(1.0));
    }
    sim.opponent_press_belief.insert(blocker, aggressive);
    let posterior_aggressive = lane_risk(&sim);

    assert!(
        posterior_passive < analytic,
        "a defender proven to sit off should lower the posterior lane risk (passive={posterior_passive}, analytic={analytic})"
    );
    assert!(
        posterior_aggressive >= analytic,
        "a defender proven to step in should not lower the posterior lane risk (aggressive={posterior_aggressive}, analytic={analytic})"
    );
}

#[test]
fn opponent_belief_block_is_zero_when_disabled_and_signed_when_present() {
    let actor = 3; // home
    let actor_team = Team::Home;

    // Disabled (default): the snapshot tendency map is empty, so the block is all zeros and a
    // neural net sees the same input as before the feature existed.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.ball.position = Vec2::new(40.0, 50.0);
    sim.players[actor].position = Vec2::new(40.0, 50.0);
    let off_block =
        soccer_opponent_belief_block(&WorldSnapshot::from_match(&sim), actor, actor_team);
    assert_eq!(off_block.len(), SOCCER_NEURAL_OPP_BELIEF_DIM);
    assert!(
        off_block.iter().all(|v| *v == 0.0),
        "disabled belief => all-zero block (legacy-equivalent), got {off_block:?}"
    );

    // Enabled with a strongly-passive opponent right next to the actor: the nearest-tendency
    // channel reads clearly below neutral and coverage is positive.
    let mut sim_on = SoccerMatch::default_11v11(MatchConfig {
        opponent_belief_enabled: true,
        ..Default::default()
    });
    sim_on.ball.position = Vec2::new(40.0, 50.0);
    sim_on.players[actor].position = Vec2::new(40.0, 50.0);
    let opp = 14; // away
    sim_on.players[opp].position = Vec2::new(42.0, 50.0);
    let mut passive = OpponentPressBelief::default();
    for _ in 0..40 {
        passive.step(1.0, Some(0.0));
    }
    sim_on.opponent_press_belief.insert(opp, passive);

    let on_block =
        soccer_opponent_belief_block(&WorldSnapshot::from_match(&sim_on), actor, actor_team);
    assert!(
        on_block[0] < -0.1,
        "nearest passive opponent should read below neutral, got {}",
        on_block[0]
    );
    assert!(
        on_block[3] > 0.0,
        "coverage should be positive when a belief is held, got {}",
        on_block[3]
    );
}

#[test]
fn opponent_belief_block_reaches_the_neural_feature_tail() {
    // capture -> encode -> net input: a known belief block must surface at the dedicated tail
    // slots, right after the whole-field motion block.
    let sim = SoccerMatch::default_11v11(MatchConfig::default());
    let actor_id = 3;
    let actor_team = sim.players[actor_id].team;
    let snapshot = WorldSnapshot::from_match(&sim);
    let belief = vec![0.3_f32, -0.2, 0.4, 1.0];
    let decision = test_decision_trace(&snapshot, actor_id, "carry-forward");
    let transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: actor_id,
        team: actor_team,
        role: sim.players[actor_id].role,
        state: decision.mdp_state.clone(),
        observation: snapshot.observation_for(actor_id),
        belief: decision.belief.clone(),
        action: decision.action.clone(),
        action_target: decision.action_target.clone(),
        decision_context: SoccerDecisionContext {
            opponent_belief: belief.clone(),
            ..Default::default()
        },
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(actor_id),
        next_observation: snapshot.observation_for(actor_id),
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert_eq!(features.len(), SOCCER_NEURAL_FEATURE_DIM);
    // The opponent-press block is stacked AFTER the Kalman perception-belief block, so it starts
    // at base + motion + perception-belief, not at base + motion.
    let start = SOCCER_NEURAL_BASE_FEATURE_DIM
        + SOCCER_NEURAL_FIELD_MOTION_DIM
        + SOCCER_NEURAL_BELIEF_FEATURE_DIM;
    for (i, &v) in belief.iter().enumerate() {
        assert_eq!(
            features[start + i],
            f64::from(v),
            "opponent-press belief channel {i} must appear in the neural feature tail"
        );
    }
    // Both earlier six-channel motion totals (base+motion and base+motion+perception)
    // must remain recognised legacy input dims so older nets migrate by zero-padding.
    assert!(SOCCER_NEURAL_LEGACY_FEATURE_DIMS
        .contains(&(SOCCER_NEURAL_BASE_FEATURE_DIM + SOCCER_NEURAL_FIELD_MOTION_DIM_V1)));
    assert!(SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(
        &(SOCCER_NEURAL_BASE_FEATURE_DIM
            + SOCCER_NEURAL_FIELD_MOTION_DIM_V1
            + SOCCER_NEURAL_BELIEF_FEATURE_DIM)
    ));
    assert!(SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&start));
}

#[test]
fn pass_through_a_defender_in_the_lane_is_down_weighted() {
    // A defender physically in the passing corridor is a SITUATIONAL block: completion is
    // pulled down hard (the lane-clearance gate is multiplicative, so an open receiver
    // downfield can't rescue it) — but it is NOT collapsed to a near-zero "gift", and we no
    // longer special-case a slow vs fast defender on the line. Whether the defender actually
    // cuts the ball out is left to the simulation. What the ESTIMATE must capture: a clear
    // lane >> a defender drifting into it > a defender already sitting in it.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 26_140,
        ..Default::default()
    });
    let passer = 6;
    let receiver = 9;
    let blocker = 14; // an opponent (away team)
    park_players_except(&mut sim, &[passer, receiver, blocker]);
    let passer_pos = Vec2::new(40.0, 40.0);
    let receiver_pos = Vec2::new(40.0, 58.0);
    sim.players[passer].position = passer_pos;
    sim.players[passer].home_position = passer_pos;
    sim.players[passer].skills.passing_completion_rate = 7.5;
    sim.players[receiver].position = receiver_pos;
    sim.players[receiver].home_position = receiver_pos;
    sim.ball.holder = Some(passer);
    sim.ball.position = passer_pos;

    let completion = |sim: &SoccerMatch| -> f64 {
        let snap = WorldSnapshot::from_match(sim);
        let p = snap.players.iter().find(|p| p.id == passer).unwrap();
        let t = snap.players.iter().find(|p| p.id == receiver).unwrap();
        let p_pos = snap.player_position(passer).unwrap_or(p.position);
        let t_pos = snap.player_position(receiver).unwrap_or(t.position);
        pass_target_quality_for_snapshot(&snap, p, p_pos, t, t_pos, PassFlight::Floor)
            .expected_completion
    };
    let lane_risk = |sim: &SoccerMatch| -> f64 {
        WorldSnapshot::from_match(sim)
            .pass_lane_interception_risk(
                passer_pos,
                receiver_pos,
                Team::Away,
                2.5,
                17.0,
                PASS_LANE_DECISION_LOOKAHEAD_SECONDS,
            )
            .risk
    };

    // Defender parked dead in the passing lane = a ball straight through them.
    sim.players[blocker].position = Vec2::new(40.0, 49.0);
    sim.players[blocker].velocity = Vec2::zero();
    let blocked = completion(&sim);
    let blocked_risk = lane_risk(&sim);

    // Same defender, off to the side (not in the corridor) = clear lane.
    sim.players[blocker].position = Vec2::new(62.0, 49.0);
    sim.players[blocker].velocity = Vec2::zero();
    let clear = completion(&sim);
    let clear_risk = lane_risk(&sim);

    // Currently 3yd off the lane but SPRINTING into it: priced between clear and blocked.
    sim.players[blocker].position = Vec2::new(43.0, 49.0);
    sim.players[blocker].velocity = Vec2::new(-8.0, 0.0);
    let drifting = completion(&sim);
    let drifting_risk = lane_risk(&sim);

    assert!(
        blocked < clear * 0.5,
        "a floor pass straight through a defender in the corridor must be heavily \
             down-weighted by the lane gate: blocked={blocked} clear={clear}"
    );
    assert!(
        drifting > blocked && drifting < clear,
        "a defender drifting into the lane is worse than a clear lane but not as bad as one \
             already sitting in it: clear={clear} drifting={drifting} blocked={blocked}"
    );
    assert!(
        blocked_risk > 0.95 && drifting_risk >= PASS_LANE_DYNAMIC_RISK_HIGH && clear_risk < 0.20,
        "POMDP/MPC lane risk should ask whether the lane is clear now or in the next two seconds: \
         blocked={blocked_risk} drifting={drifting_risk} clear={clear_risk}"
    );
}

#[test]
fn named_carry_moves_have_directional_geometry_and_legal_labels() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2263,
        ..Default::default()
    });
    let holder = 6;
    let defender = 12;
    park_players_except(&mut sim, &[holder, defender]);
    sim.players[holder].position = Vec2::new(40.0, 64.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[defender].position = Vec2::new(40.0, 60.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[holder].position;
    let carry_forward = snapshot.dribble_move_target_for(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryForward,
    );
    let carry_left = snapshot.dribble_move_target_for(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryOutLeft,
    );
    let carry_right = snapshot.dribble_move_target_for(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryOutRight,
    );
    let protect = snapshot.dribble_move_target_for(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::ProtectBall,
    );

    assert!(carry_forward.y > origin.y + 0.9);
    assert!(
        carry_forward.distance(sim.players[defender].position)
            >= origin.distance(sim.players[defender].position),
        "carry-forward should advance without closing the nearest defender gap: origin={origin:?} target={carry_forward:?}"
    );
    assert!(carry_left.x < origin.x && carry_left.y > origin.y);
    assert!(carry_right.x > origin.x && carry_right.y > origin.y);
    assert!(
        protect.distance(sim.players[defender].position)
            > origin.distance(sim.players[defender].position),
        "protect-ball should move the touch away from the nearest defender"
    );
    assert!(learned_action_label_is_legal(
        "carry_forward",
        &snapshot,
        holder
    ));
    assert!(learned_action_label_is_legal(
        "carry_out_left",
        &snapshot,
        holder
    ));
    assert!(learned_action_label_is_legal(
        "carry_out_right",
        &snapshot,
        holder
    ));
    assert!(learned_action_label_is_legal(
        "protect_ball",
        &snapshot,
        holder
    ));
}

#[test]
fn carry_forward_in_goal_approach_bends_toward_goal() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2265,
        ..Default::default()
    });
    let holder = 9;
    let blocker = 13;
    let keeper = 11;
    park_players_except(&mut sim, &[holder, blocker, keeper]);
    sim.players[holder].position = Vec2::new(69.0, 78.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].velocity = Vec2::new(0.0, 4.0);
    sim.players[holder].skills.dribbling = 8.2;
    sim.players[holder].skills.acceleration = 8.0;
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(holder);
    let origin = sim.players[holder].position;
    let goal_center_x = snapshot.field_width * 0.5;
    let target = snapshot.dribble_move_target_for(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryForward,
    );

    assert!(observation.yards_to_goal <= tunables().shooting.goal_approach_carry_yards);
    assert!(goal_approach_carry_preferred(
        &observation,
        sim.players[holder].role
    ));
    assert!(
        (target.x - goal_center_x).abs() < (origin.x - goal_center_x).abs(),
        "goal-approach carry should bend inside toward goal: origin={origin:?} target={target:?}"
    );
    assert!(
        (target.y - origin.y) * Team::Home.attack_dir() > 0.8,
        "goal-approach carry should still advance toward goal: origin={origin:?} target={target:?}"
    );
    assert!(
        target.y < snapshot.field_length - 20.0,
        "approach carry should create a shooting lane before the endline: target={target:?}"
    );
}

#[test]
fn wide_final_third_carrier_commits_to_byline_drive_strategy() {
    // The committed MDP/POMDP decision: a wide carrier attacking the flank, with the team enjoying
    // an attacking overload, commits to the byline-drive ("drive the corner and cross") strategy —
    // a Pair-layer maneuver held for the strategy-commit window. A central carrier does not.
    let overload = AttackingOverloadProfile {
        attackers: 5,
        defenders: 2,
        advantage: 3,
        score: 0.80,
    };
    // Wide and deep (~32yd from the byline): a corner-drive strategy (crash-the-box at this depth).
    let wide_deep = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::HomeAttack,
        Some(Team::Home),
        Vec2::new(8.0, 88.0), // wide LEFT, ~32yd from the byline
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        overload,
        false,
        &SoccerTacticalLearningWeights::default(),
    );
    assert!(
        matches!(
            wide_deep.attack_strategy,
            TeamAttackStrategy::CrashTheBox
                | TeamAttackStrategy::BylineCrossLeftToPenaltySpot
                | TeamAttackStrategy::BylineCrossRightToPenaltySpot
        ),
        "a wide deep carrier should commit to a corner-drive strategy, got {:?}",
        wide_deep.attack_strategy
    );
    // A wide carrier at the edge of the byline-drive band (~40yd out, before crash-the-box depth)
    // commits to the named byline-cross Pair maneuver.
    let wide_edge = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::HomeAttack,
        Some(Team::Home),
        Vec2::new(8.0, 80.0), // wide LEFT, ~40yd from the byline
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        overload,
        false,
        &SoccerTacticalLearningWeights::default(),
    );
    assert_eq!(
        wide_edge.attack_strategy,
        TeamAttackStrategy::BylineCrossLeftToPenaltySpot,
        "a wide left carrier at the byline-drive band edge should commit to the byline drive"
    );
    assert_eq!(wide_edge.attack_strategy.layer(), StrategyLayer::Pair);
    let central = tactical_directive_for_team(
        Team::Home,
        TacticalPhase::HomeAttack,
        Some(Team::Home),
        Vec2::new(40.0, 88.0), // dead central — drive at goal, not the corner
        0,
        DEFAULT_FIELD_WIDTH_YARDS,
        DEFAULT_FIELD_LENGTH_YARDS,
        DefensiveCoverProfile::default(),
        overload,
        false,
        &SoccerTacticalLearningWeights::default(),
    );
    assert!(
        !matches!(
            central.attack_strategy,
            TeamAttackStrategy::BylineCrossLeftToPenaltySpot
                | TeamAttackStrategy::BylineCrossRightToPenaltySpot
        ),
        "a central carrier should NOT commit to the byline drive, got {:?}",
        central.attack_strategy
    );
}

#[test]
fn byline_drive_steers_the_carry_to_the_corner_under_commitment_or_solo_opt_in() {
    // Execution: the drive-to-corner carry fires when the team has committed to the byline drive OR
    // when an individual wide carrier opts in on his own (isolated wide, in the build-up band, with
    // an open lane) — see `winger_byline_drive_opt_in`. Outside both it never spuriously hijacks a
    // carry. The handoff to the cross at the corner is also checked.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 5151,
        ..Default::default()
    });
    let carrier = 7;
    park_players_except(&mut sim, &[carrier]);
    sim.players[carrier].role = PlayerRole::Forward;
    sim.players[carrier].position = Vec2::new(8.0, 88.0); // wide LEFT, 32yd from the byline
    sim.players[carrier].home_position = sim.players[carrier].position;
    sim.ball.holder = Some(carrier);
    sim.ball.position = sim.players[carrier].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let committed = matches!(
        snapshot.tactical_directive(Team::Home).attack_strategy,
        TeamAttackStrategy::BylineCrossLeftToPenaltySpot
            | TeamAttackStrategy::BylineCrossRightToPenaltySpot
    );
    let solo_opt_in = snapshot.winger_byline_drive_opt_in(carrier);
    // Wide, in the build-up band, with an open lane (everyone else parked): the solo opt-in alone
    // is enough to engage the drive even with no team commitment — the fix for "stalls ~30yd out".
    assert!(
        solo_opt_in,
        "an isolated wide carrier in the build-up band must be able to drive the byline on his own"
    );
    let drive = snapshot.byline_corner_drive_target_for(carrier);
    // The execution gate fires iff committed OR the individual opt-in is on.
    assert_eq!(
        drive.is_some(),
        committed || solo_opt_in,
        "the corner drive must fire iff committed or the solo opt-in is on \
         (committed={committed} solo_opt_in={solo_opt_in})"
    );
    if let Some(corner) = drive {
        // When it fires, the carry heads forward-and-wide toward the left corner flag.
        let origin = sim.players[carrier].position;
        let target = snapshot.dribble_move_target_for(
            carrier,
            sim.players[carrier].home_position,
            DribbleMoveKind::CarryForward,
        );
        assert!(
            corner.y > 110.0 && corner.x < 12.0,
            "corner target near the left flag: {corner:?}"
        );
        assert!(
            target.x <= origin.x + 0.01 && (target.y - origin.y) > 0.2,
            "byline drive carries forward-and-wide to the corner: origin={origin:?} target={target:?}"
        );
    }

    // Inside the release window the drive always hands off to the cross.
    sim.players[carrier].position = Vec2::new(
        6.0,
        sim.config.field_length_yards - (BYLINE_CROSS_RELEASE_DEPTH_YARDS - 1.0),
    );
    sim.ball.position = sim.players[carrier].position;
    let at_release = WorldSnapshot::from_match(&sim);
    assert!(
        at_release.byline_corner_drive_target_for(carrier).is_none(),
        "inside the release depth the drive yields to the (legal, scored) flank cross"
    );

    // At the corner (inside the hard safety trigger) the drive also yields to the cross.
    sim.players[carrier].position = Vec2::new(6.0, 116.0); // 4yd from the byline
    sim.ball.position = sim.players[carrier].position;
    let at_corner = WorldSnapshot::from_match(&sim);
    assert!(
        at_corner.byline_corner_drive_target_for(carrier).is_none(),
        "at the corner the drive yields to the (legal, scored) flank cross"
    );
}

#[test]
fn winger_byline_solo_opt_in_respects_band_width_and_lane() {
    // The solo (no team-commitment) byline opt-in is deliberately scoped so it does not hijack
    // good central / finishing / blocked situations: it fires only for a WIDE carrier in the
    // BUILD-UP band with an OPEN lane ahead. Lock those discriminators in.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 5151,
        ..Default::default()
    });
    let carrier = 7;
    park_players_except(&mut sim, &[carrier]);
    sim.players[carrier].role = PlayerRole::Forward;
    let set = |sim: &mut SoccerMatch, pos: Vec2| {
        sim.players[carrier].position = pos;
        sim.players[carrier].home_position = pos;
        sim.ball.holder = Some(carrier);
        sim.ball.position = pos;
        sim.ball.last_touch_team = Some(Team::Home);
    };

    // Baseline: touchline LEFT, 32yd from the byline (in the build-up band), lane clear -> opt in.
    set(&mut sim, Vec2::new(6.0, 88.0));
    assert!(
        WorldSnapshot::from_match(&sim).winger_byline_drive_opt_in(carrier),
        "touchline winger in the build-up band with an open lane should opt in"
    );

    // Too CENTRAL (not a wide attacker) -> defer to the cut-inside / goal drive.
    set(&mut sim, Vec2::new(34.0, 88.0));
    assert!(
        !WorldSnapshot::from_match(&sim).winger_byline_drive_opt_in(carrier),
        "a central carrier drives at goal, not the corner"
    );

    // Merely HALF-SPACE wide (well infield of the touchline) -> keeps the deliberate cut-inside
    // toward goal in the approach band; only a touchline-hugging winger drives the corner.
    set(&mut sim, Vec2::new(66.0, 88.0));
    assert!(
        !WorldSnapshot::from_match(&sim).winger_byline_drive_opt_in(carrier),
        "a half-space carrier cuts inside toward goal rather than driving the corner"
    );

    // Too DEEP (inside the finishing zone) -> reserve the run to the byline for the committed drive.
    set(&mut sim, Vec2::new(8.0, 108.0)); // 12yd from the byline
    assert!(
        !WorldSnapshot::from_match(&sim).winger_byline_drive_opt_in(carrier),
        "in the deep finishing zone, cutting inside to shoot wins over a solo corner run"
    );
    set(
        &mut sim,
        Vec2::new(8.0, DEFAULT_FIELD_LENGTH_YARDS - WINGER_BYLINE_SOLO_MIN_DEPTH_YARDS),
    );
    assert!(
        !WorldSnapshot::from_match(&sim).winger_byline_drive_opt_in(carrier),
        "at the solo-drive release floor, the winger should switch out of the corner carry"
    );

    // Wide + build-up band, but the LANE is blocked by a defender straight ahead -> no reckless run.
    set(&mut sim, Vec2::new(8.0, 88.0));
    let blocker = sim
        .players
        .iter()
        .position(|p| p.team == Team::Away && p.role != PlayerRole::Goalkeeper)
        .expect("an away outfielder");
    sim.players[blocker].position = Vec2::new(8.0, 92.0); // 4yd directly ahead, in the lane
    assert!(
        !WorldSnapshot::from_match(&sim).winger_byline_drive_opt_in(carrier),
        "a defender packing the lane should suppress the solo drive"
    );
}

#[test]
fn deep_defender_carry_bends_away_from_a_closing_opponent() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 4471,
        ..Default::default()
    });
    let holder = 9;
    park_players_except(&mut sim, &[holder]);
    // Deep in our own half (well outside the final third) so the wider defender
    // carrying cushion applies.
    sim.players[holder].role = PlayerRole::Defender;
    sim.players[holder].position = Vec2::new(40.0, 30.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.0;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);
    // An opponent closing front-right, inside the ~4yd cushion.
    let opponent = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && p.role != PlayerRole::Goalkeeper)
        .map(|p| p.id)
        .unwrap();
    let opponent_pos = Vec2::new(42.0, 31.5);
    sim.players[opponent].position = opponent_pos;

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[holder].position;
    let touch = DribbleTouchDecision::new(0, 4.8);
    let target = snapshot.dribble_move_target_for_touch(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryForward,
        touch,
    );
    let straight = Vec2::new(origin.x, origin.y + touch.distance_yards);

    assert!(
        target.distance(opponent_pos) > straight.distance(opponent_pos) + 0.5,
        "deep defender should bend the carry AWAY from the closing opponent: \
         origin={origin:?} target={target:?} straight={straight:?} opp={opponent_pos:?}"
    );

    // Control: a forward in the identical situation may still bend away from
    // pressure via the generic ball-carrier escape model, but should not use the
    // defender-only wider cushion more aggressively than the defender.
    sim.players[holder].role = PlayerRole::Forward;
    let snapshot = WorldSnapshot::from_match(&sim);
    let fwd_target = snapshot.dribble_move_target_for_touch(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryForward,
        touch,
    );
    assert!(
        fwd_target.distance(opponent_pos) <= target.distance(opponent_pos) + 0.35,
        "forward carry can escape pressure, but the defender-only cushion should remain stronger: \
         defender_target={target:?} fwd_target={fwd_target:?} straight={straight:?}"
    );
}

#[test]
fn near_goal_carry_forward_bends_toward_goalmouth() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2265,
        ..Default::default()
    });
    let holder = 9;
    park_players_except(&mut sim, &[holder]);
    sim.players[holder].position = Vec2::new(15.0, 94.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 8.0;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[holder].position;
    let touch = DribbleTouchDecision::new(0, 4.8);
    let target = snapshot.dribble_move_target_for_touch(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryForward,
        touch,
    );
    let straight = Vec2::new(origin.x, origin.y + touch.distance_yards);
    let goal = Vec2::new(
        snapshot.field_width * 0.5,
        Team::Home.goal_y(snapshot.field_length),
    );

    assert!(
        target.x > origin.x + 0.75,
        "wide attacker should bend the carry toward goalmouth: origin={origin:?} target={target:?}"
    );
    assert!(
            target.distance(goal) < straight.distance(goal) - 0.45,
            "goal-directed carry should improve distance to goal versus straight-line endline carry: target={target:?} straight={straight:?}"
        );
    assert!(
            snapshot.goal_angle_degrees(target, Team::Home)
                > snapshot.goal_angle_degrees(straight, Team::Home),
            "goal-directed carry should improve shooting angle: target={target:?} straight={straight:?}"
        );
}

#[test]
fn near_goal_lateral_carry_still_bends_toward_goalmouth() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2267,
        ..Default::default()
    });
    let holder = 9;
    park_players_except(&mut sim, &[holder]);
    sim.players[holder].position = Vec2::new(15.0, 94.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 8.0;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[holder].position;
    let touch = DribbleTouchDecision::new(9, 4.8);
    let target = snapshot.dribble_move_target_for_touch(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryOutLeft,
        touch,
    );
    let raw_wide_endline_target =
        origin + Vec2::new(-0.52, Team::Home.attack_dir() * 0.78).normalized() * 4.8;
    let goal = Vec2::new(
        snapshot.field_width * 0.5,
        Team::Home.goal_y(snapshot.field_length),
    );

    assert!(
            target.x > origin.x + 0.35,
            "even a lateral carry selected near goal should bend inside: origin={origin:?} target={target:?}"
        );
    assert!(
            target.distance(goal) < raw_wide_endline_target.distance(goal) - 0.45,
            "near-goal lateral carry should improve goalmouth geometry instead of running wide: target={target:?} raw={raw_wide_endline_target:?}"
        );
    assert!(
        target.y <= snapshot.field_length - 4.0,
        "near-goal lateral carry should stop short of the endline: target={target:?}"
    );
}

#[test]
fn deep_near_goal_carry_cuts_inside_instead_of_deeper_to_endline() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2269,
        ..Default::default()
    });
    let holder = 9;
    park_players_except(&mut sim, &[holder]);
    sim.players[holder].position = Vec2::new(70.0, 114.5);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 8.8;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[holder].position;
    let target = snapshot.dribble_move_target_for_touch(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryOutRight,
        DribbleTouchDecision::new(3, 4.8),
    );
    let goal_center_x = snapshot.field_width * 0.5;

    assert!(
        (target.x - goal_center_x).abs() < (origin.x - goal_center_x).abs() - 1.5,
        "deep wide carry should cut inside toward goalmouth: origin={origin:?} target={target:?}"
    );
    assert!(
            target.y <= origin.y + 0.30,
            "deep near-goal carry should not keep pushing toward the endline: origin={origin:?} target={target:?}"
        );
    assert!(
            target.y <= Team::Home.goal_y(snapshot.field_length) - 5.5,
            "deep near-goal carry should stay in the shooting pocket instead of the byline: target={target:?}"
        );
}

