#[test]
fn goalmouth_carry_learning_reward_prefers_pocket_over_endline_trap() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2273,
        ..Default::default()
    });
    let holder = 9;
    let blocker = 13;
    let keeper = 11;
    park_players_except(&mut sim, &[holder, blocker, keeper]);
    sim.players[holder].position = Vec2::new(70.0, 90.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].velocity = Vec2::new(0.0, 4.0);
    sim.players[holder].skills.dribbling = 8.8;
    sim.players[holder].skills.acceleration = 8.2;
    sim.players[holder].skills.shooting = 6.2;
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let before = WorldSnapshot::from_match(&sim);
    let before_observation = before.observation_for(holder);
    assert!(before_observation.yards_to_goal <= tunables().shooting.goal_approach_carry_yards);

    let pocket_target = Vec2::new(48.0, 104.0);
    let mut pocket_after = before.clone();
    pocket_after.ball.holder = Some(holder);
    pocket_after.ball.position = pocket_target;
    pocket_after.set_player_position(holder, pocket_target);
    let pocket_component = goalmouth_dribble_learning_reward(
        &sim.players[holder],
        "carry-forward",
        &before_observation,
        &pocket_after.observation_for(holder),
        &before,
        &pocket_after,
        sim.players[holder].position,
        pocket_target,
    );

    let endline_target = Vec2::new(77.0, 117.0);
    let mut endline_after = before.clone();
    endline_after.ball.holder = Some(holder);
    endline_after.ball.position = endline_target;
    endline_after.set_player_position(holder, endline_target);
    let endline_component = goalmouth_dribble_learning_reward(
        &sim.players[holder],
        "carry-forward",
        &before_observation,
        &endline_after.observation_for(holder),
        &before,
        &endline_after,
        sim.players[holder].position,
        endline_target,
    );

    assert!(
            pocket_component > endline_component + 0.80,
            "learning should prefer a shooting-pocket carry over an endline trap: pocket={pocket_component} endline={endline_component}"
        );
    assert!(
        pocket_component > 1.0,
        "shooting-pocket carry should produce positive learning signal: {pocket_component}"
    );
}

#[test]
fn learned_endline_dribble_near_goal_is_rewritten_to_goalmouth_drive() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2271,
        ..Default::default()
    });
    let holder = 9;
    let blocker = 13;
    let keeper = 11;
    park_players_except(&mut sim, &[holder, blocker, keeper]);
    sim.players[holder].position = Vec2::new(70.0, 90.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].velocity = Vec2::new(0.0, 4.0);
    sim.players[holder].skills.dribbling = 8.8;
    sim.players[holder].skills.acceleration = 8.2;
    sim.players[holder].skills.shooting = 5.4;
    sim.players[blocker].position = Vec2::new(56.0, 104.0);
    sim.players[blocker].skills.defending = 8.9;
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(holder);
    let origin = sim.players[holder].position;
    let stale_endline_target = Vec2::new(78.0, 118.0);
    assert!(!goal_attack_shot_is_required(
        &observation,
        sim.players[holder].role
    ));
    assert!(goal_approach_forces_goalmouth_carry(
        &observation,
        sim.players[holder].role
    ));

    for action in ["carry-out-right", "hold-up-flank", "protect-ball"] {
        let plan = SoccerLearnedPlan {
            action: action.to_string(),
            target_player: None,
            target_point: Some(stale_endline_target),
            mpc_replan: None,
        };
        let (learned_action, label) = sim.players[holder]
            .action_from_learned_plan(&plan, &snapshot, &observation)
            .expect("learned dribble action");
        let SoccerAction::DribbleMove { target, kind, .. } = learned_action else {
            panic!("expected rewritten dribble for {action}, got {learned_action:?}");
        };

        assert_eq!(label, "carry-forward");
        assert_eq!(kind, DribbleMoveKind::CarryForward);
        assert!(
            (target.x - snapshot.field_width * 0.5).abs()
                < (origin.x - snapshot.field_width * 0.5).abs(),
            "rewritten {action} should move toward goalmouth: origin={origin:?} target={target:?}"
        );
        assert!(
                target.y > origin.y && target.y <= Team::Home.goal_y(snapshot.field_length) - 7.0,
                "rewritten {action} should advance into the shooting pocket, not the endline: target={target:?}"
            );
        assert_ne!(
            target, stale_endline_target,
            "learned target point should be ignored in the goal-drive window"
        );
    }
}

#[test]
fn match_step_timing_stats_accumulate_and_reset() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.3,
        seed: 22_406,
        ..Default::default()
    });

    assert_eq!(sim.step_timing_stats().ticks, 0);
    sim.run_time_step();
    sim.run_time_step();

    let stats = sim.step_timing_stats();
    assert_eq!(stats.ticks, 2);
    assert_eq!(stats.tick_budget_ms, DEFAULT_DT_SECONDS * 1_000.0);
    assert_eq!(
        stats.learning_budget_ms,
        stats.tick_budget_ms * SOCCER_LEARNING_TICK_BUDGET_RATIO
    );
    assert_eq!(stats.over_budget, stats.over_budget_ticks > 0);
    assert_eq!(
        stats.learning_over_budget,
        stats.learning_over_budget_ticks > 0
    );
    assert!(stats.over_budget_ticks <= stats.ticks);
    assert!(stats.learning_over_budget_ticks <= stats.ticks);
    assert!(stats.max_budget_overrun_ms >= 0.0);
    assert!(stats.max_learning_budget_overrun_ms >= 0.0);
    assert!(stats.total_ms > 0.0);
    assert!(stats.max_step_ms > 0.0);
    assert!(stats.max_step_ms <= stats.total_ms);
    assert!(stats.pre_field_ms >= 0.0);
    assert!(stats.max_pre_field_ms <= stats.pre_field_ms);
    assert!(stats.pre_field_snapshot_ms >= 0.0);
    assert!(stats.pre_field_adversarial_ms >= 0.0);
    assert!(stats.central_brain_ms >= 0.0);
    assert!(stats.max_central_brain_ms <= stats.central_brain_ms);
    assert!(stats.controller_yield_ms >= 0.0);
    assert!(stats.max_controller_yield_ms <= stats.controller_yield_ms);
    let pre_field_parts = stats.pre_field_snapshot_ms
        + stats.pre_field_adversarial_ms
        + stats.central_brain_ms
        + stats.controller_yield_ms;
    assert!(
            pre_field_parts <= stats.pre_field_ms + 0.75,
            "split pre-field timing should fit inside total pre-field timing: parts={pre_field_parts} total={}",
            stats.pre_field_ms
        );
    assert!(stats.field_loop_ms >= 0.0);
    assert!(stats.max_field_loop_ms <= stats.field_loop_ms);
    assert!(stats.field_schedule_ms >= 0.0);
    assert!(stats.field_snapshot_ms > 0.0);
    assert!(stats.max_field_snapshot_ms <= stats.field_snapshot_ms);
    assert!(stats.field_player_decision_ms > 0.0);
    assert!(stats.max_field_player_decision_ms <= stats.field_player_decision_ms);
    let decision_bucket_ms = stats.field_player_possession_decision_ms
        + stats.field_player_support_decision_ms
        + stats.field_player_defensive_decision_ms
        + stats.field_player_loose_decision_ms;
    assert!(
            (decision_bucket_ms - stats.field_player_decision_ms).abs() < 0.001,
            "decision timing buckets should add back to player decision time: buckets={decision_bucket_ms} total={}",
            stats.field_player_decision_ms
        );
    assert!(stats.field_intent_ms >= 0.0);
    assert!(stats.field_official_ms >= 0.0);
    assert!(stats.max_field_official_ms <= stats.field_official_ms);
    assert!(stats.field_ball_ms >= 0.0);
    assert!(stats.max_field_ball_ms <= stats.field_ball_ms);
    assert!(stats.max_post_field_ms <= stats.post_field_ms);
    assert!(stats.max_learning_ms <= stats.learning_ms());
    assert!(stats.field_loop_pct() >= 0.0);
    assert!(stats.learning_pct() >= 0.0);

    sim.reset_step_timing_stats();
    assert_eq!(sim.step_timing_stats().ticks, 0);
    assert_eq!(sim.step_timing_stats().total_ms, 0.0);
    assert_eq!(sim.step_timing_stats().over_budget_ticks, 0);
}

#[test]
fn official_decision_snapshot_skips_ball_history_clone() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.8,
        seed: 22_407,
        ..Default::default()
    });
    for _ in 0..5 {
        sim.run_time_step();
    }

    let player_snapshot = WorldSnapshot::from_match_for_agent_decision(&sim);
    let official_snapshot = WorldSnapshot::from_match_for_official_decision(&sim);

    assert!(
        !player_snapshot.ball_history.is_empty(),
        "player decisions still keep ball history for settled-possession spacing"
    );
    assert!(
        official_snapshot.ball_history.is_empty(),
        "official decisions do not need cloned rolling ball history"
    );
    assert_eq!(official_snapshot.players.len(), 22);
    assert_eq!(official_snapshot.ball.position, sim.ball.position);
    assert!(assistant_offside_line_snapshot(
        &official_snapshot,
        OfficialKind::AssistantRefereeNear
    )
    .is_some());

    let mut assistant = sim.officials[1].clone();
    assistant.run_time_step(&official_snapshot, &mut mulberry32(22_407));
    assert!(assistant.position.x.is_finite());
    assert!(assistant.position.y.is_finite());
}

#[test]
fn player_decision_context_classifies_holder_support_defense_and_loose() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.2,
        seed: 22_408,
        ..Default::default()
    });
    let holder = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Midfielder)
        .map(|player| player.id)
        .expect("home holder");
    let support = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.id != holder)
        .map(|player| player.id)
        .expect("home support");
    let defender = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Defender)
        .map(|player| player.id)
        .expect("away defender");
    let holder_idx = sim.player_index_for_id(holder).expect("holder index");
    let support_idx = sim.player_index_for_id(support).expect("support index");
    let defender_idx = sim.player_index_for_id(defender).expect("defender index");
    sim.ball.holder = Some(holder);
    sim.ball.last_touch_team = Some(Team::Home);

    assert_eq!(
        sim.player_decision_timing_context_for(holder_idx, holder),
        SoccerPlayerDecisionTimingContext::Possession
    );
    assert_eq!(
        sim.player_decision_timing_context_for(support_idx, support),
        SoccerPlayerDecisionTimingContext::Support
    );
    assert_eq!(
        sim.player_decision_timing_context_for(defender_idx, defender),
        SoccerPlayerDecisionTimingContext::Defense
    );

    sim.ball.holder = None;
    assert_eq!(
        sim.player_decision_timing_context_for(defender_idx, defender),
        SoccerPlayerDecisionTimingContext::Loose
    );
}

#[test]
fn defensive_and_loose_decision_snapshots_keep_ball_history_for_loose_ball_pomdp() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.8,
        seed: 22_409,
        ..Default::default()
    });
    for _ in 0..5 {
        sim.run_time_step();
    }
    let defender = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Defender)
        .map(|player| player.id)
        .expect("away defender");
    let defender_idx = sim.player_index_for_id(defender).expect("defender index");
    let defender_home = sim.players[defender_idx].home_position;

    let rich = WorldSnapshot::from_match_for_agent_decision(&sim);
    let light = WorldSnapshot::from_match_for_defensive_or_loose_agent_decision(&sim);
    assert!(
        !rich.ball_history.is_empty(),
        "support/possession decisions keep settled-possession ball history"
    );
    assert!(
        !light.ball_history.is_empty(),
        "defensive/loose decisions keep ball history for history-aware loose-ball POMDP choices"
    );
    assert_eq!(rich.ball_history.len(), light.ball_history.len());
    assert_eq!(rich.ball.position, light.ball.position);
    assert_eq!(rich.players.len(), light.players.len());
    assert_eq!(
        light.shared_positions.latest.len(),
        SOCCER_MATCH_PLAYER_COUNT
    );
    assert_eq!(
        light.shared_positions.official_latest.len(),
        SOCCER_MATCH_OFFICIAL_COUNT
    );
    assert!(light.shared_positions.ball_latest.is_some());
    assert!(light.shared_positions.histories.is_empty());
    assert!(light.shared_positions.official_histories.is_empty());
    assert!(light.shared_positions.ball_history.is_empty());
    for player in &light.players {
        let sample = light
            .shared_positions
            .latest_for(player.id)
            .expect("light snapshot should keep latest player x/y");
        assert!(
            sample.position.distance(player.position) < SOCCER_PHYSICS_FRAME_EPSILON_YARDS,
            "light snapshot shared player position should match authoritative player {}",
            player.id
        );
    }
    assert_eq!(
        rich.defensive_assignment_for(defender, defender_home, false),
        light.defensive_assignment_for(defender, defender_home, false)
    );

    let rich_obs = rich.observation_for(defender);
    let light_obs = light.observation_for(defender);
    assert_eq!(rich_obs.has_ball, light_obs.has_ball);
    assert_eq!(rich_obs.visible_ball, light_obs.visible_ball);
    assert_eq!(rich_obs.visible_teammates, light_obs.visible_teammates);
    assert_eq!(rich_obs.visible_opponents, light_obs.visible_opponents);
    assert_eq!(rich_obs.team_brain_mode, light_obs.team_brain_mode);
    assert!(
        (rich_obs.ball_distance - light_obs.ball_distance).abs() < 1e-9,
        "defender ball distance should not depend on cloned ball history"
    );
    assert!(
        (rich_obs.real_pressure - light_obs.real_pressure).abs() < 1e-9,
        "defender pressure should not depend on cloned ball history"
    );

    let chaser = defender;
    sim.ball.holder = None;
    sim.ball.velocity = Vec2::new(1.6, -7.5);
    sim.pending_pass = None;
    let rich_loose = WorldSnapshot::from_match_for_agent_decision(&sim);
    let light_loose = WorldSnapshot::from_match_for_defensive_or_loose_agent_decision(&sim);
    assert!(!light_loose.ball_history.is_empty());
    assert_eq!(
        rich_loose.loose_ball_recovery_target_for(chaser),
        light_loose.loose_ball_recovery_target_for(chaser)
    );
    let rich_loose_obs = rich_loose.observation_for(chaser);
    let light_loose_obs = light_loose.observation_for(chaser);
    assert_eq!(rich_loose_obs.has_ball, light_loose_obs.has_ball);
    assert_eq!(
        rich_loose.controlled_possession_team(),
        light_loose.controlled_possession_team()
    );
    assert!(
        (rich_loose_obs.ball_distance - light_loose_obs.ball_distance).abs() < 1e-9,
        "loose-ball distance should not depend on cloned ball history"
    );
}

#[test]
fn carry_out_legality_uses_configured_pitch_width() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        field_width_yards: 60.0,
        seed: 2264,
        ..Default::default()
    });
    let holder = 6;
    park_players_except(&mut sim, &[holder]);
    sim.players[holder].position = Vec2::new(58.4, 64.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.6;
    sim.players[holder].preferences.dribble_bias = 1.0;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(holder);
    let options = sim.players[holder].possession_action_options(
        &observation,
        &snapshot.tactical_directive(Team::Home),
        0,
        0,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let carry_left = options
        .iter()
        .find(|option| option.label == "carry-out-left")
        .expect("carry-out-left option");
    let carry_right = options
        .iter()
        .find(|option| option.label == "carry-out-right")
        .expect("carry-out-right option");

    assert!(carry_left.legal);
    assert!(
        !carry_right.legal,
        "custom pitch width should make right touchline carry illegal: width={} x={}",
        snapshot.field_width, sim.players[holder].position.x
    );
}

#[test]
fn non_elite_overheld_dribble_is_suppressed_under_pressure() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Midfielder)
        .map(|player| player.id)
        .expect("home midfielder");
    park_players_except(&mut sim, &[holder]);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut observation = snapshot.observation_for(holder);
    observation.actual_time_on_ball_seconds = 3.2;
    observation.perceived_pressure = 0.82;
    observation.pressure_urgency = 0.86;
    observation.defensive_urgency = 0.58;
    observation.immediate_dispossession_risk = 0.70;

    let non_elite = ability01(7.8);
    let elite = ability01(9.3);
    let non_elite_hold_pressure = excessive_hold_pressure(&observation, non_elite);
    let elite_hold_pressure = excessive_hold_pressure(&observation, elite);
    let non_elite_hold_multiplier = dribble_hold_score_multiplier(&observation, non_elite);
    let elite_hold_multiplier = dribble_hold_score_multiplier(&observation, elite);
    let non_elite_release = release_after_hold_multiplier(&observation, non_elite);
    let elite_release = release_after_hold_multiplier(&observation, elite);

    assert!(
            non_elite_hold_pressure > elite_hold_pressure + 0.55,
            "ordinary good dribblers should be forced off stale carries sooner: non_elite={non_elite_hold_pressure} elite={elite_hold_pressure}"
        );
    assert!(
        non_elite_hold_multiplier < 0.40,
        "non-elite stale carries should be sharply suppressed, got {non_elite_hold_multiplier}"
    );
    assert!(
        elite_hold_multiplier > 0.88,
        "9+/10 dribblers should retain more carry permission, got {elite_hold_multiplier}"
    );
    assert!(
            non_elite_release > elite_release + 0.80,
            "overheld non-elite carries should boost pass/clear release more than elite carries: non_elite={non_elite_release} elite={elite_release}"
        );
}

#[test]
fn advanced_dribbler_fit_gates_take_on_appetite_to_the_three_most_forward() {
    // The take-a-man-on / dribble-into-pressure appetite is reserved for the three
    // most-forward outfielders (teammates_ahead 0..=2): full for the furthest forward,
    // fading by rank, and zero for anyone deeper. Lock the shape (not the exact mid
    // values) so the live policy and the learning-reward shaping can't silently drift.
    assert_eq!(advanced_dribbler_fit_from_rank(0), 1.0);
    assert!(advanced_dribbler_fit_from_rank(1) < advanced_dribbler_fit_from_rank(0));
    assert!(advanced_dribbler_fit_from_rank(2) < advanced_dribbler_fit_from_rank(1));
    assert!(
        advanced_dribbler_fit_from_rank(2) > 0.0,
        "the third-most-forward player keeps SOME appetite"
    );
    assert_eq!(
        advanced_dribbler_fit_from_rank(3),
        0.0,
        "the fourth-most-forward (and deeper) gets no take-on appetite"
    );
    assert_eq!(advanced_dribbler_fit_from_rank(9), 0.0);
}

#[test]
fn stale_pressured_dribble_is_penalized_in_learning_reward() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 22_683,
        ..Default::default()
    });
    let holder = 7;
    let pressure = 14;
    park_players_except(&mut sim, &[holder, pressure]);
    sim.players[holder].position = Vec2::new(38.0, 42.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.8;
    sim.players[pressure].position = Vec2::new(35.0, 40.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let before = WorldSnapshot::from_match(&sim);
    let mut stale_observation = before.observation_for(holder);
    stale_observation.actual_time_on_ball_seconds = 3.5;
    stale_observation.perceived_pressure = 0.88;
    stale_observation.pressure_urgency = 0.90;
    stale_observation.immediate_dispossession_risk = 0.78;
    stale_observation.excessive_hold_pressure = excessive_hold_pressure(
        &stale_observation,
        ability01(sim.players[holder].skills.dribbling),
    );
    let stale_penalty = pressured_stale_dribble_learning_penalty_points(
        &stale_observation,
        ability01(sim.players[holder].skills.dribbling),
        0.35,
        0.35,
        true,
    );
    let elite_penalty = pressured_stale_dribble_learning_penalty_points(
        &stale_observation,
        ability01(9.4),
        0.35,
        0.35,
        true,
    );

    assert!(
            stale_penalty >= 0.80,
            "non-elite overheld pressured carry should get a strong learning penalty, got {stale_penalty}"
        );
    assert_eq!(
        elite_penalty, 0.0,
        "9+/10 dribblers should be exempt unless the hold is extreme"
    );

    let mut stale_decision = test_decision_trace(&before, holder, "carry-forward");
    stale_decision.observation = stale_observation.clone();
    let mut fresh_decision = stale_decision.clone();
    fresh_decision.observation.actual_time_on_ball_seconds = 0.6;
    fresh_decision.observation.excessive_hold_pressure = excessive_hold_pressure(
        &fresh_decision.observation,
        ability01(sim.players[holder].skills.dribbling),
    );

    sim.players[holder].position = Vec2::new(38.0, 42.35);
    sim.ball.position = sim.players[holder].position;
    let after = WorldSnapshot::from_match(&sim);
    let stale_reward = dense_soccer_transition_reward(
        &sim.players[holder],
        &stale_decision,
        &before,
        &after,
        "carry-forward",
        &SoccerTacticalLearningWeights::default(),
    );
    let fresh_reward = dense_soccer_transition_reward(
        &sim.players[holder],
        &fresh_decision,
        &before,
        &after,
        "carry-forward",
        &SoccerTacticalLearningWeights::default(),
    );

    assert!(
            stale_reward < fresh_reward - 0.65,
            "stale pressured carry should train below a fresh carry: stale={stale_reward} fresh={fresh_reward}"
        );
}

#[test]
fn pressured_overholding_midfielder_gets_pass_release_probability_floor() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 22_681,
        ..Default::default()
    });
    let holder = 7;
    let outlet = 8;
    let pressure = 14;
    park_players_except(&mut sim, &[holder, outlet, pressure]);
    sim.players[holder].position = Vec2::new(38.0, 42.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].action_facing = FacingBucket::South;
    sim.players[holder].receive_facing = FacingBucket::South;
    sim.players[holder].skills.dribbling = 7.7;
    sim.players[holder].skills.passing_completion_rate = 7.8;
    sim.players[holder].preferences.dribble_bias = 1.18;
    sim.players[holder].preferences.pass_bias = 0.70;
    sim.players[outlet].position = Vec2::new(40.0, 58.0);
    sim.players[outlet].home_position = sim.players[outlet].position;
    sim.players[pressure].position = Vec2::new(22.0, 32.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let pass_targets = snapshot.ranked_visible_pass_targets(holder, 3);
    let any_targets = snapshot.ranked_pass_targets(holder, 3);
    let can_see_outlet = snapshot.player_can_see_player(holder, outlet);
    assert!(
        pass_targets.contains(&outlet),
        "test setup should expose a visible outlet, got {pass_targets:?}; any={any_targets:?}; can_see={can_see_outlet}"
    );
    let mut observation = snapshot.observation_for(holder);
    observation.actual_time_on_ball_seconds = 3.4;
    observation.perceived_pressure = 0.84;
    observation.pressure_urgency = 0.88;
    observation.immediate_dispossession_risk = 0.72;
    observation.expected_pass_completion = 0.58;
    observation.best_pass_receiver_openness = 0.62;

    let options = sim.players[holder].possession_action_options(
        &observation,
        &snapshot.tactical_directive(Team::Home),
        pass_targets.len(),
        snapshot.ranked_visible_aerial_pass_targets(holder, 3).len(),
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let pass1 = options
        .iter()
        .find(|option| option.label == "pass1")
        .expect("pass1 option");
    let dribble = options
        .iter()
        .find(|option| option.label == "dribble")
        .expect("dribble option");
    let carry_forward = options
        .iter()
        .find(|option| option.label == "carry-forward")
        .expect("carry-forward option");

    assert!(pass1.legal);
    assert!(
        pass1.probability >= 0.28,
        "overheld pressure should force a meaningful pass release floor, got {pass1:?}"
    );
    assert!(
            pass1.probability > dribble.probability
                && pass1.probability > carry_forward.probability,
            "release to an open outlet should outrank stale carrying: pass={pass1:?} dribble={dribble:?} carry={carry_forward:?}"
        );
}

#[test]
fn open_support_outlets_raise_pressured_release_over_stale_carry() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 22_684,
        ..Default::default()
    });
    let holder = 7;
    let outlet = 8;
    let pressure = 14;
    park_players_except(&mut sim, &[holder, outlet, pressure]);
    sim.players[holder].position = Vec2::new(38.0, 42.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.7;
    sim.players[holder].skills.passing_completion_rate = 7.8;
    sim.players[holder].preferences.dribble_bias = 1.22;
    sim.players[holder].preferences.pass_bias = 0.68;
    sim.players[outlet].position = Vec2::new(45.0, 50.0);
    sim.players[outlet].home_position = sim.players[outlet].position;
    sim.players[pressure].position = Vec2::new(35.0, 40.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let pass_targets = snapshot.ranked_visible_pass_targets(holder, 3);
    assert!(pass_targets.contains(&outlet));
    let mut open_observation = snapshot.observation_for(holder);
    open_observation.actual_time_on_ball_seconds = 3.4;
    open_observation.perceived_pressure = 0.84;
    open_observation.pressure_urgency = 0.88;
    open_observation.immediate_dispossession_risk = 0.72;
    open_observation.expected_pass_completion = 0.58;
    open_observation.best_pass_receiver_openness = 0.62;
    open_observation.open_support_outlets = 2;
    let mut closed_observation = open_observation.clone();
    closed_observation.open_support_outlets = 0;

    let directive = snapshot.tactical_directive(Team::Home);
    let aerial_targets = snapshot.ranked_visible_aerial_pass_targets(holder, 3).len();
    let open_options = sim.players[holder].possession_action_options(
        &open_observation,
        &directive,
        pass_targets.len(),
        aerial_targets,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let closed_options = sim.players[holder].possession_action_options(
        &closed_observation,
        &directive,
        pass_targets.len(),
        aerial_targets,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let option_probability = |options: &[AgentActionOptionTrace], label: &str| {
        options
            .iter()
            .find(|option| option.label == label && option.legal)
            .map(|option| option.probability)
            .unwrap_or(0.0)
    };
    let open_pass = option_probability(&open_options, "pass1");
    let closed_pass = option_probability(&closed_options, "pass1");
    let open_carry = option_probability(&open_options, "carry-forward");
    let closed_carry = option_probability(&closed_options, "carry-forward");

    assert!(
            open_pass > closed_pass + 0.08,
            "open support outlets should materially raise pressure release: open={open_pass} closed={closed_pass}"
        );
    assert!(
            open_carry < closed_carry,
            "open support outlets should reduce stale carry preference: open={open_carry} closed={closed_carry}"
        );
    assert!(
            open_pass > open_carry,
            "with open outlets under pressure, pass should outrank stale carry: pass={open_pass} carry={open_carry}"
        );
}

#[test]
fn learned_stale_non_elite_dribble_releases_to_open_outlet() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 22_682,
        ..Default::default()
    });
    let holder = 7;
    let outlet = 8;
    let pressure = 14;
    park_players_except(&mut sim, &[holder, outlet, pressure]);
    sim.players[holder].position = Vec2::new(38.0, 42.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.8;
    sim.players[holder].skills.passing_completion_rate = 8.0;
    sim.players[outlet].position = Vec2::new(45.0, 50.0);
    sim.players[outlet].home_position = sim.players[outlet].position;
    sim.players[pressure].position = Vec2::new(35.0, 40.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut observation = snapshot.observation_for(holder);
    observation.actual_time_on_ball_seconds = 3.5;
    observation.perceived_pressure = 0.86;
    observation.pressure_urgency = 0.88;
    observation.immediate_dispossession_risk = 0.74;
    observation.expected_pass_completion = 0.60;
    observation.best_pass_receiver_openness = 0.64;
    observation.excessive_hold_pressure = excessive_hold_pressure(
        &observation,
        ability01(sim.players[holder].skills.dribbling),
    );
    let plan = SoccerLearnedPlan {
        action: "carry-forward".to_string(),
        target_player: None,
        target_point: Some(Vec2::new(38.0, 48.0)),
        mpc_replan: None,
    };

    let (action, label) = sim.players[holder]
        .action_from_learned_plan(&plan, &snapshot, &observation)
        .expect("stale learned carry should release to an outlet");
    assert_eq!(label, "pass1");
    let SoccerAction::Pass {
        target_player: Some(target),
        flight: PassFlight::Floor,
        ..
    } = action
    else {
        panic!("stale learned carry should become a floor pass, got {action:?}");
    };
    assert_eq!(target, outlet);

    let mut elite_holder = sim.players[holder].clone();
    elite_holder.skills.dribbling = 9.4;
    // High dispossession risk (0.74) + a clearly-open forward outlet: even an
    // elite dribbler yields the carry and releases the open pass rather than
    // dribbling into a likely turnover (the reported "should have passed" bug).
    let elite_observation = SoccerPomdpObservation {
        excessive_hold_pressure: excessive_hold_pressure(&observation, ability01(9.4)),
        ..observation.clone()
    };
    let (elite_action, elite_label) = elite_holder
        .action_from_learned_plan(&plan, &snapshot, &elite_observation)
        .expect("elite under high dispossession risk should release the open outlet");
    assert_eq!(elite_label, "pass1");
    assert!(
            matches!(
                elite_action,
                SoccerAction::Pass {
                    target_player: Some(target),
                    flight: PassFlight::Floor,
                    ..
                } if target == outlet
            ),
            "elite should release the open forward outlet under high dispossession risk, got {elite_action:?}"
        );

    // In MODERATE pressure (dispossession risk below the yield floor) the elite
    // KEEPS carry permission — the exemption that lets a skilled dribbler take a
    // man on is preserved; only an imminent turnover overrides it.
    let moderate_elite_observation = SoccerPomdpObservation {
        immediate_dispossession_risk: 0.30,
        ..elite_observation
    };
    let (moderate_action, moderate_label) = elite_holder
        .action_from_learned_plan(&plan, &snapshot, &moderate_elite_observation)
        .expect("elite in moderate pressure should retain the carry");
    assert!(
            matches!(moderate_action, SoccerAction::DribbleMove { .. }),
            "elite dribbler should retain carry permission in moderate pressure, got {moderate_action:?}"
        );
    assert_ne!(moderate_label, "pass1");
}

#[test]
fn excessive_hold_pressure_is_visible_to_table_and_neural_learners() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Midfielder)
        .map(|player| player.id)
        .expect("home midfielder");
    park_players_except(&mut sim, &[holder]);
    sim.players[holder].skills.dribbling = 7.8;
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut observation = snapshot.observation_for(holder);
    observation.actual_time_on_ball_seconds = 3.2;
    observation.perceived_pressure = 0.82;
    observation.pressure_urgency = 0.86;
    observation.defensive_urgency = 0.58;
    observation.immediate_dispossession_risk = 0.70;
    observation.excessive_hold_pressure = excessive_hold_pressure(
        &observation,
        ability01(sim.players[holder].skills.dribbling),
    );

    let q_key = SoccerQStateKey::from_parts(
        &snapshot.mdp_state_for_player(holder),
        &observation,
        Team::Home,
        sim.players[holder].role,
    );
    let decision = test_decision_trace(&snapshot, holder, "carry-forward");
    let transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: holder,
        team: Team::Home,
        role: sim.players[holder].role,
        state: decision.mdp_state,
        observation: observation.clone(),
        belief: decision.belief,
        action: "carry-forward".to_string(),
        action_target: decision.action_target,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(holder),
        next_observation: observation.clone(),
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);

    assert!(
        observation.excessive_hold_pressure > 0.60,
        "test setup should create a stale pressured carry: {:?}",
        observation.excessive_hold_pressure
    );
    assert!(
        q_key.excessive_hold_pressure_bin >= 3,
        "Q-state should expose overheld-pressure bins, got {}",
        q_key.excessive_hold_pressure_bin
    );
    assert!(
        features[SOCCER_NEURAL_FEATURE_EXCESSIVE_HOLD_PRESSURE] > 0.60,
        "neural learner should directly see excessive hold pressure"
    );
}

#[test]
fn ball_surface_physics_reaches_pomdp_table_and_neural_learners() {
    fn surface_learning_slice(
        config: MatchConfig,
        resistance: BallResistanceFrame,
    ) -> (
        SoccerPomdpObservation,
        SoccerQStateKey,
        [f64; SOCCER_NEURAL_FEATURE_DIM],
    ) {
        let mut sim = SoccerMatch::default_11v11(config);
        let holder = sim
            .players
            .iter()
            .find(|player| player.team == Team::Home && player.role == PlayerRole::Midfielder)
            .map(|player| player.id)
            .expect("home midfielder");
        park_players_except(&mut sim, &[holder]);
        sim.players[holder].position = Vec2::new(40.0, 54.0);
        sim.players[holder].home_position = sim.players[holder].position;
        sim.ball.holder = Some(holder);
        sim.ball.position = sim.players[holder].position;
        sim.ball.velocity = Vec2::new(8.0, 18.0);
        sim.ball.resistance = resistance;
        sim.ball.last_touch_team = Some(Team::Home);
        sim.shared_positions.sync_from_players_and_ball(
            &sim.players,
            &sim.officials,
            &sim.ball,
            sim.tick,
            sim.clock_seconds,
        );

        let snapshot = WorldSnapshot::from_match(&sim);
        let observation = snapshot.observation_for(holder);
        let q_key = SoccerQStateKey::from_parts(
            &snapshot.mdp_state_for_player(holder),
            &observation,
            Team::Home,
            sim.players[holder].role,
        );
        let decision = test_decision_trace(&snapshot, holder, "carry-forward");
        let transition = SoccerLearningTransition {
            tick: snapshot.tick,
            player_id: holder,
            team: Team::Home,
            role: sim.players[holder].role,
            state: decision.mdp_state,
            observation: observation.clone(),
            belief: decision.belief,
            action: "carry-forward".to_string(),
            action_target: decision.action_target,
            decision_context: SoccerDecisionContext::default(),
            tactical_trace: SoccerTacticalLearningTrace::default(),
            reward: 0.0,
            next_state: snapshot.mdp_state_for_player(holder),
            next_observation: observation.clone(),
            done: false,
        };
        let features = soccer_neural_transition_features(&transition);
        (observation, q_key, features)
    }

    let (fast_observation, _fast_key, fast_features) = surface_learning_slice(
        MatchConfig {
            seed: 24_901,
            ball_drag_per_tick: 0.006,
            ball_air_resistance: 0.0015,
            ball_grass_resistance_yps2: 0.20,
            ball_stop_speed_yps: 0.16,
            ..Default::default()
        },
        BallResistanceFrame {
            total_loss_yps: 0.08,
            rolling_contact: 0.15,
            ..Default::default()
        },
    );
    let (heavy_observation, _heavy_key, heavy_features) = surface_learning_slice(
        MatchConfig {
            seed: 24_901,
            ball_drag_per_tick: 0.074,
            ball_air_resistance: 0.020,
            ball_grass_resistance_yps2: 2.30,
            ball_stop_speed_yps: 1.55,
            ..Default::default()
        },
        BallResistanceFrame {
            total_loss_yps: 1.65,
            rolling_contact: 0.95,
            ..Default::default()
        },
    );

    assert!(
        heavy_observation.ball_surface_drag_per_tick > fast_observation.ball_surface_drag_per_tick
    );
    assert!(
        heavy_observation.ball_surface_grass_resistance_yps2
            > fast_observation.ball_surface_grass_resistance_yps2
    );
    assert!(
        heavy_observation.ball_resistance_total_loss_yps
            > fast_observation.ball_resistance_total_loss_yps
    );
    // Pitch-surface physics was removed from the Q-key; its discriminative
    // signal is preserved on the observation (above) and the neural features.
    assert!(
        heavy_features[SOCCER_NEURAL_FEATURE_BALL_SURFACE_DRAG]
            > fast_features[SOCCER_NEURAL_FEATURE_BALL_SURFACE_DRAG]
    );
    assert!(
        heavy_features[SOCCER_NEURAL_FEATURE_BALL_SURFACE_GRASS_RESISTANCE]
            > fast_features[SOCCER_NEURAL_FEATURE_BALL_SURFACE_GRASS_RESISTANCE]
    );
    assert!(
        heavy_features[SOCCER_NEURAL_FEATURE_BALL_RESISTANCE_TOTAL_LOSS]
            > fast_features[SOCCER_NEURAL_FEATURE_BALL_RESISTANCE_TOTAL_LOSS]
    );
    assert!(
        heavy_features[SOCCER_NEURAL_FEATURE_BALL_RESISTANCE_ROLLING_CONTACT]
            > fast_features[SOCCER_NEURAL_FEATURE_BALL_RESISTANCE_ROLLING_CONTACT]
    );
}

#[test]
fn pressured_defender_in_own_half_gets_clearance_probability_floor() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 2265,
        ..Default::default()
    });
    let defender = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Defender)
        .map(|player| player.id)
        .expect("home defender");
    let pressure = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Forward)
        .map(|player| player.id)
        .expect("away forward");
    park_players_except(&mut sim, &[defender, pressure]);
    sim.players[defender].position = Vec2::new(40.0, 22.0);
    sim.players[defender].home_position = sim.players[defender].position;
    sim.players[defender].skills.dribbling = 7.4;
    sim.players[defender].skills.defending = 8.4;
    sim.players[defender].preferences.dribble_bias = 1.0;
    sim.players[defender].preferences.pass_bias = 0.40;
    sim.players[pressure].position = Vec2::new(40.9, 22.2);
    sim.ball.holder = Some(defender);
    sim.ball.position = sim.players[defender].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let mut observation = snapshot.observation_for(defender);
    observation.actual_time_on_ball_seconds = 3.4;
    observation.perceived_pressure = 0.88;
    observation.pressure_urgency = 0.86;
    observation.defensive_urgency = 0.82;
    observation.immediate_dispossession_risk = 0.78;
    observation.yards_to_own_goal = 22.0;
    observation.yards_to_goal = 98.0;
    observation.forward_dribble_space_yards = 7.0;
    observation.expected_pass_completion = 0.18;
    observation.best_pass_receiver_openness = 0.18;

    let options = sim.players[defender].possession_action_options(
        &observation,
        &snapshot.tactical_directive(Team::Home),
        0,
        0,
        false,
        snapshot.dt_seconds,
        snapshot.field_width,
    );
    let clearance = options
        .iter()
        .find(|option| option.label == "clearance")
        .expect("clearance option");
    let carry_forward = options
        .iter()
        .find(|option| option.label == "carry-forward")
        .expect("carry-forward option");
    let dribble = options
        .iter()
        .find(|option| option.label == "dribble")
        .expect("dribble option");

    assert!(clearance.legal);
    assert!(
        clearance.probability >= 0.50,
        "pressured defenders in their own half need a strong clearance floor, got {clearance:?}"
    );
    assert!(
            clearance.probability > carry_forward.probability
                && clearance.probability > dribble.probability,
            "clearance should beat stale carry choices under own-half pressure: clearance={clearance:?} carry={carry_forward:?} dribble={dribble:?}"
        );
}

#[test]
fn pressured_overholding_defender_runtime_prefers_clearance_over_stale_dribble() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 2266,
        ..Default::default()
    });
    let defender = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Defender)
        .map(|player| player.id)
        .expect("home defender");
    let pressure = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Forward)
        .map(|player| player.id)
        .expect("away forward");
    park_players_except(&mut sim, &[defender, pressure]);
    sim.tick = 34;
    sim.clock_seconds = 3.4;
    sim.players[defender].position = Vec2::new(40.0, 22.0);
    sim.players[defender].home_position = sim.players[defender].position;
    sim.players[defender].skills.dribbling = 7.4;
    sim.players[defender].skills.defending = 8.4;
    sim.players[defender].skills.decision_noise = 0.0;
    sim.players[defender].preferences.dribble_bias = 1.0;
    sim.players[defender].preferences.pass_bias = 0.35;
    sim.players[pressure].position = Vec2::new(40.8, 22.1);
    sim.ball.holder = Some(defender);
    sim.ball.position = sim.players[defender].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.ball.position_history.clear();
    sim.ball.position_history.push_back(BallPositionSample {
        tick: 0,
        clock_seconds: 0.0,
        position: sim.ball.position,
        velocity: Vec2::zero(),
        acceleration: Vec2::zero(),
        jerk: Vec2::zero(),
        curl_acceleration: Vec2::zero(),
        altitude_yards: 0.0,
        resistance: BallResistanceFrame::default(),
        holder: Some(defender),
        last_touch_team: Some(Team::Home),
    });

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(defender);
    assert!(
        observation.excessive_hold_pressure >= 0.20,
        "test setup should expose stale pressured possession: {:?}",
        observation.excessive_hold_pressure
    );
    assert!(
        observation.yards_to_own_goal < observation.yards_to_goal,
        "defender should be holding the ball in his own half"
    );

    let mut clearances = 0;
    let mut stale_dribbles = 0;
    let trials = 120;
    for seed in 0..trials {
        let mut player = sim.players[defender].clone();
        let intent =
            player.run_time_step(&snapshot, None, None, &mut SeededRandom::new(91_000 + seed));
        match intent.action {
            SoccerAction::Clearance { .. } => clearances += 1,
            SoccerAction::DribbleMove { .. } | SoccerAction::Dribble(_) => stale_dribbles += 1,
            _ => {}
        }
    }

    assert!(
            clearances >= 90,
            "pressured overholding own-half defenders should overwhelmingly clear danger, got {clearances}/{trials}"
        );
    assert!(
            stale_dribbles <= 15,
            "stale pressured dribbles should be rare once the safety valve is active, got {stale_dribbles}/{trials}"
        );
}

#[test]
fn learned_stale_defender_dribble_is_overridden_to_clearance() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 2267,
        ..Default::default()
    });
    let defender = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Defender)
        .map(|player| player.id)
        .expect("home defender");
    let pressure = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role == PlayerRole::Forward)
        .map(|player| player.id)
        .expect("away forward");
    park_players_except(&mut sim, &[defender, pressure]);
    sim.tick = 36;
    sim.clock_seconds = 3.6;
    sim.players[defender].position = Vec2::new(39.0, 21.5);
    sim.players[defender].home_position = sim.players[defender].position;
    sim.players[defender].skills.dribbling = 7.2;
    sim.players[defender].skills.defending = 8.5;
    sim.players[defender].preferences.dribble_bias = 1.20;
    sim.players[pressure].position = Vec2::new(39.7, 21.7);
    sim.ball.holder = Some(defender);
    sim.ball.position = sim.players[defender].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);
    sim.ball.position_history.clear();
    sim.ball.position_history.push_back(BallPositionSample {
        tick: 0,
        clock_seconds: 0.0,
        position: sim.ball.position,
        velocity: Vec2::zero(),
        acceleration: Vec2::zero(),
        jerk: Vec2::zero(),
        curl_acceleration: Vec2::zero(),
        altitude_yards: 0.0,
        resistance: BallResistanceFrame::default(),
        holder: Some(defender),
        last_touch_team: Some(Team::Home),
    });

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(defender);
    let plan = SoccerLearnedPlan {
        action: "carry_forward".to_string(),
        target_player: None,
        target_point: Some(Vec2::new(39.0, 28.0)),
        mpc_replan: None,
    };
    let (action, label) = sim.players[defender]
        .action_from_learned_plan(&plan, &snapshot, &observation)
        .expect("learned stale carry should resolve through the safety valve");

    assert!(
        observation.excessive_hold_pressure >= 0.18,
        "test setup should expose excessive hold pressure: {:?}",
        observation.excessive_hold_pressure
    );
    assert!(
        observation.yards_to_own_goal < observation.yards_to_goal,
        "defender should be overholding in his own half"
    );
    assert_eq!(label, "clearance");
    let SoccerAction::Clearance { target, power } = action else {
        panic!("learned stale defender carry should become clearance, got {action:?}");
    };
    assert!(
        (target.y - sim.players[defender].position.y) * Team::Home.attack_dir() > 25.0,
        "clearance should send the ball upfield: target={target:?}"
    );
    assert!(power >= 0.90);
}

#[test]
fn goalkeeper_save_probability_is_halved_even_for_direct_shots() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper_id = sim.goalkeeper_for(Team::Away).expect("away keeper");
    sim.players[keeper_id].position = Vec2::new(40.0, 118.4);
    sim.players[keeper_id].skills.goalkeeping = 10.0;
    sim.players[keeper_id].skills.defending = 10.0;
    sim.players[keeper_id].skills.first_touch = 10.0;
    sim.players[keeper_id].skills.acceleration = 10.0;

    let save_probability = goalkeeper_save_probability(
        &sim.players[keeper_id],
        Vec2::new(40.0, 100.0),
        Vec2::new(40.0, 120.0),
        mph_to_yps(54.0),
        sim.config.goal_width_yards,
        0.0,
    );

    assert!(
        save_probability <= 0.70,
        "even a set keeper is bounded by the 20-yd distance baseline, got {save_probability}"
    );
    assert!(
        save_probability >= 0.06,
        "keeper should still have a nonzero chance on direct shots"
    );
}

#[test]
fn goalkeeper_save_probability_improves_with_distance_and_clear_sightline() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper_id = sim.goalkeeper_for(Team::Away).expect("away keeper");
    sim.players[keeper_id].position = Vec2::new(40.0, 118.4);
    sim.players[keeper_id].skills.goalkeeping = 9.2;
    sim.players[keeper_id].skills.defending = 8.6;
    sim.players[keeper_id].skills.first_touch = 9.0;
    sim.players[keeper_id].skills.acceleration = 8.8;

    let long_clean = goalkeeper_save_probability(
        &sim.players[keeper_id],
        Vec2::new(40.0, 62.0),
        Vec2::new(40.0, 120.0),
        mph_to_yps(42.0),
        sim.config.goal_width_yards,
        0.0,
    );
    let close_hard_screened = goalkeeper_save_probability(
        &sim.players[keeper_id],
        Vec2::new(40.0, 108.0),
        Vec2::new(40.0, 120.0),
        mph_to_yps(64.0),
        sim.config.goal_width_yards,
        0.82,
    );

    assert!(
            long_clean > close_hard_screened + 0.18,
            "long clear-sightline shots should be more keeper-friendly: long={long_clean} close={close_hard_screened}"
        );
    assert!(
        long_clean > 0.50,
        "long clear-sightline shots can exceed the short direct-shot cap, got {long_clean}"
    );
}

#[test]
fn goalkeeper_save_probability_sanitizes_bad_physics_inputs() {
    let skills = SkillProfile {
        goalkeeping: 8.0,
        defending: 7.2,
        first_touch: 7.5,
        acceleration: 7.1,
        top_speed: 7.4,
        ..SkillProfile::default()
    };
    let keeper = Vec2::new(40.0, 118.4);
    let shooter = Vec2::new(40.0, 100.0);
    let crossing = Vec2::new(40.0, 120.0);
    let cases = [
        (
            "nan shot speed",
            keeper,
            Vec2::zero(),
            0.0,
            shooter,
            crossing,
            f64::NAN,
            DEFAULT_GOAL_WIDTH_YARDS,
            0.0,
        ),
        (
            "nan goal width",
            keeper,
            Vec2::zero(),
            0.0,
            shooter,
            crossing,
            mph_to_yps(48.0),
            f64::NAN,
            0.0,
        ),
        (
            "nan sightline",
            keeper,
            Vec2::zero(),
            0.0,
            shooter,
            crossing,
            mph_to_yps(48.0),
            DEFAULT_GOAL_WIDTH_YARDS,
            f64::NAN,
        ),
        (
            "non-finite vectors",
            Vec2::new(f64::NAN, f64::INFINITY),
            Vec2::new(f64::NAN, 0.0),
            f64::NAN,
            Vec2::new(f64::NAN, 100.0),
            Vec2::new(40.0, f64::NAN),
            f64::INFINITY,
            -1.0,
            f64::INFINITY,
        ),
        (
            "overflow-scale geometry",
            keeper,
            Vec2::zero(),
            0.0,
            Vec2::new(f64::MAX, f64::MAX),
            Vec2::new(-f64::MAX, f64::MAX),
            mph_to_yps(48.0),
            DEFAULT_GOAL_WIDTH_YARDS,
            0.0,
        ),
    ];

    for (
        name,
        keeper_position,
        keeper_velocity,
        keeper_fatigue,
        shooter_position,
        shot_crossing,
        shot_speed,
        goal_width,
        sightline_screen_probability,
    ) in cases
    {
        let probability = goalkeeper_save_probability_from_traits(
            &skills,
            keeper_position,
            keeper_velocity,
            keeper_fatigue,
            shooter_position,
            shot_crossing,
            shot_speed,
            goal_width,
            sightline_screen_probability,
        );
        assert!(
            probability.is_finite() && (0.0..=0.995).contains(&probability),
            "{name} produced invalid save probability {probability}"
        );
    }
}

#[test]
fn goalkeeper_reach_saves_slow_ball_within_one_yard() {
    // A ball crossing within ~1 yard of the keeper that is slow (<20mph) or
    // struck from range should be saved markedly more often than the same
    // ball crossing out of reach — the keeper gets a hand/body to it.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let keeper_id = sim.goalkeeper_for(Team::Away).expect("away keeper");
    let keeper = &mut sim.players[keeper_id];
    keeper.position = Vec2::new(40.0, 118.4);
    keeper.skills.goalkeeping = 7.5;
    keeper.skills.defending = 7.0;
    keeper.skills.first_touch = 7.5;
    keeper.skills.acceleration = 7.0;

    // Slow ball (~12mph) crossing right at the keeper's x.
    let within_reach_slow = goalkeeper_save_probability(
        &sim.players[keeper_id],
        Vec2::new(40.0, 100.0),
        Vec2::new(40.3, 120.0),
        mph_to_yps(12.0),
        sim.config.goal_width_yards,
        0.0,
    );
    // Same slow ball crossing well wide of the keeper (out of reach).
    let out_of_reach_slow = goalkeeper_save_probability(
        &sim.players[keeper_id],
        Vec2::new(40.0, 100.0),
        Vec2::new(46.0, 120.0),
        mph_to_yps(12.0),
        sim.config.goal_width_yards,
        0.0,
    );
    assert!(
        within_reach_slow > out_of_reach_slow + 0.10,
        "a slow ball within a yard should be saved far more than one out of reach: \
             within={within_reach_slow} out={out_of_reach_slow}"
    );
    assert!(within_reach_slow <= 0.995);
}

#[test]
fn just_dispossessed_player_cannot_immediately_re_tackle() {
    // Reproduces the 1v1 duel livelock: A holds, B wins it, then A tries to
    // win it straight back within the grace window — which must fail so the
    // ball does not ping-pong forever.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    // Outfield players: a keeper holding the ball in his own box is now unstealable
    // (its own rule), which is not what this re-tackle-grace test is exercising.
    let winner = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home && p.role != PlayerRole::Goalkeeper)
        .unwrap()
        .id;
    let loser = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away && p.role != PlayerRole::Goalkeeper)
        .unwrap()
        .id;
    // Stage the ball with the eventual loser, then have the winner take it.
    sim.ball.holder = Some(loser);
    sim.complete_defensive_dispossession(winner, loser, "tackle");
    assert_eq!(sim.ball.holder, Some(winner));
    let recent = sim.recent_dispossession.expect("dispossession recorded");
    assert_eq!(recent.winner, winner);
    assert_eq!(recent.loser, loser);

    // The grace blocks the loser winning it straight back from the winner.
    let blocked = sim.recent_dispossession.is_some_and(|r| {
        sim.tick.saturating_sub(r.tick) < POSSESSION_REGAIN_GRACE_TICKS
            && r.winner == winner
            && r.loser == loser
    });
    assert!(
        blocked,
        "immediate reverse steal must be inside the grace window"
    );

    // After the grace window elapses, the block lifts.
    sim.tick += POSSESSION_REGAIN_GRACE_TICKS;
    let blocked_after = sim.recent_dispossession.is_some_and(|r| {
        sim.tick.saturating_sub(r.tick) < POSSESSION_REGAIN_GRACE_TICKS
            && r.winner == winner
            && r.loser == loser
    });
    assert!(!blocked_after, "grace must expire so play is not frozen");
}

#[test]
fn body_shielded_carrier_denies_a_clean_steal_to_a_defender_behind() {
    // A carrier running with the ball pushed out in front, body between ball and
    // a trailing defender, cannot be cleanly dispossessed from behind (only a foul
    // reaches the ball). The geometric shield must recognise that situation.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home)
        .unwrap()
        .id;
    let defender = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away)
        .unwrap()
        .id;

    // Home attacks toward +y. Carrier at midfield facing goalward; ball pushed
    // ~1.2yd in front; defender tucked 2yd behind the body (~3.2yd off the ball).
    sim.players[carrier].position = Vec2::new(40.0, 60.0);
    sim.players[carrier].facing_yaw = std::f64::consts::FRAC_PI_2; // faces +y
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 61.2);
    sim.players[defender].position = Vec2::new(40.0, 58.0);
    assert!(
        sim.carrier_shields_ball_from_defender(carrier, defender),
        "a defender behind the body with the ball out in front must be shielded out"
    );

    // A defender goal-side (in front of the carrier, near the ball) can still
    // legitimately challenge — not shielded out.
    sim.players[defender].position = Vec2::new(40.0, 62.0);
    assert!(
        !sim.carrier_shields_ball_from_defender(carrier, defender),
        "a defender in front of the carrier is not shielded out"
    );

    // A defender behind but right on top of the ball (within a yard) can poke it.
    sim.ball.position = Vec2::new(40.0, 60.4);
    sim.players[defender].position = Vec2::new(40.0, 59.8);
    assert!(
        !sim.carrier_shields_ball_from_defender(carrier, defender),
        "a defender within a yard of the ball is not shielded out"
    );
}

#[test]
fn shielded_defender_is_blocked_at_the_carrier_body_for_the_animation() {
    // The steal is denied logically; the animation must also reflect it — a shielded-out
    // defender cannot overlap the carrier's body (which would render as it standing on the
    // ball). It is pushed back out to the body ring.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home)
        .unwrap()
        .id;
    let defender = sim
        .players
        .iter()
        .find(|p| p.team == Team::Away)
        .unwrap()
        .id;

    // Carrier at midfield, ball pushed ~1.2yd in front (toward +y); defender tries to
    // bury itself in the carrier's back from behind (~0.2yd off the body, ~1.4yd off ball).
    sim.players[carrier].position = Vec2::new(40.0, 60.0);
    sim.players[carrier].facing_yaw = std::f64::consts::FRAC_PI_2;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 61.2);
    sim.players[defender].position = Vec2::new(40.0, 59.8);
    sim.players[defender].velocity = Vec2::new(0.0, 4.0); // driving forward into the body
    assert!(sim.carrier_shields_ball_from_defender(carrier, defender));

    sim.enforce_shield_body_barrier_for(defender);

    let gap = sim.players[defender]
        .position
        .distance(sim.players[carrier].position);
    assert!(
        gap >= SHIELD_BODY_BARRIER_YARDS - 1e-6,
        "a shielded defender must be held at the carrier's body ring, got {gap}"
    );
    // It stays on its own (back) side of the carrier — not teleported past to the ball.
    assert!(
        sim.players[defender].position.y < sim.players[carrier].position.y,
        "the barrier keeps the defender behind the body, not through it"
    );
    // Forward momentum into the body is cancelled so it presses, not jitters through.
    assert!(
        sim.players[defender].velocity.y <= 1e-6,
        "into-body momentum should be removed at the barrier"
    );

    // A defender goal-side (in front, near the ball) is NOT shielded — no barrier, it can
    // sit right on the carrier to contest.
    sim.players[defender].position = Vec2::new(40.0, 60.2);
    sim.players[defender].velocity = Vec2::zero();
    assert!(!sim.carrier_shields_ball_from_defender(carrier, defender));
    sim.enforce_shield_body_barrier_for(defender);
    assert_eq!(
        sim.players[defender].position,
        Vec2::new(40.0, 60.2),
        "an unshielded defender is not pushed off the carrier"
    );
}

#[test]
fn carried_ball_orbit_holds_close_control_and_tightens_near_opponents() {
    // The carried ball rests within close-control distance (≈0.25–1.0 yd) of the
    // carrier's feet, tighter the nearer an opponent is.
    let facing = std::f64::consts::FRAC_PI_2; // faces +y
    let (_dir, loose_radius, _through, _long, _cap, _rate) =
        carried_ball_orbit_command(facing, None, f64::INFINITY, None);
    assert!(
        (0.95..=1.05).contains(&loose_radius),
        "loose control radius should be ≈1yd in open space, got {loose_radius}"
    );
    let (_dir, tight_radius, _through, _long, _cap, _rate) =
        carried_ball_orbit_command(facing, None, 0.8, None);
    assert!(
        (0.25..0.45).contains(&tight_radius),
        "tight control radius should be ≈0.3yd with an opponent on top, got {tight_radius}"
    );
    assert!(
        tight_radius < loose_radius,
        "a closer opponent must tighten control (smaller orbit radius)"
    );
}

#[test]
fn carried_ball_orbits_around_the_body_and_never_through_on_a_normal_carry() {
    // On an ordinary carry the ball swings AROUND the carrier (radius floored by
    // the body) — it never collapses through the player — and settles in front.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home)
        .unwrap()
        .id;
    park_players_except(&mut sim, &[carrier]);
    let player_pos = Vec2::new(40.0, 60.0);
    sim.players[carrier].position = player_pos;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 59.0); // start the ball BEHIND the body
    sim.ball.reset_carry_orbit();
    let mut rng = SeededRandom::new(7);
    let mut min_radius = f64::INFINITY;
    for step in 0..30u64 {
        let pos = sim.ball.advance_carried_ball_orbit(
            step + 1,
            player_pos,
            Vec2::new(0.0, 1.0), // resting spot: in front of the body
            0.9,
            false, // ordinary carry: must arc around, not through
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_NORMAL_RATE_RAD_S,
            1.0 / 30.0,
            sim.config.field_width_yards,
            sim.config.field_length_yards,
            &mut rng,
        );
        sim.ball.position = pos;
        min_radius = min_radius.min(pos.distance(player_pos));
    }
    assert!(
        min_radius >= CARRY_BODY_FLOOR_RADIUS_YARDS - 1e-6,
        "a normal carry must keep the ball off the body (>= floor); min was {min_radius}"
    );
    let rel = sim.ball.position - player_pos;
    assert!(
        rel.y > 0.5,
        "the ball should settle in front of the carrier, got rel {rel:?}"
    );
}

