#[test]
fn carried_ball_winding_is_capped_near_270_degrees_per_possession() {
    // The ball rarely winds more than 270 deg around the carrier in one possession:
    // a locked possession is clamped at the cap no matter how long it keeps turning.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home)
        .unwrap()
        .id;
    park_players_except(&mut sim, &[carrier]);
    let player_pos = Vec2::new(40.0, 60.0);
    sim.players[carrier].position = player_pos;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.9, 60.0); // start on the +x side
    sim.ball.reset_carry_orbit();
    let mut rng = SeededRandom::new(5);
    let mut angle = 0.0_f64;
    // First advance consumes the fresh-possession unlock roll; force this possession
    // LOCKED so the cap is exercised deterministically.
    let dir0 = Vec2::new(angle.cos(), angle.sin());
    sim.ball.position = sim.ball.advance_carried_ball_orbit(
        1,
        player_pos,
        dir0,
        0.9,
        false,
        false,
        CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
        CARRY_ORBIT_NORMAL_RATE_RAD_S,
        1.0 / 30.0,
        sim.config.field_width_yards,
        sim.config.field_length_yards,
        &mut rng,
    );
    sim.ball.carry_orbit_wrap_unlocked = false;
    // Chase a target that keeps rotating the SAME way around the body for ~13s.
    for step in 1..400u64 {
        angle += 0.25;
        let dir = Vec2::new(angle.cos(), angle.sin());
        sim.ball.position = sim.ball.advance_carried_ball_orbit(
            step + 1,
            player_pos,
            dir,
            0.9,
            false,
            false,
            CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD,
            CARRY_ORBIT_NORMAL_RATE_RAD_S,
            1.0 / 30.0,
            sim.config.field_width_yards,
            sim.config.field_length_yards,
            &mut rng,
        );
    }
    assert!(
        sim.ball.carry_orbit_swept_rad.abs() <= CARRY_ORBIT_POSSESSION_SOFT_CAP_RAD + 1e-6,
        "a locked possession must clamp winding at 270 deg, got {} rad",
        sim.ball.carry_orbit_swept_rad
    );
}

#[test]
fn the_carrier_turns_to_follow_the_orbiting_ball() {
    // When the ball sits off to one side, the carrier's body turns to follow it
    // (you keep the ball in front of you) — and swivelling fast enough accrues
    // disorientation (dizziness).
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = sim
        .players
        .iter()
        .find(|p| p.team == Team::Home)
        .unwrap()
        .id;
    park_players_except(&mut sim, &[carrier]);
    sim.players[carrier].position = Vec2::new(40.0, 60.0);
    sim.players[carrier].facing_yaw = std::f64::consts::FRAC_PI_2; // faces +y
    sim.players[carrier].velocity = Vec2::zero();
    sim.players[carrier].dizziness = 0.0;
    sim.ball.holder = Some(carrier);
    // Ball off to the +x side of the body (bearing ≈ 0 rad).
    sim.ball.position = Vec2::new(41.0, 60.0);

    let before = sim.players[carrier].facing_yaw;
    for _ in 0..12 {
        sim.update_player_facing_dizziness_energy();
    }
    let after = sim.players[carrier].facing_yaw;
    assert!(
        after < before - 0.3 && after.abs() < 0.6,
        "the carrier should rotate from facing +y toward the ball on its +x side: \
             before={before} after={after}"
    );
    assert!(
        sim.players[carrier].dizziness > 0.0,
        "swivelling quickly to follow the ball should accrue some disorientation"
    );
}

#[test]
fn a_defender_inside_two_yards_shifts_the_carrier_toward_passing() {
    // Critical spacing discipline: as a defender closes inside the 2-yard comfort
    // gap (with an open outlet) the carrier should release sooner — passing is
    // lifted and forward dribbling damped — vs the same picture in open space.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let passer = 9;
    let receiver = 7;
    park_players_except(&mut sim, &[passer, receiver]);
    sim.players[passer].role = PlayerRole::Midfielder;
    sim.players[passer].position = Vec2::new(40.0, 70.0);
    // Keep biases/skills modest so the scores are not pinned at their clamps and the
    // crowding response is observable.
    sim.players[passer].preferences.dribble_bias = 0.30;
    sim.players[passer].preferences.pass_bias = 0.30;
    sim.players[passer].skills.dribbling = 5.0;
    sim.players[passer].skills.passing = 5.0;
    sim.players[passer].skills.passing_completion_rate = 5.0;
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[receiver].role = PlayerRole::Forward;
    sim.players[receiver].position = Vec2::new(44.0, 86.0);

    let snapshot = WorldSnapshot::from_match(&sim);
    let visible_targets = snapshot.ranked_visible_pass_targets(passer, 3);
    let base = snapshot.observation_for(passer);
    let directive = snapshot.tactical_directive(Team::Home);

    let tops = |gap: f64| -> (f64, f64) {
        let mut observation = base.clone();
        observation.nearest_opponent_distance = gap;
        observation.best_pass_receiver_openness = 0.85;
        let options = sim.players[passer].possession_action_options(
            &observation,
            &directive,
            visible_targets.len(),
            snapshot.ranked_visible_aerial_pass_targets(passer, 3).len(),
            false,
            snapshot.dt_seconds,
            snapshot.field_width,
        );
        let top = |pred: &dyn Fn(&str) -> bool| {
            options
                .iter()
                .filter(|o| pred(o.label.as_str()))
                .map(|o| o.score)
                .fold(0.0_f64, f64::max)
        };
        let pass_top = top(&|l: &str| l == "killer-pass" || l.starts_with("pass"));
        // The `dribble` action (beat/retain under pressure) is the clean expression of the
        // crowding response. `carry-forward` is gated by forward SPACE, not lateral crowding,
        // so it isn't a reliable proxy for "dribbling" here and is excluded.
        let dribble_top = top(&|l: &str| l == "dribble");
        assert!(
            dribble_top > 0.0 && pass_top > 0.0,
            "expected scored options"
        );
        (pass_top, dribble_top)
    };

    let (pass_crowded, dribble_crowded) = tops(1.2);
    let (pass_open, dribble_open) = tops(6.0);
    assert!(
        pass_crowded > pass_open,
        "a defender inside 2yd must lift passing: crowded={pass_crowded} open={pass_open}"
    );
    assert!(
        dribble_crowded < dribble_open,
        "a defender inside 2yd must damp dribbling: crowded={dribble_crowded} open={dribble_open}"
    );
}

#[test]
fn defender_in_possession_keeps_three_to_four_yards_and_releases_as_gap_closes() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 4;
    let receiver = 7;
    park_players_except(&mut sim, &[holder, receiver]);
    sim.players[holder].role = PlayerRole::Defender;
    sim.players[holder].position = Vec2::new(40.0, 38.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].preferences.dribble_bias = 0.36;
    sim.players[holder].preferences.pass_bias = 0.38;
    sim.players[holder].skills.dribbling = 5.8;
    sim.players[holder].skills.passing = 6.1;
    sim.players[holder].skills.passing_completion_rate = 6.1;
    sim.players[receiver].position = Vec2::new(46.0, 53.0);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let directive = snapshot.tactical_directive(Team::Home);
    let base = snapshot.observation_for(holder);
    let scores = |gap: f64, closing_rate: f64| {
        let mut observation = base.clone();
        observation.nearest_opponent_distance = gap;
        observation
            .neural_extended
            .nearest_opponent_closing_rate_yps = closing_rate;
        observation.perceived_pressure = 0.16;
        observation.pressure_urgency = 0.14;
        observation.immediate_dispossession_risk = 0.08;
        observation.visible_pass_options = 1;
        observation.visible_forward_pass_options = 1;
        observation.open_support_outlets = 1;
        observation.teammates_ahead = 6;
        observation.forward_dribble_space_yards = 9.0;
        observation.expected_pass_completion = 0.82;
        observation.best_pass_receiver_openness = 0.84;
        observation.floor_pass_lane_score = 0.82;
        observation.yards_to_own_goal = 38.0;
        observation.yards_to_goal = 82.0;
        let options = sim.players[holder].possession_action_options(
            &observation,
            &directive,
            1,
            0,
            false,
            snapshot.dt_seconds,
            snapshot.field_width,
        );
        let pass = action_option_score(&options, "pass1");
        let carry = action_option_score(&options, "dribble")
            .max(action_option_score(&options, "carry-forward"));
        (pass, carry)
    };

    let (open_pass, open_carry) = scores(5.5, 0.0);
    let (soft_gap_pass, soft_gap_carry) = scores(3.25, 0.0);
    let (closing_pass, closing_carry) = scores(3.25, 6.0);

    assert!(
        soft_gap_pass > open_pass * 1.08,
        "a defender should already prefer release before the gap drops below 2yd: open={open_pass} soft_gap={soft_gap_pass}"
    );
    assert!(
        soft_gap_carry < open_carry * 0.94,
        "a defender should damp dribbling inside the 3-4yd comfort gap: open={open_carry} soft_gap={soft_gap_carry}"
    );
    assert!(
        closing_pass / closing_carry > soft_gap_pass / soft_gap_carry + 0.18,
        "closing pressure should increase defender pass urgency: closing={closing_pass}/{closing_carry} soft_gap={soft_gap_pass}/{soft_gap_carry}"
    );
}

#[test]
fn defender_under_dribble_spacing_pressure_takes_shorter_touches_than_forward() {
    let touch_summary = |role: PlayerRole| -> (f64, f64) {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let holder = 4;
        let marker = 12;
        park_players_except(&mut sim, &[holder, marker]);
        sim.players[holder].role = role;
        sim.players[holder].position = Vec2::new(40.0, 38.0);
        sim.players[holder].skills.dribbling = 8.6;
        sim.players[holder].skills.first_touch = 8.4;
        sim.players[holder].skills.acceleration = 8.8;
        sim.players[marker].position = Vec2::new(40.8, 41.0);
        sim.ball.holder = Some(holder);
        sim.ball.position = sim.players[holder].position;
        sim.ball.last_touch_team = Some(Team::Home);

        let snapshot = WorldSnapshot::from_match(&sim);
        let mut total = 0.0;
        let mut max_touch = 0.0_f64;
        let trials = 180;
        for seed in 0..trials {
            let mut rng = mulberry32(64_100 + seed);
            let touch = snapshot.choose_dribble_touch_decision_for(
                holder,
                DribbleMoveKind::CarryForward,
                &mut rng,
            );
            total += touch.distance_yards;
            max_touch = max_touch.max(touch.distance_yards);
        }
        (total / trials as f64, max_touch)
    };

    let (defender_avg, defender_max) = touch_summary(PlayerRole::Defender);
    let (forward_avg, forward_max) = touch_summary(PlayerRole::Forward);

    assert!(
        defender_avg < forward_avg - 0.25,
        "defender touches should be shorter under 3-4yd pressure: defender_avg={defender_avg} forward_avg={forward_avg}"
    );
    assert!(
        defender_max < forward_max - 0.30,
        "defender should lose the long take-on touches under spacing pressure: defender_max={defender_max} forward_max={forward_max}"
    );
}

#[test]
fn defender_carry_target_preserves_spacing_gap_under_pressure() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let holder = 4;
    let marker = 12;
    park_players_except(&mut sim, &[holder, marker]);
    sim.players[holder].role = PlayerRole::Defender;
    sim.players[holder].position = Vec2::new(40.0, 38.0);
    sim.players[holder].home_position = sim.players[holder].position;
    sim.players[holder].skills.dribbling = 7.0;
    sim.players[marker].position = Vec2::new(40.0, 41.25);
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[holder].position;
    let marker_position = sim.players[marker].position;
    let starting_gap = origin.distance(marker_position);
    let target = snapshot.dribble_move_target_for_touch(
        holder,
        sim.players[holder].home_position,
        DribbleMoveKind::CarryForward,
        DribbleTouchDecision::new(0, 4.8),
    );
    let target_gap = target.distance(marker_position);

    assert!(
        target_gap >= starting_gap - 1e-6,
        "defender carry target must not close an already-tight spacing gap: start={starting_gap} target={target_gap} target={target:?}"
    );
    assert!(
        (target.y - origin.y) * Team::Home.attack_dir() <= 0.1,
        "with the nearest opponent straight ahead, the safe defender target should not poke forward: origin={origin:?} target={target:?}"
    );
}

