#[test]
fn pressured_escape_lane_obs_is_defender_aware() {
    // The observation's lateral escape-lane clearance keys on real opponent geometry: an open lane
    // reads large, and closing it with a second defender drives it down — unlike pitch-edge room.
    let lane = |boxed_in: bool| -> f64 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let holder = 6;
        park_players_except(&mut sim, &[holder, 16, 17]);
        let origin = Vec2::new(40.0, 58.0);
        sim.players[holder].position = origin;
        sim.players[holder].home_position = origin;
        sim.ball.holder = Some(holder);
        sim.ball.position = origin;
        sim.ball.last_touch_team = Some(Team::Home);
        sim.players[16].position = Vec2::new(41.6, 58.2); // presser on the right
        sim.players[17].position = if boxed_in {
            Vec2::new(38.2, 58.0) // closes the left lane
        } else {
            Vec2::new(10.0, 10.0) // far away: left lane open
        };
        let snapshot = WorldSnapshot::from_match(&sim);
        snapshot.observation_for(holder).pressured_escape_lane_yards
    };

    let open = lane(false);
    let boxed = lane(true);
    assert!(
        open > boxed + 1.0,
        "an open defender-aware lane must read materially larger than a boxed-in one: open={open} boxed={boxed}"
    );
}

#[test]
fn defender_aware_open_lane_lifts_side_step_escape_on_pressured_receipt() {
    // A fresh receiver pressed on the right. With the LEFT lane genuinely open (defender-aware) the
    // dedicated evade (side-step) is floored up; closing that lane boxes the carrier in and the lift
    // collapses. We compare the side-step score and its standing vs the static shield.
    let score = |boxed_in: bool| -> (f64, f64) {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: 0.1,
            seed: 7,
            ..Default::default()
        });
        let holder = 6;
        park_players_except(&mut sim, &[holder, 16, 17]);
        sim.active_set_play = None;
        sim.pending_pass = None;
        sim.pending_shot = None;
        sim.ball.holder = Some(holder);
        sim.ball.position = Vec2::new(40.0, 58.0);
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);
        sim.players[holder].position = sim.ball.position;
        sim.players[holder].home_position = sim.ball.position;
        sim.players[holder].incoming_ball = None;
        sim.players[holder].skills.dribbling = 5.5; // mid-skill: gets the escape floor (not elite)
        sim.players[16].position = Vec2::new(41.6, 58.2);
        sim.players[17].position = if boxed_in {
            Vec2::new(38.2, 58.0)
        } else {
            Vec2::new(10.0, 10.0)
        };

        let snapshot = WorldSnapshot::from_match(&sim);
        let observation = snapshot.observation_for(holder);
        let directive = snapshot.tactical_directive(Team::Home);
        let options = sim.players[holder].possession_action_options(
            &observation,
            &directive,
            2,
            1,
            false,
            sim.config.dt_seconds,
            sim.config.field_width_yards,
        );
        (
            action_option_score(&options, "side-step"),
            action_option_score(&options, "protect-ball"),
        )
    };

    let (open_side_step, open_shield) = score(false);
    let (boxed_side_step, _boxed_shield) = score(true);
    assert!(
        open_side_step > boxed_side_step + 0.05,
        "an open defender-aware lane must lift the side-step escape vs being boxed in: \
         open={open_side_step} boxed={boxed_side_step}"
    );
    assert!(
        open_side_step >= open_shield,
        "with an open lane on fresh receipt under pressure, the side-step escape should be at least \
         as valued as freezing on the shield: side_step={open_side_step} shield={open_shield}"
    );
}

#[test]
fn first_touch_escape_lateral_neural_block_is_appended_and_migration_safe() {
    // The lateral escape-lane tail and then the dribble-beat tail are appended after
    // long-aerial-bounds. Later off-ball/perception/team-center/energy, killer-over-top, and
    // reception-approach tails remain after them; every pre-block total stays a legacy dim so old
    // nets migrate by zero-padding.
    assert_eq!(
        SOCCER_NEURAL_PRE_DRIBBLE_BEAT_FEATURE_DIM,
        SOCCER_NEURAL_PRE_FIRST_TOUCH_ESCAPE_LANE_FEATURE_DIM
            + SOCCER_NEURAL_FIRST_TOUCH_ESCAPE_LANE_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_PRE_OFF_BALL_RUN_FEATURE_DIM,
        SOCCER_NEURAL_PRE_DRIBBLE_BEAT_FEATURE_DIM + SOCCER_NEURAL_DRIBBLE_BEAT_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_PRE_PERCEPTION_NOISE_FEATURE_DIM,
        SOCCER_NEURAL_PRE_OFF_BALL_RUN_FEATURE_DIM + SOCCER_NEURAL_OFF_BALL_RUN_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_PRE_TEAM_CENTER_FEATURE_DIM,
        SOCCER_NEURAL_PRE_PERCEPTION_NOISE_FEATURE_DIM + SOCCER_NEURAL_PERCEPTION_NOISE_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_PRE_ENERGY_ECONOMY_FEATURE_DIM,
        SOCCER_NEURAL_PRE_TEAM_CENTER_FEATURE_DIM + SOCCER_NEURAL_TEAM_CENTER_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_PRE_KILLER_OVER_TOP_FEATURE_DIM,
        SOCCER_NEURAL_PRE_ENERGY_ECONOMY_FEATURE_DIM + SOCCER_NEURAL_ENERGY_ECONOMY_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_PRE_RECEPTION_APPROACH_FEATURE_DIM,
        SOCCER_NEURAL_PRE_KILLER_OVER_TOP_FEATURE_DIM + SOCCER_NEURAL_KILLER_OVER_TOP_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_DIM,
        SOCCER_NEURAL_PRE_RECEPTION_APPROACH_FEATURE_DIM
            + SOCCER_NEURAL_RECEPTION_APPROACH_FEATURE_DIM
    );
    assert_eq!(SOCCER_NEURAL_FIRST_TOUCH_ESCAPE_LANE_FEATURE_DIM, 2);
    assert_eq!(SOCCER_NEURAL_DRIBBLE_BEAT_FEATURE_DIM, 4);
    assert_eq!(SOCCER_NEURAL_TEAM_CENTER_FEATURE_DIM, 18);
    assert_eq!(SOCCER_NEURAL_RECEPTION_APPROACH_FEATURE_DIM, 4);
    assert_eq!(SOCCER_NEURAL_ENERGY_ECONOMY_FEATURE_DIM, 5);
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS
            .contains(&SOCCER_NEURAL_PRE_FIRST_TOUCH_ESCAPE_LANE_FEATURE_DIM),
        "the pre-lateral-escape total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_DRIBBLE_BEAT_FEATURE_DIM),
        "the pre-dribble-beat total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_OFF_BALL_RUN_FEATURE_DIM),
        "the pre-off-ball-run total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_PERCEPTION_NOISE_FEATURE_DIM),
        "the pre-perception-noise total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_TEAM_CENTER_FEATURE_DIM),
        "the pre-team-center total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_ENERGY_ECONOMY_FEATURE_DIM),
        "the pre-energy-economy total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_KILLER_OVER_TOP_FEATURE_DIM),
        "the pre-killer-over-top total must be a recognised legacy dim so old nets migrate"
    );
    assert!(
        SOCCER_NEURAL_LEGACY_FEATURE_DIMS.contains(&SOCCER_NEURAL_PRE_RECEPTION_APPROACH_FEATURE_DIM),
        "the pre-reception-approach total must be a recognised legacy dim so old nets migrate"
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_PERCEPTION_LATENCY + 1,
        SOCCER_NEURAL_FEATURE_OWN_TEAM_COM_FORWARD
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_TEAM_COA_LATERAL_GAP + 1,
        SOCCER_NEURAL_PRE_ENERGY_ECONOMY_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_ENERGY_WASTE_PRESSURE,
        SOCCER_NEURAL_PRE_ENERGY_ECONOMY_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_TEAM_ENERGY_DEBT + 1,
        SOCCER_NEURAL_PRE_KILLER_OVER_TOP_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_KILLER_OVER_TOP_GOALKEEPER_AVOIDANCE + 1,
        SOCCER_NEURAL_PRE_RECEPTION_APPROACH_FEATURE_DIM
    );
    assert_eq!(
        SOCCER_NEURAL_FEATURE_RECEPTION_APPROACH_KINEMATIC_FIT + 1,
        SOCCER_NEURAL_FEATURE_DIM
    );
    assert!(SOCCER_NEURAL_FEATURE_FIRST_TOUCH_ESCAPE_LANE_OPEN < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_FIRST_TOUCH_FREEZE_RISK < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_DRIBBLE_DEFENDER_OVERCOMMIT < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_DRIBBLE_DEFENDER_REACTION_DELAY < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_DRIBBLE_MOMENTUM_ESCAPE_SIDE < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_DRIBBLE_NUTMEG_WINDOW < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_OWN_TEAM_COM_FORWARD < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_TEAM_COA_LATERAL_GAP < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_ENERGY_WASTE_PRESSURE < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_TEAM_ENERGY_DEBT < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_RECEPTION_APPROACH_PRESSURE < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_RECEPTION_APPROACH_TARGET < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_RECEPTION_APPROACH_RACE < SOCCER_NEURAL_FEATURE_DIM);
    assert!(SOCCER_NEURAL_FEATURE_RECEPTION_APPROACH_KINEMATIC_FIT < SOCCER_NEURAL_FEATURE_DIM);
    assert_ne!(
        SOCCER_NEURAL_FEATURE_FIRST_TOUCH_ESCAPE_LANE_OPEN,
        SOCCER_NEURAL_FEATURE_FIRST_TOUCH_FREEZE_RISK
    );
    assert_ne!(
        SOCCER_NEURAL_FEATURE_DRIBBLE_DEFENDER_OVERCOMMIT,
        SOCCER_NEURAL_FEATURE_DRIBBLE_NUTMEG_WINDOW
    );
}

#[test]
fn wasted_off_ball_energy_reaches_pomdp_q_state_neural_features_and_reward() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        seed: 36_410,
        ..MatchConfig::default()
    });
    let runner = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Midfielder)
        .expect("home midfielder")
        .id;
    let holder = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role != PlayerRole::Goalkeeper)
        .expect("away holder")
        .id;

    park_players_except(&mut sim, &[runner, holder]);
    sim.clock_seconds = 9.0 * 60.0;
    sim.pending_pass = None;
    for player in sim
        .players
        .iter_mut()
        .filter(|player| player.team == Team::Home && player.role != PlayerRole::Goalkeeper)
    {
        player.fatigue = 0.30;
        player.anaerobic_load = 0.55;
    }
    sim.players[runner].position = Vec2::new(72.0, 104.0);
    sim.players[runner].home_position = sim.players[runner].position;
    sim.players[runner].velocity = Vec2::new(6.5, 0.0);
    sim.players[runner].movement_gait = MovementGait::Sprint;
    sim.players[runner].fatigue = 0.35;
    sim.players[runner].anaerobic_load = 0.70;
    sim.players[holder].position = Vec2::new(8.0, 12.0);
    sim.players[holder].velocity = Vec2::zero();
    sim.ball.holder = Some(holder);
    sim.ball.position = sim.players[holder].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Away);
    sim.shared_positions.sync_from_players_and_ball(
        &sim.players,
        &sim.officials,
        &sim.ball,
        sim.tick,
        sim.clock_seconds,
    );

    let before = WorldSnapshot::from_match(&sim);
    let observation = before.observation_for(runner);
    assert!(
        observation.neural_extended.energy_no_ball_movement_yards > 50.0,
        "test setup should project a material off-ball energy spend"
    );
    assert!(
        observation
            .neural_extended
            .energy_ball_interaction_next_ten_seconds
            < 0.12,
        "runner should have little chance of interacting with the far ball"
    );
    assert!(
        observation.neural_extended.energy_waste_pressure > 0.40,
        "waste pressure should rise for high-speed no-interaction movement"
    );
    assert!(
        observation.neural_extended.team_energy_debt > 0.03,
        "team debt should include the runner's anaerobic load"
    );

    let role = sim.players[runner].role;
    let state = before.mdp_state_for_player(runner);
    let key = SoccerQStateKey::from_parts(&state, &observation, Team::Home, role);
    assert!(key.energy_waste_pressure_bin >= 2);
    assert!(key.energy_ball_interaction_bin <= 1);
    assert!(key.team_energy_debt_bin >= 1);

    let decision = test_decision_trace(&before, runner, "support-shape");
    let transition = SoccerLearningTransition {
        tick: before.tick,
        player_id: runner,
        team: Team::Home,
        role,
        state,
        observation: observation.clone(),
        belief: belief_from_observation(&observation),
        action: "support-shape".to_string(),
        action_target: None,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: before.mdp_state_for_player(runner),
        next_observation: observation.clone(),
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert!(features[SOCCER_NEURAL_FEATURE_ENERGY_WASTE_PRESSURE] > 0.40);
    assert!(features[SOCCER_NEURAL_FEATURE_ENERGY_BALL_INTERACTION_10S] < 0.12);
    assert!(features[SOCCER_NEURAL_FEATURE_TEAM_ENERGY_DEBT] > 0.03);

    sim.players[runner].position += Vec2::new(0.70, 0.0);
    sim.shared_positions.sync_from_players_and_ball(
        &sim.players,
        &sim.officials,
        &sim.ball,
        sim.tick,
        sim.clock_seconds,
    );
    let after = WorldSnapshot::from_match(&sim);
    let waste_reward = dense_soccer_transition_reward(
        &sim.players[runner],
        &decision,
        &before,
        &after,
        "support-shape",
        &SoccerTacticalLearningWeights::default(),
    );
    let mut relaxed_decision = decision.clone();
    relaxed_decision
        .observation
        .neural_extended
        .energy_waste_pressure = 0.0;
    let relaxed_reward = dense_soccer_transition_reward(
        &sim.players[runner],
        &relaxed_decision,
        &before,
        &after,
        "support-shape",
        &SoccerTacticalLearningWeights::default(),
    );
    assert!(
        waste_reward < relaxed_reward - 0.02,
        "waste pressure should add a small negative reward: waste={waste_reward} relaxed={relaxed_reward}"
    );
}

#[test]
fn energy_economy_observation_and_reward_sanitize_bad_physics_inputs() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let runner = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role == PlayerRole::Midfielder)
        .expect("home midfielder")
        .id;
    park_players_except(&mut sim, &[runner]);
    sim.players[runner].position = Vec2::new(70.0, 104.0);
    sim.players[runner].velocity = Vec2::new(6.5, 0.0);
    sim.ball.holder = None;
    sim.ball.position = Vec2::new(f64::NAN, f64::INFINITY);
    sim.ball.velocity = Vec2::new(f64::INFINITY, f64::NAN);

    let mut snapshot = WorldSnapshot::from_match(&sim);
    snapshot.ball.position = Vec2::new(f64::NAN, f64::INFINITY);
    snapshot.ball.velocity = Vec2::new(f64::INFINITY, f64::NAN);
    let runner_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == runner)
        .expect("runner snapshot")
        .clone();
    let interaction = soccer_energy_ball_interaction_next_ten_seconds(
        &snapshot,
        &runner_snapshot,
        Vec2::new(f64::NAN, f64::INFINITY),
    );
    assert!((0.0..=1.0).contains(&interaction));
    let (movement, ball_interaction, waste_pressure, rhythm, team_debt) =
        soccer_energy_economy_profile_for_snapshot(
            &snapshot,
            &runner_snapshot,
            Vec2::new(f64::NAN, f64::INFINITY),
        );
    for value in [movement, ball_interaction, waste_pressure, rhythm, team_debt] {
        assert!(value.is_finite(), "energy economy value should be finite: {value}");
    }
    assert!((0.0..=1.0).contains(&ball_interaction));
    assert!((0.0..=1.0).contains(&waste_pressure));
    assert!((0.0..=1.0).contains(&rhythm));
    assert!((0.0..=1.0).contains(&team_debt));

    let mut before = WorldSnapshot::from_match(&SoccerMatch::default_11v11(MatchConfig::default()));
    before.dt_seconds = f64::NAN;
    let mut decision = test_decision_trace(&before, runner, "support-shape");
    decision.observation.neural_extended.energy_waste_pressure = 1.0;
    let mut after = before.clone();
    let before_pos = before.player_position(runner).expect("runner before position");
    after.set_player_position(runner, before_pos + Vec2::new(0.80, 0.0));

    let waste_reward = dense_soccer_transition_reward(
        &sim.players[runner],
        &decision,
        &before,
        &after,
        "support-shape",
        &SoccerTacticalLearningWeights::default(),
    );
    let mut relaxed_decision = decision;
    relaxed_decision
        .observation
        .neural_extended
        .energy_waste_pressure = 0.0;
    let relaxed_reward = dense_soccer_transition_reward(
        &sim.players[runner],
        &relaxed_decision,
        &before,
        &after,
        "support-shape",
        &SoccerTacticalLearningWeights::default(),
    );
    let penalty = relaxed_reward - waste_reward;
    assert!(penalty.is_finite());
    assert!((0.0..=ENERGY_ECONOMY_REWARD_PENALTY_POINTS + 1e-9).contains(&penalty));
}

#[test]
fn mappo_team_component_penalizes_relative_team_energy_waste() {
    let sim = SoccerMatch::default_11v11(MatchConfig::default());
    let snapshot = WorldSnapshot::from_match(&sim);
    let home_player = sim
        .players
        .iter()
        .find(|player| player.team == Team::Home && player.role != PlayerRole::Goalkeeper)
        .unwrap()
        .id;
    let away_player = sim
        .players
        .iter()
        .find(|player| player.team == Team::Away && player.role != PlayerRole::Goalkeeper)
        .unwrap()
        .id;

    let mut home_observation = snapshot.observation_for(home_player);
    home_observation.neural_extended.energy_waste_pressure = 1.0;
    let mut away_observation = snapshot.observation_for(away_player);
    away_observation.neural_extended.energy_waste_pressure = 0.0;

    let home_transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: home_player,
        team: Team::Home,
        role: sim.players[home_player].role,
        state: snapshot.mdp_state_for_player(home_player),
        observation: home_observation.clone(),
        belief: belief_from_observation(&home_observation),
        action: "support-shape".to_string(),
        action_target: None,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: f64::NAN,
        next_state: snapshot.mdp_state_for_player(home_player),
        next_observation: home_observation,
        done: false,
    };
    let away_transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: away_player,
        team: Team::Away,
        role: sim.players[away_player].role,
        state: snapshot.mdp_state_for_player(away_player),
        observation: away_observation.clone(),
        belief: belief_from_observation(&away_observation),
        action: "support-shape".to_string(),
        action_target: None,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(away_player),
        next_observation: away_observation,
        done: false,
    };
    let transitions = vec![home_transition, away_transition];
    let tick_rewards = soccer_marl_tick_rewards(&transitions);
    let config = SoccerNeuralLearningConfig {
        enabled: true,
        marl_algorithm: SoccerMarlAlgorithm::Mappo,
        marl_team_reward_weight: 1.0,
        marl_intermediate_reward_weight: 0.0,
        ..SoccerNeuralLearningConfig::default()
    };

    let home_adjusted = soccer_marl_adjusted_reward(&transitions[0], &tick_rewards, &config);
    let away_adjusted = soccer_marl_adjusted_reward(&transitions[1], &tick_rewards, &config);
    assert!(
        home_adjusted.is_finite() && away_adjusted.is_finite(),
        "MAPPO adjusted rewards should sanitize bad scalar rewards"
    );
    assert!(
        home_adjusted < -ENERGY_ECONOMY_MARL_TEAM_PENALTY_POINTS * 0.9,
        "the team wasting more energy should receive a small shared penalty: {home_adjusted}"
    );
    assert!(
        away_adjusted > ENERGY_ECONOMY_MARL_TEAM_PENALTY_POINTS * 0.9,
        "the opponent should get the zero-sum mirror of the energy economy signal: {away_adjusted}"
    );
}

