#[test]
fn goalkeeper_distance_save_baseline_matches_calibrated_curve() {
    // Calibrated knots (recalibrated so MORE on-target shots are goals, esp. inside the
    // box): ≈53% save @20yd, 67% @25, 77% @30, 89% @40, plateauing ≈97% by ~55yd; close
    // (point-blank) shots still beat the keeper.
    let approx = |d: f64, want: f64| {
        let got = goalkeeper_distance_save_baseline(d);
        assert!(
            (got - want).abs() < 1e-6,
            "distance {d}: got {got}, want {want}"
        );
    };
    approx(20.0, 0.53);
    approx(25.0, 0.67);
    approx(30.0, 0.77);
    approx(40.0, 0.89);
    assert!(goalkeeper_distance_save_baseline(55.0) >= 0.97);
    assert!(goalkeeper_distance_save_baseline(80.0) >= 0.97);
    // Monotonic non-decreasing in distance.
    let mut prev = 0.0;
    for d in (0..=70).map(|d| d as f64) {
        let v = goalkeeper_distance_save_baseline(d);
        assert!(v + 1e-9 >= prev, "non-monotonic at {d}: {v} < {prev}");
        prev = v;
    }
    // Close shots are low (beat the keeper).
    assert!(goalkeeper_distance_save_baseline(8.0) < 0.20);
}

#[test]
fn keeper_save_is_agentic_and_updates_shot_stats() {
    let mut outcomes = std::collections::BTreeSet::new();
    for seed in 0..60 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            seed,
            ..Default::default()
        });
        let keeper_id = sim.goalkeeper_for(Team::Away).expect("away keeper");
        sim.players[keeper_id].position = Vec2::new(40.0, 118.4);
        sim.players[keeper_id].skills.defending = 9.8;
        sim.players[keeper_id].skills.first_touch = 9.8;
        sim.players[keeper_id].skills.acceleration = 9.5;
        sim.ball.holder = None;
        // In front of the goal, approaching: the keeper now stops shots DURING
        // flight at the save plane (a ball past the line would simply be a goal).
        sim.ball.position = Vec2::new(40.0, 110.0);
        sim.ball.velocity = Vec2::new(0.0, 18.0);
        sim.pending_shot = Some(PendingShot {
            team: Team::Home,
            shooter: 9,
            origin: Vec2::new(40.0, 80.0),
        });

        for _ in 0..10 {
            sim.integrate_ball();
            if sim.stats.shots_on_target_home > 0 {
                break;
            }
        }

        assert_eq!(sim.stats.shots_on_target_home, 1);
        assert_eq!(sim.stats.saves_away, 1);
        assert!(
            sim.ball.holder == Some(keeper_id) || sim.ball.holder.is_none(),
            "saves may be caught or parried into a live rebound"
        );
        if sim.ball.holder.is_none() {
            assert_eq!(sim.ball.last_touch_team, Some(Team::Away));
            assert!(sim.ball.velocity.len() > 0.0);
        }
        assert_eq!(sim.score_home, 0);
        outcomes.insert(
            sim.ball
                .last_decision
                .as_ref()
                .map(|decision| decision.action.clone())
                .unwrap_or_default(),
        );
    }

    assert_eq!(
        outcomes.len(),
        1,
        "same shot and keeper geometry should not produce seed-varying outcomes: {outcomes:?}"
    );
}

#[test]
fn decision_trace_capture_records_bounded_on_ball_decisions() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 30.0,
        seed: 71,
        ..Default::default()
    });
    sim.clear_controller_assignments();

    // Off by default: nothing captured even as the match runs.
    for _ in 0..20 {
        sim.run_time_step();
    }
    assert!(sim.decision_trace_recent().is_empty());
    assert!(!sim.decision_trace_capture_enabled());

    // Enable and run well past the 10s window: the ring buffer only ever
    // retains the last `SOCCER_DECISION_TRACE_WINDOW_SECONDS` of decisions.
    // At 1/15s per tick, 300 ticks is 20s — twice the window.
    sim.set_decision_trace_capture(true);
    for _ in 0..300 {
        sim.run_time_step();
    }
    let mut trace = sim.decision_trace_recent();
    assert!(!trace.is_empty(), "capture should record decisions");
    // Only the last 10s of decisions are retained — nothing older leaks through.
    let cutoff = sim.clock_seconds - SOCCER_DECISION_TRACE_WINDOW_SECONDS;
    for entry in &trace {
        assert!(
                entry.clock_seconds >= cutoff,
                "entry at {}s is older than the {SOCCER_DECISION_TRACE_WINDOW_SECONDS}s window (cutoff {cutoff}s)",
                entry.clock_seconds
            );
    }
    // Per-player rings stay bounded by the memory-safety backstop; ALL players
    // (on- and off-ball) are now captured, not just the holder.
    let mut per_player: HashMap<usize, usize> = HashMap::new();
    for entry in &trace {
        *per_player.entry(entry.player_id).or_default() += 1;
    }
    for (player_id, count) in &per_player {
        assert!(
            *count <= SOCCER_DECISION_TRACE_PER_PLAYER,
            "player {player_id} ring must stay bounded: {count}"
        );
    }
    assert!(
        per_player.len() >= 2,
        "off-ball players should be captured too, not just the holder: {} players",
        per_player.len()
    );
    if !trace.iter().any(|entry| entry.has_ball) {
        let holder_index = sim
            .players
            .iter()
            .position(|player| player.team == Team::Home && player.role != PlayerRole::Goalkeeper)
            .expect("home outfield player");
        let holder = sim.players[holder_index].id;
        sim.ball.holder = Some(holder);
        sim.ball.position = sim.players[holder_index].position;
        sim.ball.last_touch_team = Some(sim.players[holder_index].team);
        sim.run_time_step();
        trace = sim.decision_trace_recent();
    }
    // The holder's on-ball decision is captured somewhere in the trace.
    assert!(
        trace.iter().any(|entry| entry.has_ball),
        "an on-ball (holder) decision should be present"
    );
    // Newest first, and each entry's chosen option matches its action.
    let newest = &trace[0];
    if trace.len() > 1 {
        assert!(
            newest.tick >= trace[1].tick,
            "entries must be newest-first: {} then {}",
            newest.tick,
            trace[1].tick
        );
    }
    let chosen = newest
        .options
        .iter()
        .find(|o| o.chosen)
        .map(|o| normalize_soccer_action_label(&o.label).to_string());
    if !newest.options.is_empty() {
        assert_eq!(
            chosen.as_deref(),
            Some(normalize_soccer_action_label(&newest.action)),
            "exactly the chosen option should be flagged"
        );
    }

    // Disabling clears the buffer.
    sim.set_decision_trace_capture(false);
    assert!(sim.decision_trace_recent().is_empty());
}

#[test]
fn decision_trace_endpoint_returns_capture_state() {
    let session = Arc::new(Mutex::new(
        SoccerRealtimeSession::new_without_controller_threads(MatchConfig {
            duration_seconds: 30.0,
            seed: 72,
            ..Default::default()
        }),
    ));
    let input_queue = session.lock().unwrap().input_queue();
    // The interactive session enables capture by default; step a bit to fill it.
    {
        let mut guard = session.lock().unwrap();
        guard.sim.set_decision_trace_capture(true);
        assert!(guard.sim.decision_trace_capture_enabled());
        for _ in 0..30 {
            guard.sim.run_time_step();
        }
    }
    let response = handle_live_soccer_request(
        "GET /api/decision-trace HTTP/1.1\r\nHost: local\r\n\r\n",
        &session,
        &input_queue,
    );
    assert_eq!(response.status, 200);
    assert!(response.body.contains("\"captureEnabled\":true"));
    assert!(response.body.contains("\"entries\""));
}

#[test]
fn inspector_snapshot_exposes_engine_internals() {
    let mut session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig {
        duration_seconds: 30.0,
        seed: 72,
        ..Default::default()
    });
    for _ in 0..30 {
        session.sim.run_time_step();
    }

    let snapshot = session.inspector_snapshot(false);
    let obj = snapshot.as_object().expect("snapshot is a JSON object");
    for key in [
        "schemaVersion",
        "game",
        "frame",
        "learning",
        "centralBrain",
        "decisionTrace",
        "perPlayerDecisions",
        "rewards",
        "neural",
    ] {
        assert!(obj.contains_key(key), "snapshot missing `{key}`");
    }

    let per_player = snapshot["perPlayerDecisions"]
        .as_array()
        .expect("perPlayerDecisions is an array");
    assert_eq!(per_player.len(), 22);

    let neural = snapshot["neural"]
        .as_object()
        .expect("neural section is an object");
    assert!(neural.contains_key("home"));
    assert!(neural.contains_key("away"));
    if snapshot["neural"]["home"].is_object() {
        assert!(snapshot["neural"]["home"]["trainingSteps"].is_number());
        assert!(snapshot["neural"]["home"].get("networkSnapshot").is_none());
        let with_weights = session.inspector_snapshot(true);
        assert!(with_weights["neural"]["home"]
            .get("networkSnapshot")
            .is_some());
    }
}

#[test]
fn live_http_frame_builder_avoids_full_snapshot_churn() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.2,
        seed: 56,
        ..Default::default()
    });
    sim.clear_controller_assignments();
    sim.run_time_step();

    let holder_id = sim.ball.holder;
    let frame = sim.to_live_http_frame();

    assert!(
        frame.shared_positions.histories.is_empty(),
        "live HTTP frames should not clone duplicate shared position histories"
    );
    assert_eq!(
        frame
            .shared_positions
            .ball_latest()
            .expect("shared ball latest")
            .position,
        frame.ball.position
    );
    assert!(
        frame.shared_positions.ball_history().is_empty(),
        "live HTTP frames should keep shared ball latest without duplicate shared ball history"
    );
    assert_eq!(
        frame.shared_positions.official_latest.len(),
        3,
        "live HTTP frames should keep current official positions"
    );
    assert!(
        frame.shared_positions.official_histories.is_empty(),
        "live HTTP frames should not clone duplicate official position histories"
    );
    assert!(
        frame
            .players
            .iter()
            .any(|player| !player.position_history.is_empty()),
        "live HTTP frames still expose per-player 50-position motion history"
    );
    let mut unique_skill_bands = HashSet::new();
    for player in &frame.players {
        assert_eq!(
            player.skill_bands.len(),
            8,
            "live HTTP player {} should expose compact skill bands",
            player.id
        );
        assert!(
            player
                .skill_bands
                .chars()
                .all(|ch| ch.to_digit(36).is_some_and(|band| (1..=10).contains(&band))),
            "live HTTP compact skill bands should stay base36 1..=10 values: {}",
            player.skill_bands
        );
        unique_skill_bands.insert(player.skill_bands.clone());
    }
    assert!(
        unique_skill_bands.len() >= 8,
        "live HTTP frame should preserve differentiated player skill bands, got {} unique bands",
        unique_skill_bands.len()
    );
    assert!(
        !frame.intents.is_empty(),
        "live HTTP frames should expose compact intent traces for the UI"
    );
    if let Some(holder_id) = holder_id {
        let holder = frame
            .players
            .iter()
            .find(|player| player.id == holder_id)
            .expect("holder frame");
        assert!(
            holder.last_decision.is_some(),
            "holder keeps the full decision trace for UI/inspection"
        );
    }
    assert!(
        frame
            .players
            .iter()
            .any(|player| Some(player.id) != holder_id && player.last_decision.is_none()),
        "autonomous non-holders should avoid cloned full decision traces"
    );
}

#[test]
fn live_http_game_id_parsing_and_sanitizing() {
    assert_eq!(sanitize_live_game_id("  AB-12_xy!  "), "ab-12xy");
    assert_eq!(
        sanitize_live_game_id(&"z".repeat(200)).len(),
        MAX_LIVE_GAME_ID_LEN
    );
    assert_eq!(
        parse_live_http_game_id("GET /api/state?game=7F3a-99 HTTP/1.1\r\n\r\n"),
        Some("7f3a-99".to_string())
    );
    // The game param survives alongside other query params.
    assert_eq!(
        parse_live_http_game_id("GET /api/step?pulse=1&game=abc HTTP/1.1\r\n\r\n"),
        Some("abc".to_string())
    );
    assert_eq!(parse_live_http_game_id("GET / HTTP/1.1\r\n\r\n"), None);
}

#[test]
fn ephemeral_games_never_write_the_shared_policy() {
    // Even when the server is configured to persist (train) the champion policy,
    // per-visitor `?game=` matches must be read-only against it, or they would
    // race on and pollute the shared policy file.
    let config = SoccerLiveServerConfig {
        autosave_team_policy: true,
        policy_keep_best: true,
        autoload_team_policy: true,
        ..Default::default()
    };
    let session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig::default());
    let input_queue = session.input_queue();
    let controller_input_router = session.controller_input_router();
    let registry = LiveGameRegistry::with_default(
        config,
        Arc::new(Mutex::new(session)),
        input_queue,
        controller_input_router,
    );
    let ephemeral = registry.ephemeral_game_config();
    assert!(!ephemeral.autosave_team_policy);
    assert!(!ephemeral.policy_keep_best);
    // Read-only autoload stays on so demo games start from trained players.
    assert!(ephemeral.autoload_team_policy);
}

#[test]
fn live_game_registry_isolates_games_and_keeps_default() {
    let config = SoccerLiveServerConfig {
        autoload_team_policy: false,
        autosave_team_policy: false,
        ..Default::default()
    };
    let session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig::default());
    let input_queue = session.input_queue();
    let controller_input_router = session.controller_input_router();
    let registry = LiveGameRegistry::with_default(
        config,
        Arc::new(Mutex::new(session)),
        input_queue,
        controller_input_router,
    );

    // The same id always returns the same game; distinct ids are independent.
    let default_a = registry.resolve("default");
    let default_b = registry.resolve("default");
    assert!(Arc::ptr_eq(&default_a, &default_b));
    let alpha = registry.resolve("alpha");
    let alpha_again = registry.resolve("alpha");
    assert!(Arc::ptr_eq(&alpha, &alpha_again));
    let beta = registry.resolve("beta");
    assert!(!Arc::ptr_eq(&alpha, &beta));
    // Each game owns an independent session.
    assert!(!Arc::ptr_eq(
        &alpha.bridge.session(),
        &beta.bridge.session()
    ));
    assert!(!Arc::ptr_eq(
        &default_a.bridge.session(),
        &alpha.bridge.session()
    ));
}

#[test]
fn live_game_registry_keeps_actively_polled_games_over_capacity() {
    // Regression: with more open tabs than `max_games`, the capacity evictor must
    // NOT reclaim a game that is still being actively polled. Reclaiming it drops
    // the session, so the tab's next ~10Hz poll re-creates the match from its seed
    // and it snaps back to kickoff — the "every game keeps freezing/restarting"
    // bug. Only genuinely idle (abandoned) games may be evicted.
    let config = SoccerLiveServerConfig {
        autoload_team_policy: false,
        autosave_team_policy: false,
        ..Default::default()
    };
    let session = SoccerRealtimeSession::new_without_controller_threads(MatchConfig::default());
    let input_queue = session.input_queue();
    let controller_input_router = session.controller_input_router();
    let mut registry = LiveGameRegistry::with_default(
        config,
        Arc::new(Mutex::new(session)),
        input_queue,
        controller_input_router,
    );
    // Tiny soft cap so "default" + one ephemeral game already sits at capacity.
    registry.max_games = 2;

    let alpha = registry.resolve("alpha");
    // Resolving a second game puts the map over the soft cap. The stalest
    // non-default game is `alpha`, but it was just accessed, so it must survive.
    let _beta = registry.resolve("beta");
    let alpha_again = registry.resolve("alpha");
    assert!(
        Arc::ptr_eq(&alpha, &alpha_again),
        "an actively-polled game must not be evicted when over capacity"
    );

    // Once a game goes idle past the eviction window (its tab closed), it IS
    // reclaimable. Backdate alpha's last access to simulate that.
    let stale = soccer_unix_millis().saturating_sub(LIVE_GAME_EVICT_IDLE_MS + 1_000);
    alpha
        .last_access_ms
        .store(stale, std::sync::atomic::Ordering::Relaxed);
    let _gamma = registry.resolve("gamma");
    let alpha_fresh = registry.resolve("alpha");
    assert!(
        !Arc::ptr_eq(&alpha, &alpha_fresh),
        "an idle/abandoned game is reclaimed once it crosses the eviction window"
    );
}

#[test]
fn live_state_response_uses_compact_http_frame() {
    let mut session = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 0.2,
        seed: 57,
        max_human_players: 1,
        ..Default::default()
    });
    session.sim.clear_controller_assignments();
    let seeded_holder = 5;
    session.sim.active_set_play = None;
    session.sim.ball.holder = Some(seeded_holder);
    session.sim.ball.position = session.sim.players[seeded_holder].position;
    session.sim.ball.velocity = Vec2::zero();
    session.sim.ball.last_touch_team = Some(session.sim.players[seeded_holder].team);
    session
        .sim
        .assign_controller_slot(0, Some(seeded_holder))
        .expect("assign seeded live player");
    session.sim.run_time_step();

    let state = session.state_response();
    let decision_player = state
        .frame
        .players
        .iter()
        .find(|player| player.last_decision.is_some())
        .expect("player decision frame");
    let decision_player_id = decision_player.id;

    assert!(
        state.frame.shared_positions.histories.is_empty(),
        "live state polling should not clone duplicate shared position histories"
    );
    assert!(
        !state.frame.intents.is_empty(),
        "live state polling should retain compact tactical intents for UI overlays"
    );
    assert!(
        decision_player.last_decision.is_some(),
        "live state polling should retain a compact MDP/POMDP player trace"
    );
    let decision = decision_player
        .last_decision
        .as_ref()
        .expect("player decision trace");
    assert!(decision.mdp_state.player_grid.fine.id > 0);
    assert!(decision.observation.player_grid.fine.id > 0);
    assert_eq!(
        decision.mdp_state.player_grid,
        decision.observation.player_grid
    );
    assert_eq!(
        decision.mdp_state.receive_facing,
        decision_player.receive_facing
    );
    assert_eq!(
        decision.mdp_state.action_facing,
        decision.observation.action_facing
    );
    assert!(decision.belief.possession_confidence.is_finite());
    assert!(decision.observation.yards_to_goal.is_finite());
    assert!(decision.observation.shot_block_probability.is_finite());
    assert!(decision.observation.decision_urgency.is_finite());
    assert!(decision.observation.perceived_pressure.is_finite());
    assert!(decision.observation.skill_dribbling > 0.0);
    assert!(decision.observation.skill_passing_completion_rate > 0.0);
    assert!(decision.observation.skill_shooting > 0.0);
    assert!(
        decision
            .action_options
            .iter()
            .any(|option| option.legal && option.probability > 0.0),
        "compact player decision should retain legal action probabilities"
    );
    assert!(
        state
            .frame
            .players
            .iter()
            .any(|player| player.id != decision_player_id && player.last_decision.is_none()),
        "live state polling should omit full autonomous non-holder traces"
    );
    let full_decision_count = state
        .frame
        .players
        .iter()
        .filter(|player| player.last_decision.is_some())
        .count();
    assert!(
            full_decision_count <= 1 + state.controller_assignments.len(),
            "live state polling should expose only compact player/controller decisions, got {full_decision_count}"
        );
}

