#[test]
fn live_http_cors_allows_legacy_auth_header_for_browser_posts() {
    let options = LiveHttpResponse::options();
    let raw = String::from_utf8(options.to_bytes()).expect("options response utf8");
    assert!(raw.contains("HTTP/1.1 204 No Content"));
    assert!(raw.contains(&format!(
        "Access-Control-Allow-Headers: {LIVE_HTTP_ACCESS_CONTROL_ALLOW_HEADERS}"
    )));
    assert!(raw.contains("Access-Control-Allow-Methods: GET,POST,OPTIONS"));
    assert!(raw.contains("Auth"));

    let mut chunked = Vec::new();
    write_live_http_chunked_header(
        &mut chunked,
        200,
        "OK",
        "application/x-ndjson; charset=utf-8",
    )
    .expect("chunked header");
    let chunked = String::from_utf8(chunked).expect("chunked header utf8");
    assert!(chunked.contains(&format!(
        "Access-Control-Allow-Headers: {LIVE_HTTP_ACCESS_CONTROL_ALLOW_HEADERS}"
    )));
    assert!(chunked.contains("Auth"));
}

#[test]
fn live_http_state_and_step_recover_from_poisoned_session_lock() {
    let realtime = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 1,
        seed: 68,
        ..Default::default()
    });
    let input_queue = realtime.input_queue();
    let session = Arc::new(Mutex::new(realtime));
    let poisoner = {
        let session = Arc::clone(&session);
        std::thread::spawn(move || {
            let _guard = session.lock().expect("test poison live session lock");
            panic!("poison soccer live session lock");
        })
    };
    assert!(poisoner.join().is_err());

    let state = handle_live_soccer_request(
        "GET /api/state HTTP/1.1\r\nHost: local\r\n\r\n",
        &session,
        &input_queue,
    );
    assert_eq!(state.status, 200);
    let state_value: serde_json::Value =
        serde_json::from_str(&state.body).expect("recovered state json");
    assert_eq!(state_value["config"]["seed"], 68);
    assert_eq!(state_value["summary"]["ticks"], 0);

    let body = r#"{"ticks":1,"recordEveryTicks":1}"#;
    let step = handle_live_soccer_request(
        &format!(
            "POST /api/step HTTP/1.1\r\nHost: local\r\nContent-Length: {}\r\n\r\n{}",
            body.len(),
            body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(step.status, 200);
    let step_value: serde_json::Value =
        serde_json::from_str(&step.body).expect("recovered step json");
    assert_eq!(step_value["summary"]["ticks"], 1);
}

#[test]
fn live_http_reset_and_assign_recover_from_poisoned_session_lock() {
    let realtime = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 2,
        seed: 69,
        ..Default::default()
    });
    let input_queue = realtime.input_queue();
    let session = Arc::new(Mutex::new(realtime));
    let poisoner = {
        let session = Arc::clone(&session);
        std::thread::spawn(move || {
            let _guard = session.lock().expect("test poison live session lock");
            panic!("poison soccer live reset assign session lock");
        })
    };
    assert!(poisoner.join().is_err());

    let assign_body = r#"{"controllerSlot":0,"playerId":5}"#;
    let assign = handle_live_soccer_request(
        &format!(
            "POST /api/assign HTTP/1.1\r\nHost: local\r\nContent-Length: {}\r\n\r\n{}",
            assign_body.len(),
            assign_body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(assign.status, 200);
    let assign_value: serde_json::Value =
        serde_json::from_str(&assign.body).expect("recovered assign json");
    assert!(assign_value["controllerAssignments"]
        .as_array()
        .expect("controller assignments")
        .iter()
        .any(|assignment| assignment["controllerSlot"] == 0 && assignment["playerId"] == 5));

    let reset = handle_live_soccer_request(
        "POST /api/reset HTTP/1.1\r\nHost: local\r\nContent-Length: 0\r\n\r\n",
        &session,
        &input_queue,
    );
    assert_eq!(reset.status, 200);
    let reset_value: serde_json::Value =
        serde_json::from_str(&reset.body).expect("recovered reset json");
    assert_eq!(reset_value["state"]["summary"]["ticks"], 0);
    assert_eq!(reset_value["keptControllerAssignments"], true);
    assert!(reset_value["state"]["controllerAssignments"]
        .as_array()
        .expect("reset controller assignments")
        .iter()
        .any(|assignment| assignment["controllerSlot"] == 0 && assignment["playerId"] == 5));
}

#[test]
fn live_http_bridge_embeds_mounted_realtime_routes() {
    let bridge = SoccerLiveHttpBridge::new(SoccerLiveServerConfig {
        match_config: MatchConfig {
            duration_seconds: 1.0,
            max_human_players: 2,
            seed: 71,
            ..Default::default()
        },
        http_worker_threads: 3,
        autoload_team_policy: false,
        ..Default::default()
    });

    let html = bridge.handle_request("GET", "/des-rs/soccer/live", "");
    assert!(html.ok());
    assert_eq!(html.content_type, "text/html; charset=utf-8");
    assert!(html.body.contains("<title>Live Soccer Simulation</title>"));
    assert!(html.body.contains("function liveApiPath"));

    let state = bridge.handle_request("GET", "/des-rs/api/state", "");
    assert!(state.ok());
    assert_eq!(state.content_type, "application/json; charset=utf-8");
    let state_value: serde_json::Value =
        serde_json::from_str(&state.body).expect("bridge mounted state json");
    assert_eq!(state_value["config"]["seed"], 71);
    assert_eq!(state_value["liveHttp"]["workerThreads"], 3);
    assert_eq!(
        state_value["liveHttp"]["workerQueueCapacity"],
        3 * LIVE_HTTP_CONNECTION_QUEUE_PER_WORKER
    );
    assert_eq!(state_value["liveHttp"]["boundedWorkerQueue"], true);
    assert_eq!(state_value["liveHttp"]["reusesWorkers"], true);
    assert_eq!(state_value["liveHttp"]["spawnsPerRequest"], false);

    let step = bridge.handle_request(
        "POST",
        "/des-rs/api/step?tick=1",
        r#"{"ticks":1,"recordEveryTicks":1}"#,
    );
    assert!(step.ok());
    let step_value: serde_json::Value =
        serde_json::from_str(&step.body).expect("bridge mounted step json");
    assert_eq!(step_value["summary"]["ticks"], 1);
    assert_eq!(step_value["liveHttp"]["workerThreads"], 3);
    assert_eq!(
        step_value["liveHttp"]["workerQueueCapacity"],
        3 * LIVE_HTTP_CONNECTION_QUEUE_PER_WORKER
    );
    assert_eq!(step_value["liveHttp"]["boundedWorkerQueue"], true);

    let bad = bridge.handle_request("GET /oops", "/des-rs/api/state", "");
    assert_eq!(bad.status, 400);
    assert!(bad.body.contains("single HTTP request-line tokens"));
}

#[test]
fn live_http_worker_pool_count_is_sanitized_and_bounded() {
    assert_eq!(live_http_worker_threads(0), 1);
    assert_eq!(live_http_worker_threads(1), 1);
    assert_eq!(
        live_http_worker_queue_capacity(0),
        LIVE_HTTP_CONNECTION_QUEUE_PER_WORKER
    );
    assert_eq!(
        live_http_worker_queue_capacity(3),
        3 * LIVE_HTTP_CONNECTION_QUEUE_PER_WORKER
    );
    assert_eq!(
        live_http_worker_threads(MAX_LIVE_HTTP_WORKER_THREADS + 100),
        MAX_LIVE_HTTP_WORKER_THREADS
    );

    let zero_worker_server = SoccerLiveServer::new(SoccerLiveServerConfig {
        match_config: MatchConfig {
            duration_seconds: 0.0,
            max_human_players: 0,
            seed: 72,
            ..Default::default()
        },
        http_worker_threads: 0,
        autoload_team_policy: false,
        autosave_team_policy: false,
        ..Default::default()
    });
    let zero_state = zero_worker_server.session.lock().unwrap().state_response();
    assert_eq!(zero_state.live_http.worker_model, "worker-pool");
    assert_eq!(zero_state.live_http.worker_threads, 1);
    assert_eq!(
        zero_state.live_http.worker_queue_capacity,
        LIVE_HTTP_CONNECTION_QUEUE_PER_WORKER
    );
    assert!(zero_state.live_http.bounded_worker_queue);
    assert!(zero_state.live_http.reuses_workers);
    assert!(!zero_state.live_http.spawns_per_request);

    let oversized_server = SoccerLiveServer::new(SoccerLiveServerConfig {
        match_config: MatchConfig {
            duration_seconds: 0.0,
            max_human_players: 0,
            seed: 73,
            ..Default::default()
        },
        http_worker_threads: usize::MAX,
        autoload_team_policy: false,
        autosave_team_policy: false,
        ..Default::default()
    });
    let oversized_state = oversized_server.session.lock().unwrap().state_response();
    assert_eq!(
        oversized_state.live_http.worker_threads,
        MAX_LIVE_HTTP_WORKER_THREADS
    );
    assert_eq!(
        oversized_state.live_http.worker_queue_capacity,
        MAX_LIVE_HTTP_WORKER_THREADS * LIVE_HTTP_CONNECTION_QUEUE_PER_WORKER
    );
    assert!(oversized_state.live_http.bounded_worker_queue);
    assert!(oversized_state.live_http.reuses_workers);
    assert!(!oversized_state.live_http.spawns_per_request);
}

#[test]
fn live_session_defaults_to_ten_minutes_at_tenth_second_ticks() {
    let session = SoccerRealtimeSession::new(MatchConfig::default());
    let state = session.state_response();

    assert_eq!(state.config.dt_seconds, DEFAULT_DT_SECONDS);
    assert_eq!(state.config.duration_seconds, DEFAULT_DURATION_SECONDS);
    assert_eq!(state.match_clock.dt_seconds, DEFAULT_DT_SECONDS);
    assert_eq!(state.match_clock.total_seconds, DEFAULT_DURATION_SECONDS);
    assert_eq!(state.match_clock.total_ticks, 9_000);
    assert_eq!(state.match_clock.remaining_ticks, 9_000);
    assert_eq!(
        state.match_clock.remaining_seconds,
        DEFAULT_DURATION_SECONDS
    );
    assert_eq!(state.summary.ticks, 0);
    assert_eq!(state.summary.simulated_seconds, 0.0);
    assert!(!state.match_clock.done);
    assert_eq!(state.frame.agent_schedule_summary.expected_total_agents, 27);
    assert_eq!(
        state
            .frame
            .agent_schedule_summary
            .expected_field_shuffle_agents,
        26
    );
    assert_eq!(state.frame.agent_schedule_summary.expected_ball_count, 1);
    assert_eq!(state.frame.players.len(), 22);
    assert_eq!(state.frame.officials.len(), 3);
}

#[test]
fn core_soccer_tick_executes_full_single_thread_runtime_contract() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 22_650,
        ..Default::default()
    });

    sim.run_time_step();

    let frame = sim.to_frame();
    assert_eq!(sim.tick, 1);
    assert_eq!(sim.clock_seconds, DEFAULT_DT_SECONDS);
    assert_eq!(frame.tick, sim.tick);
    assert_eq!(frame.clock_seconds, sim.clock_seconds);
    assert_eq!(frame.players.len(), SOCCER_MATCH_PLAYER_COUNT);
    assert_eq!(
        frame
            .players
            .iter()
            .filter(|player| player.team == Team::Home)
            .count(),
        SOCCER_MATCH_TEAM_PLAYER_COUNT
    );
    assert_eq!(
        frame
            .players
            .iter()
            .filter(|player| player.team == Team::Away)
            .count(),
        SOCCER_MATCH_TEAM_PLAYER_COUNT
    );
    assert_eq!(frame.officials.len(), SOCCER_MATCH_OFFICIAL_COUNT);
    assert_eq!(
        frame
            .officials
            .iter()
            .filter(|official| official.kind == OfficialKind::CenterReferee)
            .count(),
        1
    );
    assert_eq!(
        frame
            .officials
            .iter()
            .filter(|official| matches!(
                official.kind,
                OfficialKind::AssistantRefereeNear | OfficialKind::AssistantRefereeFar
            ))
            .count(),
        SOCCER_MATCH_ASSISTANT_REFEREE_COUNT
    );

    let summary = &frame.agent_schedule_summary;
    assert!(
        summary.complete,
        "runtime schedule should be complete: {summary:?}"
    );
    assert_eq!(summary.total_agents, 27);
    assert_eq!(summary.field_shuffle_agents, 26);
    assert_eq!(summary.player_count, SOCCER_MATCH_PLAYER_COUNT);
    assert_eq!(summary.official_count, SOCCER_MATCH_OFFICIAL_COUNT);
    assert_eq!(summary.ball_count, 1);
    assert!(summary.central_brain_first);
    assert_eq!(
        frame
            .agent_schedule
            .first()
            .map(|entry| (&entry.kind, entry.id)),
        Some((&AgentScheduleKind::CentralBrain, CENTRAL_BRAIN_AGENT_ID))
    );
    assert!(frame
        .players
        .iter()
        .all(|player| player.scheduled_index.is_some()));
    let mut player_operation_orders = HashSet::new();
    for player in &frame.players {
        let decision = player
            .last_decision
            .as_ref()
            .expect("every scheduled player agent should expose a run_time_step decision trace");
        assert_eq!(
            decision.scheduled_index, player.scheduled_index,
            "player {} decision trace should agree with the agentic schedule slot",
            player.id
        );
        assert_eq!(decision.observation.scheduled_index, player.scheduled_index);
        assert_eq!(decision.mdp_state.tick, frame.tick.saturating_sub(1));
        assert!(
            !decision.operation_order.is_empty(),
            "player {} should expose its internal operation order",
            player.id
        );
        player_operation_orders.insert(decision.operation_order.join(">"));
    }
    assert!(
            player_operation_orders.len() > 1,
            "player run_time_step operation order should vary across agents according to state/preferences: {player_operation_orders:?}"
        );
    assert!(frame
        .officials
        .iter()
        .all(|official| official.scheduled_index.is_some()));
    for official in &frame.officials {
        let decision = official
            .last_decision
            .as_ref()
            .expect("every scheduled official agent should expose a run_time_step decision trace");
        assert_eq!(
            decision.scheduled_index, official.scheduled_index,
            "official {} decision trace should agree with the agentic schedule slot",
            official.id
        );
        assert_eq!(decision.tick, frame.tick.saturating_sub(1));
        assert!(
            !decision.operation_order.is_empty(),
            "official {} should expose its internal operation order",
            official.id
        );
    }
    assert!(frame.ball.scheduled_index.is_some());
    assert!(frame.ball.last_decision.is_some());

    assert_eq!(frame.central_brain.scheduled_index, Some(0));
    assert_eq!(
        frame.central_brain.tracked_players.len(),
        SOCCER_MATCH_PLAYER_COUNT
    );
    assert_eq!(
        frame.central_brain.tracked_official_awareness.len(),
        SOCCER_MATCH_OFFICIAL_COUNT
    );
    assert_eq!(frame.central_brain.ball_position, frame.ball.position);
    assert_eq!(frame.central_brain.ball_velocity, frame.ball.velocity);
    assert_eq!(
        frame.central_brain.ball_acceleration,
        frame.ball.acceleration
    );
    assert_eq!(frame.central_brain.ball_jerk, frame.ball.jerk);
    assert_eq!(
        frame.home_brain.tracked_team_players,
        SOCCER_MATCH_TEAM_PLAYER_COUNT
    );
    assert_eq!(
        frame.away_brain.tracked_team_players,
        SOCCER_MATCH_TEAM_PLAYER_COUNT
    );
    assert!(frame.home_brain.directive.risk_tolerance.is_finite());
    assert!(frame.away_brain.directive.risk_tolerance.is_finite());
}

