#[test]
fn live_http_surface_and_learning_recover_from_poisoned_session_lock() {
    let realtime = SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        seed: 593,
        ..Default::default()
    });
    let input_queue = realtime.input_queue();
    let session = Arc::new(Mutex::new(realtime));
    let poisoner = {
        let session = Arc::clone(&session);
        std::thread::spawn(move || {
            let _guard = session.lock().expect("test poison live session lock");
            panic!("poison soccer live surface learning session lock");
        })
    };
    assert!(poisoner.join().is_err());

    let surface_body = r#"{"ballDragPerTick":0.044,"ballStopSpeedYps":0.66}"#;
    let surface = handle_live_soccer_request(
        &format!(
            "POST /api/surface HTTP/1.1\r\nHost: local\r\nContent-Length: {}\r\n\r\n{}",
            surface_body.len(),
            surface_body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(surface.status, 200);
    let surface_value: serde_json::Value =
        serde_json::from_str(&surface.body).expect("recovered surface json");
    assert_eq!(surface_value["config"]["ballDragPerTick"], 0.044);
    assert_eq!(surface_value["config"]["ballStopSpeedYps"], 0.66);

    let learning_body =
        r#"{"learningEnabled":false,"learningLoggingEnabled":false,"learningIntervalTicks":7}"#;
    let learning = handle_live_soccer_request(
        &format!(
            "POST /api/learning HTTP/1.1\r\nHost: local\r\nContent-Length: {}\r\n\r\n{}",
            learning_body.len(),
            learning_body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(learning.status, 200);
    let learning_value: serde_json::Value =
        serde_json::from_str(&learning.body).expect("recovered learning json");
    assert_eq!(learning_value["config"]["learningEnabled"], false);
    assert_eq!(learning_value["config"]["learningIntervalTicks"], 7);
    assert_eq!(learning_value["learning"]["learningEnabled"], false);
}

#[test]
fn live_http_input_route_feeds_next_step() {
    let session = Arc::new(Mutex::new(SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 1,
        seed: 56,
        ..Default::default()
    })));
    let input_queue = session.lock().unwrap().input_queue();
    {
        session
            .lock()
            .unwrap()
            .match_mut()
            .assign_controller_slot(0, Some(0))
            .expect("assign human controller");
    }
    let start_x = session.lock().unwrap().match_ref().players[0].position.x;

    let input = r#"{"controllerSlot":0,"playerId":0,"seq":1,"axis":{"x":1.0,"y":0.0},"sprint":true,"pass":false,"shoot":false,"targetPlayer":null}"#;
    let ack = handle_live_soccer_request(
        &format!(
            "POST /api/input HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            input.len(),
            input
        ),
        &session,
        &input_queue,
    );
    assert_eq!(ack.status, 200);
    let ack_value: serde_json::Value = serde_json::from_str(&ack.body).expect("ack json");
    assert_eq!(ack_value["acceptedInputs"], 1);
    assert_eq!(ack_value["queued"], true);
    assert_eq!(ack_value["queuedHumanInputs"], 1);

    let step_body = r#"{"ticks":1}"#;
    let step = handle_live_soccer_request(
        &format!(
            "POST /api/step HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            step_body.len(),
            step_body
        ),
        &session,
        &input_queue,
    );
    assert_eq!(step.status, 200);
    let step_value: serde_json::Value = serde_json::from_str(&step.body).expect("step json");
    assert_eq!(step_value["controllerThreads"].as_array().unwrap().len(), 1);
    assert_eq!(step_value["controllerThreads"][0]["controllerSlot"], 0);
    assert!(
        step_value["controllerThreads"][0]["acceptedFrames"]
            .as_u64()
            .unwrap()
            >= 1
    );
    assert!(
        step_value["controllerThreads"][0]["pushedFrames"]
            .as_u64()
            .unwrap()
            >= 1
    );
    assert!(
        step_value["controllerThreads"][0]["debouncedFrames"]
            .as_u64()
            .unwrap()
            >= 1
    );
    assert!(
        step_value["controllerThreads"][0]["lastDebounceMs"]
            .as_f64()
            .unwrap()
            >= 0.0
    );
    assert!(
        step_value["controllerThreads"][0]["totalDebounceMs"]
            .as_f64()
            .unwrap()
            >= 0.0
    );
    assert!(
        step_value["controllerThreads"][0]["maxDebounceMs"]
            .as_f64()
            .unwrap()
            >= step_value["controllerThreads"][0]["lastDebounceMs"]
                .as_f64()
                .unwrap()
    );
    assert_eq!(step_value["controllerYield"]["assignedPlayers"], 1);
    assert!(
        step_value["controllerYield"]["waitAttempts"]
            .as_u64()
            .unwrap()
            >= 1,
        "step should attempt to yield for the assigned controller slot"
    );
    assert_eq!(step_value["controllerYield"]["lateWaitAttempts"], 0);
    assert_eq!(step_value["controllerYield"]["lastWaitLate"], false);
    assert_eq!(
        step_value["controllerLatencyBudget"]["tickBudgetMs"],
        DEFAULT_DT_SECONDS * 1_000.0
    );
    let tick_budget_ms = step_value["controllerLatencyBudget"]["tickBudgetMs"]
        .as_f64()
        .unwrap();
    assert_eq!(step_value["controllerLatencyBudget"]["consumedInputs"], 1);
    let budget_slots = step_value["controllerLatencyBudget"]["slots"]
        .as_array()
        .expect("controller latency budget slots");
    assert_eq!(budget_slots.len(), 1);
    assert_eq!(budget_slots[0]["controllerSlot"], 0);
    assert_eq!(budget_slots[0]["assigned"], true);
    assert_eq!(budget_slots[0]["playerId"], 0);
    assert_eq!(budget_slots[0]["consumedInputs"], 1);
    assert!(
        budget_slots[0]["maxQueueAgeMs"].as_f64().unwrap()
            <= step_value["controllerLatencyBudget"]["maxQueueAgeMs"]
                .as_f64()
                .unwrap()
    );
    let slot_estimated_control_latency_ms = budget_slots[0]["estimatedControlLatencyMs"]
        .as_f64()
        .unwrap();
    assert!(slot_estimated_control_latency_ms.is_finite());
    assert!(slot_estimated_control_latency_ms >= 0.0);
    assert_eq!(
        budget_slots[0]["overBudget"].as_bool().unwrap(),
        slot_estimated_control_latency_ms > tick_budget_ms
    );
    let estimated_control_latency_ms = step_value["controllerLatencyBudget"]
        ["estimatedControlLatencyMs"]
        .as_f64()
        .unwrap();
    assert!(estimated_control_latency_ms.is_finite());
    assert!(estimated_control_latency_ms >= 0.0);
    assert_eq!(
        step_value["controllerLatencyBudget"]["overBudget"]
            .as_bool()
            .unwrap(),
        estimated_control_latency_ms > tick_budget_ms
    );
    assert!(
        step_value["controllerYield"]["lastWaitMs"]
            .as_f64()
            .unwrap()
            >= 0.0
    );
    assert!(
        step_value["controllerYield"]["totalWaitMs"]
            .as_f64()
            .unwrap()
            >= 0.0
    );
    assert!(
        step_value["controllerYield"]["maxWaitMs"].as_f64().unwrap()
            >= step_value["controllerYield"]["lastWaitMs"]
                .as_f64()
                .unwrap()
    );
    assert!(
        step_value["controllerYield"]["notifiedWaits"].as_u64().unwrap()
            + step_value["controllerYield"]["immediatePendingWaits"].as_u64().unwrap()
            + step_value["controllerYield"]["timedOutWaits"].as_u64().unwrap()
            >= 1,
        "controller yield should account for the assigned-slot wait regardless of parallel-test timing: yield={:?}",
        step_value["controllerYield"]
    );
    assert_eq!(step_value["queuedHumanInputs"], 0);
    assert!(session.lock().unwrap().match_ref().players[0].position.x > start_x);
}

#[test]
fn live_http_input_route_rejects_unassigned_or_wrong_player_frames() {
    let session = Arc::new(Mutex::new(SoccerRealtimeSession::new(MatchConfig {
        duration_seconds: 1.0,
        max_human_players: 1,
        seed: 565,
        ..Default::default()
    })));
    let input_queue = session.lock().unwrap().input_queue();

    let unassigned = r#"{"controllerSlot":0,"playerId":0,"seq":1,"axis":{"x":1.0,"y":0.0},"sprint":true,"pass":false,"shoot":false,"targetPlayer":null}"#;
    let ack = handle_live_soccer_request(
        &format!(
            "POST /api/input HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            unassigned.len(),
            unassigned
        ),
        &session,
        &input_queue,
    );
    assert_eq!(ack.status, 200);
    let ack_value: serde_json::Value = serde_json::from_str(&ack.body).expect("ack json");
    assert_eq!(ack_value["acceptedInputs"], 0);
    assert_eq!(ack_value["rejectedInputs"], 1);
    assert_eq!(ack_value["queued"], false);
    assert_eq!(ack_value["queuedHumanInputs"], 0);
    assert_eq!(input_queue.queued_len(), 0);

    {
        session
            .lock()
            .unwrap()
            .match_mut()
            .assign_controller_slot(0, Some(5))
            .expect("assign slot 0 to player 5");
    }
    let wrong_player = r#"{"controllerSlot":0,"playerId":0,"seq":2,"axis":{"x":1.0,"y":0.0},"sprint":true,"pass":false,"shoot":false,"targetPlayer":null}"#;
    let ack = handle_live_soccer_request(
        &format!(
            "POST /api/input HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            wrong_player.len(),
            wrong_player
        ),
        &session,
        &input_queue,
    );
    assert_eq!(ack.status, 200);
    let ack_value: serde_json::Value = serde_json::from_str(&ack.body).expect("ack json");
    assert_eq!(ack_value["acceptedInputs"], 0);
    assert_eq!(ack_value["rejectedInputs"], 1);
    assert_eq!(ack_value["queued"], false);
    assert_eq!(ack_value["queuedHumanInputs"], 0);
    assert_eq!(input_queue.queued_len(), 0);
    assert_eq!(
        session.lock().unwrap().controller_thread_stats()[0].accepted_frames,
        0
    );

    let slot_level = r#"{"controllerSlot":0,"seq":2,"axis":{"x":1.0,"y":0.0},"sprint":true,"pass":false,"shoot":false,"targetPlayer":null}"#;
    let ack = handle_live_soccer_request(
        &format!(
            "POST /api/input HTTP/1.1\r\nContent-Length: {}\r\n\r\n{}",
            slot_level.len(),
            slot_level
        ),
        &session,
        &input_queue,
    );
    assert_eq!(ack.status, 200);
    let ack_value: serde_json::Value = serde_json::from_str(&ack.body).expect("ack json");
    assert_eq!(ack_value["acceptedInputs"], 1);
    assert_eq!(ack_value["rejectedInputs"], 0);
    assert_eq!(ack_value["queued"], true);
    assert_eq!(
        session.lock().unwrap().controller_thread_stats()[0].accepted_frames,
        1
    );
}

