#[test]
fn round_goalkeeper_turns_blocked_twenty_yard_shot_into_closer_dribble() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        dt_seconds: 1.0,
        seed: 2235,
        ..Default::default()
    });
    let attacker = 9;
    let keeper = 11;
    park_players_except(&mut sim, &[attacker, keeper]);
    sim.players[attacker].role = PlayerRole::Forward;
    sim.players[attacker].position = Vec2::new(40.0, 96.0);
    sim.players[attacker].home_position = sim.players[attacker].position;
    sim.players[attacker].velocity = Vec2::zero();
    sim.players[attacker].skills.dribbling = 9.0;
    sim.players[attacker].skills.acceleration = 8.8;
    sim.players[attacker].skills.first_touch = 8.4;
    sim.players[attacker].skills.shooting = 7.4;
    sim.players[attacker].skills.decision_noise = 0.0;
    sim.players[attacker].preferences.dribble_bias = 1.15;
    sim.players[attacker].preferences.shoot_bias = 0.55;
    sim.players[keeper].role = PlayerRole::Goalkeeper;
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.players[keeper].home_position = sim.players[keeper].position;
    sim.players[keeper].velocity = Vec2::zero();
    sim.players[keeper].skills.goalkeeping = 9.0;
    sim.players[keeper].skills.acceleration = 8.4;
    sim.ball.holder = Some(attacker);
    sim.ball.position = sim.players[attacker].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(attacker);
    assert!(
        observation.yards_to_goal >= 20.0,
        "fixture should start outside the preferred close-shot window: {observation:?}"
    );
    assert!(learned_action_label_is_legal(
        "round-the-goalkeeper",
        &snapshot,
        attacker
    ));

    let learned = SoccerLearnedPlan {
        action: "round-goalkeeper".to_string(),
        target_player: None,
        target_point: None,
        mpc_replan: None,
    };
    let direct_action =
        sim.players[attacker].action_from_learned_plan(&learned, &snapshot, &observation);
    assert!(
        matches!(
            direct_action,
            Some((SoccerAction::DribbleMove { .. }, ref label))
                if label == "round-goalkeeper"
        ),
        "learned round-goalkeeper should resolve to the keeper-rounding dribble: {direct_action:?}"
    );
    let Some((SoccerAction::DribbleMove { target, .. }, _)) = direct_action else {
        unreachable!("asserted round-goalkeeper dribble above");
    };
    let origin = sim.players[attacker].position;
    let goal_y = Team::Home.goal_y(snapshot.field_length);
    let keeper_position = sim.players[keeper].position;
    let target_yards_to_goal = (goal_y - target.y).abs();
    let step_yards = origin.distance(target);
    assert!(
        (1.2..=8.05).contains(&step_yards),
        "rounding touch should be a bounded dribble, got {step_yards} to {:?}",
        target
    );
    assert!(
        target_yards_to_goal < observation.yards_to_goal - 0.75,
        "rounding should move closer to goal instead of shooting from range: before={} after={target_yards_to_goal}",
        observation.yards_to_goal
    );
    assert!(
        target.distance(keeper_position) >= 2.15,
        "target must round the keeper rather than collide with him: target={:?} keeper={keeper_position:?}",
        target
    );
    assert!(
        segment_distance_to_point(origin, target, keeper_position) >= 1.05,
        "dribble path should go around the keeper, not through him: origin={origin:?} target={:?}",
        target
    );
    let player_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == attacker)
        .expect("attacker snapshot");
    let direct_window = snapshot.shooting_window_score_at(player_snapshot, origin);
    let rounded_window = snapshot.shooting_window_score_at(player_snapshot, target);
    assert!(
        rounded_window > direct_window,
        "dribble target should improve the eventual shooting window: before={direct_window} after={rounded_window} target={:?}",
        target
    );
}

#[test]
fn stale_dribble_at_shooting_pocket_cuts_across_not_to_endline() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 2231,
        ..Default::default()
    });
    let attacker = 9;
    let blocker = 13;
    let keeper = 11;
    park_players_except(&mut sim, &[attacker, blocker, keeper]);
    sim.players[attacker].position = Vec2::new(40.0, 110.0);
    sim.players[attacker].home_position = sim.players[attacker].position;
    sim.players[attacker].skills.dribbling = 8.8;
    sim.players[blocker].position = Vec2::new(40.6, 112.0);
    sim.players[blocker].skills.defending = 8.7;
    sim.players[keeper].position = Vec2::new(40.0, 116.0);
    sim.ball.holder = Some(attacker);
    sim.ball.position = sim.players[attacker].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[attacker].position;
    let target = snapshot.dribble_move_target_for_touch(
        attacker,
        sim.players[attacker].home_position,
        DribbleMoveKind::CarryForward,
        DribbleTouchDecision::new(0, 4.8),
    );

    assert!(
            target.y <= origin.y + 0.05,
            "stale pocket dribble should not poke the ball toward the endline: origin={origin:?} target={target:?}"
        );
    assert!(
            target.x < origin.x - 1.0,
            "blocked central pocket dribble should cut across the shooting pocket to open a lane: origin={origin:?} target={target:?}"
        );
}

#[test]
fn clear_striker_takes_attempts_from_thirty_yard_window() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 1.0,
        dt_seconds: 1.0,
        seed: 2224,
        ..Default::default()
    });
    let attacker = 9;
    let keeper = 11;
    park_players_except(&mut sim, &[attacker, keeper]);
    sim.players[attacker].position = Vec2::new(40.0, 91.0);
    sim.players[attacker].velocity = Vec2::new(0.0, 4.0);
    sim.players[attacker].skills.shooting = 9.2;
    sim.players[attacker].skills.right_foot_shot_power = 9.4;
    sim.players[attacker].skills.left_foot_shot_power = 8.8;
    sim.players[attacker].skills.decision_noise = 0.0;
    sim.players[attacker].preferences.shoot_bias = 0.98;
    sim.players[attacker].preferences.pass_bias = 0.02;
    sim.players[attacker].preferences.dribble_bias = 0.04;
    sim.players[keeper].position = Vec2::new(38.5, 116.0);
    sim.players[keeper].skills.goalkeeping = 5.0;
    sim.ball.holder = Some(attacker);
    sim.ball.position = sim.players[attacker].position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(attacker);
    assert!(observation.yards_to_goal > STRIKER_MUST_SHOOT_YARDS);
    assert!(observation.yards_to_goal <= tunables().shooting.striker_shot_window_yards);
    // The long shot stays a LEGAL option from the 25-30yd window...
    assert!(shot_decision_is_qualified_for_role(
        &observation,
        sim.players[attacker].role
    ));
    // ...but with the keeper SET on his line, the shot-trigger discipline (default-ON) keeps
    // its value low, so a disciplined striker rarely sprays it from ~29yd — he works it
    // closer toward 20/15 instead. This is the "shoots from 25 when he should from 20/15"
    // fix; set DD_SOCCER_DISABLE_SHOT_TRIGGER_MDP for the legacy shoot-often-from-30 behavior.
    assert!(observation.shot_trigger_mdp_value < 0.25);

    let mut shoot_count = 0;
    let trials = 120;
    for seed in 0..trials {
        let mut player = sim.players[attacker].clone();
        let mut rng = mulberry32(22_000 + seed);
        let intent = player.run_time_step(&snapshot, None, None, &mut rng);
        if matches!(intent.action, SoccerAction::Shoot { .. }) {
            shoot_count += 1;
        }
    }

    assert!(
        shoot_count <= 20,
        "disciplined striker should rarely spray from ~29yd at a SET keeper (work it closer), got {shoot_count}/{trials}"
    );
}

#[test]
fn decisive_goal_actions_ramp_as_ball_gets_closer_to_goal() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 22_236,
        ..Default::default()
    });
    let attacker = 8;
    let runner = 9;
    let keeper = 11;
    park_players_except(&mut sim, &[attacker, runner, keeper]);
    sim.players[attacker].role = PlayerRole::Midfielder;
    sim.players[attacker].skills.shooting = 7.9;
    sim.players[attacker].skills.passing_completion_rate = 8.8;
    sim.players[attacker].skills.vision = 9.0;
    sim.players[attacker].skills.decision_noise = 0.0;
    sim.players[attacker].preferences.shoot_bias = 0.72;
    sim.players[attacker].preferences.pass_bias = 1.0;
    sim.players[attacker].preferences.dribble_bias = 0.88;
    sim.players[runner].role = PlayerRole::Forward;
    sim.players[runner].skills.shooting = 8.7;
    sim.players[runner].skills.top_speed = 9.0;
    sim.players[runner].velocity = Vec2::new(0.8, 5.6);
    sim.players[keeper].position = Vec2::new(40.0, 116.5);
    sim.players[keeper].skills.goalkeeping = 5.0;

    let mut previous_direct = 0.0;
    let mut previous_recycle = f64::INFINITY;
    for (idx, y) in [90.0, 98.0, 104.0].into_iter().enumerate() {
        sim.players[attacker].position = Vec2::new(40.0, y);
        sim.players[attacker].velocity = Vec2::new(0.0, 4.0);
        sim.players[runner].position = Vec2::new(47.0, (y + 18.0).min(112.0));
        sim.ball.holder = Some(attacker);
        sim.ball.position = sim.players[attacker].position;
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);

        let snapshot = WorldSnapshot::from_match(&sim);
        let observation = snapshot.observation_for(attacker);
        let pass_targets = snapshot.ranked_visible_pass_targets(attacker, 3);
        let aerial_targets = snapshot.ranked_visible_aerial_pass_targets(attacker, 3);
        let options = sim.players[attacker].possession_action_options(
            &observation,
            &snapshot.tactical_directive(Team::Home),
            pass_targets.len(),
            aerial_targets.len(),
            false,
            sim.config.dt_seconds,
            snapshot.field_width,
        );
        let option_probability = |label: &str| {
            options
                .iter()
                .find(|option| option.label == label && option.legal)
                .map(|option| option.probability)
                .unwrap_or(0.0)
        };
        let decisive = option_probability("shoot") + option_probability("killer-pass");
        let direct = decisive + option_probability("carry-forward");
        let recycle = option_probability("pass1")
            + option_probability("pass2")
            + option_probability("aerial-pass1")
            + option_probability("dribble");

        if idx > 0 {
            assert!(
                    direct + 0.02 >= previous_direct,
                    "direct goal pressure should stay saturated as the ball nears goal: y={y} direct={direct} previous={previous_direct} decisive={decisive} options={options:?}"
                );
            assert!(
                    recycle <= previous_recycle + 0.01 || recycle <= 0.02,
                    "generic recycle pressure should stay tiny near goal: y={y} recycle={recycle} previous={previous_recycle} options={options:?}"
                );
        }
        assert!(
                decisive >= 0.75,
                "goal-entry decisions should keep shoot/killer-pass pressure high even when direct carry is viable: y={y} decisive={decisive} recycle={recycle} options={options:?}"
            );
        assert!(
                direct > recycle * 20.0,
                "goal-entry decisions should favor direct goal pressure over recycling: y={y} direct={direct} recycle={recycle} options={options:?}"
            );
        previous_direct = direct;
        previous_recycle = recycle;
    }
}

#[test]
fn near_goal_shot_and_killer_pass_pressure_both_ramp_over_recycling() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 22_246,
        ..Default::default()
    });
    let attacker = 8;
    let runner = 9;
    let keeper = 11;
    let shot_blocker = 13;
    let offside_line_defender = 14;
    park_players_except(
        &mut sim,
        &[
            attacker,
            runner,
            keeper,
            shot_blocker,
            offside_line_defender,
        ],
    );
    sim.players[attacker].role = PlayerRole::Midfielder;
    sim.players[attacker].skills.shooting = 7.7;
    sim.players[attacker].skills.passing_completion_rate = 9.1;
    sim.players[attacker].skills.vision = 9.5;
    sim.players[attacker].skills.decision_noise = 0.0;
    sim.players[attacker].preferences.shoot_bias = 0.52;
    sim.players[attacker].preferences.pass_bias = 1.0;
    sim.players[attacker].preferences.dribble_bias = 0.92;
    sim.players[runner].role = PlayerRole::Forward;
    sim.players[runner].skills.shooting = 8.9;
    sim.players[runner].skills.top_speed = 9.2;
    sim.players[keeper].position = Vec2::new(40.0, 116.5);
    sim.players[keeper].skills.goalkeeping = 5.0;
    for defender in [shot_blocker, offside_line_defender] {
        sim.players[defender].skills.defending = 9.4;
        sim.players[defender].skills.defensive_tracking = 9.2;
    }

    let mut previous_decisive = 0.0;
    let mut previous_thread_pressure = 0.0;
    // Positions within the 30yd shot cap (yards_to_goal = 120 - y => 26, 20, 14), ramping in.
    for (idx, y) in [94.0, 100.0, 106.0].into_iter().enumerate() {
        sim.players[attacker].position = Vec2::new(39.0, y);
        sim.players[attacker].velocity = Vec2::new(0.2, 4.0);
        sim.players[runner].position = Vec2::new(47.0, (y + 12.0).min(108.0));
        sim.players[runner].velocity = Vec2::new(0.4, 1.2);
        sim.players[shot_blocker].position = Vec2::new(70.0, (y + 8.0).min(108.0));
        sim.players[offside_line_defender].position = Vec2::new(20.0, (y + 20.0).min(116.0));
        sim.ball.holder = Some(attacker);
        sim.ball.position = sim.players[attacker].position;
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);

        let snapshot = WorldSnapshot::from_match(&sim);
        let observation = snapshot.observation_for(attacker);
        let pass_targets = snapshot.ranked_visible_pass_targets(attacker, 3);
        assert_eq!(
                snapshot.killer_pass_target_for(attacker, &pass_targets),
                Some(runner),
                "runner should stay the single threaded receiver toward goal at y={y}: {pass_targets:?}"
            );

        let options = sim.players[attacker].possession_action_options(
            &observation,
            &snapshot.tactical_directive(Team::Home),
            pass_targets.len(),
            snapshot
                .ranked_visible_aerial_pass_targets(attacker, 3)
                .len(),
            false,
            sim.config.dt_seconds,
            snapshot.field_width,
        );
        let option_probability = |label: &str| {
            options
                .iter()
                .find(|option| option.label == label && option.legal)
                .map(|option| option.probability)
                .unwrap_or(0.0)
        };
        let shoot = option_probability("shoot");
        let killer = option_probability("killer-pass");
        let decisive = shoot + killer;
        let recycle = option_probability("pass1")
            + option_probability("pass2")
            + option_probability("aerial-pass1")
            + option_probability("dribble")
            + option_probability("carry-forward");
        let thread_pressure = single_pass_goal_thread_pressure_score(&observation);

        if idx > 0 {
            if previous_decisive < 0.95 {
                assert!(
                        decisive > previous_decisive + 0.04,
                        "shot/killer-pass family should strengthen as the ball nears goal before saturation: y={y} decisive={decisive} previous={previous_decisive} options={options:?}"
                    );
            } else {
                assert!(
                        decisive >= 0.95,
                        "shot/killer-pass family should stay saturated near goal: y={y} decisive={decisive} previous={previous_decisive} options={options:?}"
                    );
            }
            assert!(
                    thread_pressure > previous_thread_pressure + 0.03,
                    "single threaded goal-pass pressure should ramp with goal proximity: y={y} pressure={thread_pressure} previous={previous_thread_pressure} observation={observation:?}"
                );
        }
        if idx > 0 {
            assert!(
                    shoot >= 0.08,
                    "goal approach should preserve a real shot threat once inside the shot-pressure window: y={y} shoot={shoot} options={options:?}"
                );
        }
        // The killer-pass option is preserved through the build-up, but very close to goal it
        // deliberately yields to the shot (decisive prob saturates) — only require it while the
        // shot family has not saturated.
        if decisive < 0.95 {
            assert!(
                killer >= 0.16,
                "build-up should preserve the single killer-pass option: y={y} killer={killer} options={options:?}"
            );
        }
        let decisive_recycle_ratio = if idx == 0 { 1.0 } else { 2.4 };
        assert!(
                decisive > recycle * decisive_recycle_ratio,
                "near-goal policy should prefer shoot/killer-pass over recycle: y={y} decisive={decisive} recycle={recycle} ratio={decisive_recycle_ratio} options={options:?}"
            );

        previous_decisive = decisive;
        previous_thread_pressure = thread_pressure;
    }
}

