    assert_eq!(meta["cadence"]["defaultTickHz"], 1.0 / DEFAULT_DT_SECONDS);
    assert_eq!(
        meta["cadence"]["defaultTickMillis"],
        DEFAULT_DT_SECONDS * 1_000.0
    );
    assert_eq!(
        meta["cadence"]["defaultDurationSeconds"],
        DEFAULT_DURATION_SECONDS
    );
    assert_eq!(meta["cadence"]["defaultTotalTicks"], 9_000);
    assert!(meta["cadence"].get("recordEveryTicks").is_none());
    assert_eq!(meta["cadence"]["expectedFrameCount"], trace.frames.len());
