#[test]
fn neural_snapshot_sidecar_round_trips_independently_of_tabular_artifact() {
    let policy_path = std::env::temp_dir().join(format!(
        "soccer-neural-sidecar-test-{}.json",
        std::process::id()
    ));
    let sidecar_path = policy_neural_snapshot_disk_path(&policy_path);
    let _ = std::fs::remove_file(&sidecar_path);

    // Missing sidecar reads as None, never an error (cold start with no net yet).
    assert!(read_soccer_neural_snapshot(&policy_path)
        .expect("missing sidecar is Ok(None)")
        .is_none());

    let snapshot = SoccerNeuralNetworkSnapshot {
        input_dim: 7,
        output_dim: 1,
        parameter_count: 3865,
        l2_norm: 1.25,
        layers: Vec::new(),
        ..Default::default()
    };
    write_soccer_neural_snapshot(&policy_path, &snapshot).expect("write sidecar");
    // The sidecar exists on its own — the (over-cap) tabular artifact was never written.
    assert!(sidecar_path.exists());
    assert!(!policy_path.exists());

    let loaded = read_soccer_neural_snapshot(&policy_path)
        .expect("read sidecar")
        .expect("sidecar present");
    assert_eq!(loaded.parameter_count, 3865);
    assert_eq!(loaded.input_dim, 7);
    assert!((loaded.l2_norm - 1.25).abs() < 1e-9);

    let _ = std::fs::remove_file(&sidecar_path);
}

