// --- Wall pass / one-two (give-and-go) -----------------------------------------

/// Set up a Home attack in the opponent half with a beatable man in front of the
/// carrier, a free side-on wall, and onside space to run into.
fn wall_pass_scenario() -> SoccerMatch {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.tick = 30;
    sim.clock_seconds = 12.0;
    let carrier = 6;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 80.0);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[carrier].position = sim.ball.position;
    // Side-on wall, onside.
    sim.players[7].position = Vec2::new(30.0, 83.0);
    // Away keeper deep; man-to-beat just ahead of the carrier; the rest form a line
    // at y = 95 (so the second-last-defender line sits there and everything in front
    // is onside).
    sim.players[11].position = Vec2::new(40.0, 118.0);
    sim.players[12].position = Vec2::new(42.0, 85.0);
    for (k, away) in (13..22).enumerate() {
        sim.players[away].position = Vec2::new(20.0 + k as f64 * 6.0, 95.0);
    }
    sim
}

#[test]
fn wall_pass_available_with_beatable_man_and_free_wall() {
    let sim = wall_pass_scenario();
    let snapshot = WorldSnapshot::from_match(&sim);
    let plan = snapshot
        .wall_pass_option_for(6)
        .expect("a wall pass should be on");
    // The burst run gains ground toward goal and stays onside (behind the line at 95).
    assert!(
        (plan.return_target.y - 80.0) * Team::Home.attack_dir() >= WALL_PASS_MIN_RUN_GAIN_YARDS,
        "return target should gain ground: {plan:?}"
    );
    assert!(
        plan.return_target.y <= 95.0 - ONSIDE_RUN_HOLD_BUFFER_YARDS + 1e-6,
        "return target must stay onside: {plan:?}"
    );
    assert!(
        plan.quality > 0.0,
        "plan should have positive quality: {plan:?}"
    );
}

#[test]
fn completed_one_two_return_credits_runner_and_wall() {
    // The runner (A) laid the ball off to the wall (B) and is mid one-two; B returns it first-time
    // into A's forward run. Completing this give->burst->return must add a wall-pass bonus ON TOP of
    // the generic pass reward, crediting BOTH players, so the POMDP can learn to prefer one-twos.
    let runner = 6usize; // A: gave it, burst forward, receives the return
    let wall = 7usize; // B: the wall, returns first-time
    let wall_pos = Vec2::new(40.0, 60.0);
    let runner_pos = Vec2::new(44.0, 70.0); // advanced, into the forward run
    let pass = test_pending_pass(Team::Home, wall, runner, wall_pos, runner_pos);

    let runner_reward = |with_one_two: bool| -> (f64, f64) {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        sim.players[wall].position = wall_pos;
        sim.players[runner].position = runner_pos;
        if with_one_two {
            sim.players[runner].one_two = Some(OneTwoRun {
                wall_partner: wall,
                launch_clock_seconds: sim.clock_seconds,
                return_target: Vec2::new(44.0, 72.0),
            });
        }
        sim.ball.position = pass.intended_target;
        sim.reward_events.clear();
        sim.record_completed_pass_reward(&pass, runner);
        let r: f64 = sim
            .reward_events
            .iter()
            .filter(|e| e.player_id == runner)
            .map(|e| e.amount)
            .sum();
        let w: f64 = sim
            .reward_events
            .iter()
            .filter(|e| e.player_id == wall)
            .map(|e| e.amount)
            .sum();
        (r, w)
    };

    let (runner_with, wall_with) = runner_reward(true);
    let (runner_plain, wall_plain) = runner_reward(false);
    assert!(
        runner_with > runner_plain + 2.0,
        "completing a one-two return must add a wall-pass bonus to the runner: with={runner_with} plain={runner_plain}"
    );
    assert!(
        wall_with > wall_plain,
        "the wall (returner) must get extra credit for the lay-off+return: with={wall_with} plain={wall_plain}"
    );
}

#[test]
fn third_man_run_credits_the_running_receiver_not_a_static_outlet() {
    // A -> B (feed), then B -> C where C is the running THIRD MAN. C must be credited for the run,
    // and an otherwise-identical C standing still must get strictly less (no combination-run bonus).
    let a = 5usize;
    let b = 6usize;
    let c = 7usize;
    let c_reward = |c_forward_velocity: f64| -> f64 {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        sim.players[a].position = Vec2::new(40.0, 40.0);
        sim.players[b].position = Vec2::new(42.0, 48.0);
        sim.players[c].position = Vec2::new(44.0, 60.0);
        // First pass A -> B registers the chain link into B (making C the third man).
        let feed = test_pending_pass(
            Team::Home,
            a,
            b,
            sim.players[a].position,
            sim.players[b].position,
        );
        sim.ball.position = feed.intended_target;
        sim.record_completed_pass_reward(&feed, b);
        // Second pass B -> C, with C running forward (or static) onto the ball.
        let mut second = test_pending_pass(
            Team::Home,
            b,
            c,
            sim.players[b].position,
            sim.players[c].position,
        );
        second.receiver_velocity_at_launch = Some(Vec2::new(0.0, c_forward_velocity));
        sim.ball.position = second.intended_target;
        sim.reward_events.clear();
        sim.record_completed_pass_reward(&second, c);
        sim.reward_events
            .iter()
            .filter(|e| e.player_id == c)
            .map(|e| e.amount)
            .sum()
    };
    let running = c_reward(5.0);
    let static_outlet = c_reward(0.0);
    assert!(
        running > static_outlet,
        "a third man running onto the ball must out-earn a static receiver: running={running} static={static_outlet}"
    );
}

#[test]
fn runaround_dribble_gate_fires_on_a_pace_beat_and_is_disablable() {
    let scenario = || {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let carrier = 7usize;
        sim.ball.holder = Some(carrier);
        sim.ball.position = Vec2::new(40.0, 70.0);
        sim.players[carrier].position = sim.ball.position;
        sim.players[carrier].velocity = Vec2::new(0.0, 6.0); // forward momentum (+y for Home)
        sim.players[carrier].skills.top_speed = 9.0; // pace advantage
                                                     // A committed defender just ahead, in the path, slower than the carrier.
        sim.players[12].position = Vec2::new(40.5, 73.0);
        sim.players[12].velocity = Vec2::zero();
        sim.players[12].skills.top_speed = 7.0;
        // Everyone else far away (clear ball lane + open re-collect zone).
        for away in [11usize, 13, 14, 15, 16, 17, 18, 19, 20, 21] {
            sim.players[away].position = Vec2::new(8.0 + away as f64, 20.0);
        }
        sim
    };
    let sim = scenario();
    let snapshot = WorldSnapshot::from_match(&sim);
    let plan = snapshot
        .runaround_dribble_option_for(7)
        .expect("a run-around should be on against a slower committed defender with space behind");
    assert_eq!(
        plan.defender, 12,
        "targets the committed defender: {plan:?}"
    );
    assert!(
        (plan.recollect_point.y - sim.players[7].position.y) * Team::Home.attack_dir() > 0.0,
        "re-collect point is beyond the carrier toward goal: {plan:?}"
    );
    assert!(plan.quality > 0.0, "positive quality: {plan:?}");
}

#[test]
fn ball_holder_pomdp_encodes_overcommitted_defender_reaction_and_nutmeg_window() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 7usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 70.0);
    sim.players[carrier].position = sim.ball.position;
    sim.players[carrier].velocity = Vec2::new(0.0, 3.8);
    sim.players[carrier].skills.dribbling = 8.8;
    sim.players[carrier].skills.first_touch = 8.6;
    sim.players[carrier].skills.flair_passing = 8.4;
    sim.players[defender].position = Vec2::new(40.25, 72.4);
    sim.players[defender].velocity = Vec2::new(2.6, -3.4);
    sim.players[defender].acceleration = Vec2::new(0.4, -1.2);
    sim.players[defender].skills.defensive_tracking = 3.0;
    sim.players[defender].fatigue = 0.50;

    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(carrier);
    let perception = &tunables().pomdp_perception;
    assert!(
        observation
            .neural_extended
            .nearest_defender_reaction_delay_seconds
            >= perception.player_reaction_min_seconds
            && observation
                .neural_extended
                .nearest_defender_reaction_delay_seconds
                <= perception.player_reaction_max_seconds,
        "defender POMDP reaction delay should sit in the configured band: {:?}",
        observation.neural_extended
    );
    assert!(
        observation
            .neural_extended
            .nearest_defender_overcommit_score
            > 0.24,
        "closing defender momentum should register as overcommit: {:?}",
        observation.neural_extended
    );
    assert!(
        observation.neural_extended.dribble_momentum_escape_side < -0.25,
        "escape side should point opposite the defender's +x momentum: {:?}",
        observation.neural_extended
    );
    assert!(
        observation.neural_extended.dribble_nutmeg_window_score > 0.20,
        "central committed defender should expose a nutmeg window: {:?}",
        observation.neural_extended
    );

    let q_key = SoccerQStateKey::from_parts(
        &snapshot.mdp_state_for_player(carrier),
        &observation,
        Team::Home,
        PlayerRole::Midfielder,
    );
    assert!(q_key.dribble_defender_overcommit_bin > 0);
    assert!(q_key.dribble_defender_reaction_delay_bin > 0);
    assert_eq!(q_key.dribble_momentum_escape_side_bin, -1);
    assert!(q_key.dribble_nutmeg_window_bin > 0);

    let decision = test_decision_trace(&snapshot, carrier, "nutmeg");
    let transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: carrier,
        team: Team::Home,
        role: PlayerRole::Midfielder,
        state: snapshot.mdp_state_for_player(carrier),
        observation: observation.clone(),
        belief: decision.belief,
        action: "nutmeg".to_string(),
        action_target: decision.action_target,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(carrier),
        next_observation: observation.clone(),
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert!(features[SOCCER_NEURAL_FEATURE_DRIBBLE_DEFENDER_OVERCOMMIT] > 0.0);
    assert!(features[SOCCER_NEURAL_FEATURE_DRIBBLE_DEFENDER_REACTION_DELAY] > 0.0);
    assert!(features[SOCCER_NEURAL_FEATURE_DRIBBLE_MOMENTUM_ESCAPE_SIDE] < 0.0);
    assert!(features[SOCCER_NEURAL_FEATURE_DRIBBLE_NUTMEG_WINDOW] > 0.0);

    let directive = snapshot.tactical_directive(Team::Home);
    let options = sim.players[carrier].possession_action_options(
        &observation,
        &directive,
        0,
        0,
        false,
        sim.config.dt_seconds,
        sim.config.field_width_yards,
    );
    assert!(
        action_option_score(&options, "nutmeg") > 0.0,
        "nutmeg should be a live player-level option when the POMDP sees the window"
    );
}

#[test]
fn runaround_dribble_prefers_escape_opposite_defender_lateral_momentum() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let carrier = 7usize;
    let defender = 12usize;
    park_players_except(&mut sim, &[carrier, defender]);
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 70.0);
    sim.players[carrier].position = sim.ball.position;
    sim.players[carrier].velocity = Vec2::new(0.0, 6.0);
    sim.players[carrier].skills.top_speed = 9.0;
    sim.players[carrier].skills.dribbling = 8.8;
    sim.players[carrier].skills.acceleration = 8.6;
    sim.players[defender].position = Vec2::new(40.5, 73.0);
    sim.players[defender].velocity = Vec2::new(3.0, -2.0);
    sim.players[defender].acceleration = Vec2::new(0.3, -0.7);
    sim.players[defender].skills.top_speed = 7.0;
    sim.players[defender].skills.defensive_tracking = 3.5;

    let snapshot = WorldSnapshot::from_match(&sim);
    let perception = &tunables().pomdp_perception;
    let plan = snapshot
        .runaround_dribble_option_for(carrier)
        .expect("overcommitted defender with space should leave a runaround lane");
    assert!(
        plan.recollect_point.x < sim.players[defender].position.x,
        "carrier should escape left when the defender's lateral momentum is rightward: {plan:?}"
    );
    assert!(
        segment_distance_to_point(
            sim.players[carrier].position,
            plan.recollect_point,
            sim.players[defender].position
                + sim.players[defender].velocity * perception.player_reaction_max_seconds,
        ) > 1.0,
        "rendered body path should bend around the defender projection rather than collide: {plan:?}"
    );
}

fn outside_mid_takeon_scenario(with_cover: bool) -> SoccerMatch {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        dt_seconds: 0.0,
        ..MatchConfig::default()
    });
    let carrier = 7usize;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(68.0, 70.0);
    sim.players[carrier].role = PlayerRole::Midfielder;
    sim.players[carrier].position = sim.ball.position;
    sim.players[carrier].home_position = Vec2::new(68.0, 62.0);
    sim.players[carrier].velocity = Vec2::new(0.0, 3.4);
    sim.players[carrier].skills.dribbling = 8.8;
    sim.players[carrier].skills.top_speed = 8.6;
    sim.players[carrier].skills.acceleration = 8.4;
    sim.players[12].position = Vec2::new(67.6, 73.0);
    sim.players[12].velocity = Vec2::new(0.0, 3.2);
    sim.players[12].skills.top_speed = 8.45;
    for away in [11usize, 13, 14, 15, 16, 17, 18, 19, 20, 21] {
        sim.players[away].position = Vec2::new(10.0 + away as f64, 22.0);
        sim.players[away].velocity = Vec2::zero();
    }
    if with_cover {
        sim.players[13].position = Vec2::new(67.8, 81.5);
    }
    sim
}

#[test]
fn outside_mid_takeon_isolation_reaches_mdp_pomdp_neural_and_execution() {
    let sim = outside_mid_takeon_scenario(false);
    let carrier = 7usize;
    let snapshot = WorldSnapshot::from_match(&sim);
    let observation = snapshot.observation_for(carrier);
    let plan = snapshot
        .runaround_dribble_option_for(carrier)
        .expect("isolated outside mid should have a runaround plan");
    assert_eq!(plan.defender, 12);
    assert!(
        observation.outside_mid_takeon_isolation >= 0.70,
        "isolated outside mid should see a high take-on cue: {}",
        observation.outside_mid_takeon_isolation
    );
    let q_key = SoccerQStateKey::from_parts(
        &snapshot.mdp_state_for_player(carrier),
        &observation,
        Team::Home,
        PlayerRole::Midfielder,
    );
    assert!(
        q_key.outside_mid_takeon_isolation_bin > 0,
        "Q-state should bucket the take-on cue: {q_key:?}"
    );
    let decision = test_decision_trace(&snapshot, carrier, "runaround-dribble");
    let transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: carrier,
        team: Team::Home,
        role: PlayerRole::Midfielder,
        state: snapshot.mdp_state_for_player(carrier),
        observation: observation.clone(),
        belief: decision.belief,
        action: "runaround-dribble".to_string(),
        action_target: decision.action_target,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(carrier),
        next_observation: observation.clone(),
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert!(
        features[SOCCER_NEURAL_FEATURE_OUTSIDE_MID_TAKEON_ISOLATION] >= 0.70,
        "neural feature should preserve outside-mid isolation: {}",
        features[SOCCER_NEURAL_FEATURE_OUTSIDE_MID_TAKEON_ISOLATION]
    );
    let learned = SoccerLearnedPlan {
        action: "outside-mid-attack-defender".to_string(),
        target_player: None,
        target_point: None,
        mpc_replan: None,
    };
    let mut carrier_agent = sim.players[carrier].clone();
    let intent =
        carrier_agent.run_time_step(&snapshot, None, Some(&learned), &mut mulberry32(58_407));
    assert!(
        intent.sprint,
        "runaround take-on should sprint to re-collect"
    );
    assert!(
        matches!(intent.action, SoccerAction::MoveTo(target) if target.distance(plan.recollect_point) <= 1e-9),
        "runaround intent should move the body to the re-collect point: {intent:?} vs {plan:?}"
    );
    let runaround = carrier_agent
        .runaround
        .expect("learned outside-mid attack should store the runaround commitment");
    assert_eq!(runaround.defender, 12);
    let trace = carrier_agent
        .last_decision
        .as_ref()
        .expect("decision trace should be recorded");
    assert_eq!(trace.action, "runaround-dribble");
    assert!(
        trace
            .operation_order
            .iter()
            .any(|op| op == "outside-mid-attack-defender"),
        "trace should expose the named attacking strategy: {:?}",
        trace.operation_order
    );
}

#[test]
fn outside_mid_takeon_isolation_collapses_when_cover_is_within_ten_yards() {
    let clear = WorldSnapshot::from_match(&outside_mid_takeon_scenario(false));
    let covered = WorldSnapshot::from_match(&outside_mid_takeon_scenario(true));
    let clear_obs = clear.observation_for(7);
    let covered_obs = covered.observation_for(7);
    assert!(
        clear_obs.outside_mid_takeon_isolation >= 0.70,
        "clear fixture should start high: {}",
        clear_obs.outside_mid_takeon_isolation
    );
    assert!(
        covered_obs.outside_mid_takeon_isolation <= 0.20,
        "cover within 10 yards should collapse the cue: {}",
        covered_obs.outside_mid_takeon_isolation
    );
    assert!(
        covered.runaround_dribble_option_for(7).is_none(),
        "cover near the re-collect zone should block the runaround option"
    );
}

#[test]
fn outside_mid_attack_defender_strategy_is_registered_and_classified() {
    // The named "outside mid attack defender" play is a first-class catalogue entry, classified
    // as a wide take-on AND as a byline drive-and-cross program (it reuses that machinery).
    for s in [
        TeamAttackStrategy::OutsideMidAttackDefenderLeft,
        TeamAttackStrategy::OutsideMidAttackDefenderRight,
    ] {
        assert!(TeamAttackStrategy::ALL.contains(&s), "{s:?} must be in ALL");
        assert!(
            is_outside_mid_attack_strategy(s),
            "{s:?} is an outside-mid play"
        );
        assert!(
            is_byline_cross_drive_strategy(s),
            "{s:?} should drive the byline and cross"
        );
    }
    assert!(!is_outside_mid_attack_strategy(
        TeamAttackStrategy::CrashTheBox
    ));
    assert_eq!(
        TeamAttackStrategy::OutsideMidAttackDefenderLeft.as_str(),
        "outside-mid-attack-defender-left"
    );
    assert_eq!(
        TeamAttackStrategy::OutsideMidAttackDefenderRight.as_str(),
        "outside-mid-attack-defender-right"
    );
}

#[test]
fn outside_mid_attack_defender_keeps_driving_to_corner_inside_thirty_yards() {
    let mut sim =
        outside_mid_take_on_scenario(TeamAttackStrategy::OutsideMidAttackDefenderRight, 4.0, 8.0);
    let carrier = 7usize;
    sim.players[carrier].position = Vec2::new(64.0, 90.0); // 30yd from the Home attacking byline
    sim.ball.position = sim.players[carrier].position;
    let snapshot = WorldSnapshot::from_match(&sim);
    let origin = sim.players[carrier].position;
    let corner = snapshot
        .byline_corner_drive_target_for(carrier)
        .expect("outside-mid byline strategy should target the corner flag at 30yd");
    assert!(
        snapshot.byline_cross_drive_active_for(carrier),
        "outside mid should still be in the drive phase at 30yd from the byline"
    );
    assert!(
        corner.x > snapshot.field_width - 8.0 && corner.y > snapshot.field_length - 8.0,
        "right outside mid should drive at the right corner flag: {corner:?}"
    );

    let target = snapshot.dribble_move_target_for_touch(
        carrier,
        sim.players[carrier].home_position,
        DribbleMoveKind::CarryForward,
        DribbleTouchDecision::new(0, 4.8),
    );
    assert!(
        target.distance(corner) < origin.distance(corner),
        "carry touch should move closer to the corner flag: origin={origin:?} target={target:?} corner={corner:?}"
    );
    assert!(
        target.x > origin.x && target.y > origin.y,
        "right-sided byline drive should go forward-and-wide, not stop/cut inside: origin={origin:?} target={target:?}"
    );

    sim.players[carrier].position = Vec2::new(64.0, 96.0); // 24yd from the byline
    sim.ball.position = sim.players[carrier].position;
    let nearer_snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        nearer_snapshot.byline_cross_drive_active_for(carrier),
        "outside mid should not flip to the cross-release phase around 25yd"
    );

    sim.players[carrier].position = Vec2::new(
        64.0,
        sim.config.field_length_yards - (BYLINE_CROSS_RELEASE_DEPTH_YARDS - 1.0),
    );
    sim.ball.position = sim.players[carrier].position;
    let release_snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        !release_snapshot.byline_cross_drive_active_for(carrier),
        "outside mid should leave the drive phase inside the byline release depth"
    );
    assert!(
        release_snapshot
            .byline_corner_drive_target_for(carrier)
            .is_none(),
        "outside mid should cross/release rather than keep dribbling inside the release depth"
    );
}

/// A wide-right midfielder carrying at a committed full-back who has no covering team-mate near him.
fn outside_mid_take_on_scenario(
    strategy: TeamAttackStrategy,
    carrier_forward_speed: f64,
    carrier_top_speed: f64,
) -> SoccerMatch {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.central_brain.home_directive.attack_strategy = strategy;
    let carrier = 7usize;
    sim.players[carrier].role = PlayerRole::Midfielder;
    sim.players[carrier].home_position = Vec2::new(68.0, 60.0); // wide right of an 80yd pitch
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(64.0, 85.0); // wide, in the opponent half (Home attacks +y)
    sim.players[carrier].position = sim.ball.position;
    sim.players[carrier].velocity = Vec2::new(0.0, carrier_forward_speed);
    sim.players[carrier].skills.top_speed = carrier_top_speed;
    // The committed full-back, just ahead in the lane.
    sim.players[12].position = Vec2::new(64.5, 88.0);
    sim.players[12].velocity = Vec2::zero();
    sim.players[12].skills.top_speed = 7.0;
    // Every other opponent far away: the full-back is ISOLATED (nobody within 10yd of him).
    for away in [11usize, 13, 14, 15, 16, 17, 18, 19, 20, 21] {
        sim.players[away].position = Vec2::new(8.0, 20.0);
    }
    sim
}

#[test]
fn outside_mid_attack_defender_lifts_take_on_quality_vs_isolated_defender() {
    // Same wide carrier + isolated full-back; only the team strategy differs. The outside-mid play
    // should back the take-on more strongly (higher run-around quality => higher carrier appetite).
    let mut omad =
        outside_mid_take_on_scenario(TeamAttackStrategy::OutsideMidAttackDefenderRight, 6.0, 8.0);
    let mut plain =
        outside_mid_take_on_scenario(TeamAttackStrategy::PullWideRightThenCenter, 6.0, 8.0);
    // A deep cover man ~15yd behind the full-back: still BEYOND the 10yd isolation radius (so the
    // full-back is "isolated" for the take-on), but near enough the re-collect zone that the
    // baseline run-around quality is no longer saturated — exposing the appetite uplift.
    for sim in [&mut omad, &mut plain] {
        sim.players[13].position = Vec2::new(64.5, 103.0);
    }
    let omad_q = WorldSnapshot::from_match(&omad)
        .runaround_dribble_option_for(7)
        .expect("a take-on is on for the outside-mid play")
        .quality;
    let plain_q = WorldSnapshot::from_match(&plain)
        .runaround_dribble_option_for(7)
        .expect("a take-on is on at baseline too here")
        .quality;
    assert!(
        omad_q > plain_q + 0.05,
        "outside-mid play must lift the isolated-defender take-on appetite: omad={omad_q} plain={plain_q}"
    );
}

#[test]
fn outside_mid_attack_defender_takes_on_isolated_man_with_only_modest_momentum() {
    // Momentum below the baseline run-around threshold (4.0yps) but above the relaxed outside-mid
    // one (1.8yps), with no top-speed edge. Baseline declines (needs more momentum); the outside-mid
    // play backs the carrier to attack the isolated man anyway.
    let omad =
        outside_mid_take_on_scenario(TeamAttackStrategy::OutsideMidAttackDefenderRight, 2.5, 7.0);
    let plain = outside_mid_take_on_scenario(TeamAttackStrategy::PullWideRightThenCenter, 2.5, 7.0);
    assert!(
        WorldSnapshot::from_match(&omad)
            .runaround_dribble_option_for(7)
            .is_some(),
        "outside-mid play should take the isolated man on even from modest momentum"
    );
    assert!(
        WorldSnapshot::from_match(&plain)
            .runaround_dribble_option_for(7)
            .is_none(),
        "baseline run-around needs full forward momentum / a pace edge"
    );
}

#[test]
fn give_and_go_strategy_commits_to_wall_pass_and_runner_expectation() {
    let mut sim = wall_pass_scenario();
    sim.config.dt_seconds = PROBABILITY_REFERENCE_DT_SECONDS;
    sim.central_brain.home_directive.attack_strategy = TeamAttackStrategy::GiveAndGoCentral;
    sim.players[6].skills.passing_completion_rate = 9.0;
    sim.players[6].skills.passing = 9.0;
    sim.players[6].skills.vision = 9.0;
    sim.players[6].preferences.pass_bias = 1.0;

    let snapshot = WorldSnapshot::from_match(&sim);
    let plan = snapshot
        .wall_pass_option_for(6)
        .expect("a named give-and-go strategy should have a viable wall-pass plan");
    assert!(
        plan.quality >= WALL_PASS_STRATEGY_COMMIT_MIN_QUALITY,
        "fixture must clear the strategy commitment quality floor: {plan:?}"
    );

    let mut carrier = sim.players[6].clone();
    let intent = carrier.run_time_step(&snapshot, None, None, &mut mulberry32(58_401));
    match intent.action {
        SoccerAction::Pass {
            target_player,
            flight,
            ..
        } => {
            assert_eq!(target_player, Some(plan.wall_partner));
            assert_eq!(flight, PassFlight::Floor);
        }
        other => panic!("give-and-go strategy should commit to the wall pass, got {other:?}"),
    }
    let commitment = carrier
        .one_two
        .expect("carrier should store the one-two run");
    assert_eq!(commitment.wall_partner, plan.wall_partner);
    assert!(
        commitment.return_target.distance(plan.return_target) <= 1e-9,
        "stored return target should match the planned burst: {commitment:?} vs {plan:?}"
    );
    assert_eq!(
        carrier
            .last_decision
            .as_ref()
            .expect("decision trace")
            .action,
        "wall-pass"
    );
}

