#[test]
fn wall_partner_returns_first_time_to_committed_runner() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.clock_seconds = 8.0;
    let runner = 9;
    let wall = 7;
    sim.ball.holder = Some(wall);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[wall].position = Vec2::new(35.0, 84.0);
    sim.players[runner].position = Vec2::new(38.0, 90.0);
    // Away deep so the runner is onside and the return lane is clean.
    sim.players[11].position = Vec2::new(40.0, 118.0);
    for (k, away) in (12..22).enumerate() {
        sim.players[away].position = Vec2::new(20.0 + k as f64 * 5.0, 100.0);
    }
    sim.players[runner].one_two = Some(OneTwoRun {
        wall_partner: wall,
        launch_clock_seconds: sim.clock_seconds - 0.2,
        return_target: Vec2::new(40.0, 96.0),
    });
    let snapshot = WorldSnapshot::from_match(&sim);
    assert_eq!(
        snapshot.wall_return_pass_target_for(wall),
        Some(runner),
        "the wall should return the ball first-time to the committed runner"
    );

    // Once the live return lane is legal, the wall must execute it rather than roll a second
    // probabilistic appetite check and fall into generic first-touch/pass selection.
    sim.players[wall].skills.first_touch = 1.0;
    sim.players[wall].skills.passing = 1.0;
    let snapshot = WorldSnapshot::from_match(&sim);
    let mut wall_agent = sim.players[wall].clone();
    let intent = wall_agent.run_time_step(&snapshot, None, None, &mut mulberry32(58_404));
    assert!(
        matches!(
            intent.action,
            SoccerAction::Pass {
                target_player: Some(target),
                flight: PassFlight::Floor,
                ..
            } if target == runner
        ),
        "a bound wall should execute the return even with low technique: {:?}",
        intent.action
    );
    assert_eq!(
        wall_agent
            .last_decision
            .as_ref()
            .map(|decision| decision.action.as_str()),
        Some("wall-return")
    );
}

#[test]
fn pass_anticipation_intended_target_backs_off_when_teammate_is_closer() {
    // Intended-target belief & hand-off: the named receiver is dragged well off where the ball
    // will arrive, while a team-mate sits right on it. Receiver election always lets the named man
    // realise he is beaten and back off; broader pass anticipation only gates extra support and
    // first-touch behaviours.
    let from = Vec2::new(40.0, 45.0);
    let to = Vec2::new(40.0, 75.0);
    let build = |enabled: bool| {
        let mut sim = pass_anticipation_scene(&[10], from, to, enabled);
        sim.players[9].position = Vec2::new(22.0, 75.0); // named receiver, 18yd off the spot
        sim.players[9].velocity = Vec2::zero();
        sim.players[10].position = to; // team-mate sitting on the arrival point
        sim.players[10].velocity = Vec2::zero();
        sim
    };

    let on = WorldSnapshot::from_match(&build(true));
    assert!(
        on.pending_pass_reception_target_for(9).is_none(),
        "the named receiver backs off when a team-mate is clearly closer to the ball"
    );
    assert!(
        on.pending_pass_reception_target_for(10).is_some(),
        "the genuinely closer team-mate becomes the de-facto receiver and meets the ball"
    );

    let off = WorldSnapshot::from_match(&build(false));
    assert!(
        off.pending_pass_reception_target_for(9).is_none(),
        "even with anticipation off the named receiver backs off when a team-mate is clearly closer"
    );
    assert!(
        off.pending_pass_reception_target_for(10).is_some(),
        "even with anticipation off the closer team-mate becomes the de-facto receiver"
    );
}

#[test]
fn long_aerial_pass_receiver_attacks_descending_control_window() {
    // A long aerial should be attacked at the playable falling window (8ft -> 5ft), not only at
    // the final landing point. The teammate set near that window becomes the de-facto receiver,
    // and the POMDP/Q/neural surfaces all expose the control decision for learning.
    let from = Vec2::new(40.0, 20.0);
    let to = Vec2::new(40.0, 85.0);
    let named_receiver = 9usize;
    let window_receiver = 10usize;
    let mut sim = pass_anticipation_scene(&[window_receiver], from, to, true);
    sim.ball.velocity = (to - from).normalized() * 24.0;
    sim.players[named_receiver].position = to;
    sim.players[named_receiver].velocity = Vec2::zero();
    sim.players[window_receiver].position = Vec2::new(40.0, 75.0);
    sim.players[window_receiver].velocity = Vec2::zero();
    sim.players[window_receiver].skills.first_touch = 8.4;
    sim.players[window_receiver].skills.height = 7.6;
    sim.players[window_receiver].skills.vision = 7.8;
    let pass = sim.pending_pass.as_mut().expect("pending pass");
    pass.flight = PassFlight::Aerial;
    pass.launch_speed_yps = sim.ball.velocity.len();
    pass.distance_yards = from.distance(to);

    let snapshot = WorldSnapshot::from_match(&sim);
    let profile = snapshot.long_aerial_control_profile_for(window_receiver);
    assert!(
        profile.available,
        "nearby teammate should see a long-aerial falling control window: {profile:?}"
    );
    assert!(
        profile.target.y < to.y - 5.0 && profile.target.y > from.y + 45.0,
        "control target should be the descending 8ft->5ft window before final landing: {:?}",
        profile.target
    );
    assert!(
        profile.distance_yards <= 2.0,
        "fixture player should be near the falling control point: {profile:?}"
    );

    let named_target = snapshot.pending_pass_reception_target_for(named_receiver);
    assert!(
        named_target.is_none(),
        "named receiver at final landing should defer to the teammate already at the falling window"
    );
    let (target, sprint) = snapshot
        .pending_pass_reception_target_for(window_receiver)
        .expect("window receiver should attack the aerial control point");
    assert!(sprint, "attacking the falling long ball should be a sprint");
    assert!(
        target.distance(profile.target) < 0.75,
        "movement target should use the falling-window control point: target={target:?} profile={profile:?}"
    );

    let observation = snapshot.observation_for(window_receiver);
    assert!(observation.receiving_pending_pass);
    assert!(observation.long_aerial_control_window_available);
    assert!(observation.long_aerial_control_attack_score >= 0.45);
    assert!(
        observation.pending_pass_receiver_urgency >= 0.40,
        "long-aerial control score should lift receiver urgency: {:?}",
        observation.pending_pass_receiver_urgency
    );
    let q_key = SoccerQStateKey::from_parts(
        &snapshot.mdp_state_for_player(window_receiver),
        &observation,
        Team::Home,
        sim.players[window_receiver].role,
    );
    assert!(q_key.long_aerial_control_window_available);
    assert!(q_key.long_aerial_control_attack_bin >= 2);

    let transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: window_receiver,
        team: Team::Home,
        role: sim.players[window_receiver].role,
        state: snapshot.mdp_state_for_player(window_receiver),
        observation: observation.clone(),
        belief: belief_from_observation(&observation),
        action: "recover".to_string(),
        action_target: None,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(window_receiver),
        next_observation: observation,
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert!(
        features[SOCCER_NEURAL_FEATURE_LONG_AERIAL_CONTROL_ATTACK] > 0.40,
        "neural learner should see the aerial-control attack score"
    );
    assert!(
        features[SOCCER_NEURAL_FEATURE_LONG_AERIAL_CONTROL_DISTANCE] > 0.80,
        "neural learner should see the receiver is close to the control window"
    );
}

#[test]
fn long_aerial_control_profile_uses_receiver_take_point() {
    // The shared falling-window cue marks where the ball first becomes playable at ~8ft, but
    // each receiver still needs the POMDP reception decision: a free player already under the
    // ~5ft settle point should cushion it there instead of being pulled back to attack it high.
    let from = Vec2::new(40.0, 20.0);
    let to = Vec2::new(40.0, 85.0);
    let receiver = 9usize;
    let mut sim = pass_anticipation_scene(&[], from, to, true);
    sim.ball.velocity = (to - from).normalized() * 24.0;
    sim.ball.altitude_yards = AERIAL_CONTROL_BAND_TOP_YARDS + 0.75;
    sim.players[receiver].skills.first_touch = 8.8;
    sim.players[receiver].skills.height = 7.6;
    sim.players[receiver].skills.vision = 8.2;
    let pass = sim.pending_pass.as_mut().expect("pending pass");
    pass.flight = PassFlight::Aerial;
    pass.launch_speed_yps = sim.ball.velocity.len();
    pass.distance_yards = from.distance(to);

    let setup_snapshot = WorldSnapshot::from_match(&sim);
    let setup_pass = setup_snapshot.pending_pass.as_ref().expect("pending pass");
    let setup_player = setup_snapshot
        .players
        .iter()
        .find(|player| player.id == receiver)
        .expect("receiver snapshot");
    let (setup_descent, _, _) = setup_snapshot
        .aerial_reception_resolve(setup_player, setup_pass, setup_player.position)
        .expect("aerial descent setup");
    sim.players[receiver].position = setup_descent.settle_point;
    sim.players[receiver].velocity = Vec2::zero();

    let snapshot = WorldSnapshot::from_match(&sim);
    let pass = snapshot.pending_pass.as_ref().expect("pending pass");
    let player = snapshot
        .players
        .iter()
        .find(|player| player.id == receiver)
        .expect("receiver snapshot");
    let (descent, _, plan) = snapshot
        .aerial_reception_resolve(player, pass, player.position)
        .expect("aerial reception plan");
    assert_eq!(plan.decision, AerialReceptionDecision::SettleUnder);
    assert!(
        descent.attack_point.distance(descent.settle_point) > 2.0,
        "fixture should separate the 8ft attack point from the 5ft settle point: {descent:?}"
    );

    let profile = snapshot.long_aerial_control_profile_for(receiver);
    assert!(profile.available, "settle receiver should still see the long-aerial profile");
    assert!(
        profile.target.distance(plan.target) < 0.05,
        "profile should follow the POMDP take point, not the shared attack cue: profile={profile:?} plan={plan:?}"
    );
    assert!(
        profile.target.distance(descent.attack_point) > 2.0,
        "profile target should not collapse back to the 8ft attack point: profile={profile:?} descent={descent:?}"
    );
    assert!((profile.attack_blend - plan.attack_blend).abs() < 1e-9);
    assert!((profile.control_estimate - plan.control_estimate).abs() < 1e-9);
    assert!((profile.seconds_until_window - descent.time_to_settle).abs() < 1e-9);
}

#[test]
fn long_aerial_bounds_risk_reaims_and_reaches_learning_features() {
    // A long aerial aimed into the sideline/byline danger band should be priced as a pass-quality
    // risk, corrected inward for execution, and recorded in the learned completion feature vector.
    let origin = Vec2::new(40.0, 30.0);
    let risky_target = Vec2::new(1.0, 105.0);
    let risk =
        long_aerial_bounds_risk_for_target(origin, risky_target, 80.0, 120.0, PassFlight::Aerial);
    assert!(
        risk.risk > 0.45,
        "wide long aerial near touchline/byline should carry out-of-bounds risk: {risk:?}"
    );
    assert!(
        risk.inward_correction_yards > 3.0,
        "unsafe target should require an inward correction: {risk:?}"
    );
    let safe_target = long_aerial_safe_in_bounds_target(risky_target, 80.0, 120.0);
    assert!(
        safe_target.x >= LONG_AERIAL_BOUNDS_SAFE_TOUCHLINE_MARGIN_YARDS - 1e-6,
        "safe long-aerial target should be pulled inside touchline margin: {safe_target:?}"
    );
    assert!(
        safe_target.y <= 120.0 - LONG_AERIAL_BOUNDS_SAFE_BYLINE_MARGIN_YARDS + 1e-6,
        "safe long-aerial target should stay in front of byline margin: {safe_target:?}"
    );
    let floor_risk =
        long_aerial_bounds_risk_for_target(origin, risky_target, 80.0, 120.0, PassFlight::Floor);
    assert_eq!(
        floor_risk.risk, 0.0,
        "short/grounded decisions should not inherit long-aerial boundary risk"
    );

    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let passer = 6usize;
    let receiver = 9usize;
    park_players_except(&mut sim, &[passer, receiver]);
    sim.players[passer].team = Team::Home;
    sim.players[passer].position = origin;
    sim.players[receiver].team = Team::Home;
    sim.players[receiver].position = risky_target;
    sim.ball.holder = Some(passer);
    sim.ball.position = origin;
    sim.ball.last_touch_team = Some(Team::Home);
    let snapshot = WorldSnapshot::from_match(&sim);
    let features = snapshot.pass_completion_learn_features(
        Team::Home,
        origin,
        risky_target,
        origin.distance(risky_target),
        0.25,
        0.65,
        PassFlight::Aerial,
    );
    assert_eq!(features.len(), SOCCER_PASS_COMPLETION_FEATURE_DIM);
    assert!(
        features[SOCCER_PASS_COMPLETION_FEATURE_DIM_V1] > 0.45,
        "pass-completion learner should see long-aerial bounds risk"
    );
    assert!(
        features[SOCCER_PASS_COMPLETION_FEATURE_DIM_V1 + 2] > 0.40,
        "pass-completion learner should see the inward correction needed to stay in play"
    );
}

#[test]
fn long_aerial_bounds_risk_is_pomdp_q_and_neural_ready() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 0.1,
        seed: 91_337,
        formation_lp_enabled: false,
        ..Default::default()
    });
    let passer = 6usize;
    let risky_receiver = 9usize;
    park_players_except(&mut sim, &[passer, risky_receiver]);
    sim.players[passer].team = Team::Home;
    sim.players[passer].position = Vec2::new(40.0, 30.0);
    sim.players[passer].velocity = Vec2::zero();
    sim.players[passer].facing_yaw = std::f64::consts::FRAC_PI_2;
    sim.players[passer].action_facing = FacingBucket::South;
    sim.players[passer].skills.passing_completion_rate = 10.0;
    sim.players[passer].skills.passing = 10.0;
    sim.players[passer].skills.vision = 10.0;
    sim.players[passer].skills.crossing_left = 10.0;
    sim.players[passer].skills.crossing_right = 10.0;
    sim.players[risky_receiver].team = Team::Home;
    sim.players[risky_receiver].role = PlayerRole::Forward;
    sim.players[risky_receiver].position = Vec2::new(1.0, 58.0);
    sim.players[risky_receiver].velocity = Vec2::zero();
    sim.players[risky_receiver].skills.height = 10.0;
    sim.players[risky_receiver].skills.strength = 10.0;
    sim.players[risky_receiver].skills.first_touch = 10.0;
    sim.ball.holder = Some(passer);
    sim.ball.position = sim.players[passer].position;
    sim.ball.last_touch_team = Some(Team::Home);

    let snapshot = WorldSnapshot::from_match(&sim);
    let passer_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == passer)
        .expect("passer");
    let risky_receiver_snapshot = snapshot
        .players
        .iter()
        .find(|player| player.id == risky_receiver)
        .expect("risky receiver");
    let risky_quality = pass_target_quality_for_snapshot(
        &snapshot,
        passer_snapshot,
        sim.players[passer].position,
        risky_receiver_snapshot,
        sim.players[risky_receiver].position,
        PassFlight::Aerial,
    );
    assert!(
        risky_quality.long_aerial_bounds_risk > 0.25,
        "risky wide receiver should be scored with long-aerial boundary risk: {risky_quality:?}"
    );
    let observation = snapshot.observation_for(passer);
    let visible_aerial_targets = snapshot.ranked_visible_aerial_pass_targets(passer, 11);
    assert!(
        observation.long_aerial_bounds_risk > 0.05,
        "POMDP observation should expose the best-aerial boundary risk; visible_aerial_targets={visible_aerial_targets:?} can_see={} direct_risk={}",
        snapshot.player_can_see_player(passer, risky_receiver),
        risky_quality.long_aerial_bounds_risk
    );
    assert!(
        observation.long_aerial_bounds_inward_correction_yards > 0.25,
        "POMDP observation should expose how far the pass must be corrected inward"
    );
    let q_key = SoccerQStateKey::from_parts(
        &snapshot.mdp_state_for_player(passer),
        &observation,
        Team::Home,
        sim.players[passer].role,
    );
    assert!(
        q_key.long_aerial_bounds_risk_bin > 0,
        "Q-state key should bucket long-aerial boundary risk"
    );
    assert!(
        q_key.long_aerial_bounds_correction_bin > 0,
        "Q-state key should bucket long-aerial inward correction"
    );

    let transition = SoccerLearningTransition {
        tick: snapshot.tick,
        player_id: passer,
        team: Team::Home,
        role: sim.players[passer].role,
        state: snapshot.mdp_state_for_player(passer),
        observation: observation.clone(),
        belief: belief_from_observation(&observation),
        action: "pass".to_string(),
        action_target: None,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward: 0.0,
        next_state: snapshot.mdp_state_for_player(passer),
        next_observation: observation,
        done: false,
    };
    let features = soccer_neural_transition_features(&transition);
    assert!(
        features[SOCCER_NEURAL_FEATURE_LONG_AERIAL_BOUNDS_RISK] > 0.05,
        "neural learner should see long-aerial boundary risk"
    );
    assert!(
        features[SOCCER_NEURAL_FEATURE_LONG_AERIAL_BOUNDS_CORRECTION] > 0.05,
        "neural learner should see long-aerial inward correction"
    );
}

#[test]
fn pass_anticipation_first_touch_retains_away_from_a_bearing_down_marker() {
    // No team-mate to flick to: under a marker closing straight onto him, the receiver's first
    // touch pushes the ball into space AWAY from the marker's momentum to keep it.
    let from = Vec2::new(40.0, 45.0);
    let to = Vec2::new(40.0, 60.0);
    let build = |enabled: bool| {
        let mut sim = pass_anticipation_scene(&[17], from, to, enabled);
        sim.players[9].position = Vec2::new(40.0, 60.0);
        sim.players[9].velocity = Vec2::zero();
        sim.players[17].position = Vec2::new(43.0, 60.0);
        sim.players[17].velocity = Vec2::new(-5.0, 0.0); // bearing down from the right
        sim
    };
    let neutral = Vec2::new(40.0, 61.0);

    let on = WorldSnapshot::from_match(&build(true));
    let target = on.first_touch_directional_target_for(9, neutral);
    assert!(
        target.x < 40.0 - 0.3,
        "the retaining first touch pushes the ball away from the marker on the right: {target:?}"
    );

    let off = WorldSnapshot::from_match(&build(false));
    assert_eq!(
        off.first_touch_directional_target_for(9, neutral),
        neutral,
        "with anticipation off the first touch is the neutral controlling touch"
    );
}

#[test]
fn pass_anticipation_first_touch_flicks_onto_a_forward_runner() {
    // A team-mate breaks forward into clear space; the receiver (in his own half, so offside can't
    // apply) flicks his first touch onto that run rather than just settling it at his feet.
    let from = Vec2::new(40.0, 20.0);
    let to = Vec2::new(40.0, 35.0);
    let build = |enabled: bool| {
        let mut sim = pass_anticipation_scene(&[10], from, to, enabled);
        sim.players[9].position = Vec2::new(40.0, 30.0);
        sim.players[9].velocity = Vec2::zero();
        sim.players[10].position = Vec2::new(50.0, 40.0);
        sim.players[10].velocity = Vec2::new(0.0, 5.0); // forward run, out to the right
        sim
    };
    let neutral = Vec2::new(40.0, 31.0);

    let on = WorldSnapshot::from_match(&build(true));
    let target = on.first_touch_directional_target_for(9, neutral);
    assert!(
        target.x > 41.0 && target.y > 30.0,
        "the first touch is flicked forward toward the runner on the right: {target:?}"
    );

    let off = WorldSnapshot::from_match(&build(false));
    assert_eq!(
        off.first_touch_directional_target_for(9, neutral),
        neutral,
        "with anticipation off the first touch is the neutral controlling touch"
    );
}

fn install_fresh_controlled_ground_reception(sim: &mut SoccerMatch, receiver: usize, origin: Vec2) {
    let position = sim.players[receiver].position;
    let team = sim.players[receiver].team;
    sim.players[receiver].incoming_ball = Some(IncomingBallContext {
        from_player: Some(6),
        target_player: Some(receiver),
        team: Some(team),
        kind: IncomingBallKind::GroundPass,
        origin: Some(origin),
        intended_target: Some(position),
        speed_yps: 14.0,
        distance_yards: origin.distance(position),
        received_tick: sim.tick,
        is_cross: false,
        is_aerial: false,
    });
    sim.ball.holder = Some(receiver);
    sim.ball.position = position;
    sim.ball.velocity = Vec2::zero();
    sim.ball.last_touch_team = Some(team);
}

fn resisted_airborne_distance_for_pass(pass: &PendingPass) -> (f64, f64) {
    let mut speed = pass.launch_speed_yps.max(0.0);
    let mut covered = 0.0;
    let mut elapsed = 0.0;
    let apex = pass_loft_apex_yards(pass);
    let hang_time = 2.0 * (2.0 * apex / GRAVITY_YPS2).sqrt();
    while elapsed < hang_time - 1e-9 {
        let dt = (hang_time - elapsed).min(DEFAULT_DT_SECONDS);
        let altitude = pass_ball_altitude_yards(pass, elapsed + dt * 0.5);
        let step = ball_resistance_after(
            Vec2::new(speed, 0.0),
            dt,
            DEFAULT_BALL_DRAG_PER_TICK,
            DEFAULT_BALL_AIR_RESISTANCE,
            DEFAULT_BALL_GRASS_RESISTANCE_YPS2,
            altitude,
            DEFAULT_BALL_STOP_SPEED_YPS,
        );
        let next_speed = step.velocity.x.max(0.0);
        covered += (speed + next_speed) * 0.5 * dt;
        speed = next_speed;
        elapsed += dt;
    }
    (covered, speed)
}

#[test]
fn weak_long_aerial_does_not_float_in_the_air() {
    // Regression: a lofted ball is now a true gravity projectile, so it comes down at its hang
    // time T = 2·√(2·apex/g) regardless of pace and can never float. The x-y physics must also
    // keep carrying through that same window: launch speed is calibrated from distance / T and
    // airborne drag is light enough that the ball does not crawl short while gravity ticks.
    // This guards the worst case: a low-power, low-skill long ball.
    let weak = SkillProfile {
        passing: 0.15,
        passing_completion_rate: 0.15,
        strength: 0.15,
        ..SkillProfile::default()
    };
    let from = Vec2::new(34.0, 10.0);
    for distance in [12.0, 25.0, 40.0, 55.0, 68.0] {
        let target = Vec2::new(34.0, 10.0 + distance);
        // Lowest-power launch is the worst case for floating.
        let raw = pass_speed_yps_from_power(0.0, PassFlight::Aerial, false, &weak);
        let mut rng = SeededRandom::new(7);
        let speed = modulated_pass_speed_yps(
            raw,
            from,
            target,
            PassFlight::Aerial,
            false,
            pass_execution_skill(&weak, PassFlight::Aerial, false),
            0.5,
            &mut rng,
        );
        let pass = PendingPass {
            team: Team::Home,
            from: 4,
            target: Some(9),
            flight: PassFlight::Aerial,
            is_cross: false,
            launch_tick: 123,
            origin: from,
            intended_target: target,
            distance_yards: distance,
            receiver_openness: 0.50,
            passer_skill: pass_execution_skill(&weak, PassFlight::Aerial, false),
            launch_speed_yps: speed,
            receiver_position_at_launch: Some(target),
            receiver_velocity_at_launch: Some(Vec2::zero()),
            offside: None,
            offside_candidates: Vec::new(),
            learn_features: Vec::new(),
        };
        let flight_time = distance / speed;
        assert!(
            flight_time <= 2.85,
            "a {distance:.0}yd aerial floats for {flight_time:.2}s (speed {speed:.1} yps) — \
             the gravity hang-time ceiling should keep it under ~2.7s"
        );
        let (covered, end_speed) = resisted_airborne_distance_for_pass(&pass);
        assert!(
            covered >= distance * 0.99,
            "a {distance:.0}yd aerial should still cover the target before landing; \
             covered {covered:.1}yd, end_speed {end_speed:.1} yps, launch {speed:.1} yps"
        );
    }
}

#[test]
fn scoop_pass_is_low_and_snappy_not_a_balloon() {
    let skills = SkillProfile {
        passing: 0.45,
        passing_completion_rate: 0.50,
        flair_passing: 0.55,
        ..SkillProfile::default()
    };
    let from = Vec2::new(38.0, 48.0);
    for distance in [5.0, 8.0, 12.0, 15.0] {
        let target = Vec2::new(38.0, 48.0 + distance);
        let raw = pass_speed_yps_from_power(0.30, PassFlight::Scoop, false, &skills);
        let mut rng = SeededRandom::new(17);
        let speed = modulated_pass_speed_yps(
            raw,
            from,
            target,
            PassFlight::Scoop,
            false,
            pass_execution_skill(&skills, PassFlight::Scoop, false),
            0.70,
            &mut rng,
        );
        let pass = PendingPass {
            team: Team::Home,
            from: 4,
            target: Some(9),
            flight: PassFlight::Scoop,
            is_cross: false,
            launch_tick: 123,
            origin: from,
            intended_target: target,
            distance_yards: distance,
            receiver_openness: 0.70,
            passer_skill: pass_execution_skill(&skills, PassFlight::Scoop, false),
            launch_speed_yps: speed,
            receiver_position_at_launch: Some(target),
            receiver_velocity_at_launch: Some(Vec2::zero()),
            offside: None,
            offside_candidates: Vec::new(),
            learn_features: Vec::new(),
        };
        let apex = pass_loft_apex_yards(&pass);
        let apex_feet = apex * 3.0;
        let hang_time = 2.0 * (2.0 * apex / GRAVITY_YPS2).sqrt();
        let flight_time = distance / speed;
        assert!(
            (7.0 - 1e-9..=12.25 + 1e-9).contains(&apex_feet),
            "scoop apex should stay in the 7-12ft window, got {apex_feet:.1}ft"
        );
        assert!(
            hang_time <= 1.75,
            "scoop hang time should follow 12ft gravity math, got {hang_time:.2}s for {distance:.0}yd"
        );
        assert!(
            flight_time <= hang_time + 0.05,
            "scoop should reach the target inside its gravity hang-time window, got {flight_time:.2}s \
             vs {hang_time:.2}s for {distance:.0}yd"
        );
        assert!(
            flight_time <= 1.35,
            "scoop should be clipped and snappy, got {flight_time:.2}s for {distance:.0}yd"
        );
        let (covered, end_speed) = resisted_airborne_distance_for_pass(&pass);
        assert!(
            covered >= distance,
            "scoop x-y speed should carry to the receiver before gravity lands it; \
             covered {covered:.1}yd, end_speed {end_speed:.1} yps, launch {speed:.1} yps"
        );
    }
}

#[test]
fn slide_tackle_flag_defaults_on_and_respects_config() {
    // The committed slide-tackle mechanic is live by default (unless the process-wide
    // env flag is overriding it for an A-B/parity run), and a per-match config flag can
    // always pin it off regardless.
    if std::env::var("DD_SOCCER_DISABLE_SLIDE_TACKLE").is_err() {
        assert!(slide_tackle_enabled(&MatchConfig::default()));
    }
    assert!(!slide_tackle_enabled(&MatchConfig {
        disable_slide_tackle: true,
        ..Default::default()
    }));
}

#[test]
fn slide_tackle_wins_the_ball_more_often_than_a_standing_tackle() {
    // A full-stretch slide is more likely to win the ball than a standing poke: its
    // computed steal probability strictly exceeds the standing tackle's for the same
    // matchup (the tradeoff being the grounding risk on a miss, exercised elsewhere).
    let sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = &sim.players[0].skills;
    let attacker = &sim.players[11].skills;
    let standing = tackle_success_probability(defender, attacker);
    let slide = slide_tackle_success_probability(defender, attacker);
    assert!(
        slide > standing,
        "slide ({slide:.3}) should beat standing ({standing:.3})"
    );
    assert!(slide <= 0.97);
}

#[test]
fn standing_tackle_from_behind_is_blocked_but_ball_reachable_slide_can_win() {
    // The ball is led in front of the carrier; a trailing defender cannot poke it
    // cleanly with a standing tackle.
    {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let defender = 0;
        let attacker = 11;
        sim.players[attacker].position = Vec2::new(40.0, 60.0);
        sim.players[attacker].velocity = Vec2::new(0.0, 6.0);
        sim.players[attacker].skills.dribbling = 0.2;
        sim.players[attacker].skills.first_touch = 0.2;
        sim.players[defender].position = Vec2::new(40.0, 59.8);
        sim.players[defender].skills.defending = 10.0;
        sim.players[defender].skills.aggression = 10.0;
        sim.ball.position = Vec2::new(40.0, 60.8);
        sim.ball.holder = Some(attacker);

        assert!(
            sim.tackle_blocked_from_behind(attacker, sim.players[defender].position),
            "defender behind the led ball should be blocked"
        );
        assert!(
            !sim.carrier_shields_ball_from_defender(attacker, defender),
            "standing block should not rely only on the body-shield gap"
        );

        sim.apply_player_intent(PlayerIntent {
            player_id: defender,
            action: SoccerAction::Tackle {
                target_player: attacker,
            },
            sprint: true,
        });
        assert_eq!(
            sim.ball.holder,
            Some(attacker),
            "a standing tackle from behind must not win the ball"
        );
    }

    // A slide tackle is the exception, but only when the lunge can actually reach
    // the ball in front of the carrier.
    {
        let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
        let defender = 0;
        let attacker = 11;
        sim.players[attacker].position = Vec2::new(40.0, 60.0);
        sim.players[attacker].velocity = Vec2::new(0.0, 6.0);
        sim.players[attacker].skills.dribbling = 0.2;
        sim.players[attacker].skills.first_touch = 0.2;
        sim.players[attacker].skills.strength = 0.2;
        sim.players[defender].position = Vec2::new(40.0, 59.8);
        sim.players[defender].velocity = Vec2::new(0.0, 6.0);
        sim.players[defender].skills.defending = 10.0;
        sim.players[defender].skills.aggression = 9.0;
        sim.players[defender].skills.strength = 9.0;
        sim.ball.position = Vec2::new(40.0, 61.2);
        sim.ball.holder = Some(attacker);

        assert!(
            sim.tackle_blocked_from_behind(attacker, sim.players[defender].position),
            "the same behind-carrier geometry applies"
        );
        assert!(
            sim.carrier_shields_ball_from_defender(attacker, defender),
            "the carrier body is between defender and ball, so only a slide may reach it"
        );
        assert!(
            sim.players[defender].position.distance(sim.ball.position)
                <= SLIDE_TACKLE_MAX_REACH_YARDS,
            "slide setup must be within actual ball reach"
        );

        sim.apply_player_intent(PlayerIntent {
            player_id: defender,
            action: SoccerAction::SlideTackle {
                target_player: attacker,
            },
            sprint: true,
        });
        assert_eq!(
            sim.ball.holder,
            Some(defender),
            "a ball-reachable slide from behind is the one allowed exception"
        );
        assert_eq!(
            sim.players[defender].slide_recovery_seconds, 0.0,
            "winning the slide tackle means no recovery grounding"
        );
    }
}

#[test]
fn missed_slide_tackle_grounds_defender_for_uniform_recovery_window() {
    // A slide that fails to win the ball (here forced by being outside ball reach)
    // puts the defender flat on the grass for a uniform 1.75-2.25s and costs the
    // team the committed-challenge penalty.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 0;
    let attacker = 11;
    sim.players[attacker].position = Vec2::new(40.0, 60.0);
    sim.players[attacker].velocity = Vec2::new(0.0, 6.0);
    sim.ball.position = Vec2::new(40.0, 61.2);
    sim.ball.holder = Some(attacker);
    // Close enough to launch at the carrier, too far to reach the led ball.
    sim.players[defender].position = Vec2::new(40.0, 57.6);

    sim.apply_player_intent(PlayerIntent {
        player_id: defender,
        action: SoccerAction::SlideTackle {
            target_player: attacker,
        },
        sprint: true,
    });

    let recovery = sim.players[defender].slide_recovery_seconds;
    assert!(
        recovery >= SLIDE_TACKLE_RECOVERY_MIN_SECONDS
            && recovery <= SLIDE_TACKLE_RECOVERY_MAX_SECONDS,
        "grounded for {recovery:.3}s, expected [{:.2}, {:.2}]",
        SLIDE_TACKLE_RECOVERY_MIN_SECONDS,
        SLIDE_TACKLE_RECOVERY_MAX_SECONDS
    );
    assert_eq!(sim.ball.holder, Some(attacker));
    let defender_reward = sim
        .reward_events
        .iter()
        .filter(|event| event.player_id == defender)
        .map(|event| event.amount)
        .sum::<f64>();
    assert_eq!(defender_reward, -FAILED_SLIDE_TACKLE_PENALTY_POINTS);
}

#[test]
fn clean_slide_tackle_from_in_front_can_win_the_ball() {
    // Goal-side of a fast carrier with the ball led toward the defender (not shielded,
    // not from behind): a strong defender's slide wins it cleanly and stays on its feet.
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    let defender = 0;
    let attacker = 11;
    sim.players[attacker].position = Vec2::new(40.0, 60.0);
    sim.players[attacker].velocity = Vec2::new(0.0, 6.0);
    sim.players[attacker].skills.dribbling = 0.2;
    sim.players[attacker].skills.first_touch = 0.2;
    sim.players[attacker].skills.strength = 0.2;
    sim.ball.position = Vec2::new(40.0, 61.5);
    sim.ball.holder = Some(attacker);
    // Defender goal-side (ahead in the carrier's direction of travel), in reach.
    sim.players[defender].position = Vec2::new(40.0, 61.0);
    sim.players[defender].skills.defending = 10.0;
    sim.players[defender].skills.aggression = 9.0;
    sim.players[defender].skills.strength = 9.0;

    assert!(!sim.tackle_blocked_from_behind(attacker, sim.players[defender].position));

    sim.apply_player_intent(PlayerIntent {
        player_id: defender,
        action: SoccerAction::SlideTackle {
            target_player: attacker,
        },
        sprint: true,
    });

    assert_ne!(
        sim.ball.holder,
        Some(attacker),
        "a clean slide from in front should take the ball off the carrier"
    );
    assert_eq!(
        sim.players[defender].slide_recovery_seconds, 0.0,
        "winning the ball means staying on your feet — no grounding"
    );
}

#[test]
fn grounded_defender_holds_position_until_recovered() {
    // While grounded, a player makes no decision and does not move; the clock bleeds
    // down by dt each tick and clears after the recovery window.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        learning_enabled: false,
        full_game_learning_enabled: false,
        ..Default::default()
    });
    let grounded = 5;
    let spot = Vec2::new(3.0, 3.0);
    sim.players[grounded].position = spot;
    sim.players[grounded].home_position = spot;
    sim.players[grounded].velocity = Vec2::new(8.0, 0.0);
    sim.players[grounded].slide_recovery_seconds = 2.0;

    sim.run_time_step();
    assert!(
        sim.players[grounded].position.distance(spot) < 0.05,
        "a grounded player must not move (was {:?})",
        sim.players[grounded].position
    );
    assert!(sim.players[grounded].velocity.len() < 1e-6);
    assert!(sim.players[grounded].slide_recovery_seconds < 2.0);

    // Tick out the rest of the window; it must reach zero (back on its feet).
    for _ in 0..40 {
        if sim.players[grounded].slide_recovery_seconds <= 0.0 {
            break;
        }
        sim.run_time_step();
    }
    assert_eq!(sim.players[grounded].slide_recovery_seconds, 0.0);
    assert!(sim.players[grounded].position.distance(spot) < 0.05);
}

#[test]
fn pass_completion_head_learns_separable_pattern() {
    // The learned pass-completion model must actually learn: given samples where completion is a
    // clean function of one feature, training should separate the two classes.
    let sample = |signal: f32, completed: bool| {
        let mut features = vec![0.0f32; SOCCER_PASS_COMPLETION_FEATURE_DIM];
        // Use a couple of pass-feature slots (after the 256-d embedding) as the signal channel.
        *features.last_mut().unwrap() = signal;
        features[SOCCER_MOMENT_EMBEDDING_DIM] = signal;
        SoccerPassOutcomeSample {
            features,
            completed,
            own_half: true,
        }
    };
    let mut samples = Vec::new();
    for _ in 0..96 {
        samples.push(sample(1.0, true));
        samples.push(sample(0.0, false));
    }
    let mut head = SoccerPassCompletionHead::new(11);
    for _ in 0..250 {
        head.train(&samples, 0.05);
    }
    let p_complete = head.predict(&sample(1.0, true).features).unwrap();
    let p_fail = head.predict(&sample(0.0, false).features).unwrap();
    assert!(
        p_complete > p_fail + 0.2,
        "model should separate completed vs intercepted: complete={p_complete} fail={p_fail}"
    );
    assert!(head.training_steps() > 0);
    // Malformed input is rejected, not panicked.
    assert!(head.predict(&[0.0; 3]).is_none());
}

#[test]
fn pass_completion_head_accepts_legacy_six_feature_samples() {
    let sample = |signal: f32, completed: bool| {
        let mut features = vec![0.0f32; SOCCER_PASS_COMPLETION_FEATURE_DIM_V1];
        *features.last_mut().unwrap() = signal;
        features[SOCCER_MOMENT_EMBEDDING_DIM] = signal;
        SoccerPassOutcomeSample {
            features,
            completed,
            own_half: true,
        }
    };
    let mut samples = Vec::new();
    for _ in 0..96 {
        samples.push(sample(1.0, true));
        samples.push(sample(0.0, false));
    }
    let mut head = SoccerPassCompletionHead::new(19);
    for _ in 0..250 {
        head.train(&samples, 0.05);
    }
    let legacy_complete = sample(1.0, true);
    let legacy_fail = sample(0.0, false);
    let p_complete = head.predict(&legacy_complete.features).unwrap();
    let p_fail = head.predict(&legacy_fail.features).unwrap();
    assert!(
        p_complete > p_fail + 0.2,
        "legacy six-feature pass corpus should still train after boundary features are appended: complete={p_complete} fail={p_fail}"
    );
    assert!(head.training_steps() > 0);
}

#[test]
fn pass_completion_corpus_loaded_from_postgres_trains_a_usable_head() {
    // Item: "get the training data to load from postgres." The pass-outcome corpus that
    // `SoccerStore::load_pass_outcome_samples` returns must actually feed training. Mirror that
    // load by handing a corpus to the public load-and-train entry and confirm it learns.
    let sample = |signal: f32, completed: bool| {
        let mut features = vec![0.0f32; SOCCER_PASS_COMPLETION_FEATURE_DIM];
        *features.last_mut().unwrap() = signal;
        features[SOCCER_MOMENT_EMBEDDING_DIM] = signal;
        SoccerPassOutcomeSample {
            features,
            completed,
            own_half: true,
        }
    };
    let mut corpus = Vec::new();
    for _ in 0..128 {
        corpus.push(sample(1.0, true));
        corpus.push(sample(0.0, false));
    }
    let report = report_soccer_pass_completion_training(
        &corpus,
        7,
        300,
        DEFAULT_SOCCER_PASS_COMPLETION_LEARNING_RATE,
    )
    .expect("a non-empty corpus should train a head");
    assert_eq!(report.samples, corpus.len());
    assert_eq!(report.epochs, 300);
    assert!(report.training_steps > 0);
    assert!(
        report.accuracy > 0.9,
        "a head trained on the loaded corpus should fit the separable pattern: acc={}",
        report.accuracy
    );
    for bad_rate in [f64::NAN, -1.0, 10_000.0] {
        let report = report_soccer_pass_completion_training(&corpus, 7, 2, bad_rate)
            .expect("standalone pass-completion training should sanitize bad rates");
        assert!(report.training_steps > 0);
        assert!(report.final_loss.is_finite());
        assert!(report.accuracy.is_finite());
    }
    // An empty corpus (nothing persisted yet) trains nothing rather than persisting a random net.
    assert!(report_soccer_pass_completion_training(
        &[],
        7,
        300,
        DEFAULT_SOCCER_PASS_COMPLETION_LEARNING_RATE,
    )
    .is_none());
}

#[test]
fn pass_completion_head_installs_on_match_and_propagates_to_snapshot() {
    // #4 wiring: the learner installs the carried pass-completion head on the match via
    // `set_pass_completion_head`, and every per-tick `WorldSnapshot` shares it (Arc clone) so
    // `pass_target_quality_for_snapshot` can consume it live. Default = none (parity).
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 7,
        ..MatchConfig::default()
    });
    // Consumption is opt-in: the gate must default OFF so the wiring is byte-identical until
    // an operator flips DD_SOCCER_ENABLE_LEARNED_PASS_COMPLETION.
    assert!(
        !learned_pass_completion_enabled(),
        "learned pass-completion consumption must be off by default (parity)"
    );
    // No head installed ⇒ the snapshot carries none (analytic estimate stands alone).
    let before = WorldSnapshot::from_match(&sim);
    assert!(before.pass_completion_head.is_none());
    // Install a trained head; the snapshot must now share it.
    sim.set_pass_completion_head(SoccerPassCompletionHead::new(3));
    let after = WorldSnapshot::from_match(&sim);
    assert!(
        after.pass_completion_head.is_some(),
        "installed head must propagate into the per-tick snapshot"
    );
}

#[test]
fn pass_outcome_samples_are_captured_during_play() {
    // Phase 1 (the learning substrate): resolved passes must emit labelled training samples whose
    // features are the 22+ball config embedding + pass features captured at launch.
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        seed: 99,
        ..MatchConfig::default()
    });
    for _ in 0..1200 {
        sim.run_time_step();
    }
    assert!(
        !sim.pass_outcome_samples.is_empty(),
        "resolved passes should produce learning samples"
    );
    for sample in &sim.pass_outcome_samples {
        assert_eq!(sample.features.len(), SOCCER_PASS_COMPLETION_FEATURE_DIM);
        assert!(sample.features.iter().all(|v| v.is_finite()));
    }
    // Draining hands them off (to the cluster learner / Postgres) and clears the buffer.
    let drained = sim.drain_pass_outcome_samples();
    assert!(!drained.is_empty());
    assert!(sim.pass_outcome_samples.is_empty());
}

// --- Hold-and-summon support (wait-for-support / delay-before-pass) -------------

/// A calm Home carrier (id 6) on the ball with NO forward outlet on, one teammate (id 7)
/// level with him in a clean central channel who could make an onside forward run, and the
/// other outfielders neutralised (deep defenders) so the only viable summon is that runner.
fn hold_for_support_scenario() -> SoccerMatch {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    sim.tick = 30;
    sim.clock_seconds = 12.0;
    let carrier = 6;
    sim.ball.holder = Some(carrier);
    sim.ball.position = Vec2::new(40.0, 60.0);
    sim.ball.last_touch_team = Some(Team::Home);
    sim.players[carrier].role = PlayerRole::Midfielder;
    sim.players[carrier].position = sim.ball.position;
    sim.players[carrier].home_position = sim.ball.position;
    // Park the other Home outfielders deep as defenders: behind the carrier (not forward
    // outlets) and role-excluded from the forward-run summon, so id 7 is the only candidate.
    for (k, home) in [1usize, 2, 3, 4, 5, 8, 9, 10].into_iter().enumerate() {
        sim.players[home].role = PlayerRole::Defender;
        sim.players[home].position = Vec2::new(8.0 + k as f64 * 8.0, 45.0);
        sim.players[home].home_position = sim.players[home].position;
    }
    // The designated runner: level with the carrier (forward gain < the min, so NOT an outlet
    // yet) in a clean central channel, able to make an onside forward run.
    let runner = 7;
    sim.players[runner].role = PlayerRole::Forward;
    sim.players[runner].position = Vec2::new(46.0, 61.0);
    sim.players[runner].home_position = sim.players[runner].position;
    // Away keeper deep; a flat back line at y = 95 with a clean central channel around x = 40-46
    // (so the second-last-defender line sits at 95 and an onside run target is ~y 94).
    sim.players[11].position = Vec2::new(40.0, 118.0);
    let line_xs = [12.0, 20.0, 28.0, 56.0, 64.0, 72.0, 8.0, 76.0, 4.0, 80.0];
    for (away, x) in (12..=21).zip(line_xs) {
        sim.players[away].position = Vec2::new(x, 95.0);
    }
    // Block the carrier's STRAIGHT-AHEAD dribbling lane: one Away player steps into the central
    // channel ~6yd in front (calm — outside the 4.5yd press radius — but inside the 6yd
    // drive-into-space lane), so the picture is genuinely blocked and the answer is to wait-and-
    // summon, not to carry. Placed off the carrier→runner diagonal so it leaves that summon lane
    // clean. Without this, an unpressured carrier with the road open drives into the space itself.
    sim.players[15].position = Vec2::new(37.0, 65.5);
    sim
}

#[test]
fn hold_for_support_summons_a_forward_run_when_no_outlet_is_on() {
    let sim = hold_for_support_scenario();
    let snapshot = WorldSnapshot::from_match(&sim);
    let plan = snapshot
        .hold_for_support_option_for(6)
        .expect("a calm carrier with no forward outlet should be able to wait-and-summon");
    assert_eq!(
        plan.kind,
        SupportSummonKind::MoveForward,
        "with space ahead the carrier should summon a forward run: {plan:?}"
    );
    assert_eq!(
        plan.summoned,
        vec![7],
        "only the viable forward runner should be summoned: {plan:?}"
    );
    assert!(
        plan.summoned.len() <= HOLD_FOR_SUPPORT_MAX_SUMMONED,
        "summoned set is capped: {plan:?}"
    );
    assert!(
        plan.quality > 0.0,
        "plan should have positive quality: {plan:?}"
    );
}

#[test]
fn hold_for_support_declines_once_a_forward_outlet_already_exists() {
    let mut sim = hold_for_support_scenario();
    // Push one teammate into a clean, open, onside forward position: now a real outlet is on,
    // so there is nothing to wait for — the gate must decline (the carrier should just pass).
    sim.players[8].role = PlayerRole::Forward;
    sim.players[8].position = Vec2::new(38.0, 80.0);
    sim.players[8].home_position = sim.players[8].position;
    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        snapshot.hold_for_support_option_for(6).is_none(),
        "a clean forward outlet should self-terminate the wait"
    );
}

#[test]
fn hold_for_support_declines_when_not_calm_on_the_ball() {
    let mut sim = hold_for_support_scenario();
    // A defender steps onto the carrier: this is pressured retention (protect-ball), not the
    // calm "let the play set up" wait — the gate must decline.
    sim.players[12].position = Vec2::new(41.0, 62.0);
    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        snapshot.hold_for_support_option_for(6).is_none(),
        "a proximate defender should rule out the calm wait"
    );
}

#[test]
fn hold_for_support_declines_when_open_grass_is_ahead_to_drive_into() {
    let mut sim = hold_for_support_scenario();
    // Clear the central blocker so the carrier has an open forward dribbling lane again. A calm,
    // unpressured carrier with the road open in front should DRIVE into the space rather than
    // stand on the ball to summon support — the gate must decline (this is the freeze fix).
    sim.players[15].position = Vec2::new(56.0, 95.0);
    let snapshot = WorldSnapshot::from_match(&sim);
    assert!(
        snapshot.forward_dribble_space_yards(6) >= HOLD_FOR_SUPPORT_DRIVE_INTO_SPACE_YARDS,
        "scenario should leave open forward space to drive into"
    );
    assert!(
        snapshot.hold_for_support_option_for(6).is_none(),
        "open grass ahead should make the carrier drive, not wait"
    );
}

#[test]
fn support_summon_is_read_only_by_the_signalled_teammate() {
    let mut sim = hold_for_support_scenario();
    sim.players[6].hold_for_support = Some(HoldForSupport {
        kind: SupportSummonKind::MoveForward,
        launch_clock_seconds: sim.clock_seconds,
        summoned: vec![7],
    });
    let snapshot = WorldSnapshot::from_match(&sim);
    assert_eq!(
        snapshot.support_summon_for(7),
        Some(SupportSummonKind::MoveForward),
        "the summoned teammate reads the carrier's signal"
    );
    assert_eq!(
        snapshot.support_summon_for(8),
        None,
        "a non-summoned teammate reads nothing"
    );
    assert_eq!(
        snapshot.support_summon_for(6),
        None,
        "the carrier does not summon itself"
    );
    assert_eq!(
        snapshot.support_summon_for(13),
        None,
        "an opponent never reads our summon"
    );
}

#[test]
fn pass_learning_metrics_rollup_and_rates() {
    let mut stats = MatchStats::default();
    stats.passes_attempted_home = 10;
    stats.passes_completed_home = 8;
    stats.passes_attempted_away = 6;
    stats.passes_completed_away = 3;
    stats.completed_pass_gain_yards_home = 40.0;
    stats.completed_pass_gain_yards_away = 11.0;
    stats.pass_chains_home = 2;
    stats.pass_chains_away = 1;
    stats.pass_chain_gain_yards_home = 18.0;
    stats.pass_chains_net_loss_away = 1;
    stats.shots_on_target_home = 2;
    stats.shots_after_pass_home = 1;

    let metrics = stats.pass_learning_metrics();
    assert_eq!(metrics.passes_attempted, 16);
    assert_eq!(metrics.passes_completed, 11);
    assert!((metrics.completion_rate() - 11.0 / 16.0).abs() < 1e-9);
    assert!((metrics.completed_pass_gain_yards - 51.0).abs() < 1e-9);
    assert!((metrics.average_yards_per_completed_pass() - 51.0 / 11.0).abs() < 1e-9);
    assert_eq!(metrics.pass_chains, 3);
    assert_eq!(metrics.pass_chains_net_loss, 1);
    assert_eq!(metrics.shots_after_pass, 1);

    let mut total = SoccerPassLearningMetrics::default();
    total.accumulate(&metrics);
    total.accumulate(&metrics);
    assert_eq!(total.passes_completed, 22);
    assert_eq!(total.pass_chains, 6);
    assert!((total.completed_pass_gain_yards - 102.0).abs() < 1e-9);

    // No passes attempted => rates are a safe zero, not a divide-by-zero.
    let empty = SoccerPassLearningMetrics::default();
    assert_eq!(empty.completion_rate(), 0.0);
    assert_eq!(empty.average_yards_per_completed_pass(), 0.0);
}

#[test]
fn pass_chain_finalize_counts_only_real_chains() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());

    // A 3-pass chain that gained 12 yards counts once.
    sim.pass_chain_meter = PassChainMeter {
        team: Some(Team::Home),
        passes: 3,
        gain_yards: 12.0,
    };
    sim.finalize_pass_chain_metrics();
    assert_eq!(sim.stats.pass_chains_home, 1);
    assert!((sim.stats.pass_chain_gain_yards_home - 12.0).abs() < 1e-9);
    assert_eq!(sim.stats.pass_chains_net_loss_home, 0);
    // The meter is consumed (reset) so a second finalize is a no-op.
    assert_eq!(sim.pass_chain_meter.team, None);
    sim.finalize_pass_chain_metrics();
    assert_eq!(sim.stats.pass_chains_home, 1);

    // A single completed pass is not a chain.
    sim.pass_chain_meter = PassChainMeter {
        team: Some(Team::Away),
        passes: 1,
        gain_yards: 5.0,
    };
    sim.finalize_pass_chain_metrics();
    assert_eq!(sim.stats.pass_chains_away, 0);

    // A 2-pass chain that lost ground is flagged as a net-loss chain.
    sim.pass_chain_meter = PassChainMeter {
        team: Some(Team::Away),
        passes: 2,
        gain_yards: -4.0,
    };
    sim.finalize_pass_chain_metrics();
    assert_eq!(sim.stats.pass_chains_away, 1);
    assert_eq!(sim.stats.pass_chains_net_loss_away, 1);

    // summary() folds an open chain WITHOUT mutating live state.
    sim.pass_chain_meter = PassChainMeter {
        team: Some(Team::Home),
        passes: 4,
        gain_yards: 9.0,
    };
    let summary = sim.summary();
    assert_eq!(summary.stats.pass_chains_home, 2);
    assert_eq!(sim.stats.pass_chains_home, 1);
    assert!(sim.pass_chain_meter.team.is_some());
}

#[test]
fn pass_chain_meter_finalizes_on_possession_end_and_never_double_counts() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig::default());
    // An open chain finalises when the possession ends (this path is shared by turnover,
    // goal, half-time, kickoff and dead-ball resets).
    sim.pass_chain_meter = PassChainMeter {
        team: Some(Team::Home),
        passes: 3,
        gain_yards: 15.0,
    };
    sim.finish_possession_progress_chain(false);
    assert_eq!(sim.stats.pass_chains_home, 1);
    assert!((sim.stats.pass_chain_gain_yards_home - 15.0).abs() < 1e-9);
    // Meter is emptied, so the chain cannot leak into the next possession or across a half.
    assert_eq!(sim.pass_chain_meter.team, None);

    // summary() with an empty meter folds nothing extra (no double count of the chain above).
    assert_eq!(sim.summary().stats.pass_chains_home, 1);

    // A still-open chain at the whistle is counted exactly once by summary(), and summary()
    // must NOT mutate the live stats.
    sim.pass_chain_meter = PassChainMeter {
        team: Some(Team::Away),
        passes: 2,
        gain_yards: 6.0,
    };
    assert_eq!(sim.summary().stats.pass_chains_away, 1);
    assert_eq!(sim.stats.pass_chains_away, 0);
}

#[test]
fn neural_snapshot_carries_progress_so_loaded_net_is_warm() {
    // Train an inline neural value head briefly, then persist + reload it. The loaded net must
    // come back WARM (training progress restored) so the decision-time value blend treats it as
    // authoritative on serve — otherwise serving falls back to the aliased tabular path while
    // training used the kinematic value head.
    let config = MatchConfig {
        duration_seconds: 0.6,
        max_human_players: 0,
        neural_learning: SoccerNeuralLearningConfig {
            enabled: true,
            backend: SoccerNeuralLearningBackend::Inline,
            train_every_ticks: 1,
            hidden_units: 8,
            ..SoccerNeuralLearningConfig::default()
        },
        seed: 4242,
        ..Default::default()
    };
    let mut sim = SoccerMatch::default_11v11(config.clone())
        .with_team_policies(SoccerTeamQPolicies::new(SoccerQPolicyOptions::default()));
    for _ in 0..60 {
        sim.run_time_step();
    }
    let trained_steps = sim.learning_snapshot().neural_learning_training_steps;
    assert!(
        trained_steps > 0,
        "inline neural learning should have trained"
    );

    let snapshot = sim
        .neural_network_snapshot()
        .expect("trained neural snapshot");
    assert_eq!(
        snapshot.training_steps, trained_steps,
        "snapshot must carry the learner's training progress"
    );
    assert!(
        snapshot.average_loss.is_some_and(|loss| loss.is_finite()),
        "snapshot must carry a finite average loss"
    );

    // A freshly loaded net restores the progress (warm), not a cold step-0 learner.
    let resumed = SoccerMatch::default_11v11(config)
        .with_neural_network_snapshot(snapshot.clone())
        .expect("resume persisted neural snapshot");
    assert_eq!(
        resumed.neural_training_steps_for(Team::Home),
        snapshot.training_steps,
        "loaded net must restore training progress so the value blend treats it as warm"
    );
}

#[test]
fn overload_weighted_progression_gate_defaults_off() {
    // The whole feature must be opt-in: with the env unset the gate is off so the reward path is
    // byte-identical to the prior behaviour. (No other test in this binary sets the env.)
    assert!(
        !dd_soccer_enable_overload_weighted_progression(),
        "DD_SOCCER_ENABLE_OVERLOAD_WEIGHTED_PROGRESSION must default OFF"
    );
}

#[test]
fn overload_forward_pass_progression_points_zero_without_overload() {
    let per_yard = OVERLOAD_FORWARD_PASS_PROGRESSION_REWARD_PER_YARD_DEFAULT;
    // No overload (the gated-off weight) => no bonus, regardless of forward yards.
    assert_eq!(
        overload_forward_pass_progression_points(20.0, 0.0, per_yard),
        0.0
    );
    // Overload but the ball did not go forward => no bonus (we only reward forward progression).
    assert_eq!(
        overload_forward_pass_progression_points(-5.0, 1.0, per_yard),
        0.0
    );
    assert_eq!(
        overload_forward_pass_progression_points(0.0, 1.0, per_yard),
        0.0
    );
}

#[test]
fn overload_forward_pass_progression_points_scales_with_overload_and_caps() {
    let per_yard = OVERLOAD_FORWARD_PASS_PROGRESSION_REWARD_PER_YARD_DEFAULT;
    let half = overload_forward_pass_progression_points(10.0, 0.5, per_yard);
    let full = overload_forward_pass_progression_points(10.0, 1.0, per_yard);
    assert!(
        (full - 10.0 * per_yard).abs() < 1e-9,
        "full overload => yards*per_yard"
    );
    assert!(
        (half - full * 0.5).abs() < 1e-9,
        "bonus scales linearly in overload"
    );
    // Forward yardage is capped, so beyond the cap the bonus does not keep growing.
    let at_cap = overload_forward_pass_progression_points(
        OVERLOAD_FORWARD_PASS_PROGRESSION_REWARD_MAX_YARDS,
        1.0,
        per_yard,
    );
    let beyond_cap = overload_forward_pass_progression_points(
        OVERLOAD_FORWARD_PASS_PROGRESSION_REWARD_MAX_YARDS + 25.0,
        1.0,
        per_yard,
    );
    assert!(
        (at_cap - beyond_cap).abs() < 1e-9,
        "forward yardage is capped"
    );
}

#[test]
fn overload_pass_chain_event_multiplier_is_identity_without_overload() {
    let fraction = OVERLOAD_PASS_CHAIN_EVENT_BONUS_FRACTION_DEFAULT;
    // Gated-off weight (overload 0) => multiplier 1.0 => the chain event reward is unchanged.
    assert_eq!(overload_pass_chain_event_multiplier_for(0.0, fraction), 1.0);
    // Full overload => 1 + fraction; clamped overload keeps it bounded.
    assert!(
        (overload_pass_chain_event_multiplier_for(1.0, fraction) - (1.0 + fraction)).abs() < 1e-9
    );
    assert!(
        (overload_pass_chain_event_multiplier_for(2.0, fraction) - (1.0 + fraction)).abs() < 1e-9
    );
}

#[test]
fn marl_balanced_team_component_default_gate_off() {
    // The balanced-team-component fix must be opt-in so the default training run is byte-identical.
    assert!(
        !dd_soccer_enable_marl_balanced_team_component(),
        "DD_SOCCER_ENABLE_MARL_BALANCED_TEAM_COMPONENT must default OFF"
    );
}

#[test]
fn marl_team_component_balanced_only_suppresses_single_team_ticks() {
    // A single-team tick: only the home team logged a sample (e.g. a drained deferred goal-chain
    // credit trained apart from its 22-player cohort). The opponent mean is undefined.
    let mut home_only = SoccerMarlTickReward::default();
    home_only.record(Team::Home, 30.0, 0.0);

    // Legacy (unbalanced) behaviour: opponent mean defaults to 0.0, so the "zero-sum" term leaks
    // the full one-sided reward — this is the bias being hardened against.
    assert_eq!(
        soccer_marl_team_component(home_only, Team::Home, false),
        30.0,
        "unbalanced term leaks own reward when the opponent is absent"
    );
    // Balanced: a single-team tick contributes no centralized team component.
    assert_eq!(
        soccer_marl_team_component(home_only, Team::Home, true),
        0.0,
        "balanced term suppresses single-team ticks"
    );
}

#[test]
fn marl_team_component_unchanged_when_both_teams_present() {
    // Both teams logged samples this tick: the team component is the genuine zero-sum difference and
    // the balanced flag must NOT change it.
    let mut both = SoccerMarlTickReward::default();
    both.record(Team::Home, 4.0, 0.0);
    both.record(Team::Home, 2.0, 0.0); // home mean 3.0
    both.record(Team::Away, 1.0, 0.0); // away mean 1.0
    let unbalanced = soccer_marl_team_component(both, Team::Home, false);
    let balanced = soccer_marl_team_component(both, Team::Home, true);
    assert!(
        (unbalanced - 2.0).abs() < 1e-9,
        "home_mean - away_mean = 3 - 1"
    );
    assert_eq!(
        unbalanced, balanced,
        "balanced flag is a no-op when both teams are present"
    );
    // Antisymmetric across teams (genuinely zero-sum) when both are present.
    assert!((soccer_marl_team_component(both, Team::Away, true) + balanced).abs() < 1e-9);
}

#[test]
#[ignore]
fn audit_defender_goalside_in_lane() {
    // PHYSICS AUDIT (not an assertion): run full matches and find defenders who are
    // ball-side (NOT goal-side) of the ball while the opponent controls possession,
    // *while still holding their zonal lane* (x near their home x). Prints a report.
    const LANE_TOL: f64 = 8.0; // within this of home.x => "holding lane / zonal"
    const NEAR_BALL: f64 = 6.0; // closer than this => legit contester, exempt
    const WRONG_SIDE: f64 = 1.0; // ball-side by more than this (yards) => violation
    const TICK_CAP: u64 = 5000;

    #[derive(Default, Clone)]
    struct Acc {
        opp_poss_ticks: u64,
        def_obs: u64,
        viol_in_lane: u64,
        viol_out_lane: u64,
        worst: Vec<(u64, String, f64, f64, f64, f64, String)>, // tick, who, margin, lane_dev, ball_dist, depth, action
        by_shirt: std::collections::BTreeMap<u8, u64>,
        by_action: std::collections::BTreeMap<String, u64>,
    }

    for seed_run in 0..1u64 {
        let mut m = SoccerMatch::default_11v11(MatchConfig::live_gameplay());
        let mut acc = Acc::default();
        let mut tick: u64 = 0;
        while tick < TICK_CAP && !m.is_done() {
            m.run_time_step();
            tick += 1;
            let snap = WorldSnapshot::from_match(&m);
            let Some(poss) = snap
                .controlled_possession_team()
                .or_else(|| snap.possession_team())
            else {
                continue;
            };
            // controlled possession only (genuine attacker on the ball)
            if snap.controlled_possession_team() != Some(poss) {
                continue;
            }
            let defending = poss.other();
            acc.opp_poss_ticks += 1;
            let ball = m.ball.position;
            let attack_dir = defending.attack_dir();
            for p in m
                .players
                .iter()
                .filter(|p| p.team == defending && p.role == PlayerRole::Defender)
            {
                let ball_dist = p.position.distance(ball);
                if ball_dist <= NEAR_BALL {
                    continue; // legit contester
                }
                acc.def_obs += 1;
                // >0 => goal-side (between ball and own goal); <0 => ahead of ball.
                let margin = (ball.y - p.position.y) * attack_dir;
                if margin >= -WRONG_SIDE {
                    continue; // goal-side (or within tolerance)
                }
                let lane_dev = (p.position.x - p.home_position.x).abs();
                // own-goal depth of the defender (how deep he is)
                let own_goal_y = defending.other().goal_y(snap.field_length);
                let depth = (p.position.y - own_goal_y).abs();
                if lane_dev <= LANE_TOL {
                    acc.viol_in_lane += 1;
                    let action = p
                        .last_decision
                        .as_ref()
                        .map(|d| d.action.clone())
                        .unwrap_or_else(|| "<none>".to_string());
                    *acc.by_shirt.entry(p.shirt).or_default() += 1;
                    *acc.by_action.entry(action.clone()).or_default() += 1;
                    let who = format!(
                        "{:?}#{} (home x={:.1})",
                        defending, p.shirt, p.home_position.x
                    );
                    acc.worst
                        .push((tick, who, margin, lane_dev, ball_dist, depth, action));
                } else {
                    acc.viol_out_lane += 1;
                }
            }
        }
        acc.worst.sort_by(|a, b| a.2.partial_cmp(&b.2).unwrap());
        let pct = |n: u64, d: u64| {
            if d == 0 {
                0.0
            } else {
                100.0 * n as f64 / d as f64
            }
        };
        eprintln!(
            "\n=== RUN {seed_run}: ticks_played={tick} opp_controlled_poss_ticks={} ===",
            acc.opp_poss_ticks
        );
        eprintln!(
            "defender-observations (opp poss, >6yd off ball)={}  ball-side violations: in-lane={} ({:.1}%)  out-of-lane={} ({:.1}%)",
            acc.def_obs,
            acc.viol_in_lane,
            pct(acc.viol_in_lane, acc.def_obs),
            acc.viol_out_lane,
            pct(acc.viol_out_lane, acc.def_obs),
        );
        eprintln!("in-lane violations by shirt: {:?}", acc.by_shirt);
        eprintln!(
            "in-lane violations by chosen action label: {:?}",
            acc.by_action
        );
        eprintln!("worst 15 IN-LANE ball-side examples (defender stuck in zone, ahead of ball):");
        for (t, who, margin, lane_dev, bd, depth, action) in acc.worst.iter().take(15) {
            eprintln!(
                "  tick {t:>5}  {who:<26} ahead-of-ball={:.1}yd  lane_dev={:.1}yd  ball_dist={:.1}yd  own-depth={:.1}yd  action={action}",
                -margin, lane_dev, bd, depth
            );
        }
    }
}

/// The learnable shot-trigger MDP/POMDP (default-ON) disciplines the *when*: a far,
/// keeper-covered chance carries a much lower trigger value than a close, clear one, and
/// that flows through to the live `shoot` action score — the "shoots from 25 when he
/// should work it to 20/15" fix. (Parity with the model off is verified by running the
/// suite with `DD_SOCCER_DISABLE_SHOT_TRIGGER_MDP=1`, which skips the seam entirely.)
#[test]
fn shot_trigger_mdp_disciplines_far_covered_shots_vs_close_clear() {
    // This test asserts the model's live effect; skip it cleanly when the kill-switch is
    // set (a parity run) so disabling the feature reproduces the legacy red/green set.
    if !shot_trigger_mdp_enabled() {
        return;
    }
    let build = |attacker_y: f64, keeper_y: f64| -> SoccerMatch {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: 0.1,
            seed: 41_207,
            ..Default::default()
        });
        let attacker = 9;
        let keeper = 11;
        park_players_except(&mut sim, &[attacker, keeper]);
        sim.players[attacker].role = PlayerRole::Forward;
        sim.players[attacker].position = Vec2::new(40.0, attacker_y);
        sim.players[attacker].velocity = Vec2::zero();
        sim.players[attacker].skills.shooting = 8.0;
        sim.players[attacker].skills.right_foot_shot_power = 8.5;
        sim.players[attacker].skills.left_foot_shot_power = 7.0;
        sim.players[attacker].skills.decision_noise = 0.0;
        sim.players[attacker].preferences.shoot_bias = 0.80;
        // Keeper planted on his line, centred — covers the net for the far shot.
        sim.players[keeper].position = Vec2::new(40.0, keeper_y);
        sim.players[keeper].skills.goalkeeping = 8.0;
        sim.ball.holder = Some(attacker);
        sim.ball.position = sim.players[attacker].position;
        sim.ball.velocity = Vec2::zero();
        sim.ball.last_touch_team = Some(Team::Home);
        sim
    };

    // Close, clear: ~14yd from goal (y=106, goal line y=120).
    let close_sim = build(106.0, 119.0);
    let close_snapshot = WorldSnapshot::from_match(&close_sim);
    let close_obs = close_snapshot.observation_for(9);
    // Far, keeper-covered: ~25yd from goal (y=95), keeper set on his line.
    let far_sim = build(95.0, 118.0);
    let far_snapshot = WorldSnapshot::from_match(&far_sim);
    let far_obs = far_snapshot.observation_for(9);

    // The live seam populated the trigger value (model is ON by default).
    assert!(
        close_obs.shot_trigger_mdp_value >= 0.0 && far_obs.shot_trigger_mdp_value >= 0.0,
        "the shot-trigger seam should populate the observation when the model is on"
    );
    assert!(
        close_obs.shot_trigger_mdp_value > far_obs.shot_trigger_mdp_value,
        "a close clear chance must out-value a far covered one: close={} far={}",
        close_obs.shot_trigger_mdp_value,
        far_obs.shot_trigger_mdp_value
    );
    assert!(
        far_obs.shot_trigger_mdp_value < 0.5,
        "a 25yd covered shot should be a low-value trigger, got {}",
        far_obs.shot_trigger_mdp_value
    );

    // And it flows through to the live shoot action score.
    let close_directive = close_snapshot.tactical_directive(Team::Home);
    let close_shoot = close_sim.players[9]
        .possession_action_options(
            &close_obs,
            &close_directive,
            0,
            0,
            false,
            close_sim.config.dt_seconds,
            close_snapshot.field_width,
        )
        .into_iter()
        .find(|o| o.label == "shoot")
        .expect("close shoot option");
    let far_directive = far_snapshot.tactical_directive(Team::Home);
    let far_shoot = far_sim.players[9]
        .possession_action_options(
            &far_obs,
            &far_directive,
            0,
            0,
            false,
            far_sim.config.dt_seconds,
            far_snapshot.field_width,
        )
        .into_iter()
        .find(|o| o.label == "shoot")
        .expect("far shoot option");
    assert!(
        close_shoot.probability > far_shoot.probability,
        "the close clear shot should be preferred over the far covered one: close={:?} far={:?}",
        close_shoot,
        far_shoot
    );
}

/// Self-play training harness for the shot-trigger head (run on demand, not in CI):
///   cargo test --lib -- --ignored --nocapture shot_trigger_training_pass
/// Plays several full matches with the model ON (default), collects the reward-weighted
/// RL corpus, trains the head over epochs (printing the loss curve = convergence), and
/// reports the distribution of shot distances actually taken. Re-run with
/// `DD_SOCCER_DISABLE_SHOT_TRIGGER_MDP=1` for the A/B (model-off) distance distribution.
#[test]
#[ignore]
fn shot_trigger_training_pass_reports_convergence_and_shot_distances() {
    let games = 4usize;
    let ticks_per_game = 1_200usize;
    let mut corpus: Vec<ShotTriggerSample> = Vec::new();
    let mut shot_distances: Vec<f64> = Vec::new();

    for g in 0..games {
        let mut sim = SoccerMatch::default_11v11(MatchConfig {
            duration_seconds: ticks_per_game as f64 * DEFAULT_DT_SECONDS,
            seed: 90_000 + g as u32,
            ..Default::default()
        });
        let mut events_seen = 0usize;
        for _ in 0..ticks_per_game {
            sim.run_time_step();
            // Capture every shot's distance to goal from the shooter's observation.
            if sim.events.len() > events_seen {
                let snapshot = WorldSnapshot::from_match(&sim);
                for ev in &sim.events[events_seen..] {
                    if ev.kind == "shot" {
                        if let Some(shooter) = ev.player_id {
                            let d = snapshot.observation_for(shooter).yards_to_goal;
                            if d.is_finite() {
                                shot_distances.push(d);
                            }
                        }
                    }
                }
                events_seen = sim.events.len();
            }
        }
        corpus.extend(sim.drain_shot_trigger_samples());
    }

    let shoot_yes = corpus.iter().filter(|s| s.action_shoot >= 0.5).count();
    println!(
        "shot_trigger corpus: samples={} shoot_yes={} held={} shots_taken={}",
        corpus.len(),
        shoot_yes,
        corpus.len() - shoot_yes,
        shot_distances.len()
    );
    assert!(!corpus.is_empty(), "self-play should produce a shot-trigger corpus");

    // Train the head over epochs and print the loss curve (convergence).
    let mut head = ShotTriggerHead::new(7);
    print!("loss_curve:");
    let mut last = f64::INFINITY;
    for _ in 0..30 {
        last = head.train_reward_weighted(&corpus, 0.03);
        print!(" {last:.5}");
    }
    println!();
    assert!(last.is_finite());
    assert!(head.training_steps() > 0);

    // Shot-distance distribution actually produced under the live model.
    if !shot_distances.is_empty() {
        let n = shot_distances.len() as f64;
        let mean = shot_distances.iter().sum::<f64>() / n;
        let within_20 = shot_distances.iter().filter(|&&d| d <= 20.0).count() as f64 / n;
        let within_16 = shot_distances.iter().filter(|&&d| d <= 16.0).count() as f64 / n;
        let beyond_25 = shot_distances.iter().filter(|&&d| d > 25.0).count() as f64 / n;
        let mut buckets = [0usize; 4]; // [<=12, 12-20, 20-25, >25]
        for &d in &shot_distances {
            let i = if d <= 12.0 {
                0
            } else if d <= 20.0 {
                1
            } else if d <= 25.0 {
                2
            } else {
                3
            };
            buckets[i] += 1;
        }
        println!(
            "shot_distance model_on={} mean={:.1}yd within16={:.1}% within20={:.1}% beyond25={:.1}% buckets[<=12,12-20,20-25,>25]={:?}",
            shot_trigger_mdp_enabled(),
            mean,
            within_16 * 100.0,
            within_20 * 100.0,
            beyond_25 * 100.0,
            buckets
        );
    }
}

// ---- Terminal won-game reward (the "long" rung of the quasi-win ladder) ----

#[test]
fn match_outcome_reward_is_zero_sum_with_capped_margin() {
    // 1-0: base win reward, no margin bonus (margin 1 ⇒ 0 extra).
    let one_nil = MatchOutcomeReward::from_score(1, 0);
    assert!((one_nil.home - MATCH_OUTCOME_WIN_REWARD_POINTS).abs() < 1e-9);
    assert!((one_nil.home + one_nil.away).abs() < 1e-9, "zero-sum");

    // 3-0: +2 goals over the win margin ⇒ 2× per-goal bonus.
    let three_nil = MatchOutcomeReward::from_score(3, 0);
    let expected = MATCH_OUTCOME_WIN_REWARD_POINTS + 2.0 * MATCH_OUTCOME_PER_GOAL_MARGIN_POINTS;
    assert!((three_nil.home - expected).abs() < 1e-9);
    assert!(three_nil.away < 0.0 && (three_nil.home + three_nil.away).abs() < 1e-9);

    // A blowout is capped: the bonus saturates at MARGIN_CAP, so 9-0 == cap.
    let blowout = MatchOutcomeReward::from_score(9, 0);
    let capped = MATCH_OUTCOME_WIN_REWARD_POINTS
        + (MATCH_OUTCOME_MARGIN_CAP_GOALS - 1.0) * MATCH_OUTCOME_PER_GOAL_MARGIN_POINTS;
    assert!((blowout.home - capped).abs() < 1e-9, "margin bonus is capped");

    // Loss mirrors the win; draw is the neutral constant for both sides.
    let loss = MatchOutcomeReward::from_score(0, 2);
    assert!(loss.home < 0.0 && loss.away > 0.0);
    let draw = MatchOutcomeReward::from_score(1, 1);
    assert!((draw.home - MATCH_OUTCOME_DRAW_REWARD_POINTS).abs() < 1e-9);
    assert!((draw.away - MATCH_OUTCOME_DRAW_REWARD_POINTS).abs() < 1e-9);
}

#[test]
fn full_game_replay_outcome_label_is_broadcast_and_off_is_byte_identical() {
    let mut sim = SoccerMatch::default_11v11(MatchConfig {
        duration_seconds: 4.0,
        seed: 42_424,
        ..MatchConfig::default()
    });
    sim.run_time_step();
    sim.run_time_step();
    let after = WorldSnapshot::from_match(&sim);

    let pick = |team: Team| -> usize {
        sim.players
            .iter()
            .find(|p| {
                p.team == team && p.role != PlayerRole::Goalkeeper && p.last_decision.is_some()
            })
            .expect("a field player with a decision")
            .id
    };
    let home_id = pick(Team::Home);
    let away_id = pick(Team::Away);
    let belief = |id: usize| {
        sim.players[id]
            .last_decision
            .as_ref()
            .expect("decision")
            .belief
            .clone()
    };
    let make = |id: usize, team: Team, reward: f64| SoccerLearningTransition {
        tick: after.tick,
        player_id: id,
        team,
        role: PlayerRole::Midfielder,
        state: after.mdp_state_for_player(id),
        observation: after.observation_for(id),
        belief: belief(id),
        action: "pass".to_string(),
        action_target: None,
        decision_context: SoccerDecisionContext::default(),
        tactical_trace: SoccerTacticalLearningTrace::default(),
        reward,
        next_state: after.mdp_state_for_player(id),
        next_observation: after.observation_for(id),
        done: false,
    };
    // Both transitions share the tick, so each team's single-sample mean equals
    // its own reward and the blended baseline reward is exactly that reward.
    let transitions = vec![make(home_id, Team::Home, 2.0), make(away_id, Team::Away, 1.0)];

    let baseline = soccer_full_game_replay_transitions(&transitions, None);
    let home_base = baseline.iter().find(|t| t.team == Team::Home).unwrap().reward;
    let away_base = baseline.iter().find(|t| t.team == Team::Away).unwrap().reward;
    assert!((home_base - 2.0).abs() < 1e-6, "off-path = shaped reward only");
    assert!((away_base - 1.0).abs() < 1e-6);

    // Home wins 2-0 ⇒ a positive label on the home decision, the mirror on away.
    let outcome = MatchOutcomeReward::from_score(2, 0);
    let labelled = soccer_full_game_replay_transitions(&transitions, Some(outcome));
    let home_lab = labelled.iter().find(|t| t.team == Team::Home).unwrap().reward;
    let away_lab = labelled.iter().find(|t| t.team == Team::Away).unwrap().reward;
    assert!(
        (home_lab - (home_base + outcome.home)).abs() < 1e-6,
        "winner's whole-game decisions are credited by the result"
    );
    assert!(
        (away_lab - (away_base + outcome.away)).abs() < 1e-6,
        "loser's decisions are debited by the result"
    );
    assert!(home_lab > home_base && away_lab < away_base);
}

#[test]
fn policy_advantage_standardization_zero_means_and_skips_degenerate_batches() {
    // Fewer than two samples ⇒ nothing to standardize.
    assert!(policy_advantage_standardization(&[]).is_none());
    assert!(policy_advantage_standardization(&[3.0]).is_none());
    // Zero variance (a flat label with no contrast) is left untouched, not /0.
    assert!(policy_advantage_standardization(&[5.0, 5.0, 5.0]).is_none());
    // A non-finite advantage poisons the variance ⇒ skip rather than emit NaN.
    assert!(policy_advantage_standardization(&[1.0, f64::INFINITY]).is_none());

    // A real batch: applying (a - mean)/(std + 1e-8) yields ~zero-mean, ~unit-variance,
    // and — the property that matters for the won-game label — preserves the sign
    // contrast (winner's positive advantage stays above the loser's negative one).
    let advantages = [10.0, 2.0, -3.0, -9.0];
    let (mean, std) = policy_advantage_standardization(&advantages).expect("non-degenerate");
    let standardized: Vec<f64> = advantages.iter().map(|a| (a - mean) / (std + 1e-8)).collect();
    let new_mean = standardized.iter().sum::<f64>() / standardized.len() as f64;
    assert!(new_mean.abs() < 1e-6, "standardized batch is zero-mean");
    assert!(standardized[0] > standardized[3], "win-vs-loss contrast preserved");
    let new_var = standardized.iter().map(|a| (a - new_mean).powi(2)).sum::<f64>()
        / standardized.len() as f64;
    assert!((new_var - 1.0).abs() < 1e-3, "standardized batch is ~unit-variance");
}
